#[derive(Debug, Serialize, Deserialize, Clone, PartialEq, Eq)]
#[serde(untagged)]
enum PluginEventDeclaration {
    Name(String),
    Detailed {
        name: String,
        #[serde(default)]
        description: Option<String>,
    },
}

impl PluginEventDeclaration {
    fn name(&self) -> &str {
        match self {
            PluginEventDeclaration::Name(name) => name,
            PluginEventDeclaration::Detailed { name, .. } => name,
        }
    }

    fn description(&self) -> Option<&str> {
        match self {
            PluginEventDeclaration::Name(_) => None,
            PluginEventDeclaration::Detailed { description, .. } => description.as_deref(),
        }
    }
}

