#[derive(Debug, Clone, PartialEq, Eq)]
struct PluginPreflight {
    ready: bool,
    status: String,
    message: String,
    library_path: Option<String>,
    entrypoint: Option<String>,
}

impl PluginPreflight {
    fn registry_state_for_disabled_plugin(&self) -> PluginState {
        if self.status == "incompatible" {
            PluginState::Incompatible
        } else {
            PluginState::Disabled
        }
    }

    fn registry_state_for_enabled_plugin(&self) -> PluginState {
        if self.status == "incompatible" {
            PluginState::Incompatible
        } else {
            PluginState::Failed
        }
    }

    fn registry_error(&self) -> Option<String> {
        if self.ready {
            None
        } else {
            Some(self.message.clone())
        }
    }
}

