fn apply_download_create_options(
    mut request: CreateDownloadRequest,
    options: Option<DownloadTaskCreateOptionsRequest>,
) -> CreateDownloadRequest {
    let Some(options) = options else {
        return request;
    };
    if options.output_dir.is_some() {
        request.output_dir = options.output_dir;
    }
    if options.output_path.is_some() {
        request.output_path = options.output_path;
    }
    if options.user_agent.is_some() {
        request.user_agent = options.user_agent;
    }
    if options.referer.is_some() {
        request.referer = options.referer;
    }
    if options.proxy.is_some() {
        request.proxy = options.proxy;
    }
    if options.cookie_bucket_id.is_some() {
        request.cookie_bucket_id = options.cookie_bucket_id;
    }
    if options.auth_payload_ref.is_some() {
        request.auth_payload_ref = options.auth_payload_ref;
    }
    if options.rate_limit.is_some() {
        request.rate_limit = options.rate_limit;
    }
    if options.live_from_start.is_some() {
        request.live_from_start = options.live_from_start;
    }
    if options.concurrent_fragments.is_some() {
        request.concurrent_fragments = options.concurrent_fragments;
    }
    if options.custom_ytdlp_args.is_some() {
        request.custom_ytdlp_args = options.custom_ytdlp_args;
    }
    if options.start_seconds.is_some() {
        request.start_seconds = options.start_seconds;
    }
    if options.end_seconds.is_some() {
        request.end_seconds = options.end_seconds;
    }
    if options.quality.is_some() {
        request.quality = options.quality;
    }
    if options.audio_format.is_some() {
        request.audio_format = options.audio_format;
    }
    if options.thumbnail_url.is_some() {
        request.thumbnail_url = options.thumbnail_url;
    }
    if options.expected_sha256.is_some() {
        request.expected_sha256 = options.expected_sha256;
    }
    if options.subtitles.is_some() {
        request.subtitles = options.subtitles;
    }
    if options.sponsorblock.is_some() {
        request.sponsorblock = options.sponsorblock;
    }
    if options.metadata.is_some() {
        request.metadata = options.metadata;
    }
    if options.run_after_active_slot.is_some() {
        request.run_after_active_slot = options.run_after_active_slot;
    }
    request
}

fn apply_task_create_options_to_task(
    task: &mut DownloadTask,
    options: Option<DownloadTaskCreateOptionsRequest>,
) -> Result<(), String> {
    let Some(options) = options else {
        return Ok(());
    };
    if let Some(output_dir) = options
        .output_dir
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        task.output_dir = validate_output_dir(Some(output_dir))?;
    }
    if let Some(output_path) = options
        .output_path
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        task.output_path = Some(display_path(validate_output_file_path(
            output_path,
            "Download output file",
        )?));
    }
    if let Some(value) = sanitize_header_value(options.user_agent.as_deref()) {
        task.user_agent = Some(value);
    }
    if let Some(value) = sanitize_header_value(options.referer.as_deref()) {
        task.referer = Some(value);
    }
    if let Some(value) = sanitize_optional_text(options.proxy.as_deref()) {
        task.proxy = Some(value);
    }
    if let Some(value) = sanitize_cookie_bucket_id(options.cookie_bucket_id.as_deref()) {
        task.cookie_bucket_id = Some(value);
    }
    if let Some(value) = sanitize_auth_payload_ref(options.auth_payload_ref.as_deref()) {
        task.auth_payload_ref = Some(value);
    }
    if let Some(value) = sanitize_optional_text(options.rate_limit.as_deref()) {
        task.rate_limit = Some(value);
    }
    if let Some(value) = options.live_from_start {
        task.live_from_start = value;
    }
    if let Some(value) = sanitize_concurrent_fragments(options.concurrent_fragments) {
        task.concurrent_fragments = Some(value);
    }
    if let Some(value) = sanitize_optional_text(options.custom_ytdlp_args.as_deref()) {
        task.custom_ytdlp_args = Some(value);
    }
    validate_clip_times(options.start_seconds, options.end_seconds)?;
    if let Some(value) = sanitize_clip_seconds(options.start_seconds) {
        task.start_seconds = Some(value);
    }
    if let Some(value) = sanitize_clip_seconds(options.end_seconds) {
        task.end_seconds = Some(value);
    }
    if let Some(value) = options.quality.as_deref() {
        task.quality = Some(sanitize_quality(value));
    }
    if let Some(value) = options.audio_format.as_deref() {
        task.audio_format = Some(sanitize_audio_format(value));
    }
    if let Some(value) = options
        .thumbnail_url
        .as_deref()
        .and_then(|url| normalize_http_url(url).ok())
    {
        task.thumbnail_url = Some(value);
    }
    if let Some(value) = options.expected_sha256.as_deref() {
        set_download_task_expected_sha256(task, value)?;
    }
    if let Some(value) = options.subtitles {
        task.subtitles = Some(sanitize_subtitle_settings(value));
    }
    if let Some(value) = options.sponsorblock {
        task.sponsorblock = Some(sanitize_sponsorblock_settings(value));
    }
    if let Some(value) = options.metadata {
        task.metadata = Some(value);
    }
    if let Some(value) = options.run_after_active_slot {
        task.run_after_active_slot = value;
    }
    Ok(())
}

