fn default_release_capability_catalog_export_path(root: &Path) -> PathBuf {
    root.join("diagnostics").join(format!(
        "release-capability-catalog-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn export_release_capability_catalog_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let export_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Release capability catalog export")?,
        None => default_release_capability_catalog_export_path(root),
    };
    validate_json_file_path(&export_path, "Release capability catalog export")?;
    if let Some(parent) = export_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let catalog = build_release_capability_catalog_at_root(root);
    let review_notes = catalog.review_notes.clone();
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "fetchdock.release_capability_catalog",
        "catalog": catalog,
        "review_notes": review_notes,
        "verifies_packaged_app_e2e": false,
        "verifies_signing_e2e": false,
        "verifies_update_install_e2e": false
    });
    fs::write(
        &export_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write release capability catalog export: {error}"))?;
    Ok(DiagnosticsResponse {
        archive_path: display_path(export_path),
    })
}

#[allow(clippy::too_many_arguments)]
fn diagnostics_capability_catalog_item(
    capability: &str,
    label: &str,
    status: &str,
    commands: &[&str],
    cli_aliases: &[&str],
    desktop_ui: &[&str],
    data_files: &[&str],
    evidence_fields: &[&str],
    sensitive_fields: &[&str],
    reads_diagnostics_files: bool,
    reads_download_log_bodies: bool,
    reads_download_urls: bool,
    reads_cookie_values: bool,
    reads_auth_values: bool,
    reads_downloaded_content: bool,
    writes_diagnostics_files: bool,
    deletes_local_files: bool,
    mutates_settings: bool,
    supports_batch: bool,
    scope: &str,
    limitations: &[&str],
) -> DiagnosticsCapabilityCatalogItem {
    DiagnosticsCapabilityCatalogItem {
        capability: capability.to_string(),
        label: label.to_string(),
        status: status.to_string(),
        commands: commands.iter().map(|value| (*value).to_string()).collect(),
        cli_aliases: cli_aliases.iter().map(|value| (*value).to_string()).collect(),
        desktop_ui: desktop_ui.iter().map(|value| (*value).to_string()).collect(),
        data_files: data_files.iter().map(|value| (*value).to_string()).collect(),
        evidence_fields: evidence_fields.iter().map(|value| (*value).to_string()).collect(),
        sensitive_fields: sensitive_fields.iter().map(|value| (*value).to_string()).collect(),
        reads_diagnostics_files,
        reads_download_log_bodies,
        reads_download_urls,
        reads_cookie_values,
        reads_auth_values,
        reads_downloaded_content,
        writes_diagnostics_files,
        deletes_local_files,
        mutates_settings,
        supports_batch,
        scope: scope.to_string(),
        limitations: limitations.iter().map(|value| (*value).to_string()).collect(),
    }
}

