fn export_diagnostics_at_root(
    root: &Path,
    include_urls: bool,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let file_name = format!("diagnostics-{}.json", Utc::now().format("%Y%m%d-%H%M%S"));
    let diagnostics_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Diagnostics export")?,
        None => {
            let diagnostics_dir = root.join("diagnostics");
            fs::create_dir_all(&diagnostics_dir).map_err(|error| error.to_string())?;
            diagnostics_dir.join(file_name)
        }
    };
    let payload = serde_json::json!({
        "schema_version": 1,
        "generated_at": Utc::now().to_rfc3339(),
        "app_version": env!("CARGO_PKG_VERSION"),
        "platform": std::env::consts::OS,
        "arch": std::env::consts::ARCH,
        "includes_download_urls": include_urls,
        "note": "Diagnostics export is intentionally minimal until runtime modules are implemented."
    });

    fs::write(
        &diagnostics_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;

    Ok(DiagnosticsResponse {
        archive_path: diagnostics_path.to_string_lossy().to_string(),
    })
}

