fn export_notice_inventory_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<(PathBuf, usize, usize), String> {
    let source_root = resolve_source_root();
    let npm_entries = read_npm_notice_inventory(&source_root)?;
    let rust_entries = read_rust_notice_inventory(&source_root)?;
    let npm_package_count = npm_entries.len();
    let rust_crate_count = rust_entries.len();
    let file_name = format!(
        "third-party-notice-inventory-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    );
    let inventory_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Third-party notice inventory export")?,
        None => {
            let diagnostics_dir = root.join("diagnostics");
            fs::create_dir_all(&diagnostics_dir).map_err(|error| error.to_string())?;
            diagnostics_dir.join(file_name)
        }
    };
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "third_party_notice_inventory",
        "generated_at": Utc::now().to_rfc3339(),
        "app_version": env!("CARGO_PKG_VERSION"),
        "source_root": display_path(&source_root),
        "npm_package_count": npm_package_count,
        "rust_crate_count": rust_crate_count,
        "npm_packages": npm_entries,
        "rust_crates": rust_entries,
        "review_required": true,
        "notes": [
            "This file is a local review aid, not a final legal notice file.",
            "npm license values are read from package-lock metadata when present.",
            "Cargo.lock does not include license metadata; Rust crate licenses remain null and require cargo-about/cargo-deny/manual review.",
            "Bundled tools, icons, browser extension files, generated assets, packaging templates, and installer notices still require separate review."
        ]
    });

    fs::write(
        &inventory_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;

    Ok((inventory_path, npm_package_count, rust_crate_count))
}

