fn counted_strings<'a>(values: impl Iterator<Item = &'a str>) -> serde_json::Value {
    let mut counts: HashMap<String, usize> = HashMap::new();
    for value in values {
        let label = value.trim().to_ascii_lowercase();
        if !label.is_empty() {
            *counts.entry(label).or_default() += 1;
        }
    }
    serde_json::to_value(counts).unwrap_or_else(|_| serde_json::json!({}))
}

fn counted_local_entries(values: impl Iterator<Item = String>) -> Vec<LocalCountEntry> {
    let mut counts: BTreeMap<String, usize> = BTreeMap::new();
    for value in values {
        let label = value.trim().to_ascii_lowercase();
        if !label.is_empty() {
            *counts.entry(label).or_default() += 1;
        }
    }
    counts
        .into_iter()
        .map(|(key, count)| LocalCountEntry { key, count })
        .collect()
}

fn counted_download_statuses(tasks: &[DownloadTask]) -> serde_json::Value {
    let mut counts: HashMap<String, usize> = HashMap::new();
    for task in tasks {
        *counts
            .entry(download_status_label(&task.status).to_string())
            .or_default() += 1;
    }
    serde_json::to_value(counts).unwrap_or_else(|_| serde_json::json!({}))
}

fn counted_download_kinds(tasks: &[DownloadTask]) -> serde_json::Value {
    let mut counts: HashMap<String, usize> = HashMap::new();
    for task in tasks {
        let label = serde_json::to_value(&task.kind)
            .ok()
            .and_then(|value| value.as_str().map(str::to_string))
            .unwrap_or_else(|| "unknown".to_string());
        *counts.entry(label).or_default() += 1;
    }
    serde_json::to_value(counts).unwrap_or_else(|_| serde_json::json!({}))
}

fn resolve_source_root() -> PathBuf {
    let manifest_dir = PathBuf::from(env!("CARGO_MANIFEST_DIR"));
    let manifest_parent = manifest_dir.parent().map(Path::to_path_buf);
    for candidate in manifest_parent
        .into_iter()
        .chain(std::env::current_dir().ok())
        .flat_map(source_root_candidates)
    {
        if candidate.join("package-lock.json").exists()
            || candidate.join("src-tauri").join("Cargo.lock").exists()
        {
            return candidate;
        }
    }

    manifest_dir
}

fn source_root_candidates(path: PathBuf) -> Vec<PathBuf> {
    let mut candidates = Vec::new();
    let mut current = Some(path.as_path());
    while let Some(candidate) = current {
        candidates.push(candidate.to_path_buf());
        current = candidate.parent();
    }
    candidates
}

fn build_release_evidence_snapshot_payload(
    root: &Path,
    source_root: &Path,
) -> Result<serde_json::Value, String> {
    let diagnostics_files =
        list_local_files(&root.join("diagnostics"), Some("json,zip")).unwrap_or_default();
    let download_logs = list_local_files(&root.join("logs"), Some("log")).unwrap_or_default();
    let local_feature_evidence = build_local_evidence_summary_response(root)?;
    let plugin_trust_summary = build_local_plugin_trust_summary_at_root(root)?;
    let extension_release_safety_summary = build_extension_release_safety_summary_at_root(root)?;
    Ok(serde_json::json!({
        "schema_version": 1,
        "kind": "release_evidence_snapshot",
        "generated_at": Utc::now().to_rfc3339(),
        "app_version": env!("CARGO_PKG_VERSION"),
        "platform": std::env::consts::OS,
        "arch": std::env::consts::ARCH,
        "source_root": display_path(source_root),
        "data_root": display_path(root),
        "verification_policy": {
            "mode": "speed_first_implementation",
            "during_feature_work": "Use focused checks only; defer repeated large verification until the final gate.",
            "final_gate_script": "scripts/verify-windows.ps1"
        },
        "release_checklist": build_release_checklist_at_root(root)?,
        "legal_readiness_summary": build_legal_readiness_summary_at_root(root)?,
        "release_package_summary": build_release_package_summary()?,
        "third_party_notice_summary": build_third_party_notice_summary()?,
        "privacy_status": build_privacy_status_at_root(root)?,
        "source_documents": source_file_footprints(
            source_root,
            &RELEASE_DOCUMENT_PATHS.iter().map(|(_, path)| *path).collect::<Vec<_>>()
        ),
        "status_counts": {
            "function_parity": markdown_status_counts(
                &source_root.join("docs").join("FUNCTION_PARITY.md"),
                &["todo", "doing", "done", "blocked"]
            ),
            "acceptance": markdown_status_counts(
                &source_root.join("docs").join("ACCEPTANCE.md"),
                &["pending", "pass", "fail", "blocked"]
            )
        },
        "local_feature_evidence": local_feature_evidence,
        "plugin_trust_summary": plugin_trust_summary,
        "extension_release_safety_summary": extension_release_safety_summary,
        "package_scripts": package_scripts_summary(source_root),
        "local_inventory": {
            "diagnostics_files": diagnostics_files,
            "download_logs": download_logs
        },
        "honesty_notes": [
            "This snapshot is evidence for release review, not a release-ready claim.",
            "Pending, blocked, local-only, classifier-only, and manifest-only integrations remain visible in docs and UI.",
            "The snapshot intentionally lists diagnostics/log paths and sizes only; it does not embed Cookie values, auth payload values, downloaded content, or download log bodies."
        ]
    }))
}

fn build_release_package_summary() -> Result<ReleasePackageSummaryResponse, String> {
    let source_root = resolve_source_root();
    let frontend_dist = release_package_area(
        "Frontend dist",
        &source_root.join("dist"),
        Some(200),
        vec![
            "Built frontend assets from the most recent local npm build, if present.".to_string(),
            "This does not prove the final Tauri bundle has been rebuilt with these assets."
                .to_string(),
        ],
    )?;
    let windows_portable = release_package_area(
        "Windows portable staging",
        &source_root.join("dist-portable"),
        Some(200),
        vec![
            "Expected output from scripts/package-windows-portable.ps1.".to_string(),
            "Missing files mean portable staging has not been produced in this workspace yet."
                .to_string(),
        ],
    )?;
    let tauri_bundles = release_package_area(
        "Tauri release bundles",
        &source_root.join("src-tauri").join("target").join("release").join("bundle"),
        Some(200),
        vec![
            "Release bundle artifacts are host-specific and only appear after a successful Tauri build.".to_string(),
        ],
    )?;
    let packaging_templates = release_package_area(
        "Packaging templates",
        &source_root.join("packaging"),
        Some(120),
        vec![
            "Packaging templates are local review inputs; they are not signed or installed packages.".to_string(),
        ],
    )?;
    let scripts = release_package_area(
        "Release scripts",
        &source_root.join("scripts"),
        Some(80),
        vec![
            "Scripts are local release helpers and verification entry points; running them remains a final gate step.".to_string(),
        ],
    )?;

    let package_files = release_package_key_files(&source_root)?;
    let statuses = vec![
        frontend_dist.status.clone(),
        windows_portable.status.clone(),
        tauri_bundles.status.clone(),
        packaging_templates.status.clone(),
        scripts.status.clone(),
    ];
    let gate_counts = counted_local_entries(statuses.into_iter());

    Ok(ReleasePackageSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        source_root: display_path(&source_root),
        frontend_dist,
        windows_portable,
        tauri_bundles,
        packaging_templates,
        scripts,
        package_files,
        gate_counts,
        review_notes: vec![
            "This summary reads local release artifacts, scripts, templates, and manifests only.".to_string(),
            "It does not run npm build, Tauri build, signing, notarization, installer creation, browser extension packaging, or portable verification.".to_string(),
            "It does not include downloaded content, Cookie values, Authorization payloads, pairing tokens, or download log bodies.".to_string(),
            "Use the final verification gate before claiming packages are submit-ready.".to_string(),
        ],
    })
}

fn export_release_package_summary_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<(PathBuf, usize, bool), String> {
    let summary = build_release_package_summary()?;
    let file_name = format!(
        "release-package-summary-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    );
    let path = resolve_diagnostics_export_path(
        root,
        output_path,
        file_name,
        "Release package summary export",
    )?;
    let item_count = summary.package_files.len();
    let review_required = summary
        .gate_counts
        .iter()
        .any(|entry| matches!(entry.key.as_str(), "missing" | "empty" | "review_needed"));
    fs::write(
        &path,
        serde_json::to_vec_pretty(&summary).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;
    Ok((path, item_count, review_required))
}

fn resolve_diagnostics_export_path(
    root: &Path,
    output_path: Option<String>,
    file_name: String,
    label: &str,
) -> Result<PathBuf, String> {
    match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, label),
        None => {
            let diagnostics_dir = root.join("diagnostics");
            fs::create_dir_all(&diagnostics_dir).map_err(|error| error.to_string())?;
            Ok(diagnostics_dir.join(file_name))
        }
    }
}

fn build_legal_readiness_summary_at_root(
    root: &Path,
) -> Result<LegalReadinessSummaryResponse, String> {
    let source_root = resolve_source_root();
    let checklist = build_release_checklist_at_root(root)?;
    let documents = build_release_document_summary()?;
    let notices = build_third_party_notice_summary()?;
    let packages = build_release_package_summary()?;
    let missing_documents = documents
        .documents
        .iter()
        .filter(|document| !document.exists)
        .map(|document| document.path.clone())
        .collect::<Vec<_>>();
    let package_status_counts = packages.gate_counts.clone();
    let checklist_gate_counts =
        counted_local_entries(checklist.gates.iter().map(|gate| gate.status.clone()));

    let mut review_notes = vec![
        "This summary is a local release/legal readiness dashboard, not a release-ready claim."
            .to_string(),
        "It aggregates existing checklist, document, package, and dependency notice metadata without reading Cookie/Auth values, downloaded content, or log bodies."
            .to_string(),
        "Final license text, NOTICE, THIRD_PARTY_NOTICES, bundled assets/tools review, packaging smoke, signing, notarization, and store submission remain final-gate work."
            .to_string(),
    ];
    if !missing_documents.is_empty() {
        review_notes.push(format!(
            "Missing final review documents: {}.",
            missing_documents.join(", ")
        ));
    }
    if notices.review_required {
        review_notes.push(
            "Third-party dependency notices still require human legal review before shipping."
                .to_string(),
        );
    }

    Ok(LegalReadinessSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        source_root: display_path(&source_root),
        data_root: display_path(root),
        ready_count: checklist.ready_count,
        review_needed_count: checklist.review_needed_count,
        pending_count: checklist.pending_count,
        blocked_count: checklist.blocked_count,
        missing_document_count: missing_documents.len(),
        missing_documents,
        npm_package_count: notices.npm_package_count,
        npm_missing_license_count: notices.npm_missing_license_count,
        rust_crate_count: notices.rust_crate_count,
        rust_missing_license_count: notices.rust_missing_license_count,
        package_status_counts,
        checklist_gate_counts,
        review_notes,
    })
}

fn export_legal_readiness_summary_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<(PathBuf, usize, bool), String> {
    let summary = build_legal_readiness_summary_at_root(root)?;
    let file_name = format!(
        "legal-readiness-summary-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    );
    let path = resolve_diagnostics_export_path(
        root,
        output_path,
        file_name,
        "Legal readiness summary export",
    )?;
    let missing_document_count = summary.missing_document_count;
    let review_required = summary.review_needed_count > 0
        || summary.pending_count > 0
        || summary.blocked_count > 0
        || summary.missing_document_count > 0
        || summary.npm_missing_license_count > 0
        || summary.rust_missing_license_count > 0;
    fs::write(
        &path,
        serde_json::to_vec_pretty(&summary).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;

    Ok((path, missing_document_count, review_required))
}

#[allow(clippy::too_many_arguments)]
fn legal_capability_catalog_item(
    capability: &str,
    label: &str,
    status: &str,
    commands: &[&str],
    cli_aliases: &[&str],
    desktop_ui: &[&str],
    data_files: &[&str],
    notice_fields: &[&str],
    sensitive_fields: &[&str],
    mutates_legal_files: bool,
    reads_dependency_manifests: bool,
    reads_bundled_artifacts: bool,
    calculates_hashes: bool,
    generates_final_notices: bool,
    requires_human_review: bool,
    runs_external_audit_tools: bool,
    supports_batch: bool,
    scope: &str,
    limitations: &[&str],
) -> LegalCapabilityCatalogItem {
    LegalCapabilityCatalogItem {
        capability: capability.to_string(),
        label: label.to_string(),
        status: status.to_string(),
        commands: commands.iter().map(|value| (*value).to_string()).collect(),
        cli_aliases: cli_aliases.iter().map(|value| (*value).to_string()).collect(),
        desktop_ui: desktop_ui.iter().map(|value| (*value).to_string()).collect(),
        data_files: data_files.iter().map(|value| (*value).to_string()).collect(),
        notice_fields: notice_fields.iter().map(|value| (*value).to_string()).collect(),
        sensitive_fields: sensitive_fields.iter().map(|value| (*value).to_string()).collect(),
        mutates_legal_files,
        reads_dependency_manifests,
        reads_bundled_artifacts,
        calculates_hashes,
        generates_final_notices,
        requires_human_review,
        runs_external_audit_tools,
        supports_batch,
        scope: scope.to_string(),
        limitations: limitations.iter().map(|value| (*value).to_string()).collect(),
    }
}

