fn export_recovery_manifest_at_root(
    root: &Path,
    mode: Option<AppMode>,
    output_path: Option<String>,
) -> Result<PathBuf, String> {
    let tasks = read_download_tasks(&root).unwrap_or_default();
    let mut task_status_counts: HashMap<String, usize> = HashMap::new();
    for task in tasks {
        let status = serde_json::to_string(&task.status)
            .unwrap_or_else(|_| "\"unknown\"".to_string())
            .trim_matches('"')
            .to_string();
        *task_status_counts.entry(status).or_default() += 1;
    }
    let tool_statuses = detect_tool_statuses(&root, None).unwrap_or_default();
    let file_name = format!(
        "recovery-manifest-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    );
    let manifest_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Recovery manifest export")?,
        None => {
            let diagnostics_dir = root.join("diagnostics");
            fs::create_dir_all(&diagnostics_dir).map_err(|error| error.to_string())?;
            diagnostics_dir.join(file_name)
        }
    };
    let payload = serde_json::json!({
        "schema_version": 1,
        "generated_at": Utc::now().to_rfc3339(),
        "kind": "recovery_manifest",
        "app_version": env!("CARGO_PKG_VERSION"),
        "platform": std::env::consts::OS,
        "arch": std::env::consts::ARCH,
        "mode": mode.unwrap_or(AppMode::Regular),
        "paths": app_paths(&root),
        "task_status_counts": task_status_counts,
        "tool_statuses": tool_statuses,
        "diagnostics_files": list_local_files(&root.join("diagnostics"), Some("json,zip")).unwrap_or_default(),
        "download_logs": list_local_files(&root.join("logs"), Some("log")).unwrap_or_default(),
        "note": "Recovery manifest lists local state and paths only; it is not a full data backup."
    });

    fs::write(
        &manifest_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;

    Ok(manifest_path)
}

