#[tauri::command]
fn app_list_download_logs(
    app: AppHandle,
    request: Option<DownloadLogListRequest>,
) -> Result<DownloadLogListResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let filters = request.unwrap_or_default();
    let all_logs = list_local_files(&root.join("logs"), Some("log"))?;
    let cli_filters = CliDownloadLogsFilters {
        query: filters
            .query
            .and_then(|value| sanitize_optional_text(Some(value))),
        task_id: filters
            .task_id
            .and_then(|value| sanitize_optional_text(Some(value))),
        limit: filters.limit,
    };
    let mut logs = all_logs
        .iter()
        .filter(|file| download_log_summary_matches_filter(file, &cli_filters))
        .cloned()
        .collect::<Vec<_>>();
    let filtered_log_count = logs.len();
    if let Some(limit) = cli_filters.limit {
        logs.truncate(limit);
    }
    Ok(DownloadLogListResponse {
        logs,
        total_log_count: all_logs.len(),
        filtered_log_count,
        filters: DownloadLogListFiltersResponse {
            query: cli_filters.query,
            task_id: cli_filters.task_id,
            limit: cli_filters.limit,
        },
    })
}

