fn build_platform_local_summary() -> PlatformLocalSummaryResponse {
    let platforms = build_platform_matrix();
    let route_samples = build_platform_route_samples();
    let implemented_count = platforms
        .iter()
        .filter(|entry| entry.status == "implemented")
        .count();
    let partial_count = platforms
        .iter()
        .filter(|entry| entry.status == "partial")
        .count();
    let local_draft_count = platforms
        .iter()
        .filter(|entry| entry.status == "local_draft")
        .count();
    let classifier_only_count = platforms
        .iter()
        .filter(|entry| entry.status == "classifier_only")
        .count();

    PlatformLocalSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        platform_count: platforms.len(),
        route_sample_count: route_samples.len(),
        implemented_count,
        partial_count,
        local_draft_count,
        classifier_only_count,
        category_counts: counted_local_entries(platforms.iter().map(|entry| entry.category.clone())),
        route_counts: counted_local_entries(platforms.iter().map(|entry| entry.route.clone())),
        status_counts: counted_local_entries(platforms.iter().map(|entry| entry.status.clone())),
        platforms,
        route_samples,
        pending_real_site_verification: true,
        executes_network_checks: false,
        creates_download_tasks: false,
        includes_cookie_values: false,
        includes_authorization_values: false,
        review_notes: vec![
            "This summary reads local platform route declarations and classifier sample metadata only.".to_string(),
            "It does not probe live sites, execute yt-dlp/gallery-dl, create download tasks, read browser storage, or validate account-gated flows.".to_string(),
            "Sample URLs are local routing examples; they are not evidence of live metadata extraction, login, or download success.".to_string(),
        ],
    }
}

fn export_platform_local_summary_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<PlatformLocalSummaryExportResponse, String> {
    let summary = build_platform_local_summary();
    let file_name = format!(
        "platform-local-summary-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    );
    let summary_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Platform local summary export")?,
        None => {
            let diagnostics_dir = root.join("diagnostics");
            fs::create_dir_all(&diagnostics_dir).map_err(|error| error.to_string())?;
            diagnostics_dir.join(file_name)
        }
    };
    validate_json_file_path(&summary_path, "Platform local summary export")?;
    fs::write(
        &summary_path,
        serde_json::to_vec_pretty(&summary).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write Platform local summary export: {error}"))?;

    Ok(PlatformLocalSummaryExportResponse {
        archive_path: display_path(summary_path),
        platform_count: summary.platform_count,
        route_sample_count: summary.route_sample_count,
        pending_real_site_verification: summary.pending_real_site_verification,
    })
}

