#[tauri::command]
fn tools_install(app: AppHandle, request: ToolIdOnlyRequest) -> Result<ToolStatus, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    emit_tool_install_progress(
        &app,
        &request.id,
        ToolInstallStage::Starting,
        &format!("Starting dependency install for {}.", request.id),
        None,
    );
    match request_tool_install_with_progress(&root, &request.id, &mut |update| {
        emit_tool_install_progress_update(&app, &request.id, update, None);
    }) {
        Ok(status) => {
            let stage = if status.state == ToolState::Installed {
                ToolInstallStage::Completed
            } else {
                ToolInstallStage::Failed
            };
            let error = status.error.clone();
            emit_tool_install_progress(
                &app,
                &request.id,
                stage,
                if stage == ToolInstallStage::Completed {
                    "Dependency install completed."
                } else {
                    "Dependency install did not complete."
                },
                error,
            );
            emit_tool_status(&app, status.clone());
            Ok(status)
        }
        Err(error) => {
            emit_tool_install_progress(
                &app,
                &request.id,
                ToolInstallStage::Failed,
                "Dependency install failed.",
                Some(error.clone()),
            );
            Err(error)
        }
    }
}

