#[tauri::command]
fn cookies_export(
    app: AppHandle,
    request: CookieExportRequest,
) -> Result<CookieExportResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let bucket = find_cookie_bucket(&root, &request.bucket_id)?;
    let output_path = PathBuf::from(request.output_path.trim());
    if output_path.as_os_str().is_empty() {
        return Err("Cookie export path is required.".to_string());
    }
    if let Some(parent) = output_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::copy(cookie_bucket_storage_path(&root, &bucket), &output_path)
        .map_err(|error| error.to_string())?;
    Ok(CookieExportResponse {
        path: display_path(output_path),
    })
}

