#[tauri::command]
fn cookies_delete_bucket(
    app: AppHandle,
    request: CookieBucketIdRequest,
) -> Result<CookieDeleteResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut buckets = read_cookie_buckets(&root)?;
    let before = buckets.len();
    let mut removed = None;
    buckets.retain(|bucket| {
        if bucket.id == request.bucket_id {
            removed = Some(bucket.clone());
            false
        } else {
            true
        }
    });
    if before == buckets.len() {
        return Err(format!(
            "Cookie bucket was not found: {}",
            request.bucket_id
        ));
    }
    write_cookie_buckets(&root, &buckets)?;
    if let Some(bucket) = removed {
        let _ = fs::remove_file(cookie_bucket_storage_path(&root, &bucket));
    }
    emit_cookie_buckets_changed(&app, &root, "deleted");
    Ok(CookieDeleteResponse { deleted: true })
}

#[tauri::command]
fn cookies_rename_bucket(
    app: AppHandle,
    request: CookieRenameRequest,
) -> Result<CookieBucket, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let name = sanitize_cookie_bucket_name(&request.name)?;
    let mut buckets = read_cookie_buckets(&root)?;
    let now = Utc::now().to_rfc3339();
    let mut renamed = None;
    for bucket in &mut buckets {
        if bucket.id == request.bucket_id {
            bucket.name = name.clone();
            bucket.updated_at = now.clone();
            renamed = Some(bucket.clone());
            break;
        }
    }
    let renamed =
        renamed.ok_or_else(|| format!("Cookie bucket was not found: {}", request.bucket_id))?;
    write_cookie_buckets(&root, &buckets)?;
    emit_cookie_buckets_changed(&app, &root, "renamed");
    Ok(renamed)
}

