#[tauri::command]
fn channels_remove(
    app: AppHandle,
    request: ChannelIdRequest,
) -> Result<CookieDeleteResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut channels = read_channels(&root)?;
    let before = channels.len();
    channels.retain(|channel| channel.id != request.id);
    if before == channels.len() {
        return Err(format!("Channel was not found: {}", request.id));
    }
    write_channels(&root, &channels)?;
    emit_channels_changed(&app, &root, "removed");
    Ok(CookieDeleteResponse { deleted: true })
}

