#[tauri::command]
fn channels_update_settings(
    app: AppHandle,
    request: ChannelSettingsUpdateRequest,
) -> Result<ChannelSettingsResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut settings = read_channel_settings(&root)?;
    if let Some(enabled) = request.auto_poll_enabled {
        settings.auto_poll_enabled = enabled;
    }
    if let Some(minutes) = request.poll_interval_minutes {
        settings.poll_interval_minutes = minutes.clamp(5, 1440);
    }
    settings.last_error = None;
    let settings = write_channel_settings(&root, &settings)?;
    emit_settings_changed(&app, &root, vec!["channels"]);
    emit_channels_changed(&app, &root, "settings_updated");
    Ok(ChannelSettingsResponse { settings })
}

