#[tauri::command]
fn courses_probe(app: AppHandle, request: CourseProbeRequest) -> Result<CourseEntry, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let url = normalize_http_url(&request.source_url)?;
    match build_course_entry_with_remote_outline(&root, &url, &request, "probed") {
        Ok(entry) => Ok(entry),
        Err(error) => {
            let mut entry = build_course_candidate_entry_at_root(
                &root,
                &url,
                &request,
                "probed_metadata_pending",
            )?;
            annotate_course_remote_extraction_failure(&mut entry, &error);
            Ok(entry)
        }
    }
}

