#[tauri::command]
fn learning_notes_list(
    app: AppHandle,
    request: LearningNoteListRequest,
) -> Result<LearningNoteListResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut notes = read_learning_notes(&root)?;
    if let Some(query) = sanitize_optional_text(request.query.as_deref()) {
        let needle = query.to_ascii_lowercase();
        notes.retain(|note| {
            note.title.to_ascii_lowercase().contains(&needle)
                || note.body.to_ascii_lowercase().contains(&needle)
                || note
                    .tags
                    .iter()
                    .any(|tag| tag.to_ascii_lowercase().contains(&needle))
                || note
                    .source_url
                    .as_deref()
                    .unwrap_or_default()
                    .to_ascii_lowercase()
                    .contains(&needle)
                || note
                    .outgoing_links
                    .iter()
                    .any(|link| link.to_ascii_lowercase().contains(&needle))
        });
    }
    Ok(LearningNoteListResponse { notes })
}

