#[tauri::command]
fn spaced_review_cards_list(
    app: AppHandle,
    request: SpacedReviewCardListRequest,
) -> Result<SpacedReviewCardListResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut cards = read_spaced_review_cards(&root)?;
    if request.due_only.unwrap_or(false) {
        let now = Utc::now().to_rfc3339();
        cards.retain(|card| card.due_at <= now);
    }
    if let Some(query) = sanitize_optional_text(request.query.as_deref()) {
        let needle = query.to_ascii_lowercase();
        cards.retain(|card| {
            card.prompt.to_ascii_lowercase().contains(&needle)
                || card.answer.to_ascii_lowercase().contains(&needle)
                || card.note_id.to_ascii_lowercase().contains(&needle)
                || card
                    .tags
                    .iter()
                    .any(|tag| tag.to_ascii_lowercase().contains(&needle))
                || card
                    .source_url
                    .as_deref()
                    .unwrap_or_default()
                    .to_ascii_lowercase()
                    .contains(&needle)
        });
    }
    Ok(SpacedReviewCardListResponse { cards })
}

