#[tauri::command]
fn pomodoro_sessions_save(
    app: AppHandle,
    request: PomodoroSessionSaveRequest,
) -> Result<PomodoroSession, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let duration_minutes = request.duration_minutes.clamp(1, 180);
    let break_minutes = request.break_minutes.unwrap_or(5).clamp(0, 60);
    let label = sanitize_optional_text(request.label.as_deref())
        .unwrap_or_else(|| "Focus session".to_string());
    let linked_source_url = match sanitize_optional_text(request.linked_source_url.as_deref()) {
        Some(value) => Some(normalize_http_url(&value)?),
        None => None,
    };
    let now = Utc::now();
    let started_at = now.to_rfc3339();
    let ended_at = (now + chrono::Duration::minutes(duration_minutes as i64)).to_rfc3339();
    let session = PomodoroSession {
        schema_version: 1,
        id: format!("pomodoro-{}", Utc::now().timestamp_millis()),
        label,
        duration_minutes,
        break_minutes,
        completed: request.completed,
        linked_source_url,
        started_at,
        ended_at,
    };
    let mut sessions = read_pomodoro_sessions(&root)?;
    sessions.push(session.clone());
    write_pomodoro_sessions(&root, &sessions)?;
    if request.notify_on_complete && session.completed {
        notify_pomodoro_complete(&app, &session);
    }
    emit_library_changed(&app, "notes", "pomodoro_session_saved");
    Ok(session)
}

