#[tauri::command]
fn extension_create_pairing_token(
    app: AppHandle,
    request: ExtensionPairingTokenRequest,
) -> Result<ExtensionPairingTokenResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let now = Utc::now();
    let expires_at = (now + chrono::Duration::days(30)).to_rfc3339();
    let token = generate_pairing_token();
    let state = ExtensionPairingState {
        schema_version: 1,
        paired: true,
        token: Some(token.clone()),
        label: sanitize_optional_text(request.label.as_deref()),
        created_at: Some(now.to_rfc3339()),
        expires_at: Some(expires_at.clone()),
        revoked_at: None,
    };
    write_extension_pairing_state(&root, &state)?;
    emit_extension_pairing_changed(&app, &root, "token_created");
    Ok(ExtensionPairingTokenResponse {
        pairing_code: token,
        expires_at,
    })
}

#[tauri::command]
fn extension_revoke_pairing(app: AppHandle) -> Result<ExtensionRevokePairingResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut state = read_extension_pairing_state(&root)?;
    state.paired = false;
    state.token = None;
    state.revoked_at = Some(Utc::now().to_rfc3339());
    write_extension_pairing_state(&root, &state)?;
    emit_extension_pairing_changed(&app, &root, "token_revoked");
    Ok(ExtensionRevokePairingResponse { revoked: true })
}

