#[tauri::command]
fn settings_import_manifest(
    app: AppHandle,
    request: SettingsManifestImportRequest,
) -> Result<Settings, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let previous_shell =
        read_app_shell_settings(&root).unwrap_or_else(|_| default_app_shell_settings());
    let settings = import_settings_manifest_at_root(&root, request)?;
    apply_quick_capture_shortcut_settings(&app, &previous_shell, &settings.app_shell)?;
    start_extension_bridge(app.clone());
    emit_settings_changed(
        &app,
        &root,
        vec![
            "appearance",
            "downloads",
            "network",
            "ai",
            "update",
            "extension",
            "channels",
            "reader",
            "music",
            "auth",
            "app_shell",
            "shortcut",
            "advanced",
            "privacy",
        ],
    );
    Ok(settings)
}

#[tauri::command]
fn settings_reset_section(
    app: AppHandle,
    request: SettingsResetSectionRequest,
) -> Result<Settings, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let previous_shell =
        read_app_shell_settings(&root).unwrap_or_else(|_| default_app_shell_settings());
    let changed_paths = reset_settings_section_at_root(&root, &request.section)?;
    let settings = read_settings(&root)?;
    if changed_paths
        .iter()
        .any(|path| matches!(path.as_str(), "app_shell" | "shortcut"))
    {
        apply_quick_capture_shortcut_settings(&app, &previous_shell, &settings.app_shell)?;
    }
    if changed_paths.iter().any(|path| path == "extension") {
        start_extension_bridge(app.clone());
    }
    emit_settings_changed(
        &app,
        &root,
        changed_paths.iter().map(String::as_str).collect(),
    );
    Ok(settings)
}

#[tauri::command]
fn settings_validate_network(
    app: AppHandle,
    request: NetworkValidationRequest,
) -> Result<NetworkValidationResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let settings = read_downloads_settings(&root)?;
    let proxy = if request.proxy.is_some() {
        request
            .proxy
            .as_deref()
            .and_then(|value| sanitize_optional_text(Some(value)))
    } else {
        settings.default_proxy
    };
    let parsed = parse_direct_file_proxy(proxy.as_deref())?;
    Ok(match parsed {
        Some(proxy) => NetworkValidationResponse {
            schema_version: 1,
            ok: true,
            proxy_configured: true,
            proxy_kind: Some(format!("{:?}", proxy.kind).to_ascii_lowercase()),
            proxy_host: Some(proxy.host),
            proxy_port: Some(proxy.port),
            message: "Proxy format is valid. Connectivity is not tested in this local check."
                .to_string(),
        },
        None => NetworkValidationResponse {
            schema_version: 1,
            ok: true,
            proxy_configured: false,
            proxy_kind: None,
            proxy_host: None,
            proxy_port: None,
            message: "No proxy is configured for new tasks.".to_string(),
        },
    })
}

