#[tauri::command]
fn downloads_update_settings(
    app: AppHandle,
    request: UpdateDownloadsSettingsRequest,
) -> Result<DownloadsSettings, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut settings = read_downloads_settings(&root)?;
    if request.max_concurrency.is_none() && request.patch.is_none() {
        return Err(
            "downloads_update_settings requires max_concurrency or a downloads settings patch."
                .to_string(),
        );
    }
    if let Some(patch) = request.patch {
        apply_downloads_settings_patch(&mut settings, patch);
    }
    if let Some(max_concurrency) = request.max_concurrency {
        settings.max_concurrency = max_concurrency;
    }
    let settings = write_downloads_settings(&root, &settings)?;
    emit_settings_changed(&app, &root, vec!["downloads"]);
    Ok(settings)
}

