#[tauri::command]
fn torrent_queue_file(
    app: AppHandle,
    request: TorrentQueueFileRequest,
) -> Result<DownloadTask, String> {
    let _guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let task = queue_torrent_file_at_root(&root, request)?;
    drop(_guard);
    emit_downloads_created_and_schedule_if_needed(&app, std::slice::from_ref(&task))?;
    Ok(task)
}

