fn export_course_platform_matrix_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<CoursePlatformMatrixExportResponse, String> {
    let platforms = build_course_platform_matrix();
    let platform_count = platforms.len();
    let file_name = format!(
        "course-platform-matrix-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    );
    let matrix_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Course platform matrix export")?,
        None => {
            let diagnostics_dir = root.join("diagnostics");
            fs::create_dir_all(&diagnostics_dir).map_err(|error| error.to_string())?;
            diagnostics_dir.join(file_name)
        }
    };
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "course_platform_matrix",
        "generated_at": Utc::now().to_rfc3339(),
        "app_version": env!("CARGO_PKG_VERSION"),
        "platform_count": platform_count,
        "platforms": platforms,
        "pending_remote_extraction": true,
        "note": "This export captures local course host-hint/candidate support only. It does not prove login, remote lesson extraction, attachment download, or playback success."
    });

    fs::write(
        &matrix_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;

    Ok(CoursePlatformMatrixExportResponse {
        archive_path: display_path(matrix_path),
        platform_count,
        pending_remote_extraction: true,
    })
}

fn export_course_platform_samples_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<CoursePlatformSampleExportResponse, String> {
    let samples = build_course_platform_samples();
    let sample_count = samples.len();
    let file_name = format!(
        "course-platform-samples-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    );
    let samples_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Course platform samples export")?,
        None => {
            let diagnostics_dir = root.join("diagnostics");
            fs::create_dir_all(&diagnostics_dir).map_err(|error| error.to_string())?;
            diagnostics_dir.join(file_name)
        }
    };
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "course_platform_samples",
        "generated_at": Utc::now().to_rfc3339(),
        "app_version": env!("CARGO_PKG_VERSION"),
        "sample_count": sample_count,
        "samples": samples,
        "pending_remote_extraction": true,
        "note": "This export captures local course platform sample URLs only. It does not prove login, remote lesson extraction, attachment download, or playback success."
    });

    fs::write(
        &samples_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;

    Ok(CoursePlatformSampleExportResponse {
        archive_path: display_path(samples_path),
        sample_count,
        pending_remote_extraction: true,
    })
}
