fn export_music_service_matrix_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<MusicServiceMatrixExportResponse, String> {
    let services = build_music_service_matrix();
    let service_count = services.len();
    let file_name = format!(
        "music-service-matrix-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    );
    let matrix_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Music service matrix export")?,
        None => {
            let diagnostics_dir = root.join("diagnostics");
            fs::create_dir_all(&diagnostics_dir).map_err(|error| error.to_string())?;
            diagnostics_dir.join(file_name)
        }
    };
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "music_service_matrix",
        "generated_at": Utc::now().to_rfc3339(),
        "app_version": env!("CARGO_PKG_VERSION"),
        "service_count": service_count,
        "services": services,
        "pending_external_connectors": true,
        "note": "This export captures local music service status only. It does not prove OAuth, remote library import, playlist sync, scrobbling, entitlement checks, or external playback support."
    });

    fs::write(
        &matrix_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;

    Ok(MusicServiceMatrixExportResponse {
        archive_path: display_path(matrix_path),
        service_count,
        pending_external_connectors: true,
    })
}
