#[tauri::command]
fn downloads_create(
    app: AppHandle,
    request: CreateDownloadRequest,
) -> Result<DownloadTask, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let task = {
        let _guard = download_store_lock()
            .lock()
            .map_err(|_| "Download store lock was poisoned.".to_string())?;
        create_download_task_at_root(&root, request, &Utc::now().to_rfc3339())?
    };
    maybe_spawn_task_thumbnail_cache(root, &task);
    emit_download_created(&app, task.clone());
    if task.run_after_active_slot {
        schedule_downloads(app.clone())?;
    }
    Ok(task)
}

fn create_download_task_at_root(
    root: &Path,
    request: CreateDownloadRequest,
    now: &str,
) -> Result<DownloadTask, String> {
    let mut tasks = read_download_tasks(root)?;
    let position_seed = tasks.iter().map(|task| task.position).max().unwrap_or(0);
    let task = build_download_task_from_request_with_root(request, position_seed + 1, now, root)?;
    tasks.push(task.clone());
    write_download_tasks(root, &tasks)?;
    Ok(task)
}

fn create_download_task_with_details_at_root(
    root: &Path,
    request: CreateDownloadRequest,
    details_json: serde_json::Value,
    platform_override: Option<&str>,
    now: &str,
) -> Result<DownloadTask, String> {
    let mut tasks = read_download_tasks(root)?;
    let position_seed = tasks.iter().map(|task| task.position).max().unwrap_or(0);
    let mut task =
        build_download_task_from_request_with_root(request, position_seed + 1, now, root)?;
    if let Some(platform) = platform_override.and_then(|value| sanitize_optional_text(Some(value)))
    {
        task.platform = platform;
    }
    task.details_json = Some(details_json);
    tasks.push(task.clone());
    write_download_tasks(root, &tasks)?;
    Ok(task)
}

fn build_download_task_from_request_with_root(
    request: CreateDownloadRequest,
    position: u32,
    now: &str,
    root: &Path,
) -> Result<DownloadTask, String> {
    let settings = read_downloads_settings(root)?;
    build_download_task_from_request_with_settings(request, position, now, &settings)
}

fn build_download_task_from_request_with_settings(
    request: CreateDownloadRequest,
    position: u32,
    now: &str,
    settings: &DownloadsSettings,
) -> Result<DownloadTask, String> {
    let source_url = normalize_http_url(&request.source_url)?;
    let requested_output_dir = request
        .output_dir
        .as_deref()
        .map(str::trim)
        .filter(|path| !path.is_empty());
    let output_dir =
        validate_output_dir(requested_output_dir.or(settings.default_output_dir.as_deref()))?;
    let output_path = request
        .output_path
        .as_deref()
        .map(|path| validate_output_file_path(path, "Download output file"))
        .transpose()?
        .map(|path| display_path(path));
    let quality = sanitize_quality(
        request
            .quality
            .as_deref()
            .unwrap_or(&settings.default_quality),
    );
    let audio_format = sanitize_audio_format(
        request
            .audio_format
            .as_deref()
            .unwrap_or(&settings.default_audio_format),
    );
    let subtitles = request
        .subtitles
        .map(sanitize_subtitle_settings)
        .unwrap_or_else(|| settings.subtitles.clone());
    let sponsorblock = request
        .sponsorblock
        .map(sanitize_sponsorblock_settings)
        .unwrap_or_else(|| settings.sponsorblock.clone());
    let metadata = request
        .metadata
        .unwrap_or_else(|| settings.metadata.clone());
    validate_clip_times(request.start_seconds, request.end_seconds)?;
    let start_seconds = sanitize_clip_seconds(request.start_seconds);
    let end_seconds = sanitize_clip_seconds(request.end_seconds);
    let mut task = DownloadTask {
        schema_version: 1,
        id: format!("task-{}-{}", Utc::now().timestamp_millis(), position),
        kind: request.kind.unwrap_or(DownloadKind::Generic),
        source_url: source_url.clone(),
        platform: classify_platform(&source_url),
        title: request
            .title_override
            .filter(|title| !title.trim().is_empty())
            .unwrap_or_else(|| source_url.clone()),
        status: DownloadStatus::Queued,
        position,
        output_dir,
        output_path,
        downloaded_bytes: None,
        total_bytes: None,
        file_count: None,
        last_error: None,
        error_category: None,
        retryable: None,
        retry_count: 0,
        run_after_active_slot: request.run_after_active_slot.unwrap_or(false),
        user_agent: sanitize_header_value(request.user_agent.as_deref())
            .or_else(|| settings.default_user_agent.clone()),
        referer: sanitize_header_value(request.referer.as_deref())
            .or_else(|| settings.default_referer.clone()),
        proxy: sanitize_optional_text(request.proxy.as_deref())
            .or_else(|| settings.default_proxy.clone()),
        cookie_bucket_id: sanitize_cookie_bucket_id(request.cookie_bucket_id.as_deref()),
        auth_payload_ref: sanitize_auth_payload_ref(request.auth_payload_ref.as_deref()),
        rate_limit: sanitize_optional_text(request.rate_limit.as_deref())
            .or_else(|| settings.default_rate_limit.clone()),
        live_from_start: request
            .live_from_start
            .unwrap_or(settings.default_live_from_start),
        concurrent_fragments: sanitize_concurrent_fragments(request.concurrent_fragments)
            .or(settings.default_concurrent_fragments),
        custom_ytdlp_args: sanitize_optional_text(request.custom_ytdlp_args.as_deref())
            .or_else(|| settings.custom_ytdlp_args.clone()),
        start_seconds,
        end_seconds,
        quality: Some(quality),
        audio_format: Some(audio_format),
        thumbnail_url: request
            .thumbnail_url
            .as_deref()
            .and_then(|url| normalize_http_url(url).ok()),
        thumbnail_path: None,
        subtitles: Some(subtitles),
        sponsorblock: Some(sponsorblock),
        metadata: Some(metadata),
        details_json: None,
        created_at: now.to_string(),
        updated_at: now.to_string(),
        started_at: None,
        finished_at: None,
    };
    if let Some(expected_sha256) = request.expected_sha256.as_deref() {
        set_download_task_expected_sha256(&mut task, expected_sha256)?;
    }
    Ok(task)
}

fn build_download_tasks_from_requests(
    requests: Vec<CreateDownloadRequest>,
    position_seed: u32,
    now: &str,
    settings: &DownloadsSettings,
) -> (Vec<DownloadTask>, Vec<BatchFailure>) {
    let is_multi_item_batch = requests.len() > 1;
    let mut created = Vec::new();
    let mut failed = Vec::new();
    let mut next_position = position_seed.saturating_add(1);

    for (index, request) in requests.into_iter().enumerate() {
        let source_url = if request.source_url.trim().is_empty() {
            None
        } else {
            Some(request.source_url.clone())
        };
        if is_multi_item_batch
            && request
                .output_path
                .as_deref()
                .map(str::trim)
                .is_some_and(|path| !path.is_empty())
        {
            failed.push(BatchFailure {
                index,
                source_url,
                error: "Exact output files are only supported for single-URL task creation. Use an output folder for batch tasks.".to_string(),
            });
            continue;
        }
        match build_download_task_from_request_with_settings(request, next_position, now, settings)
        {
            Ok(task) => {
                created.push(task);
                next_position = next_position.saturating_add(1);
            }
            Err(error) => failed.push(BatchFailure {
                index,
                source_url,
                error,
            }),
        }
    }

    (created, failed)
}

#[tauri::command]
fn downloads_create_batch(
    app: AppHandle,
    request: CreateDownloadBatchRequest,
) -> Result<CreateDownloadBatchResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let (created, failed) = {
        let _guard = download_store_lock()
            .lock()
            .map_err(|_| "Download store lock was poisoned.".to_string())?;
        let mut tasks = read_download_tasks(&root)?;
        let settings = read_downloads_settings(&root)?;
        let position_seed = tasks.iter().map(|task| task.position).max().unwrap_or(0);
        let (created, failed) = build_download_tasks_from_requests(
            request.items,
            position_seed,
            &Utc::now().to_rfc3339(),
            &settings,
        );

        if !created.is_empty() {
            tasks.extend(created.clone());
            write_download_tasks(&root, &tasks)?;
        }

        (created, failed)
    };

    for task in &created {
        maybe_spawn_task_thumbnail_cache(root.clone(), task);
        emit_download_created(&app, task.clone());
    }
    if created.iter().any(|task| task.run_after_active_slot) {
        schedule_downloads(app.clone())?;
    }

    Ok(CreateDownloadBatchResponse { created, failed })
}

#[tauri::command]
fn downloads_list(app: AppHandle) -> Result<ListDownloadsResponse, String> {
    let _guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut tasks = read_download_tasks(&root)?;
    tasks.sort_by_key(|task| task.position);
    Ok(ListDownloadsResponse { tasks })
}

#[tauri::command]
fn downloads_get(app: AppHandle, request: TaskIdRequest) -> Result<DownloadTask, String> {
    let _guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    read_download_tasks(&root)?
        .into_iter()
        .find(|task| task.id == request.id)
        .ok_or_else(|| format!("Download task was not found: {}", request.id))
}

#[tauri::command]
fn downloads_cancel(app: AppHandle, request: TaskIdRequest) -> Result<DownloadTask, String> {
    let current = downloads_get(
        app.clone(),
        TaskIdRequest {
            id: request.id.clone(),
        },
    )?;
    if current.status == DownloadStatus::Completed || current.status == DownloadStatus::Archived {
        return Err("Completed or archived tasks cannot be canceled.".to_string());
    }

    request_download_stop(&request.id);
    update_download_task(app, &request.id, |task| {
        task.status = DownloadStatus::Canceled;
        task.run_after_active_slot = false;
        task.updated_at = Utc::now().to_rfc3339();
        task.finished_at = Some(task.updated_at.clone());
    })
}

#[tauri::command]
fn downloads_start(app: AppHandle, request: TaskIdRequest) -> Result<DownloadTask, String> {
    let current = downloads_get(
        app.clone(),
        TaskIdRequest {
            id: request.id.clone(),
        },
    )?;
    if current.status != DownloadStatus::Queued && current.status != DownloadStatus::Failed {
        return Err("Only queued or failed tasks can be started.".to_string());
    }

    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let queued = queue_download_start_at_root(&root, &request.id, &Utc::now().to_rfc3339())?;
    emit_download_state(&app, current.status, queued);

    schedule_downloads(app.clone())?;
    downloads_get(app, request)
}

#[tauri::command]
fn downloads_pause(app: AppHandle, request: TaskIdRequest) -> Result<DownloadTask, String> {
    let current = downloads_get(
        app.clone(),
        TaskIdRequest {
            id: request.id.clone(),
        },
    )?;
    if current.status != DownloadStatus::Active {
        return Err("Only active tasks can be paused.".to_string());
    }

    request_download_stop(&request.id);
    update_download_task(app, &request.id, |task| {
        task.status = DownloadStatus::Paused;
        task.run_after_active_slot = false;
        task.updated_at = Utc::now().to_rfc3339();
    })
}

#[tauri::command]
fn downloads_resume(app: AppHandle, request: TaskIdRequest) -> Result<DownloadTask, String> {
    let current = downloads_get(
        app.clone(),
        TaskIdRequest {
            id: request.id.clone(),
        },
    )?;
    if current.status != DownloadStatus::Paused {
        return Err("Only paused tasks can be resumed.".to_string());
    }

    let queued = update_download_task(app.clone(), &request.id, |task| {
        task.status = DownloadStatus::Queued;
        task.run_after_active_slot = true;
        task.last_error = None;
        task.error_category = None;
        task.retryable = None;
        task.finished_at = None;
        task.updated_at = Utc::now().to_rfc3339();
    })?;

    schedule_downloads(app.clone())?;
    Ok(queued)
}

#[tauri::command]
fn downloads_retry(app: AppHandle, request: TaskIdRequest) -> Result<DownloadTask, String> {
    let current = downloads_get(
        app.clone(),
        TaskIdRequest {
            id: request.id.clone(),
        },
    )?;
    if current.status != DownloadStatus::Failed && current.status != DownloadStatus::Canceled {
        return Err("Only failed or canceled tasks can be retried.".to_string());
    }

    let queued = update_download_task(app.clone(), &request.id, |task| {
        task.status = DownloadStatus::Queued;
        task.run_after_active_slot = true;
        task.last_error = None;
        task.error_category = None;
        task.retryable = None;
        task.finished_at = None;
        task.updated_at = Utc::now().to_rfc3339();
    })?;

    schedule_downloads(app.clone())?;
    Ok(queued)
}

#[tauri::command]
fn downloads_delete(
    app: AppHandle,
    request: DeleteDownloadRequest,
) -> Result<CommandResponse, String> {
    request_download_stop(&request.id);
    let _guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut tasks = read_download_tasks(&root)?;
    let original_len = tasks.len();
    tasks.retain(|task| task.id != request.id);
    if tasks.len() == original_len {
        return Err(format!("Download task was not found: {}", request.id));
    }

    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    emit_downloads_list_changed(&app, "deleted", tasks);
    Ok(CommandResponse { ok: true })
}

#[tauri::command]
fn downloads_clear_completed(
    app: AppHandle,
    request: ClearCompletedRequest,
) -> Result<AffectedResponse, String> {
    let _guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut tasks = read_download_tasks(&root)?;
    let archive = match request.archive {
        Some(archive) => archive,
        None => {
            let settings = read_downloads_settings(&root)?;
            settings.completed_task_cleanup != "delete"
        }
    };
    let mut affected = 0_usize;

    if archive {
        let now = Utc::now().to_rfc3339();
        for task in tasks
            .iter_mut()
            .filter(|task| task.status == DownloadStatus::Completed)
        {
            if archive_download_task(task, &now).is_ok() {
                affected += 1;
            }
        }
    } else {
        let original_len = tasks.len();
        tasks.retain(|task| task.status != DownloadStatus::Completed);
        affected = original_len.saturating_sub(tasks.len());
    }

    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    if affected > 0 {
        let reason = if archive {
            "completed_archived"
        } else {
            "completed_deleted"
        };
        emit_downloads_list_changed(&app, reason, tasks);
    }
    Ok(AffectedResponse { affected })
}

#[tauri::command]
fn downloads_clear_archived(app: AppHandle) -> Result<AffectedResponse, String> {
    let _guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let settings = read_downloads_settings(&root)?;
    let retention_days = settings.archived_task_retention_days;
    let now = Utc::now();
    let mut tasks = read_download_tasks(&root)?;
    let original_len = tasks.len();
    tasks.retain(|task| !archived_task_matches_clear_policy(task, retention_days, now));
    let affected = original_len.saturating_sub(tasks.len());
    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    if affected > 0 {
        emit_downloads_list_changed(&app, "archived_cleared", tasks);
    }
    Ok(AffectedResponse { affected })
}

#[tauri::command]
fn downloads_archive(
    app: AppHandle,
    request: ArchiveDownloadRequest,
) -> Result<DownloadTask, String> {
    let _guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut tasks = read_download_tasks(&root)?;
    let task = tasks
        .iter_mut()
        .find(|candidate| candidate.id == request.id)
        .ok_or_else(|| format!("Download task was not found: {}", request.id))?;

    let previous_status = task.status.clone();
    archive_download_task(task, &Utc::now().to_rfc3339())?;
    let updated = task.clone();
    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    emit_download_state(&app, previous_status, updated.clone());
    emit_downloads_list_changed(&app, "archived", tasks);
    Ok(updated)
}

