#[tauri::command]
fn downloads_bulk_action(
    app: AppHandle,
    request: BulkDownloadActionRequest,
) -> Result<BulkDownloadActionResponse, String> {
    let guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut tasks = read_download_tasks(&root)?;
    let now = Utc::now().to_rfc3339();
    let mut updated = Vec::new();
    let mut state_events = Vec::new();
    let mut failed = Vec::new();
    let mut schedule_needed = false;

    for id in dedupe_non_empty_ids(request.ids) {
        let Some(index) = tasks.iter().position(|candidate| candidate.id == id) else {
            failed.push(BulkDownloadFailure {
                id,
                error: "Download task was not found.".to_string(),
            });
            continue;
        };

        if matches!(request.action, DownloadBulkAction::Delete) {
            let task = tasks.remove(index);
            request_download_stop(&task.id);
            updated.push(task);
            continue;
        }

        let task = &mut tasks[index];
        let previous_status = task.status.clone();
        let result = apply_download_bulk_action(task, request.action, &now);
        match result {
            Ok(should_schedule) => {
                if matches!(
                    request.action,
                    DownloadBulkAction::Pause | DownloadBulkAction::Cancel
                ) {
                    request_download_stop(&task.id);
                }
                schedule_needed = schedule_needed || should_schedule;
                let updated_task = task.clone();
                state_events.push((previous_status, updated_task.clone()));
                updated.push(updated_task);
            }
            Err(error) => failed.push(BulkDownloadFailure { id, error }),
        }
    }

    if !updated.is_empty() {
        normalize_positions(&mut tasks);
        write_download_tasks(&root, &tasks)?;
    }

    drop(guard);
    for (previous_status, task) in &state_events {
        emit_download_state(&app, previous_status.clone(), task.clone());
    }
    if !updated.is_empty()
        && matches!(
            request.action,
            DownloadBulkAction::Archive | DownloadBulkAction::Restore | DownloadBulkAction::Delete
        )
    {
        let reason = match request.action {
            DownloadBulkAction::Archive => "bulk_archived",
            DownloadBulkAction::Restore => "bulk_restored",
            DownloadBulkAction::Delete => "bulk_deleted",
            _ => "bulk_updated",
        };
        emit_downloads_list_changed(&app, reason, tasks);
    }
    if schedule_needed {
        schedule_downloads(app.clone())?;
    }

    Ok(BulkDownloadActionResponse {
        tasks: updated,
        failed,
    })
}

fn dedupe_non_empty_ids(ids: Vec<String>) -> Vec<String> {
    let mut seen = HashSet::new();
    let mut result = Vec::new();
    for id in ids {
        let trimmed = id.trim();
        if trimmed.is_empty() || !seen.insert(trimmed.to_string()) {
            continue;
        }
        result.push(trimmed.to_string());
    }
    result
}

fn apply_download_bulk_action(
    task: &mut DownloadTask,
    action: DownloadBulkAction,
    now: &str,
) -> Result<bool, String> {
    match action {
        DownloadBulkAction::Start => {
            if task.status != DownloadStatus::Queued && task.status != DownloadStatus::Failed {
                return Err("Only queued or failed tasks can be started.".to_string());
            }
            task.status = DownloadStatus::Queued;
            task.run_after_active_slot = true;
            task.last_error = None;
            task.error_category = None;
            task.retryable = None;
            task.finished_at = None;
            task.updated_at = now.to_string();
            Ok(true)
        }
        DownloadBulkAction::Pause => {
            if task.status != DownloadStatus::Active {
                return Err("Only active tasks can be paused.".to_string());
            }
            task.status = DownloadStatus::Paused;
            task.run_after_active_slot = false;
            task.updated_at = now.to_string();
            Ok(false)
        }
        DownloadBulkAction::Resume => {
            if task.status != DownloadStatus::Paused {
                return Err("Only paused tasks can be resumed.".to_string());
            }
            task.status = DownloadStatus::Queued;
            task.run_after_active_slot = true;
            task.last_error = None;
            task.error_category = None;
            task.retryable = None;
            task.finished_at = None;
            task.updated_at = now.to_string();
            Ok(true)
        }
        DownloadBulkAction::Retry => {
            if task.status != DownloadStatus::Failed && task.status != DownloadStatus::Canceled {
                return Err("Only failed or canceled tasks can be retried.".to_string());
            }
            task.status = DownloadStatus::Queued;
            task.run_after_active_slot = true;
            task.last_error = None;
            task.error_category = None;
            task.retryable = None;
            task.finished_at = None;
            task.updated_at = now.to_string();
            Ok(true)
        }
        DownloadBulkAction::Cancel => {
            if task.status == DownloadStatus::Completed || task.status == DownloadStatus::Archived {
                return Err("Completed or archived tasks cannot be canceled.".to_string());
            }
            task.status = DownloadStatus::Canceled;
            task.run_after_active_slot = false;
            task.updated_at = now.to_string();
            task.finished_at = Some(now.to_string());
            Ok(false)
        }
        DownloadBulkAction::Archive => {
            archive_download_task(task, now)?;
            Ok(false)
        }
        DownloadBulkAction::Restore => {
            restore_archived_download_task(task, now)?;
            Ok(false)
        }
        DownloadBulkAction::Delete => Ok(false),
    }
}

fn archive_download_task(task: &mut DownloadTask, now: &str) -> Result<(), String> {
    if matches!(
        task.status,
        DownloadStatus::Queued | DownloadStatus::Active | DownloadStatus::Paused
    ) {
        return Err("Only completed, failed, or canceled tasks can be archived.".to_string());
    }
    if task.status == DownloadStatus::Archived {
        return Ok(());
    }

    let archived_from_status = download_status_label(&task.status);
    let mut details = task
        .details_json
        .take()
        .and_then(|value| value.as_object().cloned())
        .unwrap_or_default();
    details.insert(
        "archived_from_status".to_string(),
        serde_json::Value::String(archived_from_status.to_string()),
    );
    details.insert(
        "archived_at".to_string(),
        serde_json::Value::String(now.to_string()),
    );
    task.details_json = Some(serde_json::Value::Object(details));
    task.status = DownloadStatus::Archived;
    task.run_after_active_slot = false;
    task.updated_at = now.to_string();
    Ok(())
}

fn set_download_task_expected_sha256(
    task: &mut DownloadTask,
    expected_sha256: &str,
) -> Result<(), String> {
    let expected = normalize_sha256(expected_sha256)?;
    let mut details = task
        .details_json
        .take()
        .and_then(|value| value.as_object().cloned())
        .unwrap_or_default();
    let mut integrity = details
        .remove("integrity")
        .and_then(|value| value.as_object().cloned())
        .unwrap_or_default();
    integrity.insert(
        "expected_sha256".to_string(),
        serde_json::Value::String(expected),
    );
    details.insert(
        "integrity".to_string(),
        serde_json::Value::Object(integrity),
    );
    task.details_json = Some(serde_json::Value::Object(details));
    Ok(())
}

fn download_task_expected_sha256(task: &DownloadTask) -> Option<String> {
    task.details_json
        .as_ref()
        .and_then(|value| value.get("integrity"))
        .and_then(|value| value.get("expected_sha256"))
        .and_then(|value| value.as_str())
        .and_then(|value| normalize_sha256(value).ok())
}

fn verify_download_task_sha256(
    task: &DownloadTask,
    progress: &DownloadCopyProgress,
) -> Result<Option<String>, String> {
    let Some(expected) = download_task_expected_sha256(task) else {
        return Ok(None);
    };
    if progress.file_count != 1 {
        return Err(format!(
            "SHA-256 verification requires a single output file, but this task produced {} files.",
            progress.file_count
        ));
    }

    let output_path = PathBuf::from(&progress.output_path);
    if !output_path.is_file() {
        return Err(format!(
            "SHA-256 verification requires a file output path: {}",
            progress.output_path
        ));
    }
    let actual = file_sha256_hex(&output_path)?;
    if !actual.eq_ignore_ascii_case(&expected) {
        return Err(format!(
            "SHA-256 mismatch for {}: expected {}, got {}.",
            progress.output_path, expected, actual
        ));
    }
    Ok(Some(actual))
}

fn restore_archived_download_task(task: &mut DownloadTask, now: &str) -> Result<(), String> {
    if task.status != DownloadStatus::Archived {
        return Err("Only archived tasks can be restored.".to_string());
    }

    let restored_status = task
        .details_json
        .as_ref()
        .and_then(|value| value.get("archived_from_status"))
        .and_then(|value| value.as_str())
        .and_then(download_status_from_archive_label)
        .unwrap_or(DownloadStatus::Completed);
    task.status = restored_status;
    task.run_after_active_slot = false;
    task.updated_at = now.to_string();
    if matches!(
        task.status,
        DownloadStatus::Completed | DownloadStatus::Failed | DownloadStatus::Canceled
    ) && task.finished_at.is_none()
    {
        task.finished_at = Some(now.to_string());
    }
    Ok(())
}

fn archived_task_matches_clear_policy(
    task: &DownloadTask,
    retention_days: Option<u16>,
    now: chrono::DateTime<Utc>,
) -> bool {
    if task.status != DownloadStatus::Archived {
        return false;
    }

    let Some(days) = retention_days else {
        return true;
    };
    let Some(archived_at) = task
        .details_json
        .as_ref()
        .and_then(|value| value.get("archived_at"))
        .and_then(|value| value.as_str())
        .and_then(parse_rfc3339_timestamp)
    else {
        return false;
    };

    now.signed_duration_since(archived_at).num_days() >= i64::from(days)
}

fn download_status_label(status: &DownloadStatus) -> &'static str {
    match status {
        DownloadStatus::Queued => "queued",
        DownloadStatus::Active => "active",
        DownloadStatus::Paused => "paused",
        DownloadStatus::Completed => "completed",
        DownloadStatus::Failed => "failed",
        DownloadStatus::Canceled => "canceled",
        DownloadStatus::Archived => "archived",
    }
}

fn download_status_from_archive_label(value: &str) -> Option<DownloadStatus> {
    match value.trim().to_ascii_lowercase().as_str() {
        "completed" => Some(DownloadStatus::Completed),
        "failed" => Some(DownloadStatus::Failed),
        "canceled" | "cancelled" => Some(DownloadStatus::Canceled),
        _ => None,
    }
}

#[tauri::command]
fn downloads_reorder(
    app: AppHandle,
    request: ReorderDownloadsRequest,
) -> Result<ListDownloadsResponse, String> {
    let _guard = download_store_lock()
        .lock()
        .map_err(|_| "Download store lock was poisoned.".to_string())?;
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    let mut tasks = read_download_tasks(&root)?;
    let now = Utc::now().to_rfc3339();

    for (index, ordered_id) in request.ordered_ids.iter().enumerate() {
        let task = tasks
            .iter_mut()
            .find(|candidate| candidate.id == *ordered_id)
            .ok_or_else(|| format!("Download task was not found: {ordered_id}"))?;
        task.position = (index + 1) as u32;
        task.updated_at = now.clone();
    }

    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    tasks.sort_by_key(|task| task.position);
    emit_downloads_list_changed(&app, "reordered", tasks.clone());
    Ok(ListDownloadsResponse { tasks })
}

#[tauri::command]
fn downloads_get_logs(
    app: AppHandle,
    request: DownloadLogsRequest,
) -> Result<DownloadLogsResponse, String> {
    let (_, root) = resolve_data_root(&app).map_err(|error| error.to_string())?;
    read_download_logs_page_at_root(
        &root,
        &request.id,
        request.cursor,
        request.limit,
        request.search.as_deref(),
    )
}

fn build_downloads_local_summary_at_root(
    root: &Path,
) -> Result<DownloadsLocalSummaryResponse, String> {
    let tasks = read_download_tasks(root)?;
    let logs = list_local_files(&root.join("logs"), Some("log")).unwrap_or_default();
    let log_task_ids = logs
        .iter()
        .filter_map(|log| download_task_id_from_log_name(&log.file_name))
        .collect::<HashSet<_>>();
    let unique_output_dirs = tasks
        .iter()
        .filter_map(download_task_output_dir_label)
        .collect::<HashSet<_>>();

    Ok(DownloadsLocalSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        data_root: display_path(root),
        task_count: tasks.len(),
        visible_task_count: tasks
            .iter()
            .filter(|task| task.status != DownloadStatus::Archived)
            .count(),
        queued_task_count: tasks
            .iter()
            .filter(|task| task.status == DownloadStatus::Queued)
            .count(),
        active_task_count: tasks
            .iter()
            .filter(|task| task.status == DownloadStatus::Active)
            .count(),
        paused_task_count: tasks
            .iter()
            .filter(|task| task.status == DownloadStatus::Paused)
            .count(),
        completed_task_count: tasks
            .iter()
            .filter(|task| task.status == DownloadStatus::Completed)
            .count(),
        failed_task_count: tasks
            .iter()
            .filter(|task| task.status == DownloadStatus::Failed)
            .count(),
        canceled_task_count: tasks
            .iter()
            .filter(|task| task.status == DownloadStatus::Canceled)
            .count(),
        archived_task_count: tasks
            .iter()
            .filter(|task| task.status == DownloadStatus::Archived)
            .count(),
        retryable_task_count: tasks
            .iter()
            .filter(|task| task.retryable == Some(true))
            .count(),
        retried_task_count: tasks.iter().filter(|task| task.retry_count > 0).count(),
        retry_count_total: tasks.iter().map(|task| task.retry_count).sum(),
        tasks_with_error_count: tasks
            .iter()
            .filter(|task| {
                task.last_error
                    .as_deref()
                    .is_some_and(|error| !error.trim().is_empty())
            })
            .count(),
        output_backed_task_count: tasks
            .iter()
            .filter(|task| download_task_has_output_reference(task))
            .count(),
        output_path_count: tasks
            .iter()
            .filter(|task| option_text_present(task.output_path.as_deref()))
            .count(),
        output_dir_count: tasks
            .iter()
            .filter(|task| option_text_present(task.output_dir.as_deref()))
            .count(),
        unique_output_dir_count: unique_output_dirs.len(),
        cookie_bucket_ref_count: tasks
            .iter()
            .filter(|task| option_text_present(task.cookie_bucket_id.as_deref()))
            .count(),
        auth_payload_ref_count: tasks
            .iter()
            .filter(|task| option_text_present(task.auth_payload_ref.as_deref()))
            .count(),
        thumbnail_url_count: tasks
            .iter()
            .filter(|task| option_text_present(task.thumbnail_url.as_deref()))
            .count(),
        thumbnail_path_count: tasks
            .iter()
            .filter(|task| option_text_present(task.thumbnail_path.as_deref()))
            .count(),
        clip_task_count: tasks
            .iter()
            .filter(|task| task.start_seconds.is_some() || task.end_seconds.is_some())
            .count(),
        custom_args_task_count: tasks
            .iter()
            .filter(|task| option_text_present(task.custom_ytdlp_args.as_deref()))
            .count(),
        live_from_start_task_count: tasks.iter().filter(|task| task.live_from_start).count(),
        total_downloaded_bytes: tasks.iter().filter_map(|task| task.downloaded_bytes).sum(),
        total_known_bytes: tasks.iter().filter_map(|task| task.total_bytes).sum(),
        total_file_count: tasks
            .iter()
            .filter_map(|task| task.file_count.map(u64::from))
            .sum(),
        log_file_count: logs.len(),
        log_total_size_bytes: logs.iter().map(|log| log.size_bytes).sum(),
        log_backed_task_count: tasks
            .iter()
            .filter(|task| log_task_ids.contains(&task.id))
            .count(),
        status_counts: counted_local_entries(
            tasks
                .iter()
                .map(|task| download_status_label(&task.status).to_string()),
        ),
        kind_counts: counted_local_entries(tasks.iter().map(|task| download_kind_label(&task.kind))),
        platform_counts: counted_local_entries(tasks.iter().map(|task| {
            if task.platform.trim().is_empty() {
                "unknown".to_string()
            } else {
                task.platform.clone()
            }
        })),
        error_category_counts: counted_local_entries(tasks.iter().map(|task| {
            task.error_category
                .as_ref()
                .map(download_error_category_label)
                .unwrap_or_else(|| {
                    if task
                        .last_error
                        .as_deref()
                        .is_some_and(|error| !error.trim().is_empty())
                    {
                        "uncategorized".to_string()
                    } else {
                        "none".to_string()
                    }
                })
        })),
        output_status_counts: counted_local_entries(tasks.iter().map(|task| {
            if option_text_present(task.output_path.as_deref()) {
                "output_path".to_string()
            } else if option_text_present(task.output_dir.as_deref()) {
                "output_dir".to_string()
            } else {
                "none".to_string()
            }
        })),
        log_status_counts: counted_local_entries(tasks.iter().map(|task| {
            if log_task_ids.contains(&task.id) {
                "present".to_string()
            } else {
                "missing".to_string()
            }
        })),
        auth_usage_counts: counted_local_entries(tasks.iter().flat_map(|task| {
            let mut values = Vec::new();
            if option_text_present(task.cookie_bucket_id.as_deref()) {
                values.push("cookie_bucket".to_string());
            }
            if option_text_present(task.auth_payload_ref.as_deref()) {
                values.push("auth_payload".to_string());
            }
            if values.is_empty() {
                values.push("none".to_string());
            }
            values
        })),
        network_option_counts: counted_local_entries(tasks.iter().flat_map(|task| {
            let mut values = Vec::new();
            if option_text_present(task.user_agent.as_deref()) {
                values.push("user_agent".to_string());
            }
            if option_text_present(task.referer.as_deref()) {
                values.push("referer".to_string());
            }
            if option_text_present(task.proxy.as_deref()) {
                values.push("proxy".to_string());
            }
            if option_text_present(task.rate_limit.as_deref()) {
                values.push("rate_limit".to_string());
            }
            if task.concurrent_fragments.is_some() {
                values.push("concurrent_fragments".to_string());
            }
            if task.live_from_start {
                values.push("live_from_start".to_string());
            }
            if values.is_empty() {
                values.push("none".to_string());
            }
            values
        })),
        first_created_at: tasks.iter().map(|task| task.created_at.clone()).min(),
        last_created_at: tasks.iter().map(|task| task.created_at.clone()).max(),
        last_updated_at: tasks.iter().map(|task| task.updated_at.clone()).max(),
        last_started_at: tasks.iter().filter_map(|task| task.started_at.clone()).max(),
        last_finished_at: tasks
            .iter()
            .filter_map(|task| task.finished_at.clone())
            .max(),
        last_log_modified_at: logs.iter().filter_map(|log| log.modified_at.clone()).max(),
        includes_source_urls: false,
        includes_output_file_bodies: false,
        includes_log_bodies: false,
        includes_cookie_values: false,
        includes_authorization_values: false,
        executes_downloads: false,
        review_notes: vec![
            "This summary reads local download task metadata and log file inventory only.".to_string(),
            "It does not export individual task source URLs, downloaded file bodies, or log bodies.".to_string(),
            "Cookie bucket ids and authorization payload refs are counted as references only; Cookie values and Authorization header values are never exported.".to_string(),
            "Counts reflect the local task store at generation time and do not start, pause, resume, retry, or verify downloads.".to_string(),
        ],
    })
}

fn export_downloads_local_summary_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let export_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Downloads local summary export")?,
        None => default_downloads_local_summary_export_path(root),
    };
    validate_json_file_path(&export_path, "Downloads local summary export")?;
    if let Some(parent) = export_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let summary = build_downloads_local_summary_at_root(root)?;
    fs::write(
        &export_path,
        serde_json::to_vec_pretty(&summary).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write Downloads local summary export: {error}"))?;
    Ok(DiagnosticsResponse {
        archive_path: display_path(export_path),
    })
}

fn default_downloads_local_summary_export_path(root: &Path) -> PathBuf {
    root.join("downloads").join("exports").join(format!(
        "fetchdock-downloads-summary-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn downloads_kind_catalog_item(
    kind: &str,
    aliases: &[&str],
    label: &str,
    status: &str,
    execution_backend: &str,
    dependency_hints: &[&str],
    source_hints: &[&str],
    limitations: &[&str],
) -> DownloadsKindCatalogItem {
    DownloadsKindCatalogItem {
        kind: kind.to_string(),
        aliases: aliases.iter().map(|alias| (*alias).to_string()).collect(),
        label: label.to_string(),
        status: status.to_string(),
        create_supported: true,
        queue_supported: true,
        desktop_ui_supported: true,
        cli_supported: true,
        extension_bridge_supported: matches!(
            kind,
            "video"
                | "playlist"
                | "audio"
                | "image"
                | "pdf"
                | "book"
                | "webpage"
                | "generic"
                | "subtitles_only"
        ),
        local_summary_supported: true,
        execution_backend: execution_backend.to_string(),
        dependency_hints: dependency_hints
            .iter()
            .map(|hint| (*hint).to_string())
            .collect(),
        source_hints: source_hints
            .iter()
            .map(|hint| (*hint).to_string())
            .collect(),
        limitations: limitations
            .iter()
            .map(|limitation| (*limitation).to_string())
            .collect(),
    }
}

