fn export_downloads_kind_catalog_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let export_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Downloads kind catalog export")?,
        None => default_downloads_kind_catalog_export_path(root),
    };
    validate_json_file_path(&export_path, "Downloads kind catalog export")?;
    if let Some(parent) = export_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let catalog = build_downloads_kind_catalog_at_root(root);
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "fetchdock.downloads_kind_catalog",
        "catalog": catalog,
        "includes_source_urls": false,
        "includes_output_file_bodies": false,
        "includes_log_bodies": false,
        "includes_cookie_values": false,
        "includes_authorization_values": false,
        "executes_downloads": false,
        "verifies_remote_sources": false,
        "verifies_manual_matrix": false
    });
    fs::write(
        &export_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write Downloads kind catalog export: {error}"))?;
    Ok(DiagnosticsResponse {
        archive_path: display_path(export_path),
    })
}

#[allow(clippy::too_many_arguments)]
fn downloads_option_catalog_item(
    option: &str,
    aliases: &[&str],
    label: &str,
    status: &str,
    task_supported: bool,
    default_supported: bool,
    ytdlp_supported: bool,
    direct_file_supported: bool,
    task_field: &str,
    settings_field: Option<&str>,
    cli_flags: &[&str],
    applies_to_kinds: &[&str],
    value_hints: &[&str],
    limitations: &[&str],
) -> DownloadsOptionCatalogItem {
    DownloadsOptionCatalogItem {
        option: option.to_string(),
        aliases: aliases.iter().map(|alias| (*alias).to_string()).collect(),
        label: label.to_string(),
        status: status.to_string(),
        task_supported,
        default_supported,
        desktop_ui_supported: true,
        cli_supported: !cli_flags.is_empty(),
        ytdlp_supported,
        direct_file_supported,
        export_supported: true,
        task_field: task_field.to_string(),
        settings_field: settings_field.map(str::to_string),
        cli_flags: cli_flags.iter().map(|flag| (*flag).to_string()).collect(),
        applies_to_kinds: applies_to_kinds
            .iter()
            .map(|kind| (*kind).to_string())
            .collect(),
        value_hints: value_hints.iter().map(|hint| (*hint).to_string()).collect(),
        limitations: limitations
            .iter()
            .map(|limitation| (*limitation).to_string())
            .collect(),
    }
}

