fn default_downloads_option_catalog_export_path(root: &Path) -> PathBuf {
    root.join("downloads").join("exports").join(format!(
        "fetchdock-downloads-option-catalog-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn export_downloads_option_catalog_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let export_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Downloads option catalog export")?,
        None => default_downloads_option_catalog_export_path(root),
    };
    validate_json_file_path(&export_path, "Downloads option catalog export")?;
    if let Some(parent) = export_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let catalog = build_downloads_option_catalog_at_root(root);
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "fetchdock.downloads_option_catalog",
        "catalog": catalog,
        "includes_task_values": false,
        "includes_source_urls": false,
        "includes_output_file_bodies": false,
        "includes_log_bodies": false,
        "includes_cookie_values": false,
        "includes_authorization_values": false,
        "executes_downloads": false,
        "verifies_ytdlp_matrix": false,
        "verifies_manual_matrix": false
    });
    fs::write(
        &export_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write Downloads option catalog export: {error}"))?;
    Ok(DiagnosticsResponse {
        archive_path: display_path(export_path),
    })
}

fn downloads_status_catalog_item(
    status: &str,
    label: &str,
    visible_in_queue: bool,
    visible_in_history: bool,
    terminal: bool,
    active_runtime_state: bool,
    allowed_actions: &[&str],
    bulk_actions: &[&str],
    next_statuses: &[&str],
    event_names: &[&str],
    limitations: &[&str],
) -> DownloadsStatusCatalogItem {
    DownloadsStatusCatalogItem {
        status: status.to_string(),
        label: label.to_string(),
        visible_in_queue,
        visible_in_history,
        terminal,
        active_runtime_state,
        allowed_actions: allowed_actions
            .iter()
            .map(|action| (*action).to_string())
            .collect(),
        bulk_actions: bulk_actions
            .iter()
            .map(|action| (*action).to_string())
            .collect(),
        next_statuses: next_statuses
            .iter()
            .map(|status| (*status).to_string())
            .collect(),
        event_names: event_names
            .iter()
            .map(|event| (*event).to_string())
            .collect(),
        limitations: limitations
            .iter()
            .map(|limitation| (*limitation).to_string())
            .collect(),
    }
}

