#[allow(clippy::too_many_arguments)]
fn downloads_error_catalog_item(
    category: DownloadErrorCategory,
    label: &str,
    retryable_by_default: bool,
    sample_match_hints: &[&str],
    user_action: Option<&str>,
    applies_to_backends: &[&str],
    limitations: &[&str],
) -> DownloadsErrorCatalogItem {
    let code = download_error_category_code(&category).to_string();
    DownloadsErrorCatalogItem {
        category: download_error_category_label(&category),
        code,
        label: label.to_string(),
        retryable_by_default,
        auto_retry_supported: retryable_by_default,
        max_auto_retries: if retryable_by_default {
            MAX_DOWNLOAD_RETRIES
        } else {
            0
        },
        retry_delay_seconds: if retryable_by_default {
            (1..=MAX_DOWNLOAD_RETRIES).collect()
        } else {
            Vec::new()
        },
        sample_match_hints: sample_match_hints
            .iter()
            .map(|hint| (*hint).to_string())
            .collect(),
        user_action: user_action.map(str::to_string),
        applies_to_backends: applies_to_backends
            .iter()
            .map(|backend| (*backend).to_string())
            .collect(),
        limitations: limitations
            .iter()
            .map(|limitation| (*limitation).to_string())
            .collect(),
    }
}

