fn default_downloads_privacy_catalog_export_path(root: &Path) -> PathBuf {
    root.join("downloads").join("exports").join(format!(
        "fetchdock-downloads-privacy-catalog-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn export_downloads_privacy_catalog_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let export_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Downloads privacy catalog export")?,
        None => default_downloads_privacy_catalog_export_path(root),
    };
    validate_json_file_path(&export_path, "Downloads privacy catalog export")?;
    if let Some(parent) = export_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let catalog = build_downloads_privacy_catalog_at_root(root);
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "fetchdock.downloads_privacy_catalog",
        "catalog": catalog,
        "includes_task_values": false,
        "includes_source_urls": false,
        "includes_output_paths": false,
        "includes_output_file_bodies": false,
        "includes_log_bodies": false,
        "includes_cookie_values": false,
        "includes_authorization_values": false,
        "reads_cookie_values": false,
        "reads_authorization_values": false,
        "reads_log_bodies": false,
        "reads_output_file_bodies": false,
        "mutates_tasks": false,
        "executes_downloads": false,
        "verifies_privacy_matrix": false,
        "verifies_manual_matrix": false
    });
    fs::write(
        &export_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write Downloads privacy catalog export: {error}"))?;
    Ok(DiagnosticsResponse {
        archive_path: display_path(export_path),
    })
}

