#[allow(clippy::too_many_arguments)]
fn downloads_filter_catalog_item(
    filter: &str,
    label: &str,
    status: &str,
    desktop_ui: &[&str],
    cli_flags: &[&str],
    task_fields: &[&str],
    preset_field: Option<&str>,
    applies_to_views: &[&str],
    supports_copy: bool,
    supports_export: bool,
    mutates_tasks: bool,
    scope: &str,
    limitations: &[&str],
) -> DownloadsFilterCatalogItem {
    DownloadsFilterCatalogItem {
        filter: filter.to_string(),
        label: label.to_string(),
        status: status.to_string(),
        desktop_ui: desktop_ui
            .iter()
            .map(|surface| (*surface).to_string())
            .collect(),
        cli_flags: cli_flags.iter().map(|flag| (*flag).to_string()).collect(),
        task_fields: task_fields
            .iter()
            .map(|field| (*field).to_string())
            .collect(),
        preset_field: preset_field.map(ToString::to_string),
        applies_to_views: applies_to_views
            .iter()
            .map(|view| (*view).to_string())
            .collect(),
        supports_copy,
        supports_export,
        mutates_tasks,
        scope: scope.to_string(),
        limitations: limitations
            .iter()
            .map(|limitation| (*limitation).to_string())
            .collect(),
    }
}

