fn sanitize_download_filter_preset_backup_item(
    item: DownloadFilterPresetBackupItem,
) -> Option<DownloadFilterPresetBackupItem> {
    let name = sanitize_optional_text(Some(&item.name))?;
    Some(DownloadFilterPresetBackupItem {
        id: sanitize_optional_text(Some(&item.id)).unwrap_or_default(),
        name,
        view_mode: sanitize_optional_text(Some(&item.view_mode))
            .unwrap_or_else(|| "active".to_string()),
        status: sanitize_optional_text(Some(&item.status)).unwrap_or_else(|| "all".to_string()),
        kind: sanitize_optional_text(Some(&item.kind)).unwrap_or_else(|| "all".to_string()),
        platform: sanitize_optional_text(Some(&item.platform)).unwrap_or_else(|| "all".to_string()),
        operational: sanitize_optional_text(Some(&item.operational))
            .unwrap_or_else(|| "all".to_string()),
        query: sanitize_optional_text(Some(&item.query)).unwrap_or_default(),
        date_field: sanitize_optional_text(Some(&item.date_field))
            .unwrap_or_else(|| "created".to_string()),
        date_from: sanitize_optional_text(Some(&item.date_from)).unwrap_or_default(),
        date_to: sanitize_optional_text(Some(&item.date_to)).unwrap_or_default(),
        sort_mode: sanitize_optional_text(Some(&item.sort_mode))
            .unwrap_or_else(|| "queue".to_string()),
    })
}

