fn cli_privacy(options: &CliOptions) -> Result<(), String> {
    let root = cli_data_root(options)?;
    let payload = serde_json::to_value(build_privacy_status_at_root(&root)?)
        .map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        let telemetry = payload
            .get("telemetry_enabled")
            .and_then(serde_json::Value::as_bool)
            .unwrap_or(false);
        let network = payload
            .get("network_telemetry_enabled")
            .and_then(serde_json::Value::as_bool)
            .unwrap_or(false);
        let include_urls = payload
            .get("diagnostics_include_urls_default")
            .and_then(serde_json::Value::as_bool)
            .unwrap_or(false);
        let cookie_values = payload
            .get("cookie_values_exported_in_diagnostics")
            .and_then(serde_json::Value::as_bool)
            .unwrap_or(false);
        format!(
            "Privacy status\nTelemetry enabled: {telemetry}\nNetwork telemetry enabled: {network}\nDiagnostics include URLs by default: {include_urls}\nCookie values in diagnostics: {cookie_values}"
        )
    })?;
    Ok(())
}

