fn cli_release_package_summary(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("release-package-summary does not accept extra arguments.".to_string());
    }
    let summary = build_release_package_summary()?;
    let payload = serde_json::to_value(&summary).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        let gates = summary
            .gate_counts
            .iter()
            .map(|entry| format!("{}:{}", entry.key, entry.count))
            .collect::<Vec<_>>()
            .join(", ");
        format!(
            "Release package summary\nSource: {}\nFrontend dist: {} ({} files, {} bytes)\nWindows portable: {} ({} files, {} bytes)\nTauri bundles: {} ({} files, {} bytes)\nPackaging templates: {} ({} files)\nRelease scripts: {} ({} files)\nKey files: {}\nStatus counts: {}\nNote: local metadata only; final builds, signing, notarization, installer smoke, and store submission are still final-gate work.",
            summary.source_root,
            summary.frontend_dist.status,
            summary.frontend_dist.file_count,
            summary.frontend_dist.total_size_bytes,
            summary.windows_portable.status,
            summary.windows_portable.file_count,
            summary.windows_portable.total_size_bytes,
            summary.tauri_bundles.status,
            summary.tauri_bundles.file_count,
            summary.tauri_bundles.total_size_bytes,
            summary.packaging_templates.status,
            summary.packaging_templates.file_count,
            summary.scripts.status,
            summary.scripts.file_count,
            summary.package_files.len(),
            if gates.is_empty() { "none".to_string() } else { gates }
        )
    })?;
    Ok(())
}

