fn cli_legal_readiness_summary(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("legal-readiness-summary does not accept extra arguments.".to_string());
    }
    let root = cli_data_root(options)?;
    let summary = build_legal_readiness_summary_at_root(&root)?;
    let payload = serde_json::to_value(&summary).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        let package_statuses = summary
            .package_status_counts
            .iter()
            .map(|entry| format!("{}:{}", entry.key, entry.count))
            .collect::<Vec<_>>()
            .join(", ");
        let gates = summary
            .checklist_gate_counts
            .iter()
            .map(|entry| format!("{}:{}", entry.key, entry.count))
            .collect::<Vec<_>>()
            .join(", ");
        format!(
            "Legal readiness summary\nSource: {}\nData root: {}\nChecklist ready/review/pending/blocked: {}/{}/{}/{}\nMissing documents: {} ({})\nNPM packages: {} (missing license: {})\nRust crates: {} (missing license metadata: {})\nPackage statuses: {}\nGate statuses: {}\nNote: local metadata only; final legal review, package smoke, signing, notarization, and store submission remain final-gate work.",
            summary.source_root,
            summary.data_root,
            summary.ready_count,
            summary.review_needed_count,
            summary.pending_count,
            summary.blocked_count,
            summary.missing_document_count,
            if summary.missing_documents.is_empty() {
                "none".to_string()
            } else {
                summary.missing_documents.join(", ")
            },
            summary.npm_package_count,
            summary.npm_missing_license_count,
            summary.rust_crate_count,
            summary.rust_missing_license_count,
            if package_statuses.is_empty() {
                "none".to_string()
            } else {
                package_statuses
            },
            if gates.is_empty() {
                "none".to_string()
            } else {
                gates
            }
        )
    })?;
    Ok(())
}

