fn cli_check_due_update_manifest(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("check-due-update does not accept extra arguments.".to_string());
    }
    let root = cli_data_root(options)?;
    let response = check_due_update_manifest_at_root(&root)?;
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        let version = response
            .result
            .as_ref()
            .and_then(|result| result.latest_version.as_deref())
            .unwrap_or("unknown");
        format!(
            "Due update check\nStatus: {}\nChecked: {}\nVersion: {}\nNext check: {}",
            response.status,
            response.checked,
            version,
            response.next_check_at.as_deref().unwrap_or("unknown")
        )
    })
}

