fn cli_update_twitter_auth(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let request = cli_parse_twitter_auth_args(args)?;
    let root = cli_data_root(options)?;
    let mut settings = read_auth_settings(&root)?;
    if let Some(header) = request.manual_cookie_header {
        settings.twitter_x.manual_cookie_header = header
            .as_deref()
            .map(sanitize_cookie_header_setting)
            .transpose()?;
        if settings.twitter_x.manual_cookie_header.is_none() {
            settings.twitter_x.manual_cookie_header_enabled = false;
        }
    }
    if let Some(enabled) = request.manual_cookie_header_enabled {
        if enabled && settings.twitter_x.manual_cookie_header.is_none() {
            return Err("Save a Twitter/X manual Cookie header before enabling it.".to_string());
        }
        settings.twitter_x.manual_cookie_header_enabled = enabled;
    }
    settings.twitter_x.updated_at = Some(Utc::now().to_rfc3339());
    let public = auth_settings_public(&write_auth_settings(&root, &settings)?);
    let payload = serde_json::to_value(&public).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Twitter/X auth updated\nManual Cookie enabled: {}\nHeader stored: {}",
            public.twitter_x.manual_cookie_header_enabled,
            public.twitter_x.manual_cookie_header_set
        )
    })
}

