fn cli_local_evidence_summary(options: &CliOptions) -> Result<(), String> {
    let root = cli_data_root(options)?;
    let summary = build_local_evidence_summary_response(&root)?;
    let payload = serde_json::to_value(&summary).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        let mut lines = vec![
            "Local feature evidence summary".to_string(),
            format!(
                "Generated: {} | Modules: {} | Secrets exported: {}",
                summary.generated_at, summary.module_count, summary.secrets_exported
            ),
        ];
        if let Some(modules) = summary.modules.as_object() {
            for (name, module) in modules {
                let scope = module
                    .get("scope")
                    .and_then(serde_json::Value::as_str)
                    .unwrap_or("local evidence available");
                lines.push(format!("{name}: {scope}"));
            }
        }
        if !summary.honesty_notes.is_empty() {
            lines.push("Notes:".to_string());
            lines.extend(summary.honesty_notes.iter().map(|note| format!("- {note}")));
        }
        lines.join("\n")
    })
}

