fn cli_probe_course(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let request = cli_parse_course_probe_args(args)?;
    let root = cli_data_root(options)?;
    let url = normalize_http_url(&request.source_url)?;
    let entry = match build_course_entry_with_remote_outline(&root, &url, &request, "probed") {
        Ok(entry) => entry,
        Err(error) => {
            let mut entry = build_course_candidate_entry_at_root(
                &root,
                &url,
                &request,
                "probed_metadata_pending",
            )?;
            annotate_course_remote_extraction_failure(&mut entry, &error);
            entry
        }
    };
    let payload = serde_json::to_value(&entry).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!("Course probe\n{}\t{}", entry.id, entry.title)
    })
}

fn cli_import_course(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let request = cli_parse_course_probe_args(args)?;
    let root = cli_data_root(options)?;
    let url = normalize_http_url(&request.source_url)?;
    let mut courses = read_courses(&root)?;
    let entry = match build_course_entry_with_remote_outline(&root, &url, &request, "imported") {
        Ok(entry) => entry,
        Err(error) => {
            let mut entry = build_course_candidate_entry_at_root(
                &root,
                &url,
                &request,
                "imported_metadata_pending",
            )?;
            annotate_course_remote_extraction_failure(&mut entry, &error);
            entry
        }
    };
    courses.retain(|course| course.id != entry.id);
    courses.push(entry.clone());
    write_courses(&root, &courses)?;
    let payload = serde_json::to_value(&entry).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!("Course imported\n{}\t{}", entry.id, entry.title)
    })
}

