fn cli_export_course_manifest(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let mut output_path = None;
    let mut course_ids = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output" | "--path" => {
                output_path = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?));
                index += 2;
            }
            "--ids" | "--course-ids" => {
                course_ids = Some(cli_split_list(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?));
                index += 2;
            }
            value if value.starts_with("--output=") || value.starts_with("--path=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output requires a value.".to_string())?;
                output_path = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--ids=") || value.starts_with("--course-ids=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--ids requires a value.".to_string())?;
                course_ids = Some(cli_split_list(value));
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!(
                    "Unsupported export-course-manifest option: {value}"
                ));
            }
            value => {
                if output_path.is_some() {
                    return Err(
                        "export-course-manifest accepts at most one output path.".to_string()
                    );
                }
                output_path = sanitize_optional_text(Some(value));
                index += 1;
            }
        }
    }

    let root = cli_data_root(options)?;
    let response = export_course_manifest_at_root(
        &root,
        CourseManifestExportRequest {
            output_path,
            course_ids,
        },
    )?;
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Course manifest exported\nPath: {}\nCourses: {}",
            response.output_path, response.exported_count
        )
    })
}

