fn cli_import_bilibili_manifest(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let (manifest_path, collection) = cli_parse_bilibili_manifest_args(args)?;
    let root = cli_data_root(options)?;
    let response = import_bilibili_manifest_at_root(
        &root,
        BilibiliManifestImportRequest {
            manifest_path,
            collection,
        },
    )?;
    let watch_later_count = response
        .items
        .iter()
        .filter(|item| item.collection == "watch_later")
        .count();
    let history_count = response
        .items
        .iter()
        .filter(|item| item.collection == "history")
        .count();
    let payload = serde_json::json!({
        "imported": true,
        "item_count": response.items.len(),
        "watch_later_count": watch_later_count,
        "history_count": history_count,
        "items": &response.items
    });
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Bilibili manifest imported\nItems: {}\nWatch later: {}\nHistory: {}",
            response.items.len(),
            watch_later_count,
            history_count
        )
    })
}

