fn format_size_bytes(size: u64) -> String {
    const UNITS: [&str; 5] = ["B", "KB", "MB", "GB", "TB"];
    let mut value = size as f64;
    let mut unit = 0_usize;
    while value >= 1024.0 && unit < UNITS.len() - 1 {
        value /= 1024.0;
        unit += 1;
    }
    if unit == 0 {
        format!("{size} {}", UNITS[unit])
    } else {
        format!("{value:.1} {}", UNITS[unit])
    }
}

fn cli_queue_telegram_media(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let (ids, output_dir) = cli_parse_ids_with_output_dir(
        args,
        "queue-telegram-media",
        options.task_output_dir.clone(),
    )?;
    let root = cli_data_root(options)?;
    if ids.len() == 1 && output_dir.is_none() {
        let task = queue_telegram_media_at_root(
            &root,
            TelegramMediaIdRequest {
                id: ids[0].clone(),
                create_options: Some(cli_download_create_options(options)),
            },
        )?;
        return cli_print_task_created(options, &task, "Telegram media queued");
    }
    let response = queue_telegram_media_items_at_root(
        &root,
        TelegramMediaIdsRequest {
            ids,
            output_dir,
            create_options: Some(cli_download_create_options(options)),
        },
    )?;
    cli_print_bulk_task_response(
        options,
        &response.created,
        response.skipped.len(),
        "Telegram media queued",
    )
}

