fn cli_download_logs(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let filters = cli_parse_download_logs_args(args)?;
    let root = cli_data_root(options)?;
    let all_logs = list_local_files(&root.join("logs"), Some("log"))?;
    let mut logs = all_logs
        .iter()
        .filter(|file| download_log_summary_matches_filter(file, &filters))
        .cloned()
        .collect::<Vec<_>>();
    let filtered_count = logs.len();
    if let Some(limit) = filters.limit {
        logs.truncate(limit);
    }
    let payload = serde_json::json!({
        "schema_version": 1,
        "log_count": logs.len(),
        "total_log_count": all_logs.len(),
        "filtered_log_count": filtered_count,
        "filters": {
            "query": filters.query,
            "task_id": filters.task_id,
            "limit": filters.limit
        },
        "logs": &logs
    });
    cli_print_json_or_human(options, &payload, || {
        if logs.is_empty() {
            return format!("No download logs matched. Total stored: {}", all_logs.len());
        }
        let rows = logs
            .iter()
            .map(|file| format!("{}\t{} bytes", file.path, file.size_bytes))
            .collect::<Vec<_>>();
        format!(
            "Download logs\nShowing: {} of {} matched ({} total)\n{}",
            logs.len(),
            filtered_count,
            all_logs.len(),
            rows.join("\n")
        )
    })
}

