fn cli_read_download_log_file(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let (path, filters) = cli_parse_read_download_log_args(args)?;
    let root = cli_data_root(options)?;
    let mut response = read_scoped_download_log_file(&root.join("logs"), &path)?;
    if filters.issues_only || filters.level.is_some() || filters.source.is_some() {
        let entries = filter_download_log_entries(response.entries, &filters);
        response.content = entries
            .iter()
            .map(|entry| entry.raw.as_str())
            .collect::<Vec<_>>()
            .join("\n");
        response.issue_count = Some(entries.iter().filter(|entry| entry.is_issue).count());
        response.entries = entries;
    }
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Download log\nPath: {}\nTruncated: {}\nStructured rows: {}\nIssues in preview: {}\nFilters: issues={} level={} source={}\n\n{}",
            response.file.path,
            response.truncated,
            response.entries.len(),
            response.issue_count.unwrap_or(0),
            filters.issues_only,
            filters.level.as_deref().unwrap_or("all"),
            filters.source.as_deref().unwrap_or("all"),
            response.content
        )
    })
}

