fn cli_update_settings_json(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let patch = cli_parse_settings_patch_args(args)?;
    let root = cli_data_root(options)?;
    let mut settings = read_settings(&root)?;
    if let Some(appearance) = patch.appearance {
        apply_appearance_settings_patch(&mut settings.appearance, appearance);
    }
    if let Some(downloads) = patch.downloads {
        apply_downloads_settings_patch(&mut settings.downloads, downloads);
    }
    if let Some(ai) = patch.ai {
        apply_ai_settings_patch(&mut settings.ai, ai);
    }
    if let Some(app_shell) = patch.app_shell {
        apply_app_shell_settings_patch(&mut settings.app_shell, app_shell)?;
    }
    if let Some(advanced) = patch.advanced {
        apply_advanced_settings_patch(&mut settings.advanced, advanced);
    }
    let settings = write_settings(&root, &settings)?;
    let payload = serde_json::to_value(&settings).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Settings updated\nTheme: {}\nDownloads concurrency: {}\nAI provider: {}\nDiagnostics include URLs by default: {}",
            settings.appearance.theme,
            settings.downloads.max_concurrency,
            settings.ai.provider,
            settings.advanced.diagnostics_include_urls
        )
    })
}

fn cli_validate_network(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let request = cli_parse_network_validation_args(args)?;
    let root = cli_data_root(options)?;
    let settings = read_downloads_settings(&root)?;
    let proxy = if request.proxy.is_some() {
        request
            .proxy
            .as_deref()
            .and_then(|value| sanitize_optional_text(Some(value)))
    } else {
        settings.default_proxy
    };
    let parsed = parse_direct_file_proxy(proxy.as_deref())?;
    let response = match parsed {
        Some(proxy) => NetworkValidationResponse {
            schema_version: 1,
            ok: true,
            proxy_configured: true,
            proxy_kind: Some(format!("{:?}", proxy.kind).to_ascii_lowercase()),
            proxy_host: Some(proxy.host),
            proxy_port: Some(proxy.port),
            message: "Proxy format is valid. Connectivity is not tested in this local check."
                .to_string(),
        },
        None => NetworkValidationResponse {
            schema_version: 1,
            ok: true,
            proxy_configured: false,
            proxy_kind: None,
            proxy_host: None,
            proxy_port: None,
            message: "No proxy is configured for new tasks.".to_string(),
        },
    };
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || response.message.clone())
}

