fn cli_export_download_tasks(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let mut output_path = None;
    let mut include_archived = true;
    let mut iter = args.into_iter().peekable();
    while let Some(arg) = iter.next() {
        match arg.as_str() {
            "--without-archived" | "--exclude-archived" => include_archived = false,
            "--include-archived" => include_archived = true,
            "--output" | "-o" => {
                output_path = Some(
                    iter.next()
                        .ok_or_else(|| format!("{arg} requires a path."))?,
                );
            }
            value if value.starts_with('-') => {
                return Err(format!("Unsupported export-download-tasks option: {value}"));
            }
            value => {
                if output_path.is_some() {
                    return Err(
                        "export-download-tasks accepts at most one output path.".to_string()
                    );
                }
                output_path = Some(value.to_string());
            }
        }
    }
    let root = cli_data_root(options)?;
    let response = export_download_tasks_at_root(
        &root,
        Some(DownloadsTasksExportRequest {
            output_path,
            include_archived,
        }),
    )?;
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Downloads task backup exported\nPath: {}\nTasks: {}\nPrivacy: source URLs included; output/log bodies and Cookie/Auth values excluded.",
            response.output_path, response.exported_task_count
        )
    })
}

fn cli_import_download_tasks(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if args.len() != 1 {
        return Err("import-download-tasks requires <download-tasks.json>.".to_string());
    }
    let root = cli_data_root(options)?;
    let input_path = args.into_iter().next().unwrap_or_default();
    let response =
        import_download_tasks_at_root(&root, DownloadsTasksImportRequest { input_path })?;
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Downloads task backup imported\nInput: {}\nImported: {}\nSkipped: {}\nActive downgraded: {}\nTotal tasks: {}",
            response.input_path,
            response.imported_task_count,
            response.skipped_task_count,
            response.downgraded_active_task_count,
            response.total_task_count
        )
    })
}

fn cli_format_downloads_settings_summary(title: &str, settings: &DownloadsSettings) -> String {
    let retention = settings
        .archived_task_retention_days
        .map(|days| format!("{days} day{}", if days == 1 { "" } else { "s" }))
        .unwrap_or_else(|| "clear all archived".to_string());
    format!(
        "{title}\nMax concurrency: {}\nOutput dir: {}\nQuality: {}\nCompleted cleanup: {}\nArchived retention: {}",
        settings.max_concurrency,
        settings.default_output_dir.as_deref().unwrap_or("none"),
        settings.default_quality,
        settings.completed_task_cleanup,
        retention
    )
}

