fn cli_update_channel_settings(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let request = cli_parse_channel_settings_args(args)?;
    let root = cli_data_root(options)?;
    let mut settings = read_channel_settings(&root)?;
    if let Some(enabled) = request.auto_poll_enabled {
        settings.auto_poll_enabled = enabled;
    }
    if let Some(minutes) = request.poll_interval_minutes {
        settings.poll_interval_minutes = minutes.clamp(5, 1440);
    }
    settings.last_error = None;
    let settings = write_channel_settings(&root, &settings)?;
    let response = ChannelSettingsResponse { settings };
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Channel settings updated\nAuto poll: {}\nInterval: {} min",
            response.settings.auto_poll_enabled, response.settings.poll_interval_minutes
        )
    })
}

