fn cli_list_bilibili_imports(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let collection = cli_parse_optional_collection_filter(args, "bilibili-imports")?;
    let root = cli_data_root(options)?;
    let mut items = read_bilibili_import_items(&root)?;
    if let Some(collection) = collection.as_deref() {
        items.retain(|item| item.collection == collection);
    }
    let payload = serde_json::json!({
        "schema_version": 1,
        "item_count": items.len(),
        "collection": collection,
        "items": &items
    });
    cli_print_json_or_human(options, &payload, || {
        if items.is_empty() {
            return "No Bilibili imports matched.".to_string();
        }
        let rows = items
            .iter()
            .map(|item| {
                format!(
                    "{}\t{}\t{}\t{}",
                    item.id, item.collection, item.title, item.source_url
                )
            })
            .collect::<Vec<_>>();
        format!("Bilibili imports\n{}", rows.join("\n"))
    })
}

