fn cli_delete_channel(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let id = cli_required_id(&args, "delete-channel")?.to_string();
    let root = cli_data_root(options)?;
    let mut channels = read_channels(&root)?;
    let before = channels.len();
    channels.retain(|channel| channel.id != id);
    if before == channels.len() {
        return Err(format!("Channel was not found: {id}"));
    }
    write_channels(&root, &channels)?;
    let payload = serde_json::json!({ "schema_version": 1, "deleted": true, "id": id });
    cli_print_json_or_human(options, &payload, || "Channel deleted".to_string())
}

