fn cli_list_p2p_offers(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("p2p-offers does not accept extra arguments.".to_string());
    }
    let root = cli_data_root(options)?;
    let offers = read_p2p_offers(&root)?;
    let payload = serde_json::json!({
        "schema_version": 1,
        "offer_count": offers.len(),
        "offers": &offers
    });
    cli_print_json_or_human(options, &payload, || {
        if offers.is_empty() {
            return "No P2P offers stored.".to_string();
        }
        let rows = offers
            .iter()
            .map(|offer| {
                let sha256 = offer
                    .sha256
                    .as_deref()
                    .map(|value| {
                        let preview = value.chars().take(12).collect::<String>();
                        format!("\tsha256:{preview}")
                    })
                    .unwrap_or_default();
                format!(
                    "{}\t{:?}\t{}{}",
                    offer.short_code, offer.status, offer.file_name, sha256
                )
            })
            .collect::<Vec<_>>();
        format!("P2P offers\n{}", rows.join("\n"))
    })
}

