fn cli_start_p2p_send(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let short_code = cli_required_path_arg(&args, "start-p2p-send", "short code")?.to_string();
    let root = cli_data_root(options)?;
    let offer = start_p2p_send_at_root(&root, &short_code)?;
    let listener = take_p2p_listener(&offer.short_code)?;
    let payload = serde_json::json!({ "serving": true, "blocking": true, "offer": &offer });
    cli_print_json_or_human(options, &payload, || {
        format!(
            "P2P send serving\nCode: {}\nShare: {}\nFile: {}\nSHA-256: {}\nWaiting until one transfer completes, the offer expires, or the offer is paused/canceled.",
            offer.short_code,
            offer.share_code.as_deref().unwrap_or(&offer.short_code),
            offer.file_name,
            offer.sha256.as_deref().unwrap_or("unavailable")
        )
    })?;
    serve_p2p_offer_loop(&root, &offer, listener, |_| {});
    Ok(())
}

