fn cli_open_library_external(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let path = cli_required_path_arg(&args, "open-library-external", "item path")?;
    let (validated, _) = validate_library_item_path(path)?;
    tauri_plugin_opener::open_path(validated, None::<&str>).map_err(|error| error.to_string())?;
    let payload = serde_json::json!({ "schema_version": 1, "ok": true, "path": path });
    cli_print_json_or_human(options, &payload, || {
        "Library item opened externally".to_string()
    })
}

