fn cli_music_services(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("music-services does not accept extra arguments.".to_string());
    }
    let response = MusicServiceMatrixResponse {
        schema_version: 1,
        services: build_music_service_matrix(),
    };
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        let rows = response
            .services
            .iter()
            .map(|service| {
                format!(
                    "{}\t{}\t{}\t{}",
                    service.id, service.name, service.status, service.note
                )
            })
            .collect::<Vec<_>>();
        format!("Music service matrix\n{}", rows.join("\n"))
    })
}

