fn cli_learning_notes(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let query = cli_parse_optional_query(args, "learning-notes")?;
    let root = cli_data_root(options)?;
    let mut notes = read_learning_notes(&root)?;
    if let Some(query) = query {
        let needle = query.to_ascii_lowercase();
        notes.retain(|note| {
            note.title.to_ascii_lowercase().contains(&needle)
                || note.body.to_ascii_lowercase().contains(&needle)
                || note
                    .tags
                    .iter()
                    .any(|tag| tag.to_ascii_lowercase().contains(&needle))
                || note
                    .source_url
                    .as_deref()
                    .unwrap_or_default()
                    .to_ascii_lowercase()
                    .contains(&needle)
                || note
                    .outgoing_links
                    .iter()
                    .any(|link| link.to_ascii_lowercase().contains(&needle))
        });
    }
    let payload = serde_json::json!({
        "schema_version": 1,
        "note_count": notes.len(),
        "notes": &notes
    });
    cli_print_json_or_human(options, &payload, || {
        if notes.is_empty() {
            return "No learning notes stored.".to_string();
        }
        let rows = notes
            .iter()
            .map(|note| {
                format!(
                    "{}\t{}\t{} tags\t{} backlinks",
                    note.id,
                    note.title,
                    note.tags.len(),
                    note.backlink_count
                )
            })
            .collect::<Vec<_>>();
        format!("Learning notes\n{}", rows.join("\n"))
    })
}

