fn cli_spaced_review_cards(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let request = cli_parse_spaced_review_cards_args(args)?;
    let root = cli_data_root(options)?;
    let mut cards = read_spaced_review_cards(&root)?;
    if request.due_only.unwrap_or(false) {
        let now = Utc::now().to_rfc3339();
        cards.retain(|card| card.due_at <= now);
    }
    if let Some(query) = sanitize_optional_text(request.query.as_deref()) {
        let needle = query.to_ascii_lowercase();
        cards.retain(|card| {
            card.prompt.to_ascii_lowercase().contains(&needle)
                || card.answer.to_ascii_lowercase().contains(&needle)
                || card.note_id.to_ascii_lowercase().contains(&needle)
                || card
                    .tags
                    .iter()
                    .any(|tag| tag.to_ascii_lowercase().contains(&needle))
                || card
                    .source_url
                    .as_deref()
                    .unwrap_or_default()
                    .to_ascii_lowercase()
                    .contains(&needle)
        });
    }
    let due_count = {
        let now = Utc::now().to_rfc3339();
        cards.iter().filter(|card| card.due_at <= now).count()
    };
    let payload = serde_json::json!({
        "schema_version": 1,
        "card_count": cards.len(),
        "due_card_count": due_count,
        "cards": &cards
    });
    cli_print_json_or_human(options, &payload, || {
        if cards.is_empty() {
            return "No spaced review cards stored.".to_string();
        }
        let rows = cards
            .iter()
            .map(|card| {
                format!(
                    "{}\t{}\t{} tags\tdue {}\treviews {}",
                    card.id,
                    card.prompt,
                    card.tags.len(),
                    card.due_at,
                    card.review_count
                )
            })
            .collect::<Vec<_>>();
        format!(
            "Spaced review cards\nDue now: {due_count}\n{}",
            rows.join("\n")
        )
    })
}

