fn cli_pomodoro_sessions(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("pomodoro-sessions does not accept extra arguments.".to_string());
    }
    let root = cli_data_root(options)?;
    let sessions = read_pomodoro_sessions(&root)?;
    let payload = serde_json::json!({
        "schema_version": 1,
        "session_count": sessions.len(),
        "sessions": &sessions
    });
    cli_print_json_or_human(options, &payload, || {
        if sessions.is_empty() {
            return "No Pomodoro sessions stored.".to_string();
        }
        let rows = sessions
            .iter()
            .map(|session| {
                format!(
                    "{}\t{}\t{} min\tcompleted={}",
                    session.id, session.label, session.duration_minutes, session.completed
                )
            })
            .collect::<Vec<_>>();
        format!("Pomodoro sessions\n{}", rows.join("\n"))
    })
}

fn cli_save_pomodoro_session(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let request = cli_parse_save_pomodoro_args(args)?;
    let root = cli_data_root(options)?;
    let duration_minutes = request.duration_minutes.clamp(1, 180);
    let break_minutes = request.break_minutes.unwrap_or(5).clamp(0, 60);
    let label = sanitize_optional_text(request.label.as_deref())
        .unwrap_or_else(|| "Focus session".to_string());
    let linked_source_url = match sanitize_optional_text(request.linked_source_url.as_deref()) {
        Some(value) => Some(normalize_http_url(&value)?),
        None => None,
    };
    let now = Utc::now();
    let session = PomodoroSession {
        schema_version: 1,
        id: format!("pomodoro-{}", Utc::now().timestamp_millis()),
        label,
        duration_minutes,
        break_minutes,
        completed: request.completed,
        linked_source_url,
        started_at: now.to_rfc3339(),
        ended_at: (now + chrono::Duration::minutes(duration_minutes as i64)).to_rfc3339(),
    };
    let mut sessions = read_pomodoro_sessions(&root)?;
    sessions.push(session.clone());
    write_pomodoro_sessions(&root, &sessions)?;
    let payload = serde_json::to_value(&session).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Pomodoro session saved\n{}\t{}\t{} min",
            session.id, session.label, session.duration_minutes
        )
    })
}

