fn cli_extension_package_summary(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("extension-package-summary does not accept extra arguments.".to_string());
    }
    let summary = build_extension_local_package_summary()?;
    let payload = serde_json::to_value(&summary).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        let targets = if summary.package_targets.is_empty() {
            "none".to_string()
        } else {
            summary
                .package_targets
                .iter()
                .map(|target| {
                    format!(
                        "{}:{} files:{}",
                        target.target,
                        target.zip_path.as_deref().unwrap_or("zip missing"),
                        target.file_count
                    )
                })
                .collect::<Vec<_>>()
                .join(", ")
        };
        format!(
            "Browser extension package summary\nSource: {}\nManifest: {} {}\nSource files: {} ({} bytes)\nPackage manifest: {}\nTargets: {}\nPrivacy: metadata only; no browser storage, Cookie/Auth payload contents, pairing tokens, or downloaded content included.",
            summary.extension_dir,
            summary.extension_name.as_deref().unwrap_or("unknown"),
            summary.extension_version.as_deref().unwrap_or(""),
            summary.source_file_count,
            summary.source_total_size_bytes,
            if summary.package_manifest_present {
                summary.package_manifest_path.as_str()
            } else {
                "not generated"
            },
            targets
        )
    })
}

