fn cli_create_extension_pairing_token(
    args: Vec<String>,
    options: &CliOptions,
) -> Result<(), String> {
    let label = cli_parse_optional_label(args, "create-extension-token")?;
    let root = cli_data_root(options)?;
    let now = Utc::now();
    let expires_at = (now + chrono::Duration::days(30)).to_rfc3339();
    let token = generate_pairing_token();
    let state = ExtensionPairingState {
        schema_version: 1,
        paired: true,
        token: Some(token.clone()),
        label,
        created_at: Some(now.to_rfc3339()),
        expires_at: Some(expires_at.clone()),
        revoked_at: None,
    };
    write_extension_pairing_state(&root, &state)?;
    let response = ExtensionPairingTokenResponse {
        pairing_code: token,
        expires_at,
    };
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Extension pairing token created\nExpires: {}\nToken: {}",
            response.expires_at, response.pairing_code
        )
    })
}

fn cli_revoke_extension_pairing_token(
    args: Vec<String>,
    options: &CliOptions,
) -> Result<(), String> {
    if !args.is_empty() {
        return Err("revoke-extension-token does not accept extra arguments.".to_string());
    }
    let root = cli_data_root(options)?;
    let mut state = read_extension_pairing_state(&root)?;
    state.paired = false;
    state.token = None;
    state.revoked_at = Some(Utc::now().to_rfc3339());
    write_extension_pairing_state(&root, &state)?;
    let payload = serde_json::json!({ "schema_version": 1, "revoked": true });
    cli_print_json_or_human(options, &payload, || {
        "Extension pairing token revoked".to_string()
    })
}

