fn cli_plugins(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("plugins does not accept extra arguments.".to_string());
    }
    let root = cli_data_root(options)?;
    let plugins = list_plugins_at_root(&root)?;
    let payload = serde_json::json!({
        "schema_version": 1,
        "plugin_count": plugins.len(),
        "plugins": &plugins
    });
    cli_print_json_or_human(options, &payload, || {
        if plugins.is_empty() {
            return "No plugins installed.".to_string();
        }
        let rows = plugins
            .iter()
            .map(|plugin| {
                format!(
                    "{}\t{:?}\t{}\t{}\tcapabilities:{}\tpermissions:{}",
                    plugin.id,
                    plugin.state,
                    plugin.version,
                    plugin.preflight_status,
                    plugin.capabilities.len(),
                    plugin.permissions.len()
                )
            })
            .collect::<Vec<_>>();
        format!("Plugins\n{}", rows.join("\n"))
    })
}

