fn cli_set_plugins_state(
    args: Vec<String>,
    options: &CliOptions,
    state: PluginState,
) -> Result<(), String> {
    let command = match state {
        PluginState::Enabled => "enable-plugins",
        PluginState::Disabled => "disable-plugins",
        _ => "set-plugins-state",
    };
    let ids = cli_parse_ids_only(args, command)?;
    let root = cli_data_root(options)?;
    let response = set_plugin_states_at_root(
        &root,
        PluginBulkStateRequest {
            ids,
            state: match state {
                PluginState::Enabled => "enabled",
                PluginState::Disabled => "disabled",
                _ => "installed",
            }
            .to_string(),
        },
    )?;
    let label = match state {
        PluginState::Enabled => "Plugins enabled",
        PluginState::Disabled => "Plugins disabled",
        _ => "Plugins updated",
    };
    cli_print_plugin_bulk_state_response(options, &response, label)
}

