fn cli_rename_cookie(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let (bucket_id, name) = cli_parse_cookie_rename_args(args)?;
    let root = cli_data_root(options)?;
    let name = sanitize_cookie_bucket_name(&name)?;
    let mut buckets = read_cookie_buckets(&root)?;
    let now = Utc::now().to_rfc3339();
    let mut renamed = None;
    for bucket in &mut buckets {
        if bucket.id == bucket_id {
            bucket.name = name.clone();
            bucket.updated_at = now.clone();
            renamed = Some(bucket.clone());
            break;
        }
    }
    let bucket = renamed.ok_or_else(|| format!("Cookie bucket was not found: {bucket_id}"))?;
    write_cookie_buckets(&root, &buckets)?;
    let payload = serde_json::to_value(&bucket).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!("Cookie bucket renamed\n{}\t{}", bucket.id, bucket.name)
    })
}

fn cli_export_cookie(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let (bucket_id, output_path) = cli_parse_cookie_export_args(args)?;
    let root = cli_data_root(options)?;
    let bucket = find_cookie_bucket(&root, &bucket_id)?;
    let output_path = PathBuf::from(output_path.trim());
    if output_path.as_os_str().is_empty() {
        return Err("Cookie export path is required.".to_string());
    }
    if let Some(parent) = output_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::copy(cookie_bucket_storage_path(&root, &bucket), &output_path)
        .map_err(|error| error.to_string())?;
    let path = display_path(output_path);
    let payload = serde_json::json!({ "schema_version": 1, "path": path });
    cli_print_json_or_human(options, &payload, || {
        format!("Cookie bucket exported\n{path}")
    })
}

