fn cli_delete_cookie(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let bucket_id = cli_required_id(&args, "delete-cookie")?.to_string();
    let root = cli_data_root(options)?;
    let mut buckets = read_cookie_buckets(&root)?;
    let mut removed = None;
    buckets.retain(|bucket| {
        if bucket.id == bucket_id {
            removed = Some(bucket.clone());
            false
        } else {
            true
        }
    });
    let bucket = removed.ok_or_else(|| format!("Cookie bucket was not found: {bucket_id}"))?;
    write_cookie_buckets(&root, &buckets)?;
    let _ = fs::remove_file(cookie_bucket_storage_path(&root, &bucket));
    let payload =
        serde_json::json!({ "schema_version": 1, "deleted": true, "bucket_id": bucket_id });
    cli_print_json_or_human(options, &payload, || "Cookie bucket deleted".to_string())
}

