fn cli_tool_sources(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if !args.is_empty() {
        return Err("tool-sources does not accept extra arguments.".to_string());
    }
    let root = cli_data_root(options)?;
    let sources = list_tool_download_sources(&root)?;
    let payload = serde_json::json!({
        "schema_version": 1,
        "sources": sources
    });
    cli_print_json_or_human(options, &payload, || {
        if sources.is_empty() {
            return "No configured dependency download sources.".to_string();
        }
        let rows = sources
            .iter()
            .map(|source| {
                format!(
                    "{}\t{}\t{}{}",
                    source.tool_id,
                    source.url,
                    source.sha256,
                    source
                        .archive_member
                        .as_deref()
                        .map(|member| format!("\t{member}"))
                        .unwrap_or_default()
                )
            })
            .collect::<Vec<_>>();
        format!("Dependency download sources\n{}", rows.join("\n"))
    })
}

