fn cli_settings_search(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let query = cli_parse_required_query(args, "settings-search")?;
    let results = search_settings_catalog(&query);
    let payload = serde_json::json!({
        "schema_version": 1,
        "query": query,
        "result_count": results.len(),
        "results": &results
    });
    cli_print_json_or_human(options, &payload, || {
        if results.is_empty() {
            return "No settings matched.".to_string();
        }
        let rows = results
            .iter()
            .map(|item| format!("{}\t{}\t{}", item.section_id, item.title, item.description))
            .collect::<Vec<_>>();
        format!("Settings search\n{}", rows.join("\n"))
    })
}
