fn cli_metadata_save_subtitle(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let (url, output_dir, extras) = cli_parse_url_output_and_options(args, "save-subtitle")?;
    let output_dir = output_dir.or_else(|| options.task_output_dir.clone());
    let language = extras
        .get("language")
        .cloned()
        .or_else(|| extras.get("lang").cloned())
        .unwrap_or_else(|| "en".to_string());
    let format = extras
        .get("format")
        .cloned()
        .unwrap_or_else(|| "vtt".to_string());
    let is_auto = extras
        .get("auto")
        .map(|value| value == "true" || value == "1")
        .unwrap_or(false);
    let root = cli_data_root(options)?;
    let response = metadata_save_subtitle_at_root(
        &root,
        MetadataSaveSubtitleRequest {
            url,
            language,
            format,
            is_auto,
            output_dir,
            output_path: extras.get("output").cloned(),
            user_agent: options.task_user_agent.clone(),
            referer: options.task_referer.clone(),
            proxy: options.task_proxy.clone(),
            cookie_bucket_id: options.task_cookie_bucket_id.clone(),
            auth_payload_ref: options.task_auth_payload_ref.clone(),
            rate_limit: options.task_rate_limit.clone(),
        },
    )?;
    cli_print_saved_path(options, &response.output_path, "Subtitle saved")
}

