fn cli_parse_merge_subtitles_args(args: Vec<String>) -> Result<(Vec<String>, String), String> {
    let mut output_path = None;
    let mut positional = Vec::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output" | "--output-path" => {
                output_path = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?));
                index += 2;
            }
            value if value.starts_with("--output=") || value.starts_with("--output-path=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output requires a value.".to_string())?;
                output_path = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown merge-subtitles option: {value}"))
            }
            value => {
                positional.push(value.to_string());
                index += 1;
            }
        }
    }

    let output_path = match output_path {
        Some(path) => path,
        None => {
            if positional.len() < 3 {
                return Err(
                    "merge-subtitles requires <output-path> <input1> <input2>...".to_string(),
                );
            }
            positional.remove(0)
        }
    };
    if positional.len() < 2 {
        return Err("merge-subtitles requires at least two input subtitle files.".to_string());
    }
    Ok((positional, output_path))
}

