fn cli_parse_detect_shots_args(args: Vec<String>) -> Result<(String, Option<f64>), String> {
    let mut input_path = None;
    let mut threshold = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--threshold" => {
                threshold = Some(cli_parse_float_option(
                    cli_positional_value(&args, index, "--threshold")?,
                    "--threshold",
                )?);
                index += 2;
            }
            value if value.starts_with("--threshold=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--threshold requires a value.".to_string())?;
                threshold = Some(cli_parse_float_option(value, "--threshold")?);
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown detect-shots option: {value}"))
            }
            value => {
                if input_path.is_some() {
                    return Err("detect-shots accepts exactly one input media path.".to_string());
                }
                input_path = Some(value.to_string());
                index += 1;
            }
        }
    }
    Ok((
        input_path.ok_or_else(|| "detect-shots requires an input media path.".to_string())?,
        threshold,
    ))
}

fn cli_parse_save_shot_markers_args(args: Vec<String>) -> Result<(String, String), String> {
    let mut output_path = None;
    let mut positional = Vec::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output" | "--output-path" => {
                output_path = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?));
                index += 2;
            }
            value if value.starts_with("--output=") || value.starts_with("--output-path=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output requires a value.".to_string())?;
                output_path = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown save-shot-markers option: {value}"))
            }
            value => {
                positional.push(value.to_string());
                index += 1;
            }
        }
    }
    let output_path = match output_path {
        Some(path) => path,
        None => {
            if positional.len() != 2 {
                return Err("save-shot-markers requires <markers.json> <output.json>.".to_string());
            }
            positional.pop().unwrap_or_default()
        }
    };
    if positional.len() != 1 {
        return Err("save-shot-markers requires exactly one markers JSON path.".to_string());
    }
    Ok((positional.remove(0), output_path))
}

