fn cli_parse_required_query(args: Vec<String>, command: &str) -> Result<String, String> {
    if args.len() == 1 && !args[0].starts_with("--") {
        return sanitize_optional_text(args.first().map(String::as_str))
            .ok_or_else(|| format!("{command} requires a query."));
    }
    cli_parse_optional_query(args, command)?
        .ok_or_else(|| format!("{command} requires --query <text>."))
}

