fn cli_parse_cookie_many_test_args(
    args: Vec<String>,
) -> Result<(Vec<String>, Option<String>), String> {
    let mut bucket_ids = Vec::new();
    let mut url = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--url" => {
                url = sanitize_optional_text(Some(cli_positional_value(&args, index, "--url")?));
                index += 2;
            }
            value if value.starts_with("--url=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--url requires a value.".to_string())?;
                url = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown test-cookies option: {value}"))
            }
            value => {
                for raw_id in cli_split_list(value) {
                    let Some(bucket_id) = sanitize_cookie_bucket_id(Some(&raw_id)) else {
                        return Err("test-cookies bucket ids cannot be empty.".to_string());
                    };
                    bucket_ids.push(bucket_id);
                }
                index += 1;
            }
        }
    }
    if bucket_ids.is_empty() {
        return Err("test-cookies requires at least one bucket id.".to_string());
    }
    Ok((bucket_ids, url))
}

fn cli_parse_cookie_rename_args(args: Vec<String>) -> Result<(String, String), String> {
    if args.len() != 2 {
        return Err("rename-cookie requires <bucket-id> <new-name>.".to_string());
    }
    let bucket_id = sanitize_cookie_bucket_id(args.first().map(String::as_str))
        .ok_or_else(|| "rename-cookie requires a bucket id.".to_string())?;
    let name = sanitize_optional_text(args.get(1).map(String::as_str))
        .ok_or_else(|| "rename-cookie requires a new name.".to_string())?;
    Ok((bucket_id, name))
}

fn cli_parse_cookie_export_args(args: Vec<String>) -> Result<(String, String), String> {
    if args.len() != 2 {
        return Err("export-cookie requires <bucket-id> <output-path>.".to_string());
    }
    let bucket_id = sanitize_cookie_bucket_id(args.first().map(String::as_str))
        .ok_or_else(|| "export-cookie requires a bucket id.".to_string())?;
    let output_path = args
        .get(1)
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| "export-cookie requires an output path.".to_string())?
        .to_string();
    Ok((bucket_id, output_path))
}

fn cli_parse_cookie_buckets_export_args(
    args: Vec<String>,
) -> Result<CookieBucketsExportRequest, String> {
    let mut output_path = None;
    let mut bucket_ids = Vec::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output" | "-o" => {
                output_path =
                    Some(cli_positional_value(&args, index, args[index].as_str())?.to_string());
                index += 2;
            }
            "--bucket" | "--bucket-id" => {
                bucket_ids.extend(
                    cli_split_list(cli_positional_value(&args, index, args[index].as_str())?)
                        .into_iter()
                        .filter_map(|id| sanitize_cookie_bucket_id(Some(&id))),
                );
                index += 2;
            }
            value if value.starts_with("--output=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output requires a value.".to_string())?;
                output_path = Some(value.to_string());
                index += 1;
            }
            value if value.starts_with("--bucket=") || value.starts_with("--bucket-id=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--bucket requires a value.".to_string())?;
                bucket_ids.extend(
                    cli_split_list(value)
                        .into_iter()
                        .filter_map(|id| sanitize_cookie_bucket_id(Some(&id))),
                );
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown export-cookie-buckets option: {value}"))
            }
            value => {
                if output_path.is_none() {
                    output_path = Some(value.to_string());
                    index += 1;
                } else {
                    bucket_ids.extend(
                        cli_split_list(value)
                            .into_iter()
                            .filter_map(|id| sanitize_cookie_bucket_id(Some(&id))),
                    );
                    index += 1;
                }
            }
        }
    }
    Ok(CookieBucketsExportRequest {
        output_path,
        bucket_ids: (!bucket_ids.is_empty()).then_some(bucket_ids),
    })
}

