fn cli_parse_daily_goal_args(args: Vec<String>) -> Result<u32, String> {
    if args.len() == 1 {
        return args[0]
            .trim()
            .parse::<u32>()
            .map(|value| value.clamp(1, 720))
            .map_err(|_| "daily-goal requires minutes as an integer.".to_string());
    }
    if args.len() == 2 && args[0] == "--minutes" {
        return args[1]
            .trim()
            .parse::<u32>()
            .map(|value| value.clamp(1, 720))
            .map_err(|_| "--minutes requires an integer.".to_string());
    }
    if args.len() == 1 && args[0].starts_with("--minutes=") {
        let (_, value) = args[0]
            .split_once('=')
            .ok_or_else(|| "--minutes requires a value.".to_string())?;
        return value
            .trim()
            .parse::<u32>()
            .map(|value| value.clamp(1, 720))
            .map_err(|_| "--minutes requires an integer.".to_string());
    }
    Err("daily-goal accepts [minutes] or --minutes <n>.".to_string())
}

