fn cli_parse_url_output_and_options(
    args: Vec<String>,
    command: &str,
) -> Result<(String, Option<String>, HashMap<String, String>), String> {
    let mut url = None;
    let mut output_dir = None;
    let mut extras = HashMap::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output-dir" => {
                output_dir = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    "--output-dir",
                )?));
                index += 2;
            }
            "--language" | "--lang" | "--format" | "--file-name" => {
                let key = args[index].trim_start_matches("--").to_string();
                let value =
                    sanitize_optional_text(Some(cli_positional_value(&args, index, &args[index])?))
                        .ok_or_else(|| format!("{} requires a value.", args[index]))?;
                extras.insert(key, value);
                index += 2;
            }
            "--auto" => {
                extras.insert("auto".to_string(), "true".to_string());
                index += 1;
            }
            value if value.starts_with("--output-dir=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output-dir requires a value.".to_string())?;
                output_dir = sanitize_optional_text(Some(value));
                index += 1;
            }
            value
                if value.starts_with("--language=")
                    || value.starts_with("--lang=")
                    || value.starts_with("--format=")
                    || value.starts_with("--file-name=") =>
            {
                let (key, value) = value
                    .split_once('=')
                    .ok_or_else(|| format!("{command} option requires a value."))?;
                let key = key.trim_start_matches("--").to_string();
                let value = sanitize_optional_text(Some(value))
                    .ok_or_else(|| format!("{key} requires a value."))?;
                extras.insert(key, value);
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown {command} option: {value}"))
            }
            value => {
                if url.is_some() {
                    return Err(format!("{command} accepts exactly one URL."));
                }
                url = sanitize_optional_text(Some(value));
                index += 1;
            }
        }
    }
    let url = url.ok_or_else(|| format!("{command} requires a URL."))?;
    Ok((url, output_dir, extras))
}

#[derive(Debug, Default)]
struct CliDownloadLogsFilters {
    query: Option<String>,
    task_id: Option<String>,
    limit: Option<usize>,
}

fn cli_parse_download_logs_args(args: Vec<String>) -> Result<CliDownloadLogsFilters, String> {
    let mut filters = CliDownloadLogsFilters::default();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--query" | "--search" => {
                filters.query = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?));
                index += 2;
            }
            "--task" | "--task-id" | "--id" => {
                filters.task_id = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?));
                index += 2;
            }
            "--limit" => {
                filters.limit = Some(cli_parse_usize_option(
                    cli_positional_value(&args, index, "--limit")?,
                    "--limit",
                )?);
                index += 2;
            }
            value if value.starts_with("--query=") || value.starts_with("--search=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--query requires a value.".to_string())?;
                filters.query = sanitize_optional_text(Some(value));
                index += 1;
            }
            value
                if value.starts_with("--task=")
                    || value.starts_with("--task-id=")
                    || value.starts_with("--id=") =>
            {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--task requires a value.".to_string())?;
                filters.task_id = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--limit=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--limit requires a value.".to_string())?;
                filters.limit = Some(cli_parse_usize_option(value, "--limit")?);
                index += 1;
            }
            value => return Err(format!("Unknown download-logs option: {value}")),
        }
    }
    Ok(filters)
}

fn download_log_summary_matches_filter(
    file: &LocalFileSummary,
    filters: &CliDownloadLogsFilters,
) -> bool {
    if let Some(task_id) = filters.task_id.as_deref() {
        let expected = format!("download-{}.log", task_id.trim());
        if !file.file_name.eq_ignore_ascii_case(&expected) {
            return false;
        }
    }
    if let Some(query) = filters.query.as_deref() {
        let normalized = query.trim().to_ascii_lowercase();
        if normalized.is_empty() {
            return true;
        }
        return [
            file.file_name.as_str(),
            file.path.as_str(),
            file.modified_at.as_deref().unwrap_or(""),
        ]
        .iter()
        .any(|value| value.to_ascii_lowercase().contains(&normalized));
    }
    true
}
