fn cli_print_cookie_buckets(
    options: &CliOptions,
    buckets: &[CookieBucket],
    label: &str,
) -> Result<(), String> {
    let payload = serde_json::json!({
        "schema_version": 1,
        "bucket_count": buckets.len(),
        "buckets": buckets
    });
    cli_print_json_or_human(options, &payload, || {
        if buckets.is_empty() {
            return format!("{label}: 0");
        }
        let rows = buckets
            .iter()
            .map(|bucket| {
                format!(
                    "{}\t{}\t{}\t{:?}\t{} cookies",
                    bucket.id,
                    bucket.platform.as_deref().unwrap_or("any"),
                    bucket.name,
                    bucket.health,
                    bucket.cookie_count
                )
            })
            .collect::<Vec<_>>();
        format!("{label}\n{}", rows.join("\n"))
    })
}

