fn cli_parse_two_ids(
    args: Vec<String>,
    command: &str,
    first_label: &str,
    second_label: &str,
) -> Result<(String, String), String> {
    if args.len() != 2 {
        return Err(format!(
            "{command} requires <{first_label}> <{second_label}>."
        ));
    }
    let first = sanitize_optional_text(args.first().map(String::as_str))
        .ok_or_else(|| format!("{command} requires a {first_label}."))?;
    let second = sanitize_optional_text(args.get(1).map(String::as_str))
        .ok_or_else(|| format!("{command} requires a {second_label}."))?;
    Ok((first, second))
}

fn cli_parse_path_index_args(
    args: Vec<String>,
    command: &str,
    path_label: &str,
    index_label: &str,
) -> Result<(String, usize), String> {
    let (path, index) = cli_parse_two_ids(args, command, path_label, index_label)?;
    let index = cli_parse_usize_option(&index, index_label)?;
    if index == 0 {
        return Err(format!("{command} requires a 1-based {index_label}."));
    }
    Ok((path, index))
}

