fn cli_parse_plugin_json_args(
    args: Vec<String>,
    command: &str,
    _value_label: &str,
) -> Result<(String, serde_json::Value), String> {
    let mut id = None;
    let mut value = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--json" | "--patch" | "--payload" => {
                value = Some(cli_parse_json_value(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?)?);
                index += 2;
            }
            "--json-file" | "--patch-file" | "--payload-file" => {
                value = Some(cli_read_json_value_from_file(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?)?);
                index += 2;
            }
            value_arg
                if value_arg.starts_with("--json=")
                    || value_arg.starts_with("--patch=")
                    || value_arg.starts_with("--payload=") =>
            {
                let (_, raw) = value_arg
                    .split_once('=')
                    .ok_or_else(|| "JSON option requires a value.".to_string())?;
                value = Some(cli_parse_json_value(raw)?);
                index += 1;
            }
            value_arg
                if value_arg.starts_with("--json-file=")
                    || value_arg.starts_with("--patch-file=")
                    || value_arg.starts_with("--payload-file=") =>
            {
                let (_, path) = value_arg
                    .split_once('=')
                    .ok_or_else(|| "JSON file option requires a value.".to_string())?;
                value = Some(cli_read_json_value_from_file(path)?);
                index += 1;
            }
            value_arg if value_arg.starts_with("--") => {
                return Err(format!("Unknown {command} option: {value_arg}"));
            }
            value_arg => {
                if id.is_some() {
                    return Err(format!("{command} accepts exactly one plugin id."));
                }
                id = sanitize_optional_text(Some(value_arg));
                index += 1;
            }
        }
    }
    Ok((
        id.ok_or_else(|| format!("{command} requires a plugin id."))?,
        value.unwrap_or_else(|| serde_json::json!({})),
    ))
}

