fn cli_parse_update_settings_args(args: Vec<String>) -> Result<UpdateSettingsRequest, String> {
    let mut patch = UpdateSettingsPatch::default();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--enable" | "--enabled" => {
                patch.enabled = Some(true);
                index += 1;
            }
            "--disable" | "--disabled" => {
                patch.enabled = Some(false);
                index += 1;
            }
            "--manifest" | "--manifest-path" => {
                patch.manifest_path = Some(sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?)));
                index += 2;
            }
            "--clear-manifest" => {
                patch.manifest_path = Some(None);
                index += 1;
            }
            "--interval" | "--hours" => {
                patch.check_interval_hours = Some(cli_parse_u16_option(
                    cli_positional_value(&args, index, args[index].as_str())?,
                    args[index].as_str(),
                )?);
                index += 2;
            }
            value if value.starts_with("--manifest=") || value.starts_with("--manifest-path=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--manifest requires a value.".to_string())?;
                patch.manifest_path = Some(sanitize_optional_text(Some(value)));
                index += 1;
            }
            value if value.starts_with("--interval=") || value.starts_with("--hours=") => {
                let (name, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--interval requires a value.".to_string())?;
                patch.check_interval_hours = Some(cli_parse_u16_option(value, name)?);
                index += 1;
            }
            value => return Err(format!("Unknown save-update-settings option: {value}")),
        }
    }
    Ok(UpdateSettingsRequest { patch })
}

