fn cli_parse_app_shell_settings_args(
    args: Vec<String>,
) -> Result<AppShellSettingsUpdateRequest, String> {
    let mut patch = AppShellSettingsPatch::default();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--json" | "--patch" => {
                let value = cli_parse_json_value(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?)?;
                patch = serde_json::from_value(value)
                    .map_err(|error| format!("app shell settings patch is invalid: {error}"))?;
                index += 2;
            }
            "--json-file" | "--patch-file" => {
                let value = cli_read_json_value_from_file(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?)?;
                patch = serde_json::from_value(value)
                    .map_err(|error| format!("app shell settings patch is invalid: {error}"))?;
                index += 2;
            }
            "--shortcut" | "--quick-capture-shortcut" => {
                patch.quick_capture_shortcut =
                    Some(cli_positional_value(&args, index, args[index].as_str())?.to_string());
                index += 2;
            }
            "--default" | "--default-shortcut" => {
                patch.quick_capture_shortcut = Some(QUICK_CAPTURE_SHORTCUT.to_string());
                patch.quick_capture_enabled = Some(true);
                index += 1;
            }
            "--enable" | "--enabled" => {
                patch.quick_capture_enabled = Some(true);
                index += 1;
            }
            "--disable" | "--disabled" => {
                patch.quick_capture_enabled = Some(false);
                index += 1;
            }
            value
                if value.starts_with("--shortcut=")
                    || value.starts_with("--quick-capture-shortcut=") =>
            {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--shortcut requires a value.".to_string())?;
                patch.quick_capture_shortcut = Some(value.to_string());
                index += 1;
            }
            value if value.starts_with("--json=") || value.starts_with("--patch=") => {
                let (_, raw) = value
                    .split_once('=')
                    .ok_or_else(|| "JSON patch option requires a value.".to_string())?;
                patch = serde_json::from_value(cli_parse_json_value(raw)?)
                    .map_err(|error| format!("app shell settings patch is invalid: {error}"))?;
                index += 1;
            }
            value if value.starts_with("--json-file=") || value.starts_with("--patch-file=") => {
                let (_, path) = value
                    .split_once('=')
                    .ok_or_else(|| "JSON patch file option requires a value.".to_string())?;
                patch = serde_json::from_value(cli_read_json_value_from_file(path)?)
                    .map_err(|error| format!("app shell settings patch is invalid: {error}"))?;
                index += 1;
            }
            value => return Err(format!("Unknown update-app-shell-settings option: {value}")),
        }
    }
    Ok(AppShellSettingsUpdateRequest { patch })
}

