fn cli_parse_extension_connector_profile_args(
    args: Vec<String>,
) -> Result<ExtensionConnectorProfileRequest, String> {
    let mut request = ExtensionConnectorProfileRequest::default();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--create-token" | "--new-token" => {
                request.create_token = true;
                index += 1;
            }
            "--token" => {
                request.token =
                    sanitize_optional_text(Some(cli_positional_value(&args, index, "--token")?));
                index += 2;
            }
            "--label" => {
                request.label =
                    sanitize_optional_text(Some(cli_positional_value(&args, index, "--label")?));
                index += 2;
            }
            value if value.starts_with("--token=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--token requires a value.".to_string())?;
                request.token = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--label=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--label requires a value.".to_string())?;
                request.label = sanitize_optional_text(Some(value));
                index += 1;
            }
            value => {
                return Err(format!(
                    "Unknown extension-connector-profile option: {value}"
                ))
            }
        }
    }
    if request.create_token && request.token.is_some() {
        return Err("Use either --create-token or --token, not both.".to_string());
    }
    Ok(request)
}

fn cli_parse_reading_bookmark_update_args(
    args: Vec<String>,
) -> Result<LibraryUpdateBookmarkRequest, String> {
    let mut positional = Vec::new();
    let mut label = None;
    let mut position_percent = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--label" => {
                label =
                    sanitize_optional_text(Some(cli_positional_value(&args, index, "--label")?));
                index += 2;
            }
            "--position" | "--percent" => {
                position_percent = Some(cli_parse_u8_option(
                    cli_positional_value(&args, index, args[index].as_str())?,
                    args[index].as_str(),
                )?);
                index += 2;
            }
            value if value.starts_with("--label=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--label requires a value.".to_string())?;
                label = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--position=") || value.starts_with("--percent=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--position requires a value.".to_string())?;
                position_percent = Some(cli_parse_u8_option(value, "--position")?);
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown update-reading-bookmark option: {value}"));
            }
            value => {
                positional.push(value.to_string());
                index += 1;
            }
        }
    }
    if positional.len() != 2 {
        return Err("update-reading-bookmark requires <item-path> <bookmark-id>.".to_string());
    }
    Ok(LibraryUpdateBookmarkRequest {
        path: positional.remove(0),
        id: positional.remove(0),
        label,
        position_percent: position_percent.map(|value| value.min(100)),
    })
}

