fn cli_parse_dry_run_flag(args: Vec<String>, command: &str) -> Result<bool, String> {
    let mut dry_run = false;
    for arg in args {
        match arg.as_str() {
            "--dry-run" => dry_run = true,
            "--apply" | "--delete" => dry_run = false,
            value => return Err(format!("Unknown {command} option: {value}")),
        }
    }
    Ok(dry_run)
}

fn cli_parse_include_urls_flag(args: Vec<String>, command: &str) -> Result<bool, String> {
    let mut include_urls = false;
    for arg in args {
        match arg.as_str() {
            "--include-urls" => include_urls = true,
            "--no-include-urls" => include_urls = false,
            value => return Err(format!("Unknown {command} option: {value}")),
        }
    }
    Ok(include_urls)
}

fn cli_parse_diagnostics_export_args(args: Vec<String>) -> Result<(bool, Option<String>), String> {
    let mut include_urls = false;
    let mut output_path = None;
    for arg in args {
        match arg.as_str() {
            "--include-urls" => include_urls = true,
            "--no-include-urls" => include_urls = false,
            value if value.starts_with("--") => {
                return Err(format!("Unknown export-diagnostics option: {value}"));
            }
            value => {
                if output_path.is_some() {
                    return Err("export-diagnostics accepts at most one output path.".to_string());
                }
                output_path = sanitize_optional_text(Some(value));
            }
        }
    }
    Ok((include_urls, output_path))
}

fn cli_parse_settings_patch_args(args: Vec<String>) -> Result<SettingsPatch, String> {
    let mut value = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--json" | "--patch" => {
                value = Some(cli_parse_json_value(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?)?);
                index += 2;
            }
            "--json-file" | "--patch-file" => {
                value = Some(cli_read_json_value_from_file(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?)?);
                index += 2;
            }
            value_arg if value_arg.starts_with("--json=") || value_arg.starts_with("--patch=") => {
                let (_, raw) = value_arg
                    .split_once('=')
                    .ok_or_else(|| "JSON patch option requires a value.".to_string())?;
                value = Some(cli_parse_json_value(raw)?);
                index += 1;
            }
            value_arg
                if value_arg.starts_with("--json-file=")
                    || value_arg.starts_with("--patch-file=") =>
            {
                let (_, path) = value_arg
                    .split_once('=')
                    .ok_or_else(|| "JSON patch file option requires a value.".to_string())?;
                value = Some(cli_read_json_value_from_file(path)?);
                index += 1;
            }
            other => return Err(format!("Unknown update-settings-json option: {other}")),
        }
    }
    let value = value.ok_or_else(|| {
        "update-settings-json requires --json <object> or --json-file <path>.".to_string()
    })?;
    if !value.is_object() {
        return Err("settings patch must be a JSON object.".to_string());
    }
    serde_json::from_value(value).map_err(|error| format!("settings patch is invalid: {error}"))
}

