fn cli_parse_annotation_delete_args(
    args: Vec<String>,
) -> Result<LibraryAnnotationsDeleteRequest, String> {
    let mut path = None;
    let mut bookmark_ids = Vec::new();
    let mut highlight_ids = Vec::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--bookmark" | "--bookmarks" | "--bookmark-id" => {
                bookmark_ids.extend(cli_split_list(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?));
                index += 2;
            }
            "--highlight" | "--highlights" | "--highlight-id" => {
                highlight_ids.extend(cli_split_list(cli_positional_value(
                    &args,
                    index,
                    args[index].as_str(),
                )?));
                index += 2;
            }
            value
                if value.starts_with("--bookmark=")
                    || value.starts_with("--bookmarks=")
                    || value.starts_with("--bookmark-id=") =>
            {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--bookmark requires a value.".to_string())?;
                bookmark_ids.extend(cli_split_list(value));
                index += 1;
            }
            value
                if value.starts_with("--highlight=")
                    || value.starts_with("--highlights=")
                    || value.starts_with("--highlight-id=") =>
            {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--highlight requires a value.".to_string())?;
                highlight_ids.extend(cli_split_list(value));
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!(
                    "Unknown delete-reading-annotations option: {value}"
                ))
            }
            value => {
                if path.is_some() {
                    return Err(
                        "delete-reading-annotations accepts exactly one item path.".to_string()
                    );
                }
                path = sanitize_optional_text(Some(value));
                index += 1;
            }
        }
    }
    if bookmark_ids.is_empty() && highlight_ids.is_empty() {
        return Err(
            "delete-reading-annotations requires --bookmark or --highlight ids.".to_string(),
        );
    }
    Ok(LibraryAnnotationsDeleteRequest {
        path: path
            .ok_or_else(|| "delete-reading-annotations requires an item path.".to_string())?,
        bookmark_ids,
        highlight_ids,
    })
}

