fn cli_parse_music_queue_args(
    args: Vec<String>,
    options: &CliOptions,
) -> Result<MusicQueueSaveRequest, String> {
    let root = cli_data_root(options)?;
    let catalog = read_music_catalog(&root)?;
    let mut track_paths = Vec::new();
    let mut active_path = None;
    let mut volume_percent = None;
    let mut use_all = false;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--all" => {
                use_all = true;
                index += 1;
            }
            "--active" => {
                active_path =
                    sanitize_optional_text(Some(cli_positional_value(&args, index, "--active")?));
                index += 2;
            }
            "--volume" => {
                volume_percent = Some(cli_parse_u8_option(
                    cli_positional_value(&args, index, "--volume")?,
                    "--volume",
                )?);
                index += 2;
            }
            value if value.starts_with("--active=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--active requires a value.".to_string())?;
                active_path = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--volume=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--volume requires a value.".to_string())?;
                volume_percent = Some(cli_parse_u8_option(value, "--volume")?);
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown save-music-queue option: {value}"))
            }
            value => {
                track_paths.extend(cli_split_list(value));
                index += 1;
            }
        }
    }
    let tracks = if use_all {
        catalog.tracks
    } else {
        music_tracks_from_paths(&catalog, &track_paths)?
    };
    Ok(MusicQueueSaveRequest {
        tracks,
        active_path,
        volume_percent,
    })
}

