fn music_tracks_from_paths(
    catalog: &MusicCatalog,
    paths: &[String],
) -> Result<Vec<MusicTrack>, String> {
    if paths.is_empty() {
        return Ok(Vec::new());
    }
    let mut tracks = Vec::new();
    for path in paths {
        let Some(track) = catalog.tracks.iter().find(|track| track.path == *path) else {
            return Err(format!("Music catalog track was not found: {path}"));
        };
        tracks.push(track.clone());
    }
    Ok(tracks)
}

