fn cli_parse_course_item_queue_args(
    args: Vec<String>,
    command: &str,
    item_label: &str,
    default_output_dir: Option<String>,
) -> Result<(String, String, Option<String>), String> {
    let mut positional = Vec::new();
    let mut output_dir = default_output_dir;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output-dir" => {
                output_dir = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    "--output-dir",
                )?));
                index += 2;
            }
            value if value.starts_with("--output-dir=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output-dir requires a path.".to_string())?;
                output_dir = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown {command} option: {value}"))
            }
            value => {
                positional.push(value.to_string());
                index += 1;
            }
        }
    }
    if positional.len() != 2 {
        return Err(format!("{command} requires <course-id> <{item_label}>."));
    }
    Ok((positional.remove(0), positional.remove(0), output_dir))
}

fn cli_parse_course_bulk_queue_args(
    args: Vec<String>,
    command: &str,
    default_output_dir: Option<String>,
) -> Result<(String, Option<String>, Option<usize>), String> {
    let mut course_id = None;
    let mut output_dir = default_output_dir;
    let mut limit = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output-dir" => {
                output_dir = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    "--output-dir",
                )?));
                index += 2;
            }
            "--limit" => {
                limit = Some(cli_parse_usize_option(
                    cli_positional_value(&args, index, "--limit")?,
                    "--limit",
                )?);
                index += 2;
            }
            value if value.starts_with("--output-dir=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output-dir requires a path.".to_string())?;
                output_dir = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--limit=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--limit requires a value.".to_string())?;
                limit = Some(cli_parse_usize_option(value, "--limit")?);
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown {command} option: {value}"))
            }
            value => {
                if course_id.is_some() {
                    return Err(format!("{command} accepts exactly one course id."));
                }
                course_id = Some(value.to_string());
                index += 1;
            }
        }
    }
    Ok((
        course_id.ok_or_else(|| format!("{command} requires a course id."))?,
        output_dir,
        limit,
    ))
}

fn cli_parse_course_many_queue_args(
    args: Vec<String>,
    command: &str,
    default_output_dir: Option<String>,
) -> Result<(Vec<(String, Vec<String>)>, Option<String>), String> {
    let mut output_dir = default_output_dir;
    let mut groups: HashMap<String, Vec<String>> = HashMap::new();
    let mut order = Vec::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output-dir" => {
                output_dir = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    "--output-dir",
                )?));
                index += 2;
            }
            value if value.starts_with("--output-dir=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output-dir requires a path.".to_string())?;
                output_dir = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown {command} option: {value}"))
            }
            value => {
                for pair in cli_split_list(value) {
                    let (course_id, item_id) = pair.split_once(':').ok_or_else(|| {
                        format!("{command} entries must use <course-id>:<item-id>.")
                    })?;
                    let course_id = sanitize_required_text(course_id, "Course id")?;
                    let item_id = sanitize_required_text(item_id, "Course item id")?;
                    if !groups.contains_key(&course_id) {
                        order.push(course_id.clone());
                    }
                    groups.entry(course_id).or_default().push(item_id);
                }
                index += 1;
            }
        }
    }
    if groups.is_empty() {
        return Err(format!(
            "{command} requires at least one <course-id>:<item-id> entry."
        ));
    }
    Ok((
        order
            .into_iter()
            .filter_map(|course_id| groups.remove(&course_id).map(|ids| (course_id, ids)))
            .collect(),
        output_dir,
    ))
}

fn cli_parse_course_item_groups(
    args: Vec<String>,
    command: &str,
) -> Result<Vec<(String, Vec<String>)>, String> {
    let mut groups: HashMap<String, Vec<String>> = HashMap::new();
    let mut order = Vec::new();
    for arg in args {
        if arg.starts_with("--") {
            return Err(format!("Unknown {command} option: {arg}"));
        }
        for pair in cli_split_list(&arg) {
            let (course_id, item_id) = pair
                .split_once(':')
                .ok_or_else(|| format!("{command} entries must use <course-id>:<item-id>."))?;
            let course_id = sanitize_required_text(course_id, "Course id")?;
            let item_id = sanitize_required_text(item_id, "Course item id")?;
            if !groups.contains_key(&course_id) {
                order.push(course_id.clone());
            }
            groups.entry(course_id).or_default().push(item_id);
        }
    }
    if groups.is_empty() {
        return Err(format!(
            "{command} requires at least one <course-id>:<item-id> entry."
        ));
    }
    Ok(order
        .into_iter()
        .filter_map(|course_id| groups.remove(&course_id).map(|ids| (course_id, ids)))
        .collect())
}

