fn cli_parse_plugin_log_many_args(args: Vec<String>) -> Result<(String, Vec<String>), String> {
    let mut kind = None;
    let mut ids = Vec::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--kind" => {
                kind = sanitize_optional_text(Some(cli_positional_value(&args, index, "--kind")?));
                index += 2;
            }
            value if value.starts_with("--kind=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--kind requires commands, events, or activity.".to_string())?;
                kind = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown clear-plugin-logs-many option: {value}"))
            }
            value => {
                if kind.is_none() {
                    kind = sanitize_optional_text(Some(value));
                } else {
                    ids.extend(cli_split_list(value));
                }
                index += 1;
            }
        }
    }
    let kind = kind
        .ok_or_else(|| "clear-plugin-logs-many requires <commands|events|activity>.".to_string())?;
    if ids.is_empty() {
        return Err("clear-plugin-logs-many requires at least one plugin id.".to_string());
    }
    Ok((kind, ids))
}

fn cli_parse_local_file_delete_args(
    args: Vec<String>,
) -> Result<Vec<LocalFileBulkDeleteItem>, String> {
    let mut files = Vec::new();
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--diagnostics" | "--diagnostic" => {
                for path in cli_split_list(cli_positional_value(&args, index, args[index].as_str())?)
                {
                    files.push(LocalFileBulkDeleteItem {
                        kind: "diagnostics".to_string(),
                        path,
                    });
                }
                index += 2;
            }
            "--log" | "--download-log" => {
                for path in cli_split_list(cli_positional_value(&args, index, args[index].as_str())?)
                {
                    files.push(LocalFileBulkDeleteItem {
                        kind: "log".to_string(),
                        path,
                    });
                }
                index += 2;
            }
            value if value.starts_with("--diagnostics=") || value.starts_with("--diagnostic=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--diagnostics requires a path.".to_string())?;
                for path in cli_split_list(value) {
                    files.push(LocalFileBulkDeleteItem {
                        kind: "diagnostics".to_string(),
                        path,
                    });
                }
                index += 1;
            }
            value if value.starts_with("--log=") || value.starts_with("--download-log=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--log requires a path.".to_string())?;
                for path in cli_split_list(value) {
                    files.push(LocalFileBulkDeleteItem {
                        kind: "log".to_string(),
                        path,
                    });
                }
                index += 1;
            }
            value => {
                return Err(format!(
                    "Unknown delete-local-files option: {value}. Use --diagnostics <path> or --log <path>."
                ))
            }
        }
    }
    if files.is_empty() {
        return Err("delete-local-files requires --diagnostics or --log paths.".to_string());
    }
    Ok(files)
}

fn cli_parse_telegram_clone_args(
    args: Vec<String>,
    default_output_dir: Option<String>,
) -> Result<(String, Option<String>, Vec<String>, Option<usize>), String> {
    let mut chat_id = None;
    let mut output_dir = default_output_dir;
    let mut media_types = Vec::new();
    let mut limit = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--output-dir" => {
                output_dir = sanitize_optional_text(Some(cli_positional_value(
                    &args,
                    index,
                    "--output-dir",
                )?));
                index += 2;
            }
            "--media-types" => {
                media_types = cli_split_list(cli_positional_value(&args, index, "--media-types")?);
                index += 2;
            }
            "--limit" => {
                limit = Some(cli_parse_usize_option(
                    cli_positional_value(&args, index, "--limit")?,
                    "--limit",
                )?);
                index += 2;
            }
            value if value.starts_with("--output-dir=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--output-dir requires a path.".to_string())?;
                output_dir = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--media-types=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--media-types requires a value.".to_string())?;
                media_types = cli_split_list(value);
                index += 1;
            }
            value if value.starts_with("--limit=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--limit requires a value.".to_string())?;
                limit = Some(cli_parse_usize_option(value, "--limit")?);
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown clone-telegram-chat option: {value}"))
            }
            value => {
                if chat_id.is_some() {
                    return Err("clone-telegram-chat accepts exactly one chat id.".to_string());
                }
                chat_id = Some(value.to_string());
                index += 1;
            }
        }
    }
    Ok((
        chat_id.ok_or_else(|| "clone-telegram-chat requires a chat id.".to_string())?,
        output_dir,
        media_types,
        limit,
    ))
}

fn cli_parse_optional_collection_filter(
    args: Vec<String>,
    command: &str,
) -> Result<Option<String>, String> {
    let mut collection = None;
    let mut index = 0;
    while index < args.len() {
        match args[index].as_str() {
            "--collection" => {
                collection = Some(sanitize_bilibili_collection(cli_positional_value(
                    &args,
                    index,
                    "--collection",
                )?)?);
                index += 2;
            }
            value if value.starts_with("--collection=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--collection requires watch_later or history.".to_string())?;
                collection = Some(sanitize_bilibili_collection(value)?);
                index += 1;
            }
            value if value.starts_with("--") => {
                return Err(format!("Unknown {command} option: {value}"))
            }
            value => {
                return Err(format!(
                    "{command} does not accept positional argument: {value}"
                ))
            }
        }
    }
    Ok(collection)
}

