#[derive(Clone, Copy, PartialEq, Eq)]
enum CliTaskViewMode {
    Active,
    History,
    All,
}

impl CliTaskViewMode {
    fn label(self) -> &'static str {
        match self {
            CliTaskViewMode::Active => "active",
            CliTaskViewMode::History => "history",
            CliTaskViewMode::All => "all",
        }
    }
}

fn parse_cli_task_view_mode(value: &str) -> Result<CliTaskViewMode, String> {
    match value.trim().to_ascii_lowercase().as_str() {
        "active" | "queue" | "queued" => Ok(CliTaskViewMode::Active),
        "history" | "historical" | "archive" => Ok(CliTaskViewMode::History),
        "all" | "everything" => Ok(CliTaskViewMode::All),
        other => Err(format!(
            "Unsupported tasks view: {other}. Expected active, history, or all."
        )),
    }
}

fn cli_task_matches_view(task: &DownloadTask, view_mode: CliTaskViewMode) -> bool {
    match view_mode {
        CliTaskViewMode::Active => task.status != DownloadStatus::Archived,
        CliTaskViewMode::History => matches!(
            task.status,
            DownloadStatus::Completed
                | DownloadStatus::Failed
                | DownloadStatus::Canceled
                | DownloadStatus::Archived
        ),
        CliTaskViewMode::All => true,
    }
}

#[derive(Clone, Copy)]
enum CliTaskSortKey {
    Queue,
    Created,
    Updated,
    Title,
    Status,
    Platform,
    Kind,
}

impl CliTaskSortKey {
    fn label(self) -> &'static str {
        match self {
            CliTaskSortKey::Queue => "queue",
            CliTaskSortKey::Created => "created",
            CliTaskSortKey::Updated => "updated",
            CliTaskSortKey::Title => "title",
            CliTaskSortKey::Status => "status",
            CliTaskSortKey::Platform => "platform",
            CliTaskSortKey::Kind => "kind",
        }
    }
}

fn parse_cli_task_sort_key(value: &str) -> Result<CliTaskSortKey, String> {
    match value.trim().to_ascii_lowercase().replace('-', "_").as_str() {
        "queue" | "position" | "order" => Ok(CliTaskSortKey::Queue),
        "created" | "created_at" => Ok(CliTaskSortKey::Created),
        "updated" | "updated_at" => Ok(CliTaskSortKey::Updated),
        "title" | "name" => Ok(CliTaskSortKey::Title),
        "status" => Ok(CliTaskSortKey::Status),
        "platform" | "site" => Ok(CliTaskSortKey::Platform),
        "kind" | "type" => Ok(CliTaskSortKey::Kind),
        _ => Err(format!(
            "Unsupported tasks sort: {value}. Use queue, created, updated, title, status, platform, or kind."
        )),
    }
}

fn cli_sort_download_tasks(tasks: &mut [DownloadTask], sort_key: CliTaskSortKey, descending: bool) {
    tasks.sort_by(|left, right| {
        let ordering = match sort_key {
            CliTaskSortKey::Queue => left
                .position
                .cmp(&right.position)
                .then_with(|| left.created_at.cmp(&right.created_at)),
            CliTaskSortKey::Created => left
                .created_at
                .cmp(&right.created_at)
                .then_with(|| left.position.cmp(&right.position)),
            CliTaskSortKey::Updated => left
                .updated_at
                .cmp(&right.updated_at)
                .then_with(|| left.position.cmp(&right.position)),
            CliTaskSortKey::Title => left
                .title
                .to_ascii_lowercase()
                .cmp(&right.title.to_ascii_lowercase())
                .then_with(|| left.position.cmp(&right.position)),
            CliTaskSortKey::Status => download_status_label(&left.status)
                .cmp(download_status_label(&right.status))
                .then_with(|| left.position.cmp(&right.position)),
            CliTaskSortKey::Platform => left
                .platform
                .to_ascii_lowercase()
                .cmp(&right.platform.to_ascii_lowercase())
                .then_with(|| left.position.cmp(&right.position)),
            CliTaskSortKey::Kind => format!("{:?}", left.kind)
                .cmp(&format!("{:?}", right.kind))
                .then_with(|| left.position.cmp(&right.position)),
        };
        if descending {
            ordering.reverse()
        } else {
            ordering
        }
    });
}

#[derive(Default)]
struct CliTaskTimeFilters {
    created_after: Option<chrono::DateTime<Utc>>,
    created_before: Option<chrono::DateTime<Utc>>,
    updated_after: Option<chrono::DateTime<Utc>>,
    updated_before: Option<chrono::DateTime<Utc>>,
}

impl CliTaskTimeFilters {
    fn matches(&self, task: &DownloadTask) -> bool {
        self.matches_timestamp(
            &task.created_at,
            self.created_after.as_ref(),
            self.created_before.as_ref(),
        ) && self.matches_timestamp(
            &task.updated_at,
            self.updated_after.as_ref(),
            self.updated_before.as_ref(),
        )
    }

    fn created_after_label(&self) -> Option<String> {
        self.created_after.as_ref().map(|value| value.to_rfc3339())
    }

    fn created_before_label(&self) -> Option<String> {
        self.created_before.as_ref().map(|value| value.to_rfc3339())
    }

    fn updated_after_label(&self) -> Option<String> {
        self.updated_after.as_ref().map(|value| value.to_rfc3339())
    }

    fn updated_before_label(&self) -> Option<String> {
        self.updated_before.as_ref().map(|value| value.to_rfc3339())
    }

    fn matches_timestamp(
        &self,
        value: &str,
        after: Option<&chrono::DateTime<Utc>>,
        before: Option<&chrono::DateTime<Utc>>,
    ) -> bool {
        if after.is_none() && before.is_none() {
            return true;
        }
        let Some(timestamp) = parse_rfc3339_timestamp(value) else {
            return false;
        };
        if let Some(after) = after {
            if &timestamp < after {
                return false;
            }
        }
        if let Some(before) = before {
            if &timestamp > before {
                return false;
            }
        }
        true
    }
}

enum CliTaskTimeBoundary {
    StartOfDay,
    EndOfDay,
}

fn cli_parse_task_time_option(
    value: &str,
    name: &str,
    boundary: CliTaskTimeBoundary,
) -> Result<chrono::DateTime<Utc>, String> {
    if let Some(timestamp) = parse_rfc3339_timestamp(value) {
        return Ok(timestamp);
    }

    if let Ok(date) = chrono::NaiveDate::parse_from_str(value.trim(), "%Y-%m-%d") {
        let time = match boundary {
            CliTaskTimeBoundary::StartOfDay => chrono::NaiveTime::MIN,
            CliTaskTimeBoundary::EndOfDay => {
                chrono::NaiveTime::from_hms_nano_opt(23, 59, 59, 999_999_999)
                    .ok_or_else(|| "Failed to construct end-of-day timestamp.".to_string())?
            }
        };
        return Ok(chrono::DateTime::<Utc>::from_naive_utc_and_offset(
            date.and_time(time),
            Utc,
        ));
    }

    Err(format!(
        "{name} requires an RFC3339 timestamp or YYYY-MM-DD date, for example 2026-07-16T00:00:00Z or 2026-07-16."
    ))
}

fn cli_download_task_matches_query(task: &DownloadTask, query: &str) -> bool {
    let normalized = query.trim().to_ascii_lowercase();
    if normalized.is_empty() {
        return true;
    }
    serde_json::to_value(task)
        .ok()
        .map(|value| cli_json_value_contains_query(&value, &normalized))
        .unwrap_or(false)
}

fn cli_json_value_contains_query(value: &serde_json::Value, normalized_query: &str) -> bool {
    match value {
        serde_json::Value::Null => false,
        serde_json::Value::Bool(value) => value.to_string().contains(normalized_query),
        serde_json::Value::Number(value) => value.to_string().contains(normalized_query),
        serde_json::Value::String(value) => value.to_ascii_lowercase().contains(normalized_query),
        serde_json::Value::Array(items) => items
            .iter()
            .any(|item| cli_json_value_contains_query(item, normalized_query)),
        serde_json::Value::Object(map) => map.iter().any(|(key, item)| {
            key.to_ascii_lowercase().contains(normalized_query)
                || cli_json_value_contains_query(item, normalized_query)
        }),
    }
}

fn cli_logs(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if args.is_empty() {
        return Err("logs requires <id>.".to_string());
    }
    let id = args[0].as_str();
    let mut cursor = None;
    let mut limit = None;
    let mut search = None;
    let mut issues_only = false;
    let mut level_filter = None;
    let mut source_filter = None;
    let mut index = 1;
    while index < args.len() {
        match args[index].as_str() {
            "--cursor" => {
                let value = cli_positional_value(&args, index, "--cursor")?;
                cursor = Some(cli_parse_usize_option(value, "--cursor")?);
                index += 2;
            }
            "--limit" => {
                let value = cli_positional_value(&args, index, "--limit")?;
                limit = Some(cli_parse_usize_option(value, "--limit")?);
                index += 2;
            }
            "--search" | "--query" => {
                let value = cli_positional_value(&args, index, args[index].as_str())?;
                search = sanitize_optional_text(Some(value));
                index += 2;
            }
            "--issues" | "--errors" => {
                issues_only = true;
                index += 1;
            }
            "--level" => {
                let value = cli_positional_value(&args, index, "--level")?;
                level_filter =
                    sanitize_optional_text(Some(value)).map(|value| value.to_ascii_lowercase());
                index += 2;
            }
            "--source" => {
                let value = cli_positional_value(&args, index, "--source")?;
                source_filter =
                    sanitize_optional_text(Some(value)).map(|value| value.to_ascii_lowercase());
                index += 2;
            }
            value if value.starts_with("--cursor=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--cursor requires a value.".to_string())?;
                cursor = Some(cli_parse_usize_option(value, "--cursor")?);
                index += 1;
            }
            value if value.starts_with("--limit=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--limit requires a value.".to_string())?;
                limit = Some(cli_parse_usize_option(value, "--limit")?);
                index += 1;
            }
            value if value.starts_with("--search=") || value.starts_with("--query=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--search requires a value.".to_string())?;
                search = sanitize_optional_text(Some(value));
                index += 1;
            }
            value if value.starts_with("--level=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--level requires a value.".to_string())?;
                level_filter =
                    sanitize_optional_text(Some(value)).map(|value| value.to_ascii_lowercase());
                index += 1;
            }
            value if value.starts_with("--source=") => {
                let (_, value) = value
                    .split_once('=')
                    .ok_or_else(|| "--source requires a value.".to_string())?;
                source_filter =
                    sanitize_optional_text(Some(value)).map(|value| value.to_ascii_lowercase());
                index += 1;
            }
            other => return Err(format!("Unknown logs option: {other}")),
        }
    }
    let root = cli_data_root(options)?;
    cli_find_download_task(&root, id)?;
    let mut page = read_download_logs_page_at_root(&root, id, cursor, limit, search.as_deref())?;
    if issues_only {
        page.entries.retain(|entry| entry.is_issue);
    }
    if let Some(level) = level_filter.as_deref() {
        page.entries.retain(|entry| {
            entry.level.eq_ignore_ascii_case(level) || (level == "issue" && entry.is_issue)
        });
    }
    if let Some(source) = source_filter.as_deref() {
        page.entries
            .retain(|entry| entry.source.to_ascii_lowercase().contains(source));
    }
    page.lines = page.entries.iter().map(|entry| entry.raw.clone()).collect();
    let payload = serde_json::json!({
        "task_id": id,
        "path": display_path(download_log_path(&root, id)),
        "lines": page.lines,
        "entries": page.entries,
        "cursor": page.cursor,
        "next_cursor": page.next_cursor,
        "total_lines": page.total_lines,
        "matched_lines": page.matched_lines,
        "search": search,
        "issues_only": issues_only,
        "level": level_filter,
        "source": source_filter
    });
    cli_print_json_or_human(options, &payload, || {
        let rendered = payload
            .get("lines")
            .and_then(|value| value.as_array())
            .map(|items| {
                items
                    .iter()
                    .filter_map(|item| item.as_str())
                    .collect::<Vec<_>>()
                    .join("\n")
            })
            .unwrap_or_default();
        if rendered.is_empty() {
            format!("No log lines for task {id}.")
        } else {
            rendered
        }
    })?;
    Ok(())
}

fn cli_download_log_line_is_issue(line: &str) -> bool {
    download_log_line_is_issue(&line.to_ascii_lowercase())
}

fn cli_task_state_action(
    args: Vec<String>,
    options: &CliOptions,
    action: DownloadBulkAction,
    command: &str,
    human_label: &str,
) -> Result<(), String> {
    let id = cli_required_id(&args, command)?;
    if matches!(
        action,
        DownloadBulkAction::Pause | DownloadBulkAction::Cancel
    ) {
        request_download_stop(id);
    }
    let task = cli_update_download_task(options, id, |task, now| {
        apply_download_bulk_action(task, action, now).map(|_| ())
    })?;
    let payload = serde_json::json!({
        "action": command,
        "task": task
    });
    cli_print_json_or_human(options, &payload, || {
        format!("{human_label}\n{}", cli_format_task_summary(&task))
    })?;
    Ok(())
}
fn cli_pause(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    cli_task_state_action(
        args,
        options,
        DownloadBulkAction::Pause,
        "pause",
        "Paused task",
    )
}

fn cli_bulk_downloads(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let (action, ids) = cli_parse_bulk_download_args(args)?;
    if matches!(
        action,
        DownloadBulkAction::Pause | DownloadBulkAction::Cancel
    ) {
        for id in &ids {
            request_download_stop(id);
        }
    }
    let root = cli_data_root(options)?;
    let mut tasks = read_download_tasks(&root)?;
    let now = Utc::now().to_rfc3339();
    let mut updated = Vec::new();
    let mut failed = Vec::new();
    for id in dedupe_non_empty_ids(ids) {
        let Some(index) = tasks.iter().position(|candidate| candidate.id == id) else {
            failed.push(BulkDownloadFailure {
                id,
                error: "Download task was not found.".to_string(),
            });
            continue;
        };

        if matches!(action, DownloadBulkAction::Delete) {
            let task = tasks.remove(index);
            request_download_stop(&task.id);
            updated.push(task);
            continue;
        }

        let task = &mut tasks[index];
        match apply_download_bulk_action(task, action, &now) {
            Ok(_) => updated.push(task.clone()),
            Err(error) => failed.push(BulkDownloadFailure { id, error }),
        }
    }
    if !updated.is_empty() {
        normalize_positions(&mut tasks);
        write_download_tasks(&root, &tasks)?;
    }
    let response = BulkDownloadActionResponse {
        tasks: updated,
        failed,
    };
    let payload = serde_json::to_value(&response).map_err(|error| error.to_string())?;
    cli_print_json_or_human(options, &payload, || {
        format!(
            "Bulk download action applied\nUpdated: {}\nFailed: {}",
            response.tasks.len(),
            response.failed.len()
        )
    })
}

fn cli_reorder_downloads(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let ids = cli_parse_ids_only(args, "reorder-downloads")?;
    let root = cli_data_root(options)?;
    let mut tasks = read_download_tasks(&root)?;
    let now = Utc::now().to_rfc3339();
    for (index, ordered_id) in ids.iter().enumerate() {
        let task = tasks
            .iter_mut()
            .find(|candidate| candidate.id == *ordered_id)
            .ok_or_else(|| format!("Download task was not found: {ordered_id}"))?;
        task.position = (index + 1) as u32;
        task.updated_at = now.clone();
    }
    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    tasks.sort_by_key(|task| task.position);
    let payload = serde_json::json!({ "schema_version": 1, "tasks": &tasks });
    cli_print_json_or_human(options, &payload, || {
        format!("Download tasks reordered\nTask count: {}", tasks.len())
    })
}

