fn cli_delete(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let id = cli_required_id(&args, "delete")?;
    let root = cli_data_root(options)?;
    let mut tasks = read_download_tasks(&root)?;
    let original_len = tasks.len();
    tasks.retain(|task| task.id != id);
    if tasks.len() == original_len {
        return Err(format!("Download task was not found: {id}"));
    }
    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    let payload = serde_json::json!({ "deleted": true, "task_id": id });
    cli_print_json_or_human(options, &payload, || format!("Deleted task {id}"))?;
    Ok(())
}

fn cli_clear_completed(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let explicit_archive = args.iter().any(|arg| arg == "--archive");
    let explicit_remove = args
        .iter()
        .any(|arg| arg == "--delete" || arg == "--remove");
    if explicit_archive && explicit_remove {
        return Err("clear-completed accepts either --archive or --delete, not both.".to_string());
    }
    if let Some(unknown) = args
        .iter()
        .find(|arg| !matches!(arg.as_str(), "--archive" | "--delete" | "--remove"))
    {
        return Err(format!("Unknown clear-completed option: {unknown}"));
    }

    let root = cli_data_root(options)?;
    let mut tasks = read_download_tasks(&root)?;
    let mut affected = 0_usize;
    let remove = if explicit_remove {
        true
    } else if explicit_archive {
        false
    } else {
        read_downloads_settings(&root)?.completed_task_cleanup == "delete"
    };
    if remove {
        let original_len = tasks.len();
        tasks.retain(|task| task.status != DownloadStatus::Completed);
        affected = original_len.saturating_sub(tasks.len());
    } else {
        let now = Utc::now().to_rfc3339();
        for task in tasks
            .iter_mut()
            .filter(|task| task.status == DownloadStatus::Completed)
        {
            if archive_download_task(task, &now).is_ok() {
                affected += 1;
            }
        }
    }
    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    let payload = serde_json::json!({
        "affected": affected,
        "mode": if remove { "delete" } else { "archive" }
    });
    cli_print_json_or_human(options, &payload, || {
        if remove {
            format!("Deleted {affected} completed task record(s).")
        } else {
            format!("Archived {affected} completed task record(s).")
        }
    })?;
    Ok(())
}

fn cli_clear_archived(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    let clear_all = args.iter().any(|arg| arg == "--all");
    if let Some(unknown) = args.iter().find(|arg| !matches!(arg.as_str(), "--all")) {
        return Err(format!("Unknown clear-archived option: {unknown}"));
    }

    let root = cli_data_root(options)?;
    let retention_days = if clear_all {
        None
    } else {
        read_downloads_settings(&root)?.archived_task_retention_days
    };
    let now = Utc::now();
    let mut tasks = read_download_tasks(&root)?;
    let original_len = tasks.len();
    tasks.retain(|task| !archived_task_matches_clear_policy(task, retention_days, now));
    let affected = original_len.saturating_sub(tasks.len());
    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    let payload = serde_json::json!({
        "affected": affected,
        "retention_days": retention_days,
        "mode": if clear_all { "all" } else { "retention" }
    });
    cli_print_json_or_human(options, &payload, || {
        if clear_all {
            format!("Deleted {affected} archived task record(s).\nMode: all")
        } else {
            let retention = retention_days
                .map(|days| format!("{days} day{}", if days == 1 { "" } else { "s" }))
                .unwrap_or_else(|| "none, clear all archived".to_string());
            format!("Deleted {affected} archived task record(s).\nRetention: {retention}")
        }
    })?;
    Ok(())
}

fn cli_update_download_task<F>(
    options: &CliOptions,
    id: &str,
    update: F,
) -> Result<DownloadTask, String>
where
    F: FnOnce(&mut DownloadTask, &str) -> Result<(), String>,
{
    let root = cli_data_root(options)?;
    let mut tasks = read_download_tasks(&root)?;
    let now = Utc::now().to_rfc3339();
    let task = tasks
        .iter_mut()
        .find(|candidate| candidate.id == id)
        .ok_or_else(|| format!("Download task was not found: {id}"))?;
    update(task, &now)?;
    let updated = task.clone();
    normalize_positions(&mut tasks);
    write_download_tasks(&root, &tasks)?;
    Ok(updated)
}

fn cli_find_download_task(root: &Path, id: &str) -> Result<DownloadTask, String> {
    read_download_tasks(root)?
        .into_iter()
        .find(|task| task.id == id)
        .ok_or_else(|| format!("Download task was not found: {id}"))
}

fn cli_required_id<'a>(args: &'a [String], command: &str) -> Result<&'a str, String> {
    let id = args
        .first()
        .map(|value| value.trim())
        .filter(|value| !value.is_empty())
        .ok_or_else(|| format!("{command} requires a task id."))?;
    if args.len() > 1 {
        return Err(format!("{command} accepts exactly one task id."));
    }
    Ok(id)
}

fn cli_positional_value<'a>(
    args: &'a [String],
    index: usize,
    name: &str,
) -> Result<&'a str, String> {
    args.get(index + 1)
        .map(|value| value.as_str())
        .ok_or_else(|| format!("{name} requires a value."))
}

fn cli_parse_usize_option(value: &str, name: &str) -> Result<usize, String> {
    let parsed = value
        .trim()
        .parse::<usize>()
        .map_err(|_| format!("{name} requires a positive integer."))?;
    if parsed == 0 {
        return Err(format!("{name} requires a positive integer."));
    }
    Ok(parsed)
}

fn cli_parse_u16_option(value: &str, name: &str) -> Result<u16, String> {
    value
        .trim()
        .parse::<u16>()
        .map_err(|_| format!("{name} requires a positive integer."))
}

fn cli_parse_u32_option(value: &str, name: &str) -> Result<u32, String> {
    value
        .trim()
        .parse::<u32>()
        .map_err(|_| format!("{name} requires a positive integer."))
}

fn cli_parse_i8_option(value: &str, name: &str) -> Result<i8, String> {
    value
        .trim()
        .parse::<i8>()
        .map_err(|_| format!("{name} requires an integer between -128 and 127."))
}

fn parse_cli_download_status(value: &str) -> Result<DownloadStatus, String> {
    match value.trim().to_ascii_lowercase().as_str() {
        "queued" => Ok(DownloadStatus::Queued),
        "active" => Ok(DownloadStatus::Active),
        "paused" => Ok(DownloadStatus::Paused),
        "completed" | "complete" => Ok(DownloadStatus::Completed),
        "failed" | "fail" => Ok(DownloadStatus::Failed),
        "canceled" | "cancelled" => Ok(DownloadStatus::Canceled),
        "archived" | "archive" => Ok(DownloadStatus::Archived),
        _ => Err(format!(
            "Unsupported status: {value}. Use queued, active, paused, completed, failed, canceled, or archived."
        )),
    }
}

fn cli_format_task_summary(task: &DownloadTask) -> String {
    let mut lines = vec![
        format!("Task id: {}", task.id),
        format!("Status: {}", download_status_label(&task.status)),
        format!("Kind: {:?}", task.kind),
        format!("Title: {}", task.title),
        format!("URL: {}", task.source_url),
    ];
    if let Some(output_dir) = task.output_dir.as_deref() {
        lines.push(format!("Output dir: {output_dir}"));
    }
    if let Some(output_path) = task.output_path.as_deref() {
        lines.push(format!("Output path: {output_path}"));
    }
    let downloaded = task.downloaded_bytes.unwrap_or(0);
    if downloaded > 0 || task.total_bytes.unwrap_or(0) > 0 {
        let progress = match task.total_bytes {
            Some(total) if total > 0 => format!("{downloaded}/{total} bytes"),
            _ => format!("{downloaded} bytes downloaded"),
        };
        lines.push(format!("Progress: {progress}"));
    }
    if let Some(file_count) = task.file_count {
        lines.push(format!("Files: {file_count}"));
    }
    let option_summary = cli_task_option_summary(task);
    if !option_summary.is_empty() {
        lines.push(format!("Options: {option_summary}"));
    }
    let integrity_summary = cli_task_integrity_summary(task);
    if !integrity_summary.is_empty() {
        lines.push(format!("Integrity: {integrity_summary}"));
    }
    if let Some(error) = task.last_error.as_deref() {
        lines.push(format!("Last error: {error}"));
    }
    lines.join("\n")
}

fn cli_task_option_summary(task: &DownloadTask) -> String {
    let mut parts = Vec::new();
    if let Some(quality) = task.quality.as_deref() {
        parts.push(format!("quality {quality}"));
    }
    if let Some(audio_format) = task.audio_format.as_deref() {
        parts.push(format!("audio {audio_format}"));
    }
    if task.start_seconds.is_some() || task.end_seconds.is_some() {
        parts.push(format!(
            "clip {} -> {}",
            task.start_seconds
                .map(|value| value.to_string())
                .unwrap_or_else(|| "start".to_string()),
            task.end_seconds
                .map(|value| value.to_string())
                .unwrap_or_else(|| "end".to_string())
        ));
    }
    if let Some(fragments) = task.concurrent_fragments {
        parts.push(format!("{fragments} fragments"));
    }
    if let Some(rate_limit) = task.rate_limit.as_deref() {
        parts.push(format!("rate {rate_limit}"));
    }
    if let Some(cookie) = task.cookie_bucket_id.as_deref() {
        parts.push(format!("cookie {cookie}"));
    }
    if let Some(auth) = task.auth_payload_ref.as_deref() {
        parts.push(format!("auth {auth}"));
    }
    if let Some(subtitles) = task.subtitles.as_ref() {
        parts.push(format!(
            "subs {} auto={} embed={} keep_vtt={}",
            if subtitles.languages.is_empty() {
                "all".to_string()
            } else {
                subtitles.languages.join(",")
            },
            subtitles.auto,
            subtitles.embed,
            subtitles.keep_vtt
        ));
    }
    if let Some(sponsorblock) = task.sponsorblock.as_ref() {
        parts.push(format!(
            "SponsorBlock {} {}",
            if sponsorblock.enabled { "on" } else { "off" },
            sponsorblock.categories.join(",")
        ));
    }
    if let Some(metadata) = task.metadata.as_ref() {
        parts.push(format!(
            "metadata embed={} thumb={} chapters={}",
            metadata.embed_metadata, metadata.embed_thumbnail, metadata.split_chapters
        ));
    }
    if task.custom_ytdlp_args.as_deref().is_some() {
        parts.push("custom yt-dlp args".to_string());
    }
    parts.join(" · ")
}

fn cli_task_integrity_summary(task: &DownloadTask) -> String {
    let Some(integrity) = task
        .details_json
        .as_ref()
        .and_then(|value| value.get("integrity"))
    else {
        return String::new();
    };
    let expected = integrity
        .get("expected_sha256")
        .and_then(|value| value.as_str())
        .unwrap_or("");
    let actual = integrity
        .get("actual_sha256")
        .and_then(|value| value.as_str())
        .unwrap_or("");
    let verified_at = integrity
        .get("verified_at")
        .and_then(|value| value.as_str())
        .unwrap_or("");
    let mut parts = Vec::new();
    if !expected.is_empty() {
        parts.push(format!("expected {expected}"));
    }
    if !actual.is_empty() {
        parts.push(format!("actual {actual}"));
    }
    if !verified_at.is_empty() {
        parts.push(format!("verified {verified_at}"));
    }
    parts.join(" · ")
}
fn cli_import_cookies(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if args.len() < 2 || args.len() > 3 {
        return Err("import-cookies requires <name> <file> [platform].".to_string());
    }
    let root = cli_data_root(options)?;
    let bucket = import_cookie_bucket_at_root(
        &root,
        CookieImportRequest {
            name: args[0].clone(),
            platform: args.get(2).cloned(),
            source: CookieImportSource::File {
                path: args[1].clone(),
            },
        },
    )?;
    cli_print_cookie_import_result(options, &bucket, "Imported Cookie bucket")
}

fn cli_import_extension_cookies(args: Vec<String>, options: &CliOptions) -> Result<(), String> {
    if args.len() < 2 || args.len() > 3 {
        return Err(
            "import-extension-cookies requires <name> <payload-ref> [platform].".to_string(),
        );
    }
    let root = cli_data_root(options)?;
    let bucket = import_cookie_bucket_at_root(
        &root,
        CookieImportRequest {
            name: args[0].clone(),
            platform: args.get(2).cloned(),
            source: CookieImportSource::BrowserExtension {
                payload_ref: args[1].clone(),
            },
        },
    )?;
    cli_print_cookie_import_result(options, &bucket, "Imported extension Cookie payload")
}

fn cli_print_cookie_import_result(
    options: &CliOptions,
    bucket: &CookieBucket,
    title: &str,
) -> Result<(), String> {
    let bucket_id = bucket.id.clone();
    let bucket_name = bucket.name.clone();
    let cookie_count = bucket.cookie_count;
    let payload = serde_json::json!({
        "imported": true,
        "bucket_id": bucket_id.clone(),
        "name": bucket_name.clone(),
        "cookie_count": cookie_count
    });
    cli_print_json_or_human(options, &payload, || {
        format!(
            "{title}\nBucket id: {bucket_id}\nName: {name}\nCookies: {cookie_count}",
            title = title,
            bucket_id = bucket_id,
            name = bucket_name,
            cookie_count = cookie_count
        )
    })
}

fn cli_create_download_task(
    url: &str,
    line_number: Option<usize>,
    options: &CliOptions,
) -> Result<DownloadTask, String> {
    let root = cli_data_root(options)?;
    let task = create_download_task_at_root(
        &root,
        CreateDownloadRequest {
            source_url: url.to_string(),
            kind: Some(options.task_kind.clone().unwrap_or(DownloadKind::Video)),
            output_dir: options.task_output_dir.clone(),
            output_path: options.task_output_path.clone(),
            title_override: options
                .task_title
                .clone()
                .or_else(|| line_number.map(|line| format!("Batch item {line}"))),
            user_agent: options.task_user_agent.clone(),
            referer: options.task_referer.clone(),
            proxy: options.task_proxy.clone(),
            cookie_bucket_id: options.task_cookie_bucket_id.clone(),
            auth_payload_ref: options.task_auth_payload_ref.clone(),
            rate_limit: options.task_rate_limit.clone(),
            live_from_start: options.task_live_from_start,
            concurrent_fragments: options.task_concurrent_fragments,
            custom_ytdlp_args: options.task_custom_ytdlp_args.clone(),
            start_seconds: options.task_start_seconds,
            end_seconds: options.task_end_seconds,
            quality: options.task_quality.clone(),
            audio_format: options.task_audio_format.clone(),
            thumbnail_url: options.task_thumbnail_url.clone(),
            expected_sha256: options.task_expected_sha256.clone(),
            subtitles: options.task_subtitles.clone(),
            sponsorblock: options.task_sponsorblock.clone(),
            metadata: options.task_metadata.clone(),
            run_after_active_slot: Some(options.task_run_after_active_slot),
        },
        &Utc::now().to_rfc3339(),
    )?;
    maybe_spawn_task_thumbnail_cache(root, &task);
    Ok(task)
}

