fn parse_cli_download_kind(value: &str) -> Result<DownloadKind, String> {
    match value.trim().to_ascii_lowercase().replace('-', "_").as_str() {
        "generic" => Ok(DownloadKind::Generic),
        "video" => Ok(DownloadKind::Video),
        "playlist" => Ok(DownloadKind::Playlist),
        "audio" => Ok(DownloadKind::Audio),
        "image" | "images" | "gallery" => Ok(DownloadKind::Image),
        "subtitles" | "subtitles_only" | "subtitle" => Ok(DownloadKind::SubtitlesOnly),
        "torrent" => Ok(DownloadKind::Torrent),
        "p2p" => Ok(DownloadKind::P2p),
        "pdf" => Ok(DownloadKind::Pdf),
        "book" => Ok(DownloadKind::Book),
        "webpage" | "web" => Ok(DownloadKind::Webpage),
        "telegram_media" | "telegram" => Ok(DownloadKind::TelegramMedia),
        "course_lesson" | "course" => Ok(DownloadKind::CourseLesson),
        _ => Err(format!(
            "Unsupported --kind value: {value}. Use video, audio, playlist, image, subtitles, pdf, book, webpage, generic, torrent, p2p, telegram_media, or course_lesson."
        )),
    }
}

fn cli_print_json_or_human<F>(
    options: &CliOptions,
    payload: &serde_json::Value,
    human: F,
) -> Result<(), String>
where
    F: FnOnce() -> String,
{
    match options.output {
        CliOutputMode::Json => {
            println!(
                "{}",
                serde_json::to_string_pretty(payload).map_err(|error| error.to_string())?
            );
        }
        CliOutputMode::Human => {
            println!("{}", human());
        }
    }
    Ok(())
}

fn cli_data_root(options: &CliOptions) -> Result<PathBuf, String> {
    let data = match options.data_dir.as_ref() {
        Some(path) => path.clone(),
        None => std::env::current_dir()
            .map_err(|error| error.to_string())?
            .join("data"),
    };
    fs::create_dir_all(&data).map_err(|error| error.to_string())?;
    Ok(data)
}

