fn bridge_request_line(request: &[u8]) -> Result<(&str, &str), String> {
    let header = bridge_header_text(request)?;
    let line = header
        .lines()
        .next()
        .ok_or_else(|| "Bridge request line is missing.".to_string())?;
    let mut parts = line.split_whitespace();
    let method = parts
        .next()
        .ok_or_else(|| "Bridge request method is missing.".to_string())?;
    let path = parts
        .next()
        .ok_or_else(|| "Bridge request path is missing.".to_string())?;
    Ok((method, path))
}

fn bridge_header_text(request: &[u8]) -> Result<&str, String> {
    let header_end = request
        .windows(4)
        .position(|window| window == b"\r\n\r\n")
        .ok_or_else(|| "Bridge request headers are incomplete.".to_string())?;
    std::str::from_utf8(&request[..header_end])
        .map_err(|error| format!("Bridge request headers were not UTF-8: {error}"))
}

fn bridge_header_value(request: &[u8], header_name: &str) -> Option<String> {
    bridge_header_text(request).ok()?.lines().find_map(|line| {
        let (name, value) = line.split_once(':')?;
        name.eq_ignore_ascii_case(header_name)
            .then(|| value.trim().to_string())
    })
}
fn bridge_content_length(request: &[u8]) -> Option<usize> {
    bridge_header_text(request).ok()?.lines().find_map(|line| {
        let (name, value) = line.split_once(':')?;
        name.eq_ignore_ascii_case("content-length")
            .then(|| value.trim().parse::<usize>().ok())
            .flatten()
    })
}

fn bridge_body_bytes(request: &[u8]) -> &[u8] {
    let Some(header_end) = request.windows(4).position(|window| window == b"\r\n\r\n") else {
        return &[];
    };
    &request[header_end + 4..]
}

fn write_bridge_json_response<T: Serialize>(
    stream: &mut TcpStream,
    status: u16,
    payload: &T,
) -> Result<(), String> {
    let body = serde_json::to_vec(payload).map_err(|error| error.to_string())?;
    write_bridge_raw_response(stream, status, "application/json", &body)
}

fn write_bridge_raw_response(
    stream: &mut TcpStream,
    status: u16,
    content_type: &str,
    body: &[u8],
) -> Result<(), String> {
    let reason = match status {
        200 => "OK",
        204 => "No Content",
        400 => "Bad Request",
        404 => "Not Found",
        413 => "Payload Too Large",
        _ => "OK",
    };
    let headers = format!(
        "HTTP/1.1 {status} {reason}\r\nContent-Type: {content_type}\r\nContent-Length: {}\r\nAccess-Control-Allow-Origin: *\r\nAccess-Control-Allow-Headers: Content-Type, X-FetchDock-Token\r\nAccess-Control-Allow-Methods: GET, POST, OPTIONS\r\nConnection: close\r\n\r\n",
        body.len()
    );
    stream
        .write_all(headers.as_bytes())
        .and_then(|_| stream.write_all(body))
        .map_err(|error| format!("Bridge response write failed: {error}"))
}

