fn emit_channel_new_items(app: &AppHandle, items: &[ChannelHistoryItem]) {
    let mut counts: HashMap<&str, usize> = HashMap::new();
    for item in items.iter().filter(|item| item.error.is_none()) {
        *counts.entry(item.channel_id.as_str()).or_insert(0) += 1;
    }

    for (channel_id, item_count) in counts {
        if item_count == 0 {
            continue;
        }
        let event = ChannelNewItemsEvent {
            channel_id: channel_id.to_string(),
            item_count,
        };
        let _ = app.emit(CHANNEL_NEW_ITEMS_EVENT, event);
    }
}

