fn emit_downloads_created_and_schedule_if_needed(
    app: &AppHandle,
    tasks: &[DownloadTask],
) -> Result<(), String> {
    for task in tasks {
        emit_download_created(app, task.clone());
    }
    if tasks.iter().any(|task| task.run_after_active_slot) {
        schedule_downloads(app.clone())?;
    }
    Ok(())
}

fn emit_download_state(app: &AppHandle, previous_status: DownloadStatus, task: DownloadTask) {
    let event = DownloadStateEvent {
        task_id: task.id.clone(),
        previous_status,
        status: task.status.clone(),
        task: task.clone(),
    };
    let _ = app.emit(DOWNLOAD_STATE_EVENT, event);

    match task.status {
        DownloadStatus::Completed => {
            let _ = app.emit(DOWNLOAD_COMPLETED_EVENT, download_completed_event(task));
        }
        DownloadStatus::Failed => {
            let _ = app.emit(DOWNLOAD_FAILED_EVENT, download_failed_event(task));
        }
        _ => {}
    }
}

fn emit_downloads_list_changed(app: &AppHandle, reason: &str, mut tasks: Vec<DownloadTask>) {
    tasks.sort_by_key(|task| task.position);
    let event = DownloadsListChangedEvent {
        reason: reason.to_string(),
        tasks,
    };
    let _ = app.emit(DOWNLOADS_LIST_CHANGED_EVENT, event);
}

fn download_completed_event(task: DownloadTask) -> DownloadCompletedEvent {
    let files = task
        .output_path
        .as_ref()
        .filter(|path| !path.trim().is_empty())
        .map(|path| {
            vec![DownloadFileEvent {
                path: path.clone(),
                size_bytes: task.downloaded_bytes,
                role: "primary",
            }]
        })
        .unwrap_or_default();
    DownloadCompletedEvent { task, files }
}

fn download_failed_event(task: DownloadTask) -> DownloadFailedEvent {
    let category = task
        .error_category
        .clone()
        .unwrap_or(DownloadErrorCategory::Internal);
    let retryable = task.retryable.unwrap_or(false);
    let message = task
        .last_error
        .clone()
        .filter(|value| !value.trim().is_empty())
        .unwrap_or_else(|| "Download failed.".to_string());
    let code = format!("download_{}", download_error_category_code(&category));
    let user_action = download_error_user_action(&category, retryable);
    DownloadFailedEvent {
        task,
        error: DownloadFailureEvent {
            schema_version: 1,
            code,
            category,
            message,
            retryable,
            user_action,
        },
    }
}

