fn emit_clipboard_capture(app: &AppHandle) {
    let (url, message) = match app.clipboard().read_text() {
        Ok(text) => match extract_first_url(&text) {
            Some(url) => (
                Some(url),
                "Clipboard URL captured by the global shortcut.".to_string(),
            ),
            None => (
                None,
                "Global shortcut captured, but the clipboard does not contain a URL.".to_string(),
            ),
        },
        Err(error) => (
            None,
            format!("Global shortcut captured, but clipboard text could not be read: {error}"),
        ),
    };

    emit_shell_open(
        app,
        ShellOpenRequest {
            source: ShellOpenSource::GlobalShortcut,
            url,
            target: None,
            message,
        },
    );
}

