fn read_appearance_settings(root: &Path) -> Result<AppearanceSettings, String> {
    let path = appearance_settings_path(root);
    if !path.exists() {
        return Ok(default_appearance_settings());
    }

    let bytes = fs::read(&path).map_err(|error| error.to_string())?;
    let settings: AppearanceSettings =
        serde_json::from_slice(&bytes).map_err(|error| error.to_string())?;
    Ok(sanitize_appearance_settings(settings))
}

fn write_appearance_settings(
    root: &Path,
    settings: &AppearanceSettings,
) -> Result<AppearanceSettings, String> {
    let sanitized = sanitize_appearance_settings(settings.clone());
    let path = appearance_settings_path(root);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }

    fs::write(
        path,
        serde_json::to_vec_pretty(&sanitized).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;
    Ok(sanitized)
}

