fn appearance_theme_label(theme_id: &str) -> String {
    match theme_id {
        "system" => "System".to_string(),
        "light" => "Light".to_string(),
        "dark" => "Dark".to_string(),
        "contrast" => "Contrast".to_string(),
        "paper" => "Paper".to_string(),
        "midnight" => "Midnight".to_string(),
        "forest" => "Forest".to_string(),
        "dracula" => "Dracula".to_string(),
        "catppuccin" => "Catppuccin".to_string(),
        "one-dark" => "One Dark".to_string(),
        "e-ink" => "E-ink".to_string(),
        "solar" => "Solar".to_string(),
        "rose" => "Rose".to_string(),
        "nord" => "Nord".to_string(),
        other => other.replace('-', " "),
    }
}

fn appearance_theme_category(theme_id: &str) -> String {
    match theme_id {
        "system" => "adaptive".to_string(),
        "light" | "paper" | "e-ink" | "solar" | "rose" | "nord" | "forest" => "light".to_string(),
        "dark" | "midnight" | "dracula" | "catppuccin" | "one-dark" => "dark".to_string(),
        "contrast" => "accessibility".to_string(),
        _ => "custom".to_string(),
    }
}

fn build_appearance_theme_catalog_at_root(
    root: &Path,
) -> Result<AppearanceThemeCatalogResponse, String> {
    let settings = read_appearance_settings(root)?;
    let common_name_ids = ["dracula", "catppuccin", "one-dark"];
    let themes = APPEARANCE_THEME_IDS
        .iter()
        .map(|theme_id| {
            let common_name_compatible = common_name_ids.contains(theme_id);
            AppearanceThemeCatalogItem {
                id: (*theme_id).to_string(),
                label: appearance_theme_label(theme_id),
                css_class: format!("theme-{theme_id}"),
                category: appearance_theme_category(theme_id),
                system_aware: *theme_id == "system",
                common_name_compatible,
                original_token_set: true,
                review_note: if common_name_compatible {
                    "Uses a familiar public theme name as a compatibility label while keeping FetchDock-owned CSS tokens.".to_string()
                } else {
                    "FetchDock-owned CSS token set declared in the local app stylesheet.".to_string()
                },
            }
        })
        .collect::<Vec<_>>();
    let review_notes = vec![
        "This catalog is a local metadata summary of FetchDock theme entries and settings.".to_string(),
        "Theme ids are backed by local CSS classes in src/styles.css and do not copy external theme files, assets, screenshots, logos, or translation text.".to_string(),
        "Common names such as Dracula, Catppuccin, and One Dark are compatibility labels only; visual tokens remain FetchDock-authored.".to_string(),
        "This summary does not run browser visual QA, contrast measurement, screenshot comparison, or full manual theme review.".to_string(),
    ];
    Ok(AppearanceThemeCatalogResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        data_root: display_path(root),
        current_theme: settings.theme,
        current_language: settings.language,
        theme_count: themes.len(),
        language_count: APPEARANCE_LANGUAGE_IDS.len(),
        density_count: 3,
        font_scale_min_percent: 90,
        font_scale_max_percent: 115,
        themes,
        languages: APPEARANCE_LANGUAGE_IDS
            .iter()
            .map(|language| (*language).to_string())
            .collect(),
        densities: ["compact", "comfortable", "spacious"]
            .iter()
            .map(|density| (*density).to_string())
            .collect(),
        css_source_path: "src/styles.css".to_string(),
        includes_external_assets: false,
        copies_external_theme_text: false,
        verifies_visual_contrast: false,
        review_notes,
    })
}

