fn appearance_language_label(language_id: &str) -> (&'static str, &'static str) {
    match language_id {
        "en" => ("English", "English"),
        "zh-CN" => ("Chinese (Simplified)", "Simplified Chinese"),
        "es" => ("Spanish", "Espanol"),
        "fr" => ("French", "Francais"),
        "de" => ("German", "Deutsch"),
        "it" => ("Italian", "Italiano"),
        "ja" => ("Japanese", "Japanese"),
        "ko" => ("Korean", "Korean"),
        "pt-BR" => ("Portuguese (Brazil)", "Portugues BR"),
        _ => ("Custom", "Custom"),
    }
}

fn build_appearance_language_catalog_at_root(
    root: &Path,
) -> Result<AppearanceLanguageCatalogResponse, String> {
    let settings = read_appearance_settings(root)?;
    let shell_translation_key_count = 25;
    let languages = APPEARANCE_LANGUAGE_IDS
        .iter()
        .map(|language_id| {
            let (label, native_label) = appearance_language_label(language_id);
            AppearanceLanguageCatalogItem {
                id: (*language_id).to_string(),
                label: label.to_string(),
                native_label: native_label.to_string(),
                text_direction: "ltr".to_string(),
                shell_translation_keys: shell_translation_key_count,
                shell_translation_complete: true,
                review_note: "FetchDock-authored shell/navigation/settings-search label subset; full product translation and extension/plugin runtime locale review remain pending.".to_string(),
            }
        })
        .collect::<Vec<_>>();
    let review_notes = vec![
        "This catalog is a local metadata summary of FetchDock language entries and the lightweight app-shell dictionary.".to_string(),
        "Language ids cover the current app-shell/navigation/settings-search subset and do not claim full business-panel, extension, or plugin runtime translation coverage.".to_string(),
        "Labels are FetchDock-authored short labels and do not copy external translation files or product copy.".to_string(),
        "This summary does not run linguistic QA, full UI string extraction, screenshot review, or manual locale verification.".to_string(),
    ];
    Ok(AppearanceLanguageCatalogResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        data_root: display_path(root),
        current_language: settings.language,
        language_count: languages.len(),
        shell_translation_key_count,
        languages,
        includes_extension_locales: false,
        includes_plugin_runtime_i18n: false,
        copies_external_translation_text: false,
        verifies_full_ui_translation: false,
        review_notes,
    })
}

