#[allow(clippy::too_many_arguments)]
fn appearance_capability_catalog_item(
    capability: &str,
    label: &str,
    status: &str,
    commands: &[&str],
    cli_aliases: &[&str],
    desktop_ui: &[&str],
    setting_fields: &[&str],
    data_files: &[&str],
    sensitive_fields: &[&str],
    reads_appearance_values: bool,
    writes_appearance_values: bool,
    imports_appearance_files: bool,
    exports_appearance_files: bool,
    uses_external_assets: bool,
    copies_external_theme_text: bool,
    copies_external_translation_text: bool,
    verifies_visual_contrast: bool,
    verifies_full_ui_translation: bool,
    supports_batch: bool,
    scope: &str,
    limitations: &[&str],
) -> AppearanceCapabilityCatalogItem {
    AppearanceCapabilityCatalogItem {
        capability: capability.to_string(),
        label: label.to_string(),
        status: status.to_string(),
        commands: commands.iter().map(|value| (*value).to_string()).collect(),
        cli_aliases: cli_aliases.iter().map(|value| (*value).to_string()).collect(),
        desktop_ui: desktop_ui.iter().map(|value| (*value).to_string()).collect(),
        setting_fields: setting_fields.iter().map(|value| (*value).to_string()).collect(),
        data_files: data_files.iter().map(|value| (*value).to_string()).collect(),
        sensitive_fields: sensitive_fields.iter().map(|value| (*value).to_string()).collect(),
        reads_appearance_values,
        writes_appearance_values,
        imports_appearance_files,
        exports_appearance_files,
        uses_external_assets,
        copies_external_theme_text,
        copies_external_translation_text,
        verifies_visual_contrast,
        verifies_full_ui_translation,
        supports_batch,
        scope: scope.to_string(),
        limitations: limitations.iter().map(|value| (*value).to_string()).collect(),
    }
}

