fn network_settings_from_downloads(settings: &DownloadsSettings) -> NetworkSettingsBackup {
    sanitize_network_settings_backup(NetworkSettingsBackup {
        schema_version: 1,
        default_user_agent: settings.default_user_agent.clone(),
        default_referer: settings.default_referer.clone(),
        default_proxy: settings.default_proxy.clone(),
        default_rate_limit: settings.default_rate_limit.clone(),
        default_live_from_start: settings.default_live_from_start,
        default_concurrent_fragments: settings.default_concurrent_fragments,
    })
}

fn apply_network_settings_backup(settings: &mut DownloadsSettings, backup: NetworkSettingsBackup) {
    let backup = sanitize_network_settings_backup(backup);
    settings.default_user_agent = backup.default_user_agent;
    settings.default_referer = backup.default_referer;
    settings.default_proxy = backup.default_proxy;
    settings.default_rate_limit = backup.default_rate_limit;
    settings.default_live_from_start = backup.default_live_from_start;
    settings.default_concurrent_fragments = backup.default_concurrent_fragments;
}

