fn read_cookie_buckets(root: &Path) -> Result<Vec<CookieBucket>, String> {
    let path = cookie_buckets_path(root);
    if !path.exists() {
        return Ok(Vec::new());
    }
    let bytes = fs::read(&path).map_err(|error| error.to_string())?;
    let mut buckets: Vec<CookieBucket> =
        serde_json::from_slice(&bytes).map_err(|error| error.to_string())?;
    for bucket in &mut buckets {
        refresh_cookie_bucket_metadata(root, bucket);
    }
    buckets.sort_by(|left, right| right.updated_at.cmp(&left.updated_at));
    Ok(buckets)
}

fn write_cookie_buckets(root: &Path, buckets: &[CookieBucket]) -> Result<(), String> {
    let path = cookie_buckets_path(root);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::write(
        path,
        serde_json::to_vec_pretty(buckets).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())
}

fn import_cookie_bucket_at_root(
    root: &Path,
    request: CookieImportRequest,
) -> Result<CookieBucket, String> {
    let name = sanitize_cookie_bucket_name(&request.name)?;
    let requested_platform = sanitize_optional_text(request.platform.as_deref());
    let (source, cookie_text) = match request.source {
        CookieImportSource::Paste { text } => (CookieBucketSource::Paste, text),
        CookieImportSource::File { path } => {
            let text = fs::read_to_string(PathBuf::from(path.trim()))
                .map_err(|error| format!("Unable to read cookie file: {error}"))?;
            (CookieBucketSource::File, text)
        }
        CookieImportSource::BrowserExtension { payload_ref } => {
            let path = browser_extension_cookie_payload_path(root, &payload_ref)?;
            let text = fs::read_to_string(&path).map_err(|error| {
                format!("Unable to read browser extension cookie payload: {error}")
            })?;
            (CookieBucketSource::BrowserExtension, text)
        }
    };
    let normalized = normalize_cookie_text(&cookie_text)?;
    let domain_hints = cookie_domain_hints(&normalized);
    let platform = requested_platform.or_else(|| infer_cookie_platform_from_domains(&domain_hints));
    let path_hints = cookie_path_hints(&normalized);
    let secure_only = cookie_bucket_is_secure_only(&normalized);
    let expires_summary = cookie_expires_summary(&normalized);
    let cookie_count = count_cookie_records(&normalized);
    let now = Utc::now().to_rfc3339();
    let id = format!(
        "cookie-{}-{}",
        Utc::now().timestamp_millis(),
        sanitize_file_name(&name)
    );
    let storage_path = format!("cookies/{}.cookies.txt", sanitize_file_name(&id));
    let bucket = CookieBucket {
        schema_version: 1,
        id,
        name,
        platform,
        domain_hints,
        path_hints,
        secure_only,
        expires_summary,
        cookie_count,
        source,
        storage_path,
        created_at: now.clone(),
        updated_at: now,
        last_tested_at: None,
        health: CookieBucketHealth::Untested,
    };
    let path = cookie_bucket_storage_path(root, &bucket);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::write(&path, normalized.as_bytes()).map_err(|error| error.to_string())?;

    let mut buckets = read_cookie_buckets(root)?;
    buckets.retain(|existing| existing.id != bucket.id);
    buckets.push(bucket.clone());
    write_cookie_buckets(root, &buckets)?;
    Ok(bucket)
}

fn find_cookie_bucket(root: &Path, bucket_id: &str) -> Result<CookieBucket, String> {
    read_cookie_buckets(root)?
        .into_iter()
        .find(|bucket| bucket.id == bucket_id)
        .ok_or_else(|| format!("Cookie bucket was not found: {bucket_id}"))
}

fn export_cookie_buckets_at_root(
    root: &Path,
    request: Option<CookieBucketsExportRequest>,
) -> Result<CookieBucketsExportResponse, String> {
    let request = request.unwrap_or(CookieBucketsExportRequest {
        output_path: None,
        bucket_ids: None,
    });
    let output_path = match request
        .output_path
        .and_then(|path| sanitize_optional_text(Some(&path)))
    {
        Some(path) => validate_output_file_path(&path, "Cookie bucket backup export")?,
        None => default_cookie_buckets_export_path(root),
    };
    validate_json_file_path(&output_path, "Cookie bucket backup export")?;
    if let Some(parent) = output_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }

    let mut buckets = read_cookie_buckets(root)?;
    if let Some(ids) = request.bucket_ids {
        let requested_ids = ids
            .into_iter()
            .filter_map(|id| sanitize_cookie_bucket_id(Some(&id)))
            .collect::<HashSet<_>>();
        if requested_ids.is_empty() {
            return Err("Choose at least one Cookie bucket to export.".to_string());
        }
        buckets.retain(|bucket| requested_ids.contains(&bucket.id));
    }
    if buckets.is_empty() {
        return Err("No Cookie buckets are available to export.".to_string());
    }

    let mut entries = Vec::new();
    let mut cookie_row_count = 0usize;
    for mut bucket in buckets {
        let cookie_path = cookie_bucket_storage_path(root, &bucket);
        let cookie_text = fs::read_to_string(&cookie_path)
            .map_err(|error| format!("Unable to read Cookie bucket {}: {error}", bucket.id))?;
        let cookie_text = normalize_cookie_text(&cookie_text)?;
        bucket.cookie_count = count_cookie_records(&cookie_text);
        bucket.domain_hints = cookie_domain_hints(&cookie_text);
        if bucket.platform.is_none() {
            bucket.platform = infer_cookie_platform_from_domains(&bucket.domain_hints);
        }
        bucket.path_hints = cookie_path_hints(&cookie_text);
        bucket.secure_only = cookie_bucket_is_secure_only(&cookie_text);
        bucket.expires_summary = cookie_expires_summary(&cookie_text);
        cookie_row_count += bucket.cookie_count;
        entries.push(CookieBucketBackupEntry {
            bucket,
            cookie_text,
        });
    }

    let review_notes = vec![
        "This user-triggered backup includes Cookie row values so managed Cookie buckets can be restored.".to_string(),
        "Authorization header values, staged extension payload bodies, browser storage, pairing tokens, keychain items, and live login sessions are not included.".to_string(),
        "Importing this file writes local Cookie bucket files only; it does not test accounts, contact websites, or start downloads.".to_string(),
    ];
    let exported_bucket_count = entries.len();
    let bundle = CookieBucketsBackupBundle {
        schema_version: 1,
        kind: "fetchdock.cookie_buckets".to_string(),
        exported_at: Some(Utc::now().to_rfc3339()),
        bucket_count: exported_bucket_count,
        cookie_row_count,
        buckets: entries,
        includes_cookie_values: true,
        includes_authorization_values: false,
        includes_staged_payload_bodies: false,
        executes_network_requests: false,
        review_notes: review_notes.clone(),
    };
    fs::write(
        &output_path,
        serde_json::to_vec_pretty(&bundle).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write Cookie bucket backup export: {error}"))?;

    Ok(CookieBucketsExportResponse {
        schema_version: 1,
        output_path: display_path(&output_path),
        exported_bucket_count,
        exported_cookie_row_count: cookie_row_count,
        includes_cookie_values: true,
        includes_authorization_values: false,
        includes_staged_payload_bodies: false,
        executes_network_requests: false,
        review_notes,
    })
}

fn import_cookie_buckets_at_root(
    root: &Path,
    request: CookieBucketsImportRequest,
) -> Result<CookieBucketsImportResponse, String> {
    let input_path =
        validate_existing_input_file(&request.input_path, "Cookie bucket backup import")?;
    validate_json_file_path(&input_path, "Cookie bucket backup import")?;
    let metadata = fs::metadata(&input_path).map_err(|error| error.to_string())?;
    if metadata.len() > 10 * 1024 * 1024 {
        return Err("Cookie bucket backup import is limited to files up to 10 MB.".to_string());
    }
    let raw: serde_json::Value =
        serde_json::from_slice(&fs::read(&input_path).map_err(|error| error.to_string())?)
            .map_err(|error| {
                format!("Cookie bucket backup import must be FetchDock JSON: {error}")
            })?;
    let bundle = parse_cookie_buckets_backup_bundle(raw)?;
    let mut existing_buckets = read_cookie_buckets(root)?;
    let existing_ids = existing_buckets
        .iter()
        .map(|bucket| bucket.id.clone())
        .collect::<HashSet<_>>();
    let mut seen_import_ids = HashSet::new();
    let now = Utc::now().to_rfc3339();
    let mut imported = Vec::new();
    let mut skipped_bucket_count = 0usize;

    for entry in bundle.buckets {
        match sanitize_imported_cookie_bucket(
            root,
            entry,
            &existing_ids,
            &mut seen_import_ids,
            &now,
        ) {
            Ok(Some(bucket)) => imported.push(bucket),
            Ok(None) => skipped_bucket_count += 1,
            Err(_) => skipped_bucket_count += 1,
        }
        if imported.len() >= 1000 {
            skipped_bucket_count += 1;
            break;
        }
    }

    if imported.is_empty() {
        return Err(
            "Cookie bucket backup did not contain any new usable bucket records.".to_string(),
        );
    }

    let imported_bucket_count = imported.len();
    existing_buckets.extend(imported);
    write_cookie_buckets(root, &existing_buckets)?;
    let buckets = read_cookie_buckets(root)?;
    Ok(CookieBucketsImportResponse {
        schema_version: 1,
        input_path: display_path(&input_path),
        imported_bucket_count,
        skipped_bucket_count,
        total_bucket_count: buckets.len(),
        buckets,
        review_notes: vec![
            "Imported Cookie buckets were merged with the existing local bucket list; duplicate ids were skipped.".to_string(),
            "Cookie row values were restored into managed local bucket files because this is an explicit Cookie bucket backup.".to_string(),
            "Authorization header values, staged extension payload bodies, keychain items, browser sessions, and live account state were not imported.".to_string(),
        ],
    })
}

fn parse_cookie_buckets_backup_bundle(
    raw: serde_json::Value,
) -> Result<CookieBucketsBackupBundle, String> {
    if raw.get("buckets").is_some() {
        let mut bundle: CookieBucketsBackupBundle =
            serde_json::from_value(raw).map_err(|error| {
                format!("Cookie bucket backup JSON did not contain a valid bundle: {error}")
            })?;
        bundle.schema_version = 1;
        if bundle.kind.trim().is_empty() {
            bundle.kind = "fetchdock.cookie_buckets".to_string();
        }
        return Ok(bundle);
    }
    let entries: Vec<CookieBucketBackupEntry> = serde_json::from_value(raw).map_err(|error| {
        format!("Cookie bucket backup JSON did not contain valid bucket records: {error}")
    })?;
    Ok(CookieBucketsBackupBundle {
        schema_version: 1,
        kind: "fetchdock.cookie_buckets.legacy_list".to_string(),
        exported_at: None,
        bucket_count: entries.len(),
        cookie_row_count: entries
            .iter()
            .map(|entry| count_cookie_records(&entry.cookie_text))
            .sum(),
        buckets: entries,
        includes_cookie_values: true,
        includes_authorization_values: false,
        includes_staged_payload_bodies: false,
        executes_network_requests: false,
        review_notes: Vec::new(),
    })
}

fn sanitize_imported_cookie_bucket(
    root: &Path,
    entry: CookieBucketBackupEntry,
    existing_ids: &HashSet<String>,
    seen_import_ids: &mut HashSet<String>,
    now: &str,
) -> Result<Option<CookieBucket>, String> {
    let mut bucket = entry.bucket;
    bucket.id = sanitize_cookie_bucket_id(Some(&bucket.id))
        .ok_or_else(|| "Cookie bucket id is required.".to_string())?;
    if existing_ids.contains(&bucket.id) || !seen_import_ids.insert(bucket.id.clone()) {
        return Ok(None);
    }

    let cookie_text = normalize_cookie_text(&entry.cookie_text)?;
    bucket.schema_version = 1;
    bucket.name = sanitize_cookie_bucket_name(&bucket.name)
        .unwrap_or_else(|_| format!("Imported {}", bucket.id));
    bucket.platform = sanitize_optional_text(bucket.platform.as_deref());
    bucket.domain_hints = cookie_domain_hints(&cookie_text);
    if bucket.platform.is_none() {
        bucket.platform = infer_cookie_platform_from_domains(&bucket.domain_hints);
    }
    bucket.path_hints = cookie_path_hints(&cookie_text);
    bucket.secure_only = cookie_bucket_is_secure_only(&cookie_text);
    bucket.expires_summary = cookie_expires_summary(&cookie_text);
    bucket.cookie_count = count_cookie_records(&cookie_text);
    bucket.source = CookieBucketSource::File;
    bucket.storage_path = format!("cookies/{}.cookies.txt", sanitize_file_name(&bucket.id));
    bucket.created_at =
        sanitize_optional_text(Some(&bucket.created_at)).unwrap_or_else(|| now.to_string());
    bucket.updated_at = now.to_string();
    bucket.last_tested_at = None;
    bucket.health = CookieBucketHealth::Untested;

    let path = cookie_bucket_storage_path(root, &bucket);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::write(&path, cookie_text.as_bytes()).map_err(|error| error.to_string())?;
    Ok(Some(bucket))
}

fn default_cookie_buckets_export_path(root: &Path) -> PathBuf {
    root.join("cookies").join("exports").join(format!(
        "fetchdock-cookie-buckets-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn test_cookie_bucket_at_root(
    root: &Path,
    request: CookieTestRequest,
) -> Result<CookieBucket, String> {
    let url_match = request.url.as_deref().map(parse_http_url).transpose()?;
    let mut buckets = read_cookie_buckets(root)?;
    let bucket =
        test_cookie_bucket_in_store(root, &mut buckets, &request.bucket_id, url_match.as_ref())?;
    write_cookie_buckets(root, &buckets)?;
    Ok(bucket)
}

fn test_cookie_buckets_at_root(
    root: &Path,
    request: CookieTestManyRequest,
) -> Result<CookieTestManyResponse, String> {
    let url_match = request.url.as_deref().map(parse_http_url).transpose()?;
    let mut buckets = read_cookie_buckets(root)?;
    let mut tested = Vec::new();
    let mut failed = Vec::new();
    let mut seen = HashSet::new();
    for raw_id in request.bucket_ids {
        let Some(bucket_id) = sanitize_cookie_bucket_id(Some(&raw_id)) else {
            failed.push(BulkDownloadFailure {
                id: raw_id,
                error: "Cookie bucket id is required.".to_string(),
            });
            continue;
        };
        if !seen.insert(bucket_id.clone()) {
            continue;
        }
        match test_cookie_bucket_in_store(root, &mut buckets, &bucket_id, url_match.as_ref()) {
            Ok(bucket) => tested.push(bucket),
            Err(error) => failed.push(BulkDownloadFailure {
                id: bucket_id,
                error,
            }),
        }
    }
    if !tested.is_empty() {
        write_cookie_buckets(root, &buckets)?;
    }
    Ok(CookieTestManyResponse {
        buckets: tested,
        failed,
    })
}

fn test_cookie_bucket_in_store(
    root: &Path,
    buckets: &mut [CookieBucket],
    bucket_id: &str,
    url_match: Option<&ParsedHttpUrl>,
) -> Result<CookieBucket, String> {
    let index = buckets
        .iter()
        .position(|bucket| bucket.id == bucket_id)
        .ok_or_else(|| format!("Cookie bucket was not found: {bucket_id}"))?;
    let mut bucket = buckets[index].clone();
    let cookie_path = cookie_bucket_storage_path(root, &bucket);
    let cookie_text = fs::read_to_string(&cookie_path)
        .map_err(|error| format!("Unable to read cookie bucket file: {error}"))?;
    bucket.cookie_count = count_cookie_records(&cookie_text);
    bucket.domain_hints = cookie_domain_hints(&cookie_text);
    bucket.path_hints = cookie_path_hints(&cookie_text);
    bucket.secure_only = cookie_bucket_is_secure_only(&cookie_text);
    bucket.expires_summary = cookie_expires_summary(&cookie_text);
    bucket.last_tested_at = Some(Utc::now().to_rfc3339());
    bucket.health = classify_cookie_bucket_health(&cookie_text, url_match);
    bucket.updated_at = bucket
        .last_tested_at
        .clone()
        .unwrap_or_else(|| Utc::now().to_rfc3339());
    buckets[index] = bucket.clone();
    Ok(bucket)
}

fn clear_cookie_buckets_at_root(
    root: &Path,
    request: CookieClearRequest,
) -> Result<CookieClearResponse, String> {
    let ids = request
        .bucket_ids
        .unwrap_or_default()
        .into_iter()
        .filter_map(|id| sanitize_cookie_bucket_id(Some(&id)))
        .collect::<Vec<_>>();
    let platform =
        sanitize_optional_text(request.platform.as_deref()).map(|value| value.to_ascii_lowercase());
    if ids.is_empty() && platform.is_none() {
        return Err("Choose cookie buckets or a platform to clear.".to_string());
    }

    let mut buckets = read_cookie_buckets(root)?;
    let mut removed = Vec::new();
    buckets.retain(|bucket| {
        let id_match = ids.iter().any(|id| id == &bucket.id);
        let platform_match = platform
            .as_deref()
            .and_then(|platform| {
                bucket
                    .platform
                    .as_deref()
                    .map(|bucket_platform| bucket_platform.eq_ignore_ascii_case(platform))
            })
            .unwrap_or(false);
        if id_match || platform_match {
            removed.push(bucket.clone());
            false
        } else {
            true
        }
    });

    for bucket in &removed {
        let _ = fs::remove_file(cookie_bucket_storage_path(root, bucket));
    }
    if !removed.is_empty() {
        write_cookie_buckets(root, &buckets)?;
    }
    Ok(CookieClearResponse {
        cleared: removed.len(),
    })
}

fn build_cookie_auth_local_summary_at_root(
    root: &Path,
) -> Result<CookieAuthLocalSummaryResponse, String> {
    let buckets = read_cookie_buckets(root)?;
    let staged_cookie_payloads = list_extension_cookie_payloads_at_root(root)?;
    let staged_authorization_payloads = list_extension_authorization_payloads_at_root(root)?;
    let auth_settings = auth_settings_public(&read_auth_settings(root)?);
    let bilibili_status = get_bilibili_account_status_at_root(root)?;
    let storage_file_count = buckets
        .iter()
        .filter(|bucket| cookie_bucket_storage_path(root, bucket).is_file())
        .count();
    let missing_storage_file_count = buckets.len().saturating_sub(storage_file_count);

    Ok(CookieAuthLocalSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        data_root: display_path(root),
        cookie_bucket_count: buckets.len(),
        cookie_row_count: buckets.iter().map(|bucket| bucket.cookie_count).sum(),
        valid_cookie_bucket_count: buckets
            .iter()
            .filter(|bucket| bucket.health == CookieBucketHealth::Valid)
            .count(),
        expired_cookie_bucket_count: buckets
            .iter()
            .filter(|bucket| bucket.health == CookieBucketHealth::Expired)
            .count(),
        untested_cookie_bucket_count: buckets
            .iter()
            .filter(|bucket| bucket.health == CookieBucketHealth::Untested)
            .count(),
        error_cookie_bucket_count: buckets
            .iter()
            .filter(|bucket| bucket.health == CookieBucketHealth::Error)
            .count(),
        browser_extension_bucket_count: buckets
            .iter()
            .filter(|bucket| bucket.source == CookieBucketSource::BrowserExtension)
            .count(),
        pasted_bucket_count: buckets
            .iter()
            .filter(|bucket| bucket.source == CookieBucketSource::Paste)
            .count(),
        file_bucket_count: buckets
            .iter()
            .filter(|bucket| bucket.source == CookieBucketSource::File)
            .count(),
        secure_only_bucket_count: buckets.iter().filter(|bucket| bucket.secure_only).count(),
        domain_hint_count: buckets
            .iter()
            .flat_map(|bucket| bucket.domain_hints.iter().map(|value| value.to_ascii_lowercase()))
            .collect::<HashSet<_>>()
            .len(),
        path_hint_count: buckets
            .iter()
            .flat_map(|bucket| bucket.path_hints.iter().cloned())
            .collect::<HashSet<_>>()
            .len(),
        storage_file_count,
        missing_storage_file_count,
        staged_cookie_payload_count: staged_cookie_payloads.len(),
        staged_authorization_payload_count: staged_authorization_payloads.len(),
        twitter_x_manual_cookie_enabled: auth_settings.twitter_x.manual_cookie_header_enabled,
        twitter_x_manual_cookie_set: auth_settings.twitter_x.manual_cookie_header_set,
        twitter_x_manual_cookie_preview: auth_settings.twitter_x.manual_cookie_header_preview,
        twitter_x_manual_cookie_updated_at: auth_settings.twitter_x.updated_at,
        bilibili_cookie_bucket_set: bilibili_status.cookie_bucket_id.is_some(),
        bilibili_cookie_bucket_id: bilibili_status.cookie_bucket_id,
        bilibili_cookie_health: bilibili_status.cookie_health,
        platform_counts: counted_local_entries(buckets.iter().map(|bucket| {
            bucket
                .platform
                .clone()
                .unwrap_or_else(|| "unknown".to_string())
        })),
        source_counts: counted_local_entries(buckets.iter().map(|bucket| match &bucket.source {
            CookieBucketSource::Paste => "paste".to_string(),
            CookieBucketSource::File => "file".to_string(),
            CookieBucketSource::BrowserExtension => "browser_extension".to_string(),
        })),
        health_counts: counted_local_entries(buckets.iter().map(|bucket| match &bucket.health {
            CookieBucketHealth::Untested => "untested".to_string(),
            CookieBucketHealth::Valid => "valid".to_string(),
            CookieBucketHealth::Expired => "expired".to_string(),
            CookieBucketHealth::Error => "error".to_string(),
        })),
        expiry_summary_counts: counted_local_entries(buckets.iter().map(|bucket| {
            bucket
                .expires_summary
                .clone()
                .unwrap_or_else(|| "unknown".to_string())
        })),
        storage_status_counts: counted_local_entries(buckets.iter().map(|bucket| {
            if cookie_bucket_storage_path(root, bucket).is_file() {
                "present".to_string()
            } else {
                "missing".to_string()
            }
        })),
        staged_payload_counts: counted_local_entries(
            [("cookie", staged_cookie_payloads.len()), ("authorization", staged_authorization_payloads.len())]
                .into_iter()
                .flat_map(|(label, count)| std::iter::repeat(label.to_string()).take(count)),
        ),
        last_cookie_bucket_updated_at: buckets.iter().map(|bucket| bucket.updated_at.clone()).max(),
        last_cookie_tested_at: buckets
            .iter()
            .filter_map(|bucket| bucket.last_tested_at.clone())
            .max(),
        last_staged_cookie_payload_modified_at: staged_cookie_payloads
            .iter()
            .filter_map(|payload| payload.file.modified_at.clone())
            .max(),
        last_staged_authorization_payload_modified_at: staged_authorization_payloads
            .iter()
            .filter_map(|payload| payload.file.modified_at.clone())
            .max(),
        includes_cookie_values: false,
        includes_authorization_values: false,
        review_notes: vec![
            "This summary includes Cookie bucket metadata, health, scope hints, storage status, extension payload inventory, and public auth settings only.".to_string(),
            "It never exports Cookie row values, Authorization header values, pairing tokens, staged payload bodies, or browser storage.".to_string(),
            "Bilibili and Twitter/X entries reflect local Cookie/Auth configuration state, not live platform login verification.".to_string(),
        ],
    })
}

fn export_cookie_auth_local_summary_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let export_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Cookie/Auth local summary export")?,
        None => default_cookie_auth_local_summary_export_path(root),
    };
    validate_json_file_path(&export_path, "Cookie/Auth local summary export")?;
    if let Some(parent) = export_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let summary = build_cookie_auth_local_summary_at_root(root)?;
    fs::write(
        &export_path,
        serde_json::to_vec_pretty(&summary).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write Cookie/Auth local summary export: {error}"))?;
    Ok(DiagnosticsResponse {
        archive_path: display_path(export_path),
    })
}

fn default_cookie_auth_local_summary_export_path(root: &Path) -> PathBuf {
    root.join("cookies").join("exports").join(format!(
        "fetchdock-cookie-auth-summary-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

#[allow(clippy::too_many_arguments)]
fn cookie_auth_capability_catalog_item(
    capability: &str,
    label: &str,
    status: &str,
    commands: &[&str],
    cli_aliases: &[&str],
    desktop_ui: &[&str],
    data_files: &[&str],
    sensitive_fields: &[&str],
    stores_secret_values: bool,
    exports_secret_values: bool,
    mutates_cookie_store: bool,
    mutates_auth_settings: bool,
    executes_network_check: bool,
    supports_batch: bool,
    scope: &str,
    limitations: &[&str],
) -> CookieAuthCapabilityCatalogItem {
    CookieAuthCapabilityCatalogItem {
        capability: capability.to_string(),
        label: label.to_string(),
        status: status.to_string(),
        commands: commands.iter().map(|value| (*value).to_string()).collect(),
        cli_aliases: cli_aliases.iter().map(|value| (*value).to_string()).collect(),
        desktop_ui: desktop_ui.iter().map(|value| (*value).to_string()).collect(),
        data_files: data_files.iter().map(|value| (*value).to_string()).collect(),
        sensitive_fields: sensitive_fields
            .iter()
            .map(|value| (*value).to_string())
            .collect(),
        stores_secret_values,
        exports_secret_values,
        mutates_cookie_store,
        mutates_auth_settings,
        executes_network_check,
        supports_batch,
        scope: scope.to_string(),
        limitations: limitations
            .iter()
            .map(|value| (*value).to_string())
            .collect(),
    }
}

