fn build_local_settings_summary_at_root(
    root: &Path,
) -> Result<LocalSettingsSummaryResponse, String> {
    let settings = read_settings(root)?;
    let update = read_update_settings(root).unwrap_or_else(|_| default_update_settings());
    let extension =
        read_extension_options_state(root).unwrap_or_else(|_| default_extension_options_state());
    let channels = read_channels(root).unwrap_or_default();
    let channel_history = read_channel_history(root).unwrap_or_default();
    let channel_settings =
        read_channel_settings(root).unwrap_or_else(|_| default_channel_settings());
    let plugins = list_plugins_at_root(root).unwrap_or_default();
    let marketplace = read_plugin_marketplace_entries(root).unwrap_or_default();
    let tools = read_tool_settings(root).unwrap_or_else(|_| ToolSettings::default());

    let dependency_override_count = tools.path_overrides.len();
    let dependency_source_count = tools.download_sources.len();
    let dependency_error_count = tools.install_errors.len();
    let plugin_enabled_count = plugins
        .iter()
        .filter(|plugin| plugin.state == PluginState::Enabled)
        .count();

    Ok(LocalSettingsSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        appearance: serde_json::json!({
            "language": settings.appearance.language,
            "theme": settings.appearance.theme,
            "font_scale_percent": settings.appearance.font_scale_percent,
            "density": settings.appearance.density
        }),
        downloads: serde_json::json!({
            "max_concurrency": settings.downloads.max_concurrency,
            "default_output_dir_set": settings.downloads.default_output_dir.is_some(),
            "organize_by_platform": settings.downloads.organize_by_platform,
            "filename_template": settings.downloads.filename_template,
            "skip_existing": settings.downloads.skip_existing,
            "default_quality": settings.downloads.default_quality,
            "default_audio_format": settings.downloads.default_audio_format,
            "completed_task_cleanup": settings.downloads.completed_task_cleanup,
            "archived_task_retention_days": settings.downloads.archived_task_retention_days,
            "subtitles": settings.downloads.subtitles,
            "sponsorblock": settings.downloads.sponsorblock,
            "metadata": settings.downloads.metadata
        }),
        network: serde_json::json!({
            "user_agent_set": settings.downloads.default_user_agent.is_some(),
            "referer_set": settings.downloads.default_referer.is_some(),
            "proxy_set": settings.downloads.default_proxy.is_some(),
            "rate_limit_set": settings.downloads.default_rate_limit.is_some(),
            "live_from_start": settings.downloads.default_live_from_start,
            "concurrent_fragments": settings.downloads.default_concurrent_fragments,
            "custom_ytdlp_args_set": settings.downloads.custom_ytdlp_args.is_some()
        }),
        ai: serde_json::json!({
            "provider": settings.ai.provider,
            "local_provider_enabled": settings.ai.provider == "local",
            "cloud_provider_enabled": false,
            "api_key_configured": false,
            "whisper_model": settings.ai.whisper_model,
            "whisper_language_set": settings.ai.whisper_language.is_some(),
            "whisper_task": settings.ai.whisper_task,
            "whisper_configured": media_tool_configured(root, &tools, "whisper"),
            "whisper_path_override_set": tools.path_overrides.contains_key("whisper"),
            "whisper_download_source_set": tools.download_sources.contains_key("whisper"),
            "whisper_install_error_set": tools.install_errors.contains_key("whisper"),
            "subtitle_translate_enabled": settings.ai.subtitle_translate_enabled,
            "grammar_cleanup_enabled": settings.ai.grammar_cleanup_enabled,
            "executes_ai_workflows": false,
            "includes_prompts": false,
            "includes_api_keys": false,
            "includes_file_bodies": false
        }),
        app_shell: serde_json::json!({
            "quick_capture_enabled": settings.app_shell.quick_capture_enabled,
            "quick_capture_shortcut": settings.app_shell.quick_capture_shortcut,
            "updated_at": settings.app_shell.updated_at
        }),
        advanced: serde_json::json!({
            "diagnostics_include_urls_default": settings.advanced.diagnostics_include_urls,
            "exports_diagnostics_bodies": false,
            "exports_cookie_values": false,
            "exports_auth_payload_values": false
        }),
        update: serde_json::json!({
            "enabled": update.enabled,
            "manifest_path_set": update.manifest_path.is_some(),
            "check_interval_hours": update.check_interval_hours,
            "last_checked_at": update.last_checked_at,
            "last_result": update.last_result
        }),
        extension: serde_json::json!({
            "bridge_url": extension.bridge_url,
            "bridge_discovery_ports": extension.bridge_discovery_ports,
            "token_set": extension.token_set,
            "deep_link_fallback": extension.deep_link_fallback,
            "capture_media": extension.capture_media,
            "capture_headers": extension.capture_headers,
            "blocked_host_count": extension.blocked_hosts.len()
        }),
        channels: serde_json::json!({
            "channel_count": channels.len(),
            "history_count": channel_history.len(),
            "auto_poll_enabled": channel_settings.auto_poll_enabled,
            "poll_interval_minutes": channel_settings.poll_interval_minutes,
            "last_poll_started_at": channel_settings.last_poll_started_at,
            "last_poll_finished_at": channel_settings.last_poll_finished_at,
            "last_error": channel_settings.last_error
        }),
        plugins: serde_json::json!({
            "plugin_count": plugins.len(),
            "enabled_count": plugin_enabled_count,
            "marketplace_entry_count": marketplace.len(),
            "dynamic_execution": "not_enabled_manifest_preflight_only"
        }),
        dependencies: serde_json::json!({
            "path_override_count": dependency_override_count,
            "download_source_count": dependency_source_count,
            "install_error_count": dependency_error_count
        }),
        safety_notes: vec![
            "Summary excludes Cookie, Authorization, token, and header plaintext.".to_string(),
            "AI settings summary excludes prompts, API keys, subtitle/media bodies, and workflow execution."
                .to_string(),
            "Advanced settings summary exposes only the diagnostics URL-inclusion default and excludes diagnostic bodies."
                .to_string(),
            "Plugin dynamic libraries are not executed by this summary.".to_string(),
            "Counts describe local state only and do not prove remote service parity.".to_string(),
        ],
    })
}

