fn build_update_local_summary_at_root(root: &Path) -> Result<UpdateLocalSummaryResponse, String> {
    let settings = read_update_settings(root).unwrap_or_else(|_| default_update_settings());
    let manifest_text = settings
        .manifest_path
        .as_deref()
        .and_then(|value| sanitize_optional_text(Some(value)));
    let remote_manifest_configured = manifest_text
        .as_deref()
        .is_some_and(|value| value.starts_with("http://") || value.starts_with("https://"));
    let manifest_source_kind = match manifest_text.as_deref() {
        Some(value) if value.starts_with("http://") || value.starts_with("https://") => {
            "remote_url"
        }
        Some(_) => "local_file",
        None => "not_configured",
    }
    .to_string();

    let manifest_file = if remote_manifest_configured {
        None
    } else {
        manifest_text
            .as_deref()
            .and_then(|value| validate_existing_input_file(value, "Update manifest").ok())
            .and_then(|path| local_file_summary(&path).ok())
    };

    let local_manifest = if remote_manifest_configured {
        None
    } else {
        manifest_text
            .as_deref()
            .and_then(|value| validate_existing_input_file(value, "Update manifest").ok())
            .and_then(|path| fs::read(&path).ok())
            .and_then(|bytes| serde_json::from_slice::<LocalUpdateManifestFile>(&bytes).ok())
    };

    let now = Utc::now();
    let interval = chrono::Duration::hours(i64::from(settings.check_interval_hours.max(1)));
    let last_checked = settings
        .last_checked_at
        .as_deref()
        .and_then(parse_rfc3339_timestamp);
    let next_check_at = last_checked.map(|value| (value + interval).to_rfc3339());
    let due_now = settings.enabled
        && manifest_text.is_some()
        && last_checked
            .map(|value| now.signed_duration_since(value) >= interval)
            .unwrap_or(true);

    Ok(UpdateLocalSummaryResponse {
        schema_version: 1,
        generated_at: now.to_rfc3339(),
        current_version: env!("CARGO_PKG_VERSION").to_string(),
        enabled: settings.enabled,
        manifest_configured: manifest_text.is_some(),
        manifest_source_kind,
        manifest_path: manifest_text,
        manifest_file,
        configured_manifest_version: local_manifest
            .as_ref()
            .and_then(|manifest| sanitize_optional_text(Some(&manifest.version))),
        configured_download_url_set: local_manifest
            .as_ref()
            .and_then(|manifest| sanitize_optional_text(manifest.download_url.as_deref()))
            .is_some(),
        configured_release_notes_set: local_manifest
            .as_ref()
            .and_then(|manifest| sanitize_optional_text(manifest.release_notes.as_deref()))
            .is_some(),
        check_interval_hours: settings.check_interval_hours,
        last_checked_at: settings.last_checked_at,
        last_result: settings.last_result,
        next_check_at,
        due_now,
        can_check_without_network: !remote_manifest_configured,
        remote_manifest_configured,
        signed_updater_enabled: false,
        downloads_update: false,
        installs_update: false,
        review_notes: vec![
            "This summary reads local update settings and local manifest file metadata only.".to_string(),
            "Remote manifest URLs are not fetched by this summary; use an explicit check command to perform a read-only manifest check.".to_string(),
            "No update package is downloaded, installed, signed, verified, or applied by this summary/export.".to_string(),
            "Tauri signed updater, installer replacement, rollback, and packaged smoke verification remain final-gate work.".to_string(),
        ],
    })
}

fn export_update_local_summary_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let export_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Update local summary export")?,
        None => default_update_local_summary_export_path(root),
    };
    validate_json_file_path(&export_path, "Update local summary export")?;
    if let Some(parent) = export_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let summary = build_update_local_summary_at_root(root)?;
    fs::write(
        &export_path,
        serde_json::to_vec_pretty(&summary).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write update local summary export: {error}"))?;
    Ok(DiagnosticsResponse {
        archive_path: display_path(export_path),
    })
}

#[allow(clippy::too_many_arguments)]
fn update_capability_catalog_item(
    capability: &str,
    label: &str,
    status: &str,
    commands: &[&str],
    cli_aliases: &[&str],
    desktop_ui: &[&str],
    data_files: &[&str],
    settings_fields: &[&str],
    sensitive_fields: &[&str],
    mutates_settings: bool,
    reads_local_manifest: bool,
    fetches_remote_manifest: bool,
    downloads_update: bool,
    installs_update: bool,
    verifies_signature: bool,
    emits_notifications: bool,
    supports_due_poll: bool,
    supports_batch: bool,
    scope: &str,
    limitations: &[&str],
) -> UpdateCapabilityCatalogItem {
    UpdateCapabilityCatalogItem {
        capability: capability.to_string(),
        label: label.to_string(),
        status: status.to_string(),
        commands: commands.iter().map(|value| (*value).to_string()).collect(),
        cli_aliases: cli_aliases.iter().map(|value| (*value).to_string()).collect(),
        desktop_ui: desktop_ui.iter().map(|value| (*value).to_string()).collect(),
        data_files: data_files.iter().map(|value| (*value).to_string()).collect(),
        settings_fields: settings_fields.iter().map(|value| (*value).to_string()).collect(),
        sensitive_fields: sensitive_fields.iter().map(|value| (*value).to_string()).collect(),
        mutates_settings,
        reads_local_manifest,
        fetches_remote_manifest,
        downloads_update,
        installs_update,
        verifies_signature,
        emits_notifications,
        supports_due_poll,
        supports_batch,
        scope: scope.to_string(),
        limitations: limitations.iter().map(|value| (*value).to_string()).collect(),
    }
}

