fn build_app_infrastructure_summary(
    app: &AppHandle,
    mode: AppMode,
    root: &Path,
) -> Result<AppInfrastructureSummaryResponse, String> {
    let app_status = build_app_status_at_root(mode, root);
    let shell_settings = read_app_shell_settings(root)?;
    let autostart_result = app
        .autolaunch()
        .is_enabled()
        .map_err(|error| error.to_string());
    let (autostart_available, autostart_enabled, autostart_error) = match autostart_result {
        Ok(enabled) => (true, Some(enabled), None),
        Err(error) => (false, None, Some(error)),
    };
    let quick_capture_registered = app
        .global_shortcut()
        .is_registered(shell_settings.quick_capture_shortcut.as_str());

    Ok(AppInfrastructureSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        app_status,
        autostart_available,
        autostart_enabled,
        autostart_error,
        quick_capture_enabled: shell_settings.quick_capture_enabled,
        quick_capture_shortcut: shell_settings.quick_capture_shortcut.clone(),
        quick_capture_registered: Some(quick_capture_registered),
        shell_settings,
        path_count: 7,
        review_notes: vec![
            "This summary reads local app runtime paths, portable mode, autostart status, quick-capture shell settings, and runtime shortcut registration status only.".to_string(),
            "It does not register or unregister shortcuts, change autostart, open paths, run downloads, or prove OS tray/deep-link/manual desktop behavior.".to_string(),
            "Path values are local metadata for review and may include user directory names.".to_string(),
        ],
    })
}

fn build_cli_app_infrastructure_summary(
    root: &Path,
) -> Result<AppInfrastructureSummaryResponse, String> {
    let shell_settings = read_app_shell_settings(root)?;
    let app_status = build_app_status_at_root(AppMode::Regular, root);
    Ok(AppInfrastructureSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        app_status,
        autostart_available: false,
        autostart_enabled: None,
        autostart_error: Some(
            "Autostart status is available only inside the desktop runtime.".to_string(),
        ),
        quick_capture_enabled: shell_settings.quick_capture_enabled,
        quick_capture_shortcut: shell_settings.quick_capture_shortcut.clone(),
        quick_capture_registered: None,
        shell_settings,
        path_count: 7,
        review_notes: vec![
            "This CLI summary reads local data-root paths and app shell settings only.".to_string(),
            "Portable marker detection, autostart plugin status, tray behavior, and registered shortcut state require the desktop runtime.".to_string(),
            "It does not register shortcuts, change autostart, open paths, run downloads, or prove OS shell behavior.".to_string(),
        ],
    })
}

