#[allow(clippy::too_many_arguments)]
fn app_infrastructure_capability_item(
    capability: &str,
    label: &str,
    status: &str,
    commands: &[&str],
    cli_aliases: &[&str],
    desktop_ui: &[&str],
    config_files: &[&str],
    events: &[&str],
    runtime_scope: &str,
    mutates_state: bool,
    requires_desktop_runtime: bool,
    verifies_os_behavior: bool,
    limitations: &[&str],
) -> AppInfrastructureCapabilityItem {
    AppInfrastructureCapabilityItem {
        capability: capability.to_string(),
        label: label.to_string(),
        status: status.to_string(),
        commands: commands
            .iter()
            .map(|command| (*command).to_string())
            .collect(),
        cli_aliases: cli_aliases
            .iter()
            .map(|alias| (*alias).to_string())
            .collect(),
        desktop_ui: desktop_ui
            .iter()
            .map(|surface| (*surface).to_string())
            .collect(),
        config_files: config_files
            .iter()
            .map(|file| (*file).to_string())
            .collect(),
        events: events.iter().map(|event| (*event).to_string()).collect(),
        runtime_scope: runtime_scope.to_string(),
        mutates_state,
        requires_desktop_runtime,
        verifies_os_behavior,
        limitations: limitations
            .iter()
            .map(|limitation| (*limitation).to_string())
            .collect(),
    }
}

