fn build_metadata_local_summary_at_root(
    root: &Path,
) -> Result<MetadataLocalSummaryResponse, String> {
    let downloads = read_downloads_settings(root).unwrap_or_else(|_| default_downloads_settings());
    let ai = read_ai_settings(root).unwrap_or_else(|_| default_ai_settings());
    let tool_settings = read_tool_settings(root).unwrap_or_else(|_| ToolSettings::default());
    let managed_tool_files =
        release_area_files(&root.join("dependencies"), Some(200)).unwrap_or_default();
    let managed_tool_total_size_bytes = managed_tool_files.iter().map(|file| file.size_bytes).sum();
    let waveform_cache_files =
        release_area_files(&root.join("cache").join("waveform"), Some(200)).unwrap_or_default();
    let waveform_cache_total_size_bytes = waveform_cache_files
        .iter()
        .map(|file| file.size_bytes)
        .sum();
    let sidecar_files = collect_metadata_sidecar_files(root);
    let sidecar_total_size_bytes = sidecar_files.iter().map(|file| file.size_bytes).sum();
    let sidecar_kind_counts = counted_local_entries(
        sidecar_files
            .iter()
            .map(|file| metadata_sidecar_kind(&file.file_name).to_string()),
    );
    let tool_status_counts = metadata_tool_status_counts(root, &tool_settings);

    Ok(MetadataLocalSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        data_root: display_path(root),
        default_output_dir_set: downloads.default_output_dir.is_some(),
        default_output_dir: downloads.default_output_dir.clone(),
        subtitle_language_count: downloads.subtitles.languages.len(),
        subtitle_auto_enabled: downloads.subtitles.auto,
        subtitle_embed_enabled: downloads.subtitles.embed,
        subtitle_keep_vtt_enabled: downloads.subtitles.keep_vtt,
        sponsorblock_enabled: downloads.sponsorblock.enabled,
        sponsorblock_category_count: downloads.sponsorblock.categories.len(),
        embed_metadata_enabled: downloads.metadata.embed_metadata,
        embed_thumbnail_enabled: downloads.metadata.embed_thumbnail,
        split_chapters_enabled: downloads.metadata.split_chapters,
        ai_provider: ai.provider,
        whisper_model: ai.whisper_model,
        whisper_task: ai.whisper_task,
        whisper_language_set: ai.whisper_language.is_some(),
        subtitle_translate_enabled: ai.subtitle_translate_enabled,
        grammar_cleanup_enabled: ai.grammar_cleanup_enabled,
        tool_override_count: tool_settings.path_overrides.len(),
        tool_source_count: tool_settings.download_sources.len(),
        managed_tool_file_count: managed_tool_files.len(),
        managed_tool_total_size_bytes,
        sidecar_file_count: sidecar_files.len(),
        sidecar_total_size_bytes,
        waveform_cache_file_count: waveform_cache_files.len(),
        waveform_cache_total_size_bytes,
        tool_status_counts,
        sidecar_kind_counts,
        sidecar_files,
        waveform_cache_files,
        managed_tool_files,
        includes_source_urls: false,
        includes_cookie_values: false,
        includes_authorization_values: false,
        includes_file_bodies: false,
        executes_tools: false,
        review_notes: vec![
            "This summary reads local metadata-tool settings, managed dependency file metadata, app-managed sidecar metadata, and waveform cache metadata only.".to_string(),
            "It does not call yt-dlp, gallery-dl, FFmpeg, Whisper, torrent engines, remote sites, browser storage, or OS media tools.".to_string(),
            "File entries include path, name, size, and modified time only; subtitle, comment, info-json, live-chat, media, Cookie, Authorization, and log bodies are not embedded.".to_string(),
            "Counts are local review evidence and do not prove real-site metadata extraction, download execution, subtitle quality, media processing, or final parity.".to_string(),
        ],
    })
}

