fn build_ai_local_summary_at_root(root: &Path) -> Result<AiLocalSummaryResponse, String> {
    let ai = read_ai_settings(root).unwrap_or_else(|_| default_ai_settings());
    let tool_settings = read_tool_settings(root).unwrap_or_else(|_| ToolSettings::default());
    let whisper_configured = media_tool_configured(root, &tool_settings, "whisper");
    let local_provider_enabled = ai.provider == "local";
    let review_notes = vec![
        "This summary reads local AI settings and Whisper dependency configuration metadata only."
            .to_string(),
        "It does not execute Whisper, subtitle translation, grammar cleanup, remote providers, browser storage, or downloader workflows."
            .to_string(),
        "It does not include prompts, API keys, subtitle bodies, media file bodies, Cookie values, Authorization headers, or download log bodies."
            .to_string(),
        "Cloud providers and API key storage are intentionally not enabled in this local subset; AI translate/grammar execution parity remains pending."
            .to_string(),
    ];

    Ok(AiLocalSummaryResponse {
        schema_version: 1,
        generated_at: Utc::now().to_rfc3339(),
        data_root: display_path(root),
        provider: ai.provider,
        local_provider_enabled,
        cloud_provider_enabled: false,
        api_key_configured: false,
        whisper_model: ai.whisper_model,
        whisper_task: ai.whisper_task,
        whisper_language_set: ai.whisper_language.is_some(),
        subtitle_translate_enabled: ai.subtitle_translate_enabled,
        grammar_cleanup_enabled: ai.grammar_cleanup_enabled,
        whisper_configured,
        whisper_path_override_set: tool_settings.path_overrides.contains_key("whisper"),
        whisper_download_source_set: tool_settings.download_sources.contains_key("whisper"),
        whisper_install_error: tool_settings.install_errors.get("whisper").cloned(),
        executes_ai_workflows: false,
        includes_prompts: false,
        includes_api_keys: false,
        includes_file_bodies: false,
        review_notes,
    })
}

