#[allow(clippy::too_many_arguments)]
fn plugin_capability_catalog_item(
    capability: &str,
    label: &str,
    status: &str,
    commands: &[&str],
    cli_aliases: &[&str],
    desktop_ui: &[&str],
    data_files: &[&str],
    manifest_fields: &[&str],
    registry_fields: &[&str],
    sensitive_fields: &[&str],
    mutates_registry: bool,
    mutates_marketplace: bool,
    mutates_settings: bool,
    mutates_plugin_data: bool,
    reads_manifest_files: bool,
    reads_dynamic_libraries: bool,
    executes_dynamic_code: bool,
    imports_external_files: bool,
    deletes_local_files: bool,
    fetches_remote_registry: bool,
    supports_batch: bool,
    scope: &str,
    limitations: &[&str],
) -> PluginCapabilityCatalogItem {
    PluginCapabilityCatalogItem {
        capability: capability.to_string(),
        label: label.to_string(),
        status: status.to_string(),
        commands: commands.iter().map(|value| (*value).to_string()).collect(),
        cli_aliases: cli_aliases.iter().map(|value| (*value).to_string()).collect(),
        desktop_ui: desktop_ui.iter().map(|value| (*value).to_string()).collect(),
        data_files: data_files.iter().map(|value| (*value).to_string()).collect(),
        manifest_fields: manifest_fields.iter().map(|value| (*value).to_string()).collect(),
        registry_fields: registry_fields.iter().map(|value| (*value).to_string()).collect(),
        sensitive_fields: sensitive_fields.iter().map(|value| (*value).to_string()).collect(),
        mutates_registry,
        mutates_marketplace,
        mutates_settings,
        mutates_plugin_data,
        reads_manifest_files,
        reads_dynamic_libraries,
        executes_dynamic_code,
        imports_external_files,
        deletes_local_files,
        fetches_remote_registry,
        supports_batch,
        scope: scope.to_string(),
        limitations: limitations.iter().map(|value| (*value).to_string()).collect(),
    }
}

