fn local_count_entries(values: Vec<&str>) -> Vec<LocalCountEntry> {
    let mut counts = BTreeMap::<String, usize>::new();
    for value in values {
        let key = value.trim();
        if key.is_empty() {
            continue;
        }
        *counts.entry(key.to_string()).or_insert(0) += 1;
    }
    counts
        .into_iter()
        .map(|(key, count)| LocalCountEntry { key, count })
        .collect()
}

fn plugin_state_label(state: &PluginState) -> &'static str {
    match state {
        PluginState::Installed => "installed",
        PluginState::Enabled => "enabled",
        PluginState::Disabled => "disabled",
        PluginState::Failed => "failed",
        PluginState::Incompatible => "incompatible",
    }
}

fn default_channel_settings() -> ChannelSettings {
    ChannelSettings {
        schema_version: 1,
        auto_poll_enabled: false,
        poll_interval_minutes: 60,
        last_poll_started_at: None,
        last_poll_finished_at: None,
        last_error: None,
    }
}

fn read_channel_settings(root: &Path) -> Result<ChannelSettings, String> {
    let path = channel_settings_path(root);
    if !path.exists() {
        return Ok(default_channel_settings());
    }
    let bytes = fs::read(path).map_err(|error| error.to_string())?;
    let mut settings: ChannelSettings =
        serde_json::from_slice(&bytes).map_err(|error| error.to_string())?;
    settings.schema_version = 1;
    settings.poll_interval_minutes = settings.poll_interval_minutes.clamp(5, 1440);
    Ok(settings)
}

fn write_channel_settings(
    root: &Path,
    settings: &ChannelSettings,
) -> Result<ChannelSettings, String> {
    let mut sanitized = settings.clone();
    sanitized.schema_version = 1;
    sanitized.poll_interval_minutes = sanitized.poll_interval_minutes.clamp(5, 1440);
    let path = channel_settings_path(root);
    if let Some(parent) = path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::write(
        path,
        serde_json::to_vec_pretty(&sanitized).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;
    Ok(sanitized)
}

