fn default_course_capability_catalog_export_path(root: &Path) -> PathBuf {
    root.join("courses").join("exports").join(format!(
        "fetchdock-course-capability-catalog-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn export_course_capability_catalog_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<DiagnosticsResponse, String> {
    let export_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Course capability catalog export")?,
        None => default_course_capability_catalog_export_path(root),
    };
    validate_json_file_path(&export_path, "Course capability catalog export")?;
    if let Some(parent) = export_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let catalog = build_course_capability_catalog_at_root(root);
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "fetchdock.course_capability_catalog",
        "catalog": catalog,
        "includes_cookie_values": false,
        "includes_note_bodies": false,
        "includes_downloaded_files": false,
        "reads_remote_platforms": false,
        "verifies_platform_login_e2e": false,
        "verifies_remote_attachment_crawl": false,
        "verifies_course_player_e2e": false,
    });
    fs::write(
        &export_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Unable to write Course capability catalog export: {error}"))?;
    Ok(DiagnosticsResponse {
        archive_path: display_path(export_path),
    })
}

fn build_course_entry(url: &str, title_hint: Option<&str>, status: &str) -> CourseEntry {
    let platform = course_platform_from_url(url);
    let title = sanitize_optional_text(title_hint).unwrap_or_else(|| {
        format!(
            "{} course",
            platform
                .split('_')
                .map(|part| {
                    let mut chars = part.chars();
                    match chars.next() {
                        Some(first) => format!("{}{}", first.to_ascii_uppercase(), chars.as_str()),
                        None => String::new(),
                    }
                })
                .collect::<Vec<_>>()
                .join(" ")
        )
    });
    let mut hasher = Sha256::new();
    hasher.update(url.as_bytes());
    let digest = hasher.finalize();
    let id = digest
        .iter()
        .take(10)
        .map(|byte| format!("{byte:02x}"))
        .collect::<String>();
    let now = Utc::now().to_rfc3339();
    CourseEntry {
        schema_version: 1,
        id: format!("course-{id}"),
        source_url: url.to_string(),
        platform,
        title,
        lesson_count: 0,
        attachment_count: 0,
        status: status.to_string(),
        cookie_bucket_id: None,
        remote_extraction_note: None,
        lessons: Vec::new(),
        attachments: Vec::new(),
        created_at: now.clone(),
        updated_at: now,
    }
}

fn build_course_candidate_entry_at_root(
    root: &Path,
    url: &str,
    request: &CourseProbeRequest,
    status: &str,
) -> Result<CourseEntry, String> {
    let mut entry = build_course_entry(url, request.title_hint.as_deref(), status);
    entry.cookie_bucket_id =
        resolve_course_cookie_bucket_id(root, request.cookie_bucket_id.as_deref(), None)?;
    Ok(entry)
}

fn annotate_course_remote_extraction_failure(entry: &mut CourseEntry, error: &str) {
    entry.remote_extraction_note = Some(format!(
        "Remote outline extraction fallback: {}",
        sanitize_course_remote_error(error)
    ));
    entry.updated_at = Utc::now().to_rfc3339();
}

fn sanitize_course_remote_error(error: &str) -> String {
    let mut text = error.replace('\r', " ").replace('\n', " ");
    for marker in [
        "Cookie:",
        "Authorization:",
        "Bearer ",
        "token=",
        "key=",
        "api_key=",
    ] {
        text = redact_text_after_marker(&text, marker);
    }
    let collapsed = text.split_whitespace().collect::<Vec<_>>().join(" ");
    if collapsed.chars().count() > 240 {
        format!("{}...", collapsed.chars().take(240).collect::<String>())
    } else if collapsed.is_empty() {
        "metadata tool returned no diagnostic text".to_string()
    } else {
        collapsed
    }
}

fn redact_text_after_marker(text: &str, marker: &str) -> String {
    let lower = text.to_ascii_lowercase();
    let marker_lower = marker.to_ascii_lowercase();
    let Some(index) = lower.find(&marker_lower) else {
        return text.to_string();
    };
    let end = text[index + marker.len()..]
        .find(char::is_whitespace)
        .map(|offset| index + marker.len() + offset)
        .unwrap_or(text.len());
    format!("{}{}<redacted>{}", &text[..index], marker, &text[end..])
}

fn build_course_entry_with_remote_outline(
    root: &Path,
    url: &str,
    request: &CourseProbeRequest,
    status: &str,
) -> Result<CourseEntry, String> {
    let cookie_bucket_id =
        resolve_course_cookie_bucket_id(root, request.cookie_bucket_id.as_deref(), None)?;
    let base_request = MetadataProbeRequest {
        source_url: url.to_string(),
        user_agent: None,
        referer: None,
        proxy: None,
        cookie_bucket_id: cookie_bucket_id.clone(),
        auth_payload_ref: None,
        rate_limit: None,
    };
    let mut entry = build_course_entry(url, request.title_hint.as_deref(), status);
    entry.cookie_bucket_id = cookie_bucket_id.clone();

    let playlist = metadata_probe_playlist_at_root(
        root,
        MetadataPlaylistProbeRequest {
            source_url: url.to_string(),
            limit: Some(250),
            user_agent: None,
            referer: None,
            proxy: None,
            cookie_bucket_id: cookie_bucket_id.clone(),
            auth_payload_ref: None,
            rate_limit: None,
        },
    );

    match playlist {
        Ok(preview) if !preview.entries.is_empty() => {
            apply_course_playlist_outline(&mut entry, preview, request.title_hint.as_deref());
            entry.status = format!("{status}_remote_outline");
            Ok(entry)
        }
        _ => {
            let preview = metadata_probe_url_at_root(root, base_request)?;
            apply_course_single_lesson_outline(&mut entry, preview, request.title_hint.as_deref());
            entry.status = format!("{status}_remote_outline");
            Ok(entry)
        }
    }
}

fn apply_course_playlist_outline(
    entry: &mut CourseEntry,
    preview: MetadataPlaylistPreview,
    title_hint: Option<&str>,
) {
    if let Some(title) = sanitize_optional_text(title_hint).or(preview.title.clone()) {
        entry.title = title;
    }
    entry.source_url = preview.source_url;
    entry.platform = course_platform_from_url(&entry.source_url);
    entry.lessons = preview
        .entries
        .into_iter()
        .enumerate()
        .filter_map(|(index, item)| course_lesson_from_playlist_entry(&entry.id, index, item))
        .collect();
    entry.lesson_count = entry.lessons.len();
    entry.attachment_count = entry.attachments.len();
    entry.updated_at = Utc::now().to_rfc3339();
}

fn apply_course_single_lesson_outline(
    entry: &mut CourseEntry,
    preview: MetadataPreview,
    title_hint: Option<&str>,
) {
    let title = sanitize_optional_text(title_hint)
        .or(preview.title.clone())
        .unwrap_or_else(|| entry.title.clone());
    entry.title = title.clone();
    entry.source_url = preview.source_url.clone();
    entry.platform = course_platform_from_url(&entry.source_url);
    entry.lessons = vec![CourseLesson {
        id: stable_child_id("lesson", &entry.id, 0, &preview.source_url),
        title,
        source_url: Some(preview.source_url),
        local_path: None,
        duration_seconds: preview.duration_seconds,
        progress_percent: 0,
        note_count: 0,
        opened_at: None,
    }];
    entry.attachments = preview
        .thumbnail_url
        .and_then(|thumbnail_url| course_thumbnail_attachment(&entry.id, &thumbnail_url))
        .unwrap_or_default();
    entry.lesson_count = entry.lessons.len();
    entry.attachment_count = entry.attachments.len();
    entry.updated_at = Utc::now().to_rfc3339();
}

fn course_lesson_from_playlist_entry(
    course_id: &str,
    index: usize,
    item: MetadataPlaylistEntry,
) -> Option<CourseLesson> {
    let source_url = item
        .webpage_url
        .or_else(|| absolute_http_url_from_candidate(item.url.as_deref()));
    let title = sanitize_optional_text(item.title.as_deref()).unwrap_or_else(|| {
        item.id
            .as_deref()
            .map(|id| format!("Lesson {id}"))
            .unwrap_or_else(|| format!("Lesson {}", index + 1))
    });
    let id_seed = source_url.as_deref().unwrap_or(&title);
    Some(CourseLesson {
        id: stable_child_id("lesson", course_id, index, id_seed),
        title,
        source_url,
        local_path: None,
        duration_seconds: item.duration_seconds,
        progress_percent: 0,
        note_count: 0,
        opened_at: None,
    })
}

fn absolute_http_url_from_candidate(value: Option<&str>) -> Option<String> {
    let value = value?.trim();
    if value.starts_with("http://") || value.starts_with("https://") {
        Some(value.to_string())
    } else {
        None
    }
}

fn course_thumbnail_attachment(
    course_id: &str,
    thumbnail_url: &str,
) -> Option<Vec<CourseAttachment>> {
    let source_url = absolute_http_url_from_candidate(Some(thumbnail_url))?;
    Some(vec![CourseAttachment {
        id: stable_child_id("attachment", course_id, 0, &source_url),
        title: "Course thumbnail".to_string(),
        source_url: Some(source_url),
        local_path: None,
        size_bytes: 0,
        kind: "thumbnail".to_string(),
    }])
}

fn import_course_manifest_at_root(
    root: &Path,
    request: CourseManifestImportRequest,
) -> Result<CourseEntry, String> {
    let manifest_path = validate_existing_input_file(&request.manifest_path, "Course manifest")?;
    let bytes = fs::read(&manifest_path).map_err(|error| error.to_string())?;
    let mut entry: CourseEntry = serde_json::from_slice(&bytes)
        .map_err(|error| format!("Course manifest must be FetchDock JSON: {error}"))?;
    if let Some(cookie_bucket_id) = sanitize_cookie_bucket_id(request.cookie_bucket_id.as_deref()) {
        entry.cookie_bucket_id = Some(cookie_bucket_id);
    }
    normalize_course_entry(root, &mut entry, Some(&manifest_path))?;
    let mut courses = read_courses(root)?;
    courses.retain(|course| course.id != entry.id);
    courses.push(entry.clone());
    write_courses(root, &courses)?;
    Ok(entry)
}

fn import_course_manifest_bundle_at_root(
    root: &Path,
    request: CourseManifestBundleImportRequest,
) -> Result<CourseManifestBundleImportResponse, String> {
    let manifest_path = validate_existing_input_file(&request.manifest_path, "Course bundle")?;
    let bytes = fs::read(&manifest_path).map_err(|error| error.to_string())?;
    let value: serde_json::Value = serde_json::from_slice(&bytes)
        .map_err(|error| format!("Course bundle must be FetchDock JSON: {error}"))?;
    let kind = value
        .get("kind")
        .and_then(|value| value.as_str())
        .unwrap_or_default();
    if kind != "fetchdock.courses" {
        return Err("Course bundle kind must be fetchdock.courses.".to_string());
    }
    let course_values = value
        .get("courses")
        .and_then(|value| value.as_array())
        .ok_or_else(|| "Course bundle must include a courses array.".to_string())?;
    if course_values.is_empty() {
        return Err("Course bundle does not contain any courses.".to_string());
    }

    let mut imported = Vec::new();
    let mut seen_ids = HashSet::new();
    let cookie_bucket_id = sanitize_cookie_bucket_id(request.cookie_bucket_id.as_deref());
    for course_value in course_values {
        let mut entry: CourseEntry = serde_json::from_value(course_value.clone())
            .map_err(|error| format!("Course bundle contains an invalid course: {error}"))?;
        if let Some(cookie_bucket_id) = &cookie_bucket_id {
            entry.cookie_bucket_id = Some(cookie_bucket_id.clone());
        }
        normalize_course_entry(root, &mut entry, Some(&manifest_path))?;
        if !seen_ids.insert(entry.id.clone()) {
            continue;
        }
        imported.push(entry);
    }
    if imported.is_empty() {
        return Err("Course bundle did not contain any unique courses.".to_string());
    }

    let imported_ids: HashSet<String> = imported.iter().map(|course| course.id.clone()).collect();
    let mut courses = read_courses(root)?;
    courses.retain(|course| !imported_ids.contains(&course.id));
    courses.extend(imported.clone());
    write_courses(root, &courses)?;

    Ok(CourseManifestBundleImportResponse {
        schema_version: 1,
        imported_count: imported.len(),
        courses: imported,
    })
}

fn export_course_manifest_at_root(
    root: &Path,
    request: CourseManifestExportRequest,
) -> Result<CourseManifestExportResponse, String> {
    let mut courses = read_courses(root)?;
    if let Some(ids) = request.course_ids {
        let requested = sanitize_course_ids(ids)?;
        let requested_set: HashSet<&str> = requested.iter().map(String::as_str).collect();
        courses.retain(|course| requested_set.contains(course.id.as_str()));
    }
    if courses.is_empty() {
        return Err("No courses are available to export.".to_string());
    }

    let output_path = match request
        .output_path
        .and_then(|value| sanitize_optional_text(Some(&value)))
    {
        Some(path) => validate_output_file_path(&path, "Course manifest export")?,
        None => default_course_manifest_export_path(root),
    };
    validate_json_file_path(&output_path, "Course manifest export")?;
    if let Some(parent) = output_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }

    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "fetchdock.courses",
        "exported_at": Utc::now().to_rfc3339(),
        "course_count": courses.len(),
        "courses": courses
    });
    fs::write(
        &output_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Failed to write course manifest export: {error}"))?;

    Ok(CourseManifestExportResponse {
        schema_version: 1,
        output_path: display_path(output_path),
        exported_count: payload
            .get("course_count")
            .and_then(|value| value.as_u64())
            .unwrap_or_default() as usize,
    })
}

fn default_course_progress_export_path(root: &Path) -> PathBuf {
    root.join("courses").join("exports").join(format!(
        "fetchdock-course-progress-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn export_course_progress_at_root(
    root: &Path,
    request: CourseProgressExportRequest,
) -> Result<CourseProgressExportResponse, String> {
    let mut courses = read_courses(root)?;
    if let Some(ids) = request.course_ids {
        let requested = sanitize_course_ids(ids)?;
        let requested_set: HashSet<&str> = requested.iter().map(String::as_str).collect();
        courses.retain(|course| requested_set.contains(course.id.as_str()));
    }
    if courses.is_empty() {
        return Err("No courses are available to export progress from.".to_string());
    }

    let progress_courses = courses
        .iter()
        .filter_map(|course| {
            let lessons = course
                .lessons
                .iter()
                .filter(|lesson| {
                    lesson.progress_percent > 0
                        || lesson.opened_at.is_some()
                        || lesson.note_count > 0
                })
                .map(|lesson| CourseProgressBackupLesson {
                    id: lesson.id.clone(),
                    title: lesson.title.clone(),
                    progress_percent: lesson.progress_percent.min(100),
                    note_count: lesson.note_count,
                    opened_at: lesson.opened_at.clone(),
                })
                .collect::<Vec<_>>();
            if lessons.is_empty() {
                return None;
            }
            Some(CourseProgressBackupCourse {
                id: course.id.clone(),
                title: course.title.clone(),
                platform: course.platform.clone(),
                lessons,
            })
        })
        .collect::<Vec<_>>();
    if progress_courses.is_empty() {
        return Err("No course lesson progress is available to export.".to_string());
    }

    let output_path = match request
        .output_path
        .and_then(|value| sanitize_optional_text(Some(&value)))
    {
        Some(path) => validate_output_file_path(&path, "Course progress export")?,
        None => default_course_progress_export_path(root),
    };
    validate_json_file_path(&output_path, "Course progress export")?;
    if let Some(parent) = output_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }

    let exported_lesson_count = progress_courses
        .iter()
        .map(|course| course.lessons.len())
        .sum::<usize>();
    let payload = serde_json::json!({
        "schema_version": 1,
        "kind": "fetchdock.course_progress",
        "exported_at": Utc::now().to_rfc3339(),
        "course_count": progress_courses.len(),
        "lesson_count": exported_lesson_count,
        "courses": progress_courses
    });
    fs::write(
        &output_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Failed to write course progress export: {error}"))?;

    Ok(CourseProgressExportResponse {
        schema_version: 1,
        output_path: display_path(output_path),
        exported_course_count: payload
            .get("course_count")
            .and_then(|value| value.as_u64())
            .unwrap_or_default() as usize,
        exported_lesson_count,
    })
}

fn import_course_progress_at_root(
    root: &Path,
    request: CourseProgressImportRequest,
) -> Result<CourseProgressImportResponse, String> {
    let input_path = validate_existing_input_file(&request.input_path, "Course progress import")?;
    validate_json_file_path(&input_path, "Course progress import")?;
    let metadata = fs::metadata(&input_path).map_err(|error| error.to_string())?;
    if metadata.len() > 4 * 1024 * 1024 {
        return Err("Course progress import is limited to files up to 4 MB.".to_string());
    }
    let raw: serde_json::Value = serde_json::from_slice(
        &fs::read(&input_path)
            .map_err(|error| format!("Unable to read course progress import: {error}"))?,
    )
    .map_err(|error| format!("Invalid course progress JSON: {error}"))?;
    let raw_courses = raw
        .get("courses")
        .and_then(|value| value.as_array())
        .ok_or_else(|| "Course progress JSON must include a courses array.".to_string())?;
    if raw_courses.is_empty() {
        return Err("Course progress JSON does not contain any courses.".to_string());
    }
    let incoming = raw_courses
        .iter()
        .map(|value| {
            serde_json::from_value::<CourseProgressBackupCourse>(value.clone())
                .map_err(|error| format!("Invalid course progress entry: {error}"))
        })
        .collect::<Result<Vec<_>, _>>()?;

    let mut courses = read_courses(root)?;
    let mut imported_course_ids = HashSet::new();
    let mut imported_lesson_count = 0_usize;
    let mut skipped_course_count = 0_usize;
    let mut skipped_lesson_count = 0_usize;
    let now = Utc::now().to_rfc3339();

    for incoming_course in incoming {
        let course_id = match sanitize_optional_text(Some(&incoming_course.id)) {
            Some(value) => value,
            None => {
                skipped_course_count = skipped_course_count.saturating_add(1);
                skipped_lesson_count =
                    skipped_lesson_count.saturating_add(incoming_course.lessons.len());
                continue;
            }
        };
        let Some(course) = courses.iter_mut().find(|course| course.id == course_id) else {
            skipped_course_count = skipped_course_count.saturating_add(1);
            skipped_lesson_count =
                skipped_lesson_count.saturating_add(incoming_course.lessons.len());
            continue;
        };

        let mut changed = false;
        for incoming_lesson in incoming_course.lessons {
            let lesson_id = match sanitize_optional_text(Some(&incoming_lesson.id)) {
                Some(value) => value,
                None => {
                    skipped_lesson_count = skipped_lesson_count.saturating_add(1);
                    continue;
                }
            };
            let Some(lesson) = course
                .lessons
                .iter_mut()
                .find(|lesson| lesson.id == lesson_id)
            else {
                skipped_lesson_count = skipped_lesson_count.saturating_add(1);
                continue;
            };
            lesson.progress_percent = incoming_lesson.progress_percent.min(100);
            lesson.note_count = incoming_lesson.note_count;
            lesson.opened_at = incoming_lesson.opened_at;
            imported_lesson_count = imported_lesson_count.saturating_add(1);
            imported_course_ids.insert(course_id.clone());
            changed = true;
        }
        if changed {
            course.updated_at = now.clone();
        }
    }

    if imported_lesson_count > 0 {
        write_courses(root, &courses)?;
    }
    let updated_courses = courses
        .into_iter()
        .filter(|course| imported_course_ids.contains(&course.id))
        .collect::<Vec<_>>();

    Ok(CourseProgressImportResponse {
        schema_version: 1,
        imported_course_count: imported_course_ids.len(),
        imported_lesson_count,
        skipped_course_count,
        skipped_lesson_count,
        courses: updated_courses,
    })
}

fn sanitize_course_ids(ids: Vec<String>) -> Result<Vec<String>, String> {
    let mut sanitized = Vec::new();
    for id in ids {
        let value = sanitize_required_text(&id, "Course id")?;
        if !sanitized.iter().any(|existing| existing == &value) {
            sanitized.push(value);
        }
    }
    if sanitized.is_empty() {
        return Err("At least one course id is required.".to_string());
    }
    Ok(sanitized)
}

fn default_course_manifest_export_path(root: &Path) -> PathBuf {
    root.join("courses").join("exports").join(format!(
        "fetchdock-courses-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn delete_course_at_root(root: &Path, request: CourseIdRequest) -> Result<bool, String> {
    let course_id = sanitize_required_text(&request.course_id, "Course id")?;
    let mut courses = read_courses(root)?;
    let original_len = courses.len();
    courses.retain(|course| course.id != course_id);
    if courses.len() == original_len {
        return Ok(false);
    }
    write_courses(root, &courses)?;
    Ok(true)
}

fn delete_courses_at_root(
    root: &Path,
    request: CourseIdsRequest,
) -> Result<CourseBulkDeleteResponse, String> {
    let mut requested = Vec::new();
    let mut failed = Vec::new();
    for id in request.course_ids {
        match sanitize_required_text(&id, "Course id") {
            Ok(value) => {
                if !requested.iter().any(|item| item == &value) {
                    requested.push(value);
                }
            }
            Err(error) => failed.push(BulkDownloadFailure { id, error }),
        }
    }
    if requested.is_empty() {
        return Err("At least one course id is required.".to_string());
    }

    let mut courses = read_courses(root)?;
    let existing: HashSet<String> = courses.iter().map(|course| course.id.clone()).collect();
    let mut deleted = Vec::new();
    for id in requested {
        if existing.contains(&id) {
            deleted.push(id);
        } else {
            failed.push(BulkDownloadFailure {
                id,
                error: "Course was not found.".to_string(),
            });
        }
    }
    if !deleted.is_empty() {
        let deleted_set: HashSet<&str> = deleted.iter().map(String::as_str).collect();
        courses.retain(|course| !deleted_set.contains(course.id.as_str()));
        write_courses(root, &courses)?;
    }

    Ok(CourseBulkDeleteResponse { deleted, failed })
}

fn clear_courses_at_root(root: &Path) -> Result<usize, String> {
    let courses = read_courses(root)?;
    let cleared = courses.len();
    write_courses(root, &[])?;
    Ok(cleared)
}

fn delete_course_lesson_at_root(
    root: &Path,
    request: CourseLessonDeleteRequest,
) -> Result<CourseItemDeleteResponse, String> {
    let course_id = sanitize_required_text(&request.course_id, "Course id")?;
    let lesson_id = sanitize_required_text(&request.lesson_id, "Lesson id")?;
    let mut courses = read_courses(root)?;
    let Some(course) = courses.iter_mut().find(|course| course.id == course_id) else {
        return Err(format!("Course was not found: {course_id}"));
    };
    let original_len = course.lessons.len();
    course.lessons.retain(|lesson| lesson.id != lesson_id);
    let deleted = course.lessons.len() != original_len;
    if deleted {
        course.lesson_count = course.lessons.len();
        course.updated_at = Utc::now().to_rfc3339();
    }
    let updated = course.clone();
    if deleted {
        write_courses(root, &courses)?;
    }
    Ok(CourseItemDeleteResponse {
        deleted,
        course: updated,
    })
}

fn delete_course_lessons_at_root(
    root: &Path,
    request: CourseLessonsBulkDeleteRequest,
) -> Result<CourseItemBulkDeleteResponse, String> {
    if request.courses.is_empty() {
        return Err("At least one course lesson delete group is required.".to_string());
    }

    let mut courses = read_courses(root)?;
    let now = Utc::now().to_rfc3339();
    let mut deleted = Vec::new();
    let mut failed = Vec::new();
    let mut changed_course_ids = HashSet::new();
    let mut seen = HashSet::new();

    for group in request.courses {
        let course_id = match sanitize_required_text(&group.course_id, "Course id") {
            Ok(value) => value,
            Err(error) => {
                failed.push(BulkDownloadFailure {
                    id: group.course_id,
                    error,
                });
                continue;
            }
        };
        let Some(course) = courses.iter_mut().find(|course| course.id == course_id) else {
            failed.push(BulkDownloadFailure {
                id: course_id,
                error: "Course was not found.".to_string(),
            });
            continue;
        };
        for raw_lesson_id in group.lesson_ids {
            let lesson_id = match sanitize_required_text(&raw_lesson_id, "Lesson id") {
                Ok(value) => value,
                Err(error) => {
                    failed.push(BulkDownloadFailure {
                        id: raw_lesson_id,
                        error,
                    });
                    continue;
                }
            };
            let pair_key = format!("{course_id}\n{lesson_id}");
            if !seen.insert(pair_key) {
                continue;
            }
            let before = course.lessons.len();
            course.lessons.retain(|lesson| lesson.id != lesson_id);
            if course.lessons.len() != before {
                course.lesson_count = course.lessons.len();
                course.updated_at = now.clone();
                changed_course_ids.insert(course_id.clone());
                deleted.push(format!("{course_id}:{lesson_id}"));
            } else {
                failed.push(BulkDownloadFailure {
                    id: format!("{course_id}:{lesson_id}"),
                    error: "Course lesson was not found.".to_string(),
                });
            }
        }
    }

    if !deleted.is_empty() {
        write_courses(root, &courses)?;
    }
    let changed_courses = courses
        .into_iter()
        .filter(|course| changed_course_ids.contains(&course.id))
        .collect();

    Ok(CourseItemBulkDeleteResponse {
        deleted,
        failed,
        courses: changed_courses,
    })
}

