fn prune_missing_course_local_files_at_root(
    root: &Path,
) -> Result<CoursePruneMissingResponse, String> {
    let mut courses = read_courses(root)?;
    let mut pruned_lessons = 0_usize;
    let mut pruned_attachments = 0_usize;
    let now = Utc::now().to_rfc3339();

    for course in &mut courses {
        let mut changed = false;
        for lesson in &mut course.lessons {
            let Some(local_path) = lesson.local_path.as_deref() else {
                continue;
            };
            if !Path::new(local_path).exists() {
                lesson.local_path = None;
                pruned_lessons = pruned_lessons.saturating_add(1);
                changed = true;
            }
        }
        for attachment in &mut course.attachments {
            let Some(local_path) = attachment.local_path.as_deref() else {
                continue;
            };
            if !Path::new(local_path).exists() {
                attachment.local_path = None;
                pruned_attachments = pruned_attachments.saturating_add(1);
                changed = true;
            }
        }
        if changed {
            course.updated_at = now.clone();
        }
    }

    if pruned_lessons > 0 || pruned_attachments > 0 {
        write_courses(root, &courses)?;
    }

    Ok(CoursePruneMissingResponse {
        courses,
        pruned_lessons,
        pruned_attachments,
    })
}

fn update_course_progress_at_root(
    root: &Path,
    request: CourseProgressUpdateRequest,
) -> Result<CourseEntry, String> {
    let course_id = sanitize_required_text(&request.course_id, "Course id")?;
    let lesson_id = sanitize_required_text(&request.lesson_id, "Lesson id")?;
    let mut courses = read_courses(root)?;
    let Some(course) = courses.iter_mut().find(|course| course.id == course_id) else {
        return Err(format!("Course was not found: {course_id}"));
    };
    let Some(lesson) = course
        .lessons
        .iter_mut()
        .find(|lesson| lesson.id == lesson_id)
    else {
        return Err(format!("Course lesson was not found: {lesson_id}"));
    };
    lesson.progress_percent = request.progress_percent.min(100);
    course.updated_at = Utc::now().to_rfc3339();
    let updated = course.clone();
    write_courses(root, &courses)?;
    Ok(updated)
}

fn open_course_lesson_at_root(
    root: &Path,
    request: CourseLessonOpenRequest,
) -> Result<CourseEntry, String> {
    let course_id = sanitize_required_text(&request.course_id, "Course id")?;
    let lesson_id = sanitize_required_text(&request.lesson_id, "Lesson id")?;
    let mut courses = read_courses(root)?;
    let Some(course) = courses.iter_mut().find(|course| course.id == course_id) else {
        return Err(format!("Course was not found: {course_id}"));
    };
    let Some(lesson) = course
        .lessons
        .iter_mut()
        .find(|lesson| lesson.id == lesson_id)
    else {
        return Err(format!("Course lesson was not found: {lesson_id}"));
    };
    let local_path = lesson
        .local_path
        .as_deref()
        .ok_or_else(|| "Lesson does not have a local media path.".to_string())?;
    let path = PathBuf::from(local_path);
    if !path.exists() {
        return Err(format!(
            "Lesson media was not found: {}",
            display_path(&path)
        ));
    }
    tauri_plugin_opener::open_path(&path, None::<&str>).map_err(|error| error.to_string())?;
    let now = Utc::now().to_rfc3339();
    lesson.opened_at = Some(now.clone());
    course.updated_at = now;
    let updated = course.clone();
    write_courses(root, &courses)?;
    Ok(updated)
}

