fn queue_many_course_lessons_at_root(
    root: &Path,
    request: CourseLessonQueueManyRequest,
) -> Result<CourseLessonQueueManyResponse, String> {
    if request.courses.is_empty() {
        return Err("At least one course lesson queue group is required.".to_string());
    }

    let courses = read_courses(root)?;
    let settings = read_downloads_settings(root)?;
    let mut tasks = read_download_tasks(root)?;
    let mut position = tasks.iter().map(|task| task.position).max().unwrap_or(0);
    let now = Utc::now().to_rfc3339();
    let mut created = Vec::new();
    let mut skipped = Vec::new();
    let mut failed = Vec::new();
    let mut seen = HashSet::new();

    for group in request.courses {
        let course_id = match sanitize_required_text(&group.course_id, "Course id") {
            Ok(value) => value,
            Err(error) => {
                failed.push(BulkDownloadFailure {
                    id: group.course_id,
                    error,
                });
                continue;
            }
        };
        let Some(course) = courses.iter().find(|course| course.id == course_id) else {
            failed.push(BulkDownloadFailure {
                id: course_id,
                error: "Course was not found.".to_string(),
            });
            continue;
        };
        let output_dir = match validate_output_dir(group.output_dir.as_deref()) {
            Ok(value) => value,
            Err(error) => {
                failed.push(BulkDownloadFailure {
                    id: course_id,
                    error,
                });
                continue;
            }
        };
        let create_options = group.create_options.clone();
        let cookie_bucket_id = match resolve_course_cookie_bucket_id(
            root,
            group.cookie_bucket_id.as_deref(),
            course.cookie_bucket_id.as_deref(),
        ) {
            Ok(value) => value,
            Err(error) => {
                failed.push(BulkDownloadFailure {
                    id: course_id,
                    error,
                });
                continue;
            }
        };
        if group.lesson_ids.is_empty() {
            failed.push(BulkDownloadFailure {
                id: course_id,
                error: "At least one lesson id is required.".to_string(),
            });
            continue;
        }
        for raw_lesson_id in group.lesson_ids {
            let lesson_id = match sanitize_required_text(&raw_lesson_id, "Lesson id") {
                Ok(value) => value,
                Err(error) => {
                    failed.push(BulkDownloadFailure {
                        id: raw_lesson_id,
                        error,
                    });
                    continue;
                }
            };
            if !seen.insert(format!("{course_id}:{lesson_id}")) {
                skipped.push(CourseLessonQueueManySkippedItem {
                    course_id: course_id.clone(),
                    lesson_id,
                    title: "Duplicate lesson".to_string(),
                    reason: "duplicate_lesson".to_string(),
                });
                continue;
            }
            let Some(lesson) = course.lessons.iter().find(|lesson| lesson.id == lesson_id) else {
                failed.push(BulkDownloadFailure {
                    id: format!("{course_id}:{lesson_id}"),
                    error: "Course lesson was not found.".to_string(),
                });
                continue;
            };
            let Some(source_url) = lesson.source_url.clone() else {
                skipped.push(CourseLessonQueueManySkippedItem {
                    course_id: course_id.clone(),
                    lesson_id: lesson.id.clone(),
                    title: lesson.title.clone(),
                    reason: "missing_source_url".to_string(),
                });
                continue;
            };
            position += 1;
            let mut task = build_download_task_from_request_with_settings(
                apply_download_create_options(
                    CreateDownloadRequest {
                        source_url,
                        kind: Some(DownloadKind::CourseLesson),
                        output_dir: output_dir.clone(),
                        output_path: None,
                        title_override: Some(format!("{} - {}", course.title, lesson.title)),
                        user_agent: None,
                        referer: None,
                        proxy: None,
                        cookie_bucket_id: cookie_bucket_id.clone(),
                        auth_payload_ref: None,
                        rate_limit: None,
                        live_from_start: None,
                        concurrent_fragments: None,
                        custom_ytdlp_args: None,
                        start_seconds: None,
                        end_seconds: None,
                        quality: None,
                        audio_format: None,
                        thumbnail_url: None,
                        expected_sha256: None,
                        subtitles: None,
                        sponsorblock: None,
                        metadata: None,

                        run_after_active_slot: None,
                    },
                    create_options.clone(),
                ),
                position,
                &now,
                &settings,
            )?;
            task.platform = course.platform.clone();
            task.details_json = Some(course_lesson_task_details(course, lesson));
            tasks.push(task.clone());
            created.push(task);
        }
    }

    if !created.is_empty() {
        write_download_tasks(root, &tasks)?;
    }

    Ok(CourseLessonQueueManyResponse {
        created,
        skipped,
        failed,
    })
}

