fn sanitize_music_sleep_timer_state(mut state: MusicSleepTimerState) -> MusicSleepTimerState {
    state.schema_version = 1;
    state.duration_minutes = state.duration_minutes.clamp(1, 360);
    if !state.enabled {
        state.started_at = None;
        state.ends_at = None;
    }
    state.updated_at = Utc::now().to_rfc3339();
    state
}

fn sanitize_music_equalizer_state(mut state: MusicEqualizerState) -> MusicEqualizerState {
    state.schema_version = 1;
    state.preset = sanitize_music_equalizer_preset(&state.preset);
    state.bass_gain_db = state.bass_gain_db.clamp(-12, 12);
    state.mid_gain_db = state.mid_gain_db.clamp(-12, 12);
    state.treble_gain_db = state.treble_gain_db.clamp(-12, 12);
    if state.preset != "custom" {
        apply_music_equalizer_preset(&mut state);
    }
    state.updated_at = Utc::now().to_rfc3339();
    state
}

fn sanitize_cookie_header_setting(value: &str) -> Result<String, String> {
    let value = sanitize_required_text(value, "Cookie header")?;
    if value.contains('\r') || value.contains('\n') {
        return Err("Cookie header cannot contain line breaks.".to_string());
    }
    if value.len() > 16 * 1024 {
        return Err("Cookie header is too long.".to_string());
    }
    let pairs = value
        .split(';')
        .map(str::trim)
        .filter(|part| !part.is_empty())
        .collect::<Vec<_>>();
    if pairs.is_empty()
        || !pairs.iter().all(|part| {
            part.split_once('=')
                .is_some_and(|(name, _)| !name.trim().is_empty())
        })
    {
        return Err(
            "Cookie header must contain name=value pairs separated by semicolons.".to_string(),
        );
    }
    Ok(pairs.join("; "))
}

fn cookie_header_preview(value: &str) -> String {
    let pair_count = value.split(';').filter(|part| part.contains('=')).count();
    let names = value
        .split(';')
        .filter_map(|part| {
            part.trim()
                .split_once('=')
                .map(|(name, _)| name.trim().to_string())
        })
        .filter(|name| !name.is_empty())
        .take(4)
        .collect::<Vec<_>>();
    if names.is_empty() {
        "stored cookie header".to_string()
    } else {
        format!(
            "{}{}",
            names.join(", "),
            if pair_count > names.len() {
                ", ..."
            } else {
                ""
            }
        )
    }
}
fn sanitize_choice(value: &str, allowed: &[&str], fallback: &str) -> String {
    let trimmed = value.trim();
    allowed
        .iter()
        .find(|candidate| candidate.eq_ignore_ascii_case(trimmed))
        .copied()
        .unwrap_or(fallback)
        .to_string()
}

