fn sanitize_global_shortcut(value: &str) -> Result<String, String> {
    let shortcut =
        sanitize_optional_text(Some(value)).unwrap_or_else(|| QUICK_CAPTURE_SHORTCUT.to_string());
    let _ = shortcut
        .parse::<tauri_plugin_global_shortcut::Shortcut>()
        .map_err(|error| format!("Global shortcut is invalid: {error}"))?;
    Ok(shortcut)
}

fn apply_quick_capture_shortcut_settings(
    app: &AppHandle,
    previous: &AppShellSettings,
    next: &AppShellSettings,
) -> Result<(), String> {
    if previous.quick_capture_enabled
        && previous.quick_capture_shortcut != next.quick_capture_shortcut
    {
        if app
            .global_shortcut()
            .is_registered(previous.quick_capture_shortcut.as_str())
        {
            app.global_shortcut()
                .unregister(previous.quick_capture_shortcut.as_str())
                .map_err(|error| error.to_string())?;
        }
    }

    if !next.quick_capture_enabled {
        if app
            .global_shortcut()
            .is_registered(next.quick_capture_shortcut.as_str())
        {
            app.global_shortcut()
                .unregister(next.quick_capture_shortcut.as_str())
                .map_err(|error| error.to_string())?;
        }
        return Ok(());
    }

    if app
        .global_shortcut()
        .is_registered(next.quick_capture_shortcut.as_str())
    {
        return Ok(());
    }

    app.global_shortcut()
        .register(next.quick_capture_shortcut.as_str())
        .map_err(|error| error.to_string())
}

fn setup_quick_capture_shortcut(app: &AppHandle) -> Result<(), String> {
    let (_, root) = resolve_data_root(app).map_err(|error| error.to_string())?;
    let settings = read_app_shell_settings(&root)?;
    if settings.quick_capture_enabled {
        app.global_shortcut()
            .register(settings.quick_capture_shortcut.as_str())
            .map_err(|error| error.to_string())?;
    }
    Ok(())
}

