fn sanitize_filename_template(template: &str) -> String {
    let trimmed = template.trim();
    if trimmed.is_empty() {
        "{title}.{ext}".to_string()
    } else {
        trimmed.to_string()
    }
}

fn sanitize_quality(value: &str) -> String {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        "best".to_string()
    } else {
        trimmed.to_string()
    }
}

fn sanitize_audio_format(value: &str) -> String {
    match value.trim().to_ascii_lowercase().as_str() {
        "mp3" => "mp3".to_string(),
        "m4a" => "m4a".to_string(),
        "opus" => "opus".to_string(),
        "flac" => "flac".to_string(),
        "wav" => "wav".to_string(),
        _ => "m4a".to_string(),
    }
}

fn sanitize_completed_task_cleanup(value: &str) -> String {
    match value.trim().to_ascii_lowercase().as_str() {
        "delete" | "remove" => "delete".to_string(),
        _ => "archive".to_string(),
    }
}

fn sanitize_optional_text(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(str::to_string)
}

fn append_custom_ytdlp_args(args: &mut Vec<String>, template: Option<&str>) -> Result<(), String> {
    let custom_args = parse_custom_ytdlp_args(template)?;
    args.extend(custom_args);
    Ok(())
}

fn parse_custom_ytdlp_args(template: Option<&str>) -> Result<Vec<String>, String> {
    let Some(template) = template.map(str::trim).filter(|value| !value.is_empty()) else {
        return Ok(Vec::new());
    };

    let raw_args = split_custom_ytdlp_args(template)?;
    validate_custom_ytdlp_args(&raw_args)?;
    Ok(raw_args)
}

fn split_custom_ytdlp_args(template: &str) -> Result<Vec<String>, String> {
    let mut args = Vec::new();
    let mut current = String::new();
    let mut quote: Option<char> = None;
    let mut escaped = false;

    for ch in template.chars() {
        if escaped {
            current.push(ch);
            escaped = false;
            continue;
        }
        if ch == '\\' {
            escaped = true;
            continue;
        }
        if let Some(active_quote) = quote {
            if ch == active_quote {
                quote = None;
            } else {
                current.push(ch);
            }
            continue;
        }
        if ch == '\'' || ch == '"' {
            quote = Some(ch);
            continue;
        }
        if ch.is_whitespace() {
            if !current.is_empty() {
                args.push(current.clone());
                current.clear();
            }
            continue;
        }
        current.push(ch);
    }

    if escaped {
        current.push('\\');
    }
    if quote.is_some() {
        return Err("Custom yt-dlp args contain an unterminated quote.".to_string());
    }
    if !current.is_empty() {
        args.push(current);
    }
    Ok(args)
}

fn validate_custom_ytdlp_args(args: &[String]) -> Result<(), String> {
    let blocked_with_values = [
        "--paths",
        "-P",
        "--output",
        "-o",
        "--cookies",
        "--add-header",
        "--proxy",
        "--limit-rate",
        "--user-agent",
        "--referer",
        "--exec",
        "--external-downloader",
        "--external-downloader-args",
        "--plugin-dirs",
        "--cache-dir",
        "--ffmpeg-location",
        "--download-archive",
        "--batch-file",
        "-a",
    ];
    let blocked_exact = [
        "--rm-cache-dir",
        "--update",
        "-U",
        "--call-home",
        "--no-call-home",
        "--simulate",
        "--skip-download",
        "--dump-json",
        "-j",
        "--print",
        "--print-to-file",
        "--write-pages",
        "--load-pages",
    ];

    let mut skip_value_for: Option<&str> = None;
    for arg in args {
        if let Some(flag) = skip_value_for.take() {
            if arg.starts_with('-') {
                return Err(format!("Custom yt-dlp arg {flag} requires a value."));
            }
            continue;
        }
        let flag_name = arg.split_once('=').map(|(flag, _)| flag).unwrap_or(arg);
        if blocked_exact
            .iter()
            .any(|blocked| flag_name.eq_ignore_ascii_case(blocked))
        {
            return Err(format!(
                "Custom yt-dlp arg {flag_name} is managed by FetchDock."
            ));
        }
        if blocked_with_values
            .iter()
            .any(|blocked| flag_name.eq_ignore_ascii_case(blocked))
        {
            return Err(format!(
                "Custom yt-dlp arg {flag_name} is managed by FetchDock."
            ));
        }
        if matches!(flag_name, "--postprocessor-args" | "--ppa")
            || matches!(flag_name, "--downloader-args")
        {
            skip_value_for = Some(flag_name);
        }
    }
    Ok(())
}

fn sanitize_concurrent_fragments(value: Option<u8>) -> Option<u8> {
    value.filter(|value| (1..=16).contains(value))
}

fn sanitize_subtitle_settings(settings: SubtitleSettings) -> SubtitleSettings {
    SubtitleSettings {
        languages: unique_trimmed_strings(settings.languages),
        auto: settings.auto,
        embed: settings.embed,
        keep_vtt: settings.keep_vtt,
    }
}

fn sanitize_sponsorblock_settings(settings: SponsorBlockSettings) -> SponsorBlockSettings {
    SponsorBlockSettings {
        enabled: settings.enabled,
        categories: unique_trimmed_strings(settings.categories),
    }
}

fn unique_trimmed_strings(values: Vec<String>) -> Vec<String> {
    let mut result = Vec::new();
    for value in values {
        let trimmed = value.trim();
        if trimmed.is_empty() || result.iter().any(|existing| existing == trimmed) {
            continue;
        }
        result.push(trimmed.to_string());
    }
    result
}

fn sanitize_max_concurrency(value: usize) -> usize {
    value.clamp(1, MAX_ACTIVE_DOWNLOADS_LIMIT)
}

fn available_download_slots(max_concurrency: usize, active_count: usize) -> usize {
    sanitize_max_concurrency(max_concurrency).saturating_sub(active_count)
}

fn detect_tool_statuses(
    root: &Path,
    path_override: Option<&str>,
) -> Result<Vec<ToolStatus>, String> {
    let last_checked_at = Utc::now().to_rfc3339();
    TOOL_IDS
        .iter()
        .map(|tool_id| detect_tool_status(root, tool_id, path_override, &last_checked_at))
        .collect()
}

fn detect_tool_status(
    root: &Path,
    tool_id: &str,
    path_override: Option<&str>,
    last_checked_at: &str,
) -> Result<ToolStatus, String> {
    let settings = read_tool_settings(root)?;
    if let Some(override_path) = settings.path_overrides.get(tool_id) {
        return Ok(installed_tool_status(
            tool_id,
            PathBuf::from(override_path),
            false,
            last_checked_at,
        ));
    }

    if let Some(managed_path) = managed_tool_path(root, tool_id).filter(|path| path.is_file()) {
        return Ok(installed_tool_status(
            tool_id,
            managed_path,
            true,
            last_checked_at,
        ));
    }

    if let Some(path_tool) = find_tool_on_path(tool_id, path_override) {
        return Ok(installed_tool_status(
            tool_id,
            path_tool,
            false,
            last_checked_at,
        ));
    }

    if let Some(error) = settings.install_errors.get(tool_id) {
        return Ok(tool_error_status(
            tool_id,
            None,
            true,
            last_checked_at,
            error,
        ));
    }

    Ok(ToolStatus {
        schema_version: 1,
        id: tool_id.to_string(),
        state: ToolState::Missing,
        version: None,
        path: None,
        managed: false,
        updatable: matches!(tool_id, "yt-dlp" | "gallery-dl" | "ffmpeg"),
        last_checked_at: last_checked_at.to_string(),
        error: None,
    })
}

fn set_tool_path_override(
    root: &Path,
    tool_id: &str,
    raw_path: &str,
) -> Result<ToolStatus, String> {
    validate_tool_id(tool_id)?;
    let path = validate_tool_override_path(tool_id, raw_path)?;
    let mut settings = read_tool_settings(root)?;
    settings.schema_version = 1;
    settings
        .path_overrides
        .insert(tool_id.to_string(), display_path(&path));
    write_tool_settings(root, &settings)?;
    Ok(installed_tool_status(
        tool_id,
        path,
        false,
        &Utc::now().to_rfc3339(),
    ))
}

fn clear_tool_path_override(root: &Path, tool_id: &str) -> Result<ToolStatus, String> {
    validate_tool_id(tool_id)?;
    let mut settings = read_tool_settings(root)?;
    settings.path_overrides.remove(tool_id);
    write_tool_settings(root, &settings)?;
    detect_tool_status(root, tool_id, None, &Utc::now().to_rfc3339())
}

fn list_tool_download_sources(root: &Path) -> Result<Vec<ToolDownloadSourcePublic>, String> {
    let settings = read_tool_settings(root)?;
    let mut sources = settings
        .download_sources
        .into_iter()
        .map(|(tool_id, source)| ToolDownloadSourcePublic {
            tool_id,
            url: source.url,
            sha256: source.sha256,
            archive_member: source.archive_member,
        })
        .collect::<Vec<_>>();
    sources.sort_by(|left, right| left.tool_id.cmp(&right.tool_id));
    Ok(sources)
}

fn set_tool_download_source(
    root: &Path,
    request: ToolDownloadSourceRequest,
) -> Result<ToolDownloadSourcePublic, String> {
    validate_tool_id(&request.id)?;
    let source =
        sanitize_tool_download_source(request.url, request.sha256, request.archive_member)?;
    let mut settings = read_tool_settings(root)?;
    settings.schema_version = 1;
    settings.install_errors.remove(&request.id);
    settings
        .download_sources
        .insert(request.id.clone(), source.clone());
    write_tool_settings(root, &settings)?;
    Ok(ToolDownloadSourcePublic {
        tool_id: request.id,
        url: source.url,
        sha256: source.sha256,
        archive_member: source.archive_member,
    })
}

fn clear_tool_download_source(
    root: &Path,
    tool_id: &str,
) -> Result<Vec<ToolDownloadSourcePublic>, String> {
    validate_tool_id(tool_id)?;
    let mut settings = read_tool_settings(root)?;
    settings.download_sources.remove(tool_id);
    write_tool_settings(root, &settings)?;
    list_tool_download_sources(root)
}

fn default_tool_settings_export_path(root: &Path) -> PathBuf {
    root.join("diagnostics").join(format!(
        "fetchdock-tool-settings-{}.json",
        Utc::now().format("%Y%m%d-%H%M%S")
    ))
}

fn tool_settings_counts(settings: &ToolSettings) -> (usize, usize, usize) {
    (
        settings.path_overrides.len(),
        settings.download_sources.len(),
        settings.install_errors.len(),
    )
}

fn export_tool_settings_at_root(
    root: &Path,
    output_path: Option<String>,
) -> Result<ToolSettingsExportResponse, String> {
    let output_path = match output_path.and_then(|path| sanitize_optional_text(Some(path))) {
        Some(path) => validate_output_file_path(&path, "Tool settings export")?,
        None => default_tool_settings_export_path(root),
    };
    validate_json_file_path(&output_path, "Tool settings export")?;
    if let Some(parent) = output_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    let settings = read_tool_settings(root)?;
    let payload = serde_json::json!({
        "schema_version": 1,
        "exported_at": Utc::now().to_rfc3339(),
        "kind": "fetchdock_tool_settings",
        "settings": settings,
        "includes_cookie_values": false,
        "includes_auth_payloads": false,
        "includes_downloaded_content": false,
        "includes_managed_dependency_files": false,
        "executes_tools": false,
        "downloads_tools": false
    });
    fs::write(
        &output_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| error.to_string())?;
    let (path_override_count, download_source_count, install_error_count) =
        tool_settings_counts(&settings);
    Ok(ToolSettingsExportResponse {
        output_path: display_path(&output_path),
        path_override_count,
        download_source_count,
        install_error_count,
    })
}

fn sanitize_imported_tool_settings(settings: ToolSettings) -> (ToolSettings, usize, usize) {
    let mut sanitized = ToolSettings {
        schema_version: 1,
        path_overrides: HashMap::new(),
        install_errors: HashMap::new(),
        download_sources: HashMap::new(),
    };
    let mut skipped_path_override_count = 0;
    let mut skipped_download_source_count = 0;

    for (tool_id, raw_path) in settings.path_overrides {
        if validate_tool_id(&tool_id).is_err() {
            skipped_path_override_count += 1;
            continue;
        }
        match validate_tool_override_path(&tool_id, &raw_path) {
            Ok(path) => {
                sanitized
                    .path_overrides
                    .insert(tool_id, display_path(&path));
            }
            Err(_) => skipped_path_override_count += 1,
        }
    }

    for (tool_id, error) in settings.install_errors {
        if validate_tool_id(&tool_id).is_ok() {
            if let Some(error) = sanitize_optional_text(Some(error)) {
                sanitized.install_errors.insert(tool_id, error);
            }
        }
    }

    for (tool_id, source) in settings.download_sources {
        if validate_tool_id(&tool_id).is_err() {
            skipped_download_source_count += 1;
            continue;
        }
        match sanitize_tool_download_source(source.url, source.sha256, source.archive_member) {
            Ok(source) => {
                sanitized.download_sources.insert(tool_id, source);
            }
            Err(_) => skipped_download_source_count += 1,
        }
    }

    (
        sanitized,
        skipped_path_override_count,
        skipped_download_source_count,
    )
}

fn import_tool_settings_at_root(
    root: &Path,
    request: ToolSettingsImportRequest,
) -> Result<ToolSettingsImportResponse, String> {
    let input_path = validate_existing_input_file(&request.input_path, "Tool settings import")?;
    validate_json_file_path(&input_path, "Tool settings import")?;
    let bytes = fs::read(&input_path).map_err(|error| error.to_string())?;
    let raw: serde_json::Value = serde_json::from_slice(&bytes)
        .map_err(|error| format!("Tool settings import must be FetchDock JSON: {error}"))?;
    let raw_settings = raw.get("settings").cloned().unwrap_or_else(|| raw.clone());
    let settings: ToolSettings = serde_json::from_value(raw_settings)
        .map_err(|error| format!("Tool settings import has invalid settings: {error}"))?;
    let (settings, skipped_path_override_count, skipped_download_source_count) =
        sanitize_imported_tool_settings(settings);
    write_tool_settings(root, &settings)?;
    let (path_override_count, download_source_count, install_error_count) =
        tool_settings_counts(&settings);
    Ok(ToolSettingsImportResponse {
        input_path: display_path(&input_path),
        path_override_count,
        download_source_count,
        install_error_count,
        skipped_path_override_count,
        skipped_download_source_count,
    })
}

fn sanitize_tool_download_source(
    url: String,
    sha256: String,
    archive_member: Option<String>,
) -> Result<ToolDownloadSource, String> {
    let url = normalize_http_url(&url)?;
    let sha256 = normalize_sha256(&sha256)?;
    let archive_member = match sanitize_optional_text(archive_member.as_deref()) {
        Some(value) => Some(validate_archive_member_path(&value)?),
        None => None,
    };
    Ok(ToolDownloadSource {
        url,
        sha256,
        archive_member,
    })
}

fn validate_archive_member_path(value: &str) -> Result<String, String> {
    let normalized = value.trim().replace('\\', "/");
    if normalized.is_empty()
        || normalized.starts_with('/')
        || normalized.contains("..")
        || normalized.split('/').any(|part| part.is_empty())
    {
        return Err(
            "Archive member must be a relative path inside the downloaded archive.".to_string(),
        );
    }
    Ok(normalized)
}

fn search_settings_catalog(query: &str) -> Vec<SettingsSearchResult> {
    let normalized_query = query.trim().to_ascii_lowercase();
    if normalized_query.is_empty() {
        return Vec::new();
    }

    settings_search_catalog()
        .into_iter()
        .filter(|item| settings_search_result_matches(item, &normalized_query))
        .collect()
}

