fn metadata_save_output_dir(
    root: &Path,
    output_dir: Option<&str>,
    default_output_dir: Option<&str>,
    requested_output_path: Option<&PathBuf>,
    label: &str,
) -> Result<PathBuf, String> {
    if let Some(output_path) = requested_output_path {
        return output_path
            .parent()
            .map(Path::to_path_buf)
            .ok_or_else(|| format!("{label} parent directory is required."));
    }
    let output_dir = output_dir
        .or(default_output_dir)
        .map(PathBuf::from)
        .unwrap_or_else(|| root.join("downloads"));
    validate_output_dir(Some(output_dir.to_string_lossy().as_ref()))?
        .map(PathBuf::from)
        .ok_or_else(|| "Output directory is required.".to_string())
}

