fn metadata_save_thumbnail_at_root(
    root: &Path,
    request: MetadataSaveThumbnailRequest,
) -> Result<MetadataSaveThumbnailResponse, String> {
    let thumbnail_url = normalize_http_url(&request.url)?;
    let parsed = parse_http_url(&thumbnail_url)?;
    let settings = read_downloads_settings(root)?;
    let requested_file_name = request
        .file_name
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(sanitize_file_name);
    let requested_output_path = request
        .output_path
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty());
    let explicit_output_path = requested_output_path
        .map(|raw_path| validate_output_file_path(raw_path, "Thumbnail output"))
        .transpose()?;
    let validated_output_dir = if explicit_output_path.is_none() {
        let output_dir = request
            .output_dir
            .as_deref()
            .or(settings.default_output_dir.as_deref())
            .map(PathBuf::from)
            .unwrap_or_else(|| root.join("downloads"));
        let validated_output_dir =
            validate_output_dir(Some(output_dir.to_string_lossy().as_ref()))?
                .map(PathBuf::from)
                .ok_or_else(|| "Output directory is required.".to_string())?;
        fs::create_dir_all(&validated_output_dir).map_err(|error| error.to_string())?;
        Some(validated_output_dir)
    } else {
        None
    };
    let cookie_header = cookie_header_for_context_url(
        root,
        &parsed,
        request.cookie_bucket_id.as_deref(),
        &classify_platform(&thumbnail_url),
    )?;
    let authorization_header =
        authorization_header_for_source(root, &thumbnail_url, request.auth_payload_ref.as_deref())?;
    let mut response = open_http_response_for_url(
        &thumbnail_url,
        request.user_agent.as_deref(),
        request.referer.as_deref(),
        request.proxy.as_deref(),
        cookie_header.as_deref(),
        authorization_header.as_deref(),
        0,
    )?;
    let output_path = if let Some(output_path) = explicit_output_path {
        output_path
    } else {
        let file_name = requested_file_name
            .or_else(|| response.content_disposition_file_name.clone())
            .unwrap_or_else(|| file_name_from_url(&response.final_url));
        let validated_output_dir =
            validated_output_dir.ok_or_else(|| "Output directory is required.".to_string())?;
        unique_download_path_for_file_name(&validated_output_dir, &file_name)
    };
    let mut file = fs::File::create(&output_path)
        .map_err(|error| format!("Failed to create thumbnail file: {error}"))?;
    copy_with_optional_rate_limit(
        response.reader.as_mut(),
        &mut file,
        request.rate_limit.as_deref(),
    )
    .map_err(|error| format!("Failed to save thumbnail file: {error}"))?;

    Ok(MetadataSaveThumbnailResponse {
        output_path: display_path(output_path),
    })
}

fn metadata_save_chapters_at_root(
    root: &Path,
    request: MetadataSaveChaptersRequest,
) -> Result<MetadataSaveChaptersResponse, String> {
    let source_url = normalize_http_url(&request.url)?;
    let settings = read_downloads_settings(root)?;

    let tool_path = resolve_tool_command_path(root, "yt-dlp")?;
    let args = metadata_tool_context_args(
        root,
        &source_url,
        request.user_agent.as_deref(),
        request.referer.as_deref(),
        request.proxy.as_deref(),
        request.cookie_bucket_id.as_deref(),
        request.auth_payload_ref.as_deref(),
        request.rate_limit.as_deref(),
    )?;
    let output = run_ytdlp_metadata_probe(&tool_path, &source_url, &args, Duration::from_secs(30))?;
    let chapters = parse_ytdlp_chapter_options(&output)?;
    let file_name = request
        .file_name
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(sanitize_file_name)
        .unwrap_or_else(|| "chapters.json".to_string());
    let output_path = if let Some(raw_path) = request
        .output_path
        .as_deref()
        .map(str::trim)
        .filter(|value| !value.is_empty())
    {
        validate_output_file_path(raw_path, "Chapters output")?
    } else {
        let output_dir = request
            .output_dir
            .as_deref()
            .or(settings.default_output_dir.as_deref())
            .map(PathBuf::from)
            .unwrap_or_else(|| root.join("downloads"));
        let validated_output_dir =
            validate_output_dir(Some(output_dir.to_string_lossy().as_ref()))?
                .map(PathBuf::from)
                .ok_or_else(|| "Output directory is required.".to_string())?;
        fs::create_dir_all(&validated_output_dir).map_err(|error| error.to_string())?;
        unique_download_path_for_file_name(&validated_output_dir, &file_name)
    };
    let payload = serde_json::json!({
        "schema_version": 1,
        "source_url": source_url,
        "chapter_count": chapters.len(),
        "chapters": chapters,
    });
    fs::write(
        &output_path,
        serde_json::to_vec_pretty(&payload).map_err(|error| error.to_string())?,
    )
    .map_err(|error| format!("Failed to write chapters file: {error}"))?;

    Ok(MetadataSaveChaptersResponse {
        output_path: display_path(output_path),
        chapter_count: chapters.len(),
    })
}

