#[derive(Debug, Clone, PartialEq, Eq)]
enum BencodeValue {
    Int(i64),
    Bytes(Vec<u8>),
    List(Vec<BencodeValue>),
    Dict(Vec<(Vec<u8>, BencodeValue)>),
}

fn parse_torrent_file(path: &Path) -> Result<TorrentMetadataResponse, String> {
    if !path.exists() {
        return Err(format!(
            "Torrent file was not found: {}",
            display_path(path)
        ));
    }
    if !path.is_file() {
        return Err(format!(
            "Torrent path is not a file: {}",
            display_path(path)
        ));
    }
    let bytes = fs::read(path).map_err(|error| error.to_string())?;
    let (value, consumed) = parse_bencode_value(&bytes, 0)?;
    if consumed != bytes.len() {
        return Err("Torrent file contains trailing bencode data.".to_string());
    }
    let info_hash = torrent_info_hash_from_bytes(&bytes)?;
    torrent_metadata_from_bencode(&value, info_hash)
}

fn torrent_metadata_from_bencode(
    value: &BencodeValue,
    info_hash: String,
) -> Result<TorrentMetadataResponse, String> {
    let root =
        bencode_dict(value).ok_or_else(|| "Torrent root must be a dictionary.".to_string())?;
    let info = bencode_dict(
        bencode_dict_get(root, b"info")
            .ok_or_else(|| "Torrent info dictionary is missing.".to_string())?,
    )
    .ok_or_else(|| "Torrent info value must be a dictionary.".to_string())?;
    let name = bencode_string(
        bencode_dict_get(info, b"name.utf-8")
            .or_else(|| bencode_dict_get(info, b"name"))
            .ok_or_else(|| "Torrent info.name is missing.".to_string())?,
    )?;
    let trackers = torrent_trackers(root);
    let piece_length_bytes = i64_to_u64(
        bencode_int(
            bencode_dict_get(info, b"piece length")
                .ok_or_else(|| "Torrent info.piece length is missing.".to_string())?,
        )?,
        "Torrent piece length",
    )?;
    if piece_length_bytes == 0 {
        return Err("Torrent piece length must be greater than zero.".to_string());
    }
    let pieces_sha1_bytes = bencode_bytes_len(
        bencode_dict_get(info, b"pieces")
            .ok_or_else(|| "Torrent info.pieces is missing.".to_string())?,
    )?;
    if pieces_sha1_bytes == 0 || pieces_sha1_bytes % 20 != 0 {
        return Err("Torrent pieces field must contain 20-byte SHA-1 digests.".to_string());
    }
    let piece_count = pieces_sha1_bytes / 20;

    let files = if let Some(files_value) = bencode_dict_get(info, b"files") {
        let entries = bencode_list(files_value)
            .ok_or_else(|| "Torrent info.files must be a list.".to_string())?;
        let mut files = Vec::new();
        for entry in entries {
            let file = bencode_dict(entry)
                .ok_or_else(|| "Torrent file entry must be a dictionary.".to_string())?;
            let length = bencode_int(
                bencode_dict_get(file, b"length")
                    .ok_or_else(|| "Torrent file length is missing.".to_string())?,
            )?;
            let path_parts = bencode_list(
                bencode_dict_get(file, b"path.utf-8")
                    .or_else(|| bencode_dict_get(file, b"path"))
                    .ok_or_else(|| "Torrent file path is missing.".to_string())?,
            )
            .ok_or_else(|| "Torrent file path must be a list.".to_string())?;
            let mut parts = Vec::new();
            for part in path_parts {
                parts.push(bencode_string(part)?);
            }
            files.push(TorrentFileEntry {
                path: parts.join("/"),
                size_bytes: i64_to_u64(length, "Torrent file length")?,
            });
        }
        files
    } else {
        let length = bencode_int(
            bencode_dict_get(info, b"length")
                .ok_or_else(|| "Torrent length is missing.".to_string())?,
        )?;
        vec![TorrentFileEntry {
            path: name.clone(),
            size_bytes: i64_to_u64(length, "Torrent length")?,
        }]
    };

    let total_size_bytes = files
        .iter()
        .fold(0_u64, |total, file| total.saturating_add(file.size_bytes));
    Ok(TorrentMetadataResponse {
        name,
        info_hash,
        piece_length_bytes,
        piece_count,
        pieces_sha1_bytes,
        total_size_bytes,
        file_count: files.len(),
        files,
        trackers,
    })
}

fn torrent_info_hash_from_bytes(bytes: &[u8]) -> Result<String, String> {
    let (root_start, root_end) = parse_bencode_value_span(bytes, 0)?;
    if root_start != 0 || root_end != bytes.len() {
        return Err("Torrent file contains trailing bencode data.".to_string());
    }
    let info_span = find_bencoded_dict_value_span(bytes, 0, b"info")?
        .ok_or_else(|| "Torrent info dictionary is missing.".to_string())?;
    Ok(sha1_digest(&bytes[info_span.0..info_span.1])
        .iter()
        .map(|byte| format!("{byte:02x}"))
        .collect())
}

fn sha1_digest(input: &[u8]) -> [u8; 20] {
    let mut message = input.to_vec();
    let bit_len = (message.len() as u64).saturating_mul(8);
    message.push(0x80);
    while message.len() % 64 != 56 {
        message.push(0);
    }
    message.extend_from_slice(&bit_len.to_be_bytes());

    let mut h0: u32 = 0x6745_2301;
    let mut h1: u32 = 0xefcd_ab89;
    let mut h2: u32 = 0x98ba_dcfe;
    let mut h3: u32 = 0x1032_5476;
    let mut h4: u32 = 0xc3d2_e1f0;

    for chunk in message.chunks_exact(64) {
        let mut words = [0_u32; 80];
        for (index, word) in words.iter_mut().take(16).enumerate() {
            let offset = index * 4;
            *word = u32::from_be_bytes([
                chunk[offset],
                chunk[offset + 1],
                chunk[offset + 2],
                chunk[offset + 3],
            ]);
        }
        for index in 16..80 {
            words[index] =
                (words[index - 3] ^ words[index - 8] ^ words[index - 14] ^ words[index - 16])
                    .rotate_left(1);
        }

        let mut a = h0;
        let mut b = h1;
        let mut c = h2;
        let mut d = h3;
        let mut e = h4;

        for (index, word) in words.iter().enumerate() {
            let (f, k) = match index {
                0..=19 => ((b & c) | ((!b) & d), 0x5a82_7999),
                20..=39 => (b ^ c ^ d, 0x6ed9_eba1),
                40..=59 => ((b & c) | (b & d) | (c & d), 0x8f1b_bcdc),
                _ => (b ^ c ^ d, 0xca62_c1d6),
            };
            let temp = a
                .rotate_left(5)
                .wrapping_add(f)
                .wrapping_add(e)
                .wrapping_add(k)
                .wrapping_add(*word);
            e = d;
            d = c;
            c = b.rotate_left(30);
            b = a;
            a = temp;
        }

        h0 = h0.wrapping_add(a);
        h1 = h1.wrapping_add(b);
        h2 = h2.wrapping_add(c);
        h3 = h3.wrapping_add(d);
        h4 = h4.wrapping_add(e);
    }

    let mut digest = [0_u8; 20];
    for (offset, value) in [h0, h1, h2, h3, h4].iter().enumerate() {
        digest[offset * 4..offset * 4 + 4].copy_from_slice(&value.to_be_bytes());
    }
    digest
}

fn parse_bencode_value(bytes: &[u8], index: usize) -> Result<(BencodeValue, usize), String> {
    let Some(byte) = bytes.get(index) else {
        return Err("Unexpected end of bencode data.".to_string());
    };
    match byte {
        b'i' => parse_bencode_int(bytes, index),
        b'l' => parse_bencode_list(bytes, index),
        b'd' => parse_bencode_dict_value(bytes, index),
        b'0'..=b'9' => parse_bencode_bytes(bytes, index),
        _ => Err(format!("Invalid bencode token at byte {index}.")),
    }
}

fn parse_bencode_int(bytes: &[u8], index: usize) -> Result<(BencodeValue, usize), String> {
    let end = bytes[index + 1..]
        .iter()
        .position(|byte| *byte == b'e')
        .map(|offset| index + 1 + offset)
        .ok_or_else(|| "Unterminated bencode integer.".to_string())?;
    let text = std::str::from_utf8(&bytes[index + 1..end])
        .map_err(|_| "Bencode integer was not UTF-8.".to_string())?;
    let value = text
        .parse::<i64>()
        .map_err(|_| "Bencode integer was invalid.".to_string())?;
    Ok((BencodeValue::Int(value), end + 1))
}

fn parse_bencode_bytes(bytes: &[u8], index: usize) -> Result<(BencodeValue, usize), String> {
    let colon = bytes[index..]
        .iter()
        .position(|byte| *byte == b':')
        .map(|offset| index + offset)
        .ok_or_else(|| "Bencode byte string length was missing a colon.".to_string())?;
    let len_text = std::str::from_utf8(&bytes[index..colon])
        .map_err(|_| "Bencode byte string length was not UTF-8.".to_string())?;
    let len = len_text
        .parse::<usize>()
        .map_err(|_| "Bencode byte string length was invalid.".to_string())?;
    let start = colon + 1;
    let end = start.saturating_add(len);
    if end > bytes.len() {
        return Err("Bencode byte string exceeded file length.".to_string());
    }
    Ok((BencodeValue::Bytes(bytes[start..end].to_vec()), end))
}

fn parse_bencode_list(bytes: &[u8], index: usize) -> Result<(BencodeValue, usize), String> {
    let mut values = Vec::new();
    let mut cursor = index + 1;
    while bytes.get(cursor) != Some(&b'e') {
        let (value, next) = parse_bencode_value(bytes, cursor)?;
        values.push(value);
        cursor = next;
    }
    Ok((BencodeValue::List(values), cursor + 1))
}

fn parse_bencode_dict_value(bytes: &[u8], index: usize) -> Result<(BencodeValue, usize), String> {
    let mut values = Vec::new();
    let mut cursor = index + 1;
    while bytes.get(cursor) != Some(&b'e') {
        let (key, next) = parse_bencode_bytes(bytes, cursor)?;
        let BencodeValue::Bytes(key) = key else {
            return Err("Bencode dictionary key must be bytes.".to_string());
        };
        let (value, next) = parse_bencode_value(bytes, next)?;
        values.push((key, value));
        cursor = next;
    }
    Ok((BencodeValue::Dict(values), cursor + 1))
}

fn parse_bencode_value_span(bytes: &[u8], index: usize) -> Result<(usize, usize), String> {
    let start = index;
    let Some(byte) = bytes.get(index) else {
        return Err("Unexpected end of bencode data.".to_string());
    };
    let end = match byte {
        b'i' => bytes[index + 1..]
            .iter()
            .position(|byte| *byte == b'e')
            .map(|offset| index + 2 + offset)
            .ok_or_else(|| "Unterminated bencode integer.".to_string())?,
        b'l' | b'd' => {
            let mut cursor = index + 1;
            while bytes.get(cursor) != Some(&b'e') {
                let (_, next) = if *byte == b'd' {
                    let (_, _, key_end) = parse_bencode_bytes_span(bytes, cursor)?;
                    parse_bencode_value_span(bytes, key_end)?
                } else {
                    parse_bencode_value_span(bytes, cursor)?
                };
                cursor = next;
            }
            cursor + 1
        }
        b'0'..=b'9' => parse_bencode_bytes_span(bytes, index)?.2,
        _ => return Err(format!("Invalid bencode token at byte {index}.")),
    };
    Ok((start, end))
}

fn parse_bencode_bytes_span(bytes: &[u8], index: usize) -> Result<(usize, usize, usize), String> {
    let colon = bytes[index..]
        .iter()
        .position(|byte| *byte == b':')
        .map(|offset| index + offset)
        .ok_or_else(|| "Bencode byte string length was missing a colon.".to_string())?;
    let len_text = std::str::from_utf8(&bytes[index..colon])
        .map_err(|_| "Bencode byte string length was not UTF-8.".to_string())?;
    let len = len_text
        .parse::<usize>()
        .map_err(|_| "Bencode byte string length was invalid.".to_string())?;
    let content_start = colon + 1;
    let end = content_start.saturating_add(len);
    if end > bytes.len() {
        return Err("Bencode byte string exceeded file length.".to_string());
    }
    Ok((index, content_start, end))
}

fn find_bencoded_dict_value_span(
    bytes: &[u8],
    index: usize,
    lookup_key: &[u8],
) -> Result<Option<(usize, usize)>, String> {
    if bytes.get(index) != Some(&b'd') {
        return Err("Bencode value must be a dictionary.".to_string());
    }
    let mut cursor = index + 1;
    while bytes.get(cursor) != Some(&b'e') {
        let (_, key_start, key_end) = parse_bencode_bytes_span(bytes, cursor)?;
        let (value_start, value_end) = parse_bencode_value_span(bytes, key_end)?;
        if &bytes[key_start..key_end] == lookup_key {
            return Ok(Some((value_start, value_end)));
        }
        cursor = value_end;
    }
    Ok(None)
}

fn bencode_dict(value: &BencodeValue) -> Option<&[(Vec<u8>, BencodeValue)]> {
    match value {
        BencodeValue::Dict(values) => Some(values),
        _ => None,
    }
}

fn bencode_list(value: &BencodeValue) -> Option<&[BencodeValue]> {
    match value {
        BencodeValue::List(values) => Some(values),
        _ => None,
    }
}

fn bencode_dict_get<'a>(
    values: &'a [(Vec<u8>, BencodeValue)],
    key: &[u8],
) -> Option<&'a BencodeValue> {
    values
        .iter()
        .find_map(|(candidate, value)| (candidate.as_slice() == key).then_some(value))
}

fn bencode_int(value: &BencodeValue) -> Result<i64, String> {
    match value {
        BencodeValue::Int(value) => Ok(*value),
        _ => Err("Expected bencode integer.".to_string()),
    }
}

fn bencode_string(value: &BencodeValue) -> Result<String, String> {
    match value {
        BencodeValue::Bytes(bytes) => Ok(String::from_utf8_lossy(bytes).trim().to_string()),
        _ => Err("Expected bencode byte string.".to_string()),
    }
}

fn bencode_bytes_len(value: &BencodeValue) -> Result<usize, String> {
    match value {
        BencodeValue::Bytes(bytes) => Ok(bytes.len()),
        _ => Err("Expected bencode byte string.".to_string()),
    }
}

