fn torrent_trackers(root: &[(Vec<u8>, BencodeValue)]) -> Vec<String> {
    let mut trackers = Vec::new();
    if let Some(value) =
        bencode_dict_get(root, b"announce").and_then(|value| bencode_string(value).ok())
    {
        if !value.is_empty() {
            trackers.push(value);
        }
    }
    if let Some(tiers) = bencode_dict_get(root, b"announce-list").and_then(bencode_list) {
        for tier in tiers {
            let Some(urls) = bencode_list(tier) else {
                continue;
            };
            for url in urls {
                if let Ok(value) = bencode_string(url) {
                    if !value.is_empty() && !trackers.contains(&value) {
                        trackers.push(value);
                    }
                }
            }
        }
    }
    trackers
}

fn queue_torrent_file_at_root(
    root: &Path,
    request: TorrentQueueFileRequest,
) -> Result<DownloadTask, String> {
    let input_path = validate_existing_input_file(&request.path, "Torrent file")?;
    let metadata = parse_torrent_file(&input_path)?;
    let selected_files = select_torrent_files(&metadata.files, &request.selected_paths)?;
    let selected_total_size = selected_files
        .iter()
        .fold(0_u64, |total, file| total.saturating_add(file.size_bytes));
    let mut tasks = read_download_tasks(root)?;
    let settings = read_downloads_settings(root)?;
    let position = tasks
        .iter()
        .map(|task| task.position)
        .max()
        .unwrap_or(0)
        .saturating_add(1);
    let now = Utc::now().to_rfc3339();
    let output_dir = validate_output_dir(
        request
            .output_dir
            .as_deref()
            .map(str::trim)
            .filter(|value| !value.is_empty())
            .or(settings.default_output_dir.as_deref()),
    )?;
    let details_json = serde_json::json!({
        "type": "torrent_file",
        "source_path": display_path(&input_path),
        "name": metadata.name.as_str(),
        "info_hash": metadata.info_hash.as_str(),
        "piece_length_bytes": metadata.piece_length_bytes,
        "piece_count": metadata.piece_count,
        "pieces_sha1_bytes": metadata.pieces_sha1_bytes,
        "trackers": &metadata.trackers,
        "total_size_bytes": metadata.total_size_bytes,
        "file_count": metadata.file_count,
        "selected_total_size_bytes": selected_total_size,
        "selected_files": &selected_files,
    });
    let mut task = DownloadTask {
        schema_version: 1,
        id: format!("task-{}-{}", Utc::now().timestamp_millis(), position),
        kind: DownloadKind::Torrent,
        source_url: format!("torrent://{}", display_path(&input_path)),
        platform: "torrent".to_string(),
        title: details_json
            .get("name")
            .and_then(|value| value.as_str())
            .unwrap_or("torrent")
            .to_string(),
        status: DownloadStatus::Queued,
        position,
        output_dir,
        output_path: Some(display_path(&input_path)),
        downloaded_bytes: Some(0),
        total_bytes: Some(selected_total_size),
        file_count: Some(selected_files.len().try_into().unwrap_or(u32::MAX)),
        last_error: None,
        error_category: None,
        retryable: None,
        retry_count: 0,
        run_after_active_slot: false,
        user_agent: None,
        referer: None,
        proxy: None,
        cookie_bucket_id: None,
        auth_payload_ref: None,
        rate_limit: None,
        live_from_start: false,
        concurrent_fragments: None,
        custom_ytdlp_args: None,
        start_seconds: None,
        end_seconds: None,
        quality: None,
        audio_format: None,
        thumbnail_url: None,
        thumbnail_path: None,
        subtitles: None,
        sponsorblock: None,
        metadata: None,
        details_json: Some(details_json),
        created_at: now.clone(),
        updated_at: now,
        started_at: None,
        finished_at: None,
    };
    if let Some(sha256) = offer.sha256.as_deref() {
        set_download_task_expected_sha256(&mut task, sha256)?;
    }
    apply_task_create_options_to_task(&mut task, create_options)?;
    tasks.push(task.clone());
    normalize_positions(&mut tasks);
    write_download_tasks(root, &tasks)?;
    let selection_summary = if selected_files.len() == metadata.files.len() {
        format!("all {} files selected", selected_files.len())
    } else {
        format!(
            "{} of {} files selected: {}",
            selected_files.len(),
            metadata.files.len(),
            selected_files
                .iter()
                .take(12)
                .map(|file| file.path.as_str())
                .collect::<Vec<_>>()
                .join(", ")
        )
    };
    append_download_log_line(
        root,
        &task.id,
        &format!("torrent metadata queued; {selection_summary}; starting the task exports a metadata sidecar"),
    );
    Ok(task)
}

