fn import_music_playback_history_at_root(
    root: &Path,
    request: MusicPlaybackHistoryImportRequest,
) -> Result<MusicPlaybackHistoryImportResponse, String> {
    let input_path =
        validate_existing_input_file(&request.input_path, "Music playback history import")?;
    validate_json_file_path(&input_path, "Music playback history import")?;
    let metadata = fs::metadata(&input_path).map_err(|error| error.to_string())?;
    if metadata.len() > 10 * 1024 * 1024 {
        return Err("Music playback history import is limited to files up to 10 MB.".to_string());
    }
    let raw: serde_json::Value = serde_json::from_slice(
        &fs::read(&input_path)
            .map_err(|error| format!("Unable to read music playback history import: {error}"))?,
    )
    .map_err(|error| format!("Invalid music playback history JSON: {error}"))?;
    let raw_events = raw.get("events").cloned().unwrap_or(raw);
    let imported: Vec<MusicPlaybackEvent> =
        serde_json::from_value(raw_events).map_err(|error| {
            format!("Music playback history JSON did not contain valid events: {error}")
        })?;
    let before = imported.len();
    let mut events = imported
        .into_iter()
        .filter_map(sanitize_music_playback_event)
        .take(5000)
        .collect::<Vec<_>>();
    events.sort_by(|left, right| right.played_at.cmp(&left.played_at));
    if events.is_empty() {
        return Err("Music playback history import did not contain any usable events.".to_string());
    }
    let skipped_event_count = before.saturating_sub(events.len());
    write_music_playback_events(root, &events)?;
    let stats = music_playback_stats_from_events(events)?;
    Ok(MusicPlaybackHistoryImportResponse {
        schema_version: 1,
        imported_event_count: usize::try_from(stats.play_count).unwrap_or(usize::MAX),
        skipped_event_count,
        stats,
    })
}

fn sanitize_music_playback_event(mut event: MusicPlaybackEvent) -> Option<MusicPlaybackEvent> {
    event.schema_version = 1;
    event.track = normalize_music_playlist_tracks(vec![event.track]).pop()?;
    event.id = sanitize_optional_text(Some(event.id))
        .unwrap_or_else(|| music_playback_event_id(&event.track.path, &event.played_at));
    event.played_at = sanitize_optional_text(Some(event.played_at))?;
    event.played_seconds = event.played_seconds.clamp(1, 86_400);
    Some(event)
}

fn music_playback_stats_from_events(
    mut events: Vec<MusicPlaybackEvent>,
) -> Result<MusicPlaybackStatsResponse, String> {
    events.sort_by(|left, right| right.played_at.cmp(&left.played_at));
    let play_count = u32::try_from(events.len()).unwrap_or(u32::MAX);
    let played_seconds = events.iter().fold(0u32, |total, event| {
        total.saturating_add(event.played_seconds)
    });
    let mut by_path: HashMap<String, MusicTopTrack> = HashMap::new();
    for event in &events {
        let entry = by_path
            .entry(event.track.path.clone())
            .or_insert_with(|| MusicTopTrack {
                track: event.track.clone(),
                play_count: 0,
                played_seconds: 0,
                last_played_at: event.played_at.clone(),
            });
        entry.play_count = entry.play_count.saturating_add(1);
        entry.played_seconds = entry.played_seconds.saturating_add(event.played_seconds);
        if event.played_at > entry.last_played_at {
            entry.last_played_at = event.played_at.clone();
            entry.track = event.track.clone();
        }
    }
    let mut top_tracks = by_path.into_values().collect::<Vec<_>>();
    top_tracks.sort_by(|left, right| {
        right
            .play_count
            .cmp(&left.play_count)
            .then_with(|| right.played_seconds.cmp(&left.played_seconds))
            .then_with(|| right.last_played_at.cmp(&left.last_played_at))
    });
    top_tracks.truncate(10);
    let recent = events.into_iter().take(20).collect();
    Ok(MusicPlaybackStatsResponse {
        play_count,
        played_seconds,
        top_tracks,
        recent,
    })
}

fn music_playback_event_id(path: &str, now: &str) -> String {
    let mut hasher = Sha256::new();
    hasher.update(path.as_bytes());
    hasher.update(now.as_bytes());
    let digest = hasher.finalize();
    let id = digest
        .iter()
        .take(10)
        .map(|byte| format!("{byte:02x}"))
        .collect::<String>();
    format!("play-{id}")
}

fn i64_to_u64(value: i64, label: &str) -> Result<u64, String> {
    u64::try_from(value).map_err(|_| format!("{label} cannot be negative."))
}

fn media_clip_video_at_root_with_app(
    root: &Path,
    request: MediaClipVideoRequest,
    job_id: &str,
    app: Option<&AppHandle>,
    cancel_flag: &AtomicBool,
) -> Result<MediaClipVideoResponse, String> {
    let input_path = validate_existing_input_file(&request.input_path, "Input video")?;
    let output_path = validate_output_file_path(&request.output_path, "Output video")?;
    validate_clip_times(request.start_seconds, request.end_seconds)?;
    validate_clip_reencode_options(&request)?;
    let tool_path = resolve_tool_command_path(root, "ffmpeg")?;
    let context = MediaClipExecutionContext {
        job_id,
        app,
        cancel_flag,
        #[cfg(test)]
        progress_sink: None,
    };
    let ffmpeg_options = MediaClipFfmpegOptions {
        mode: request.mode.unwrap_or(MediaClipMode::Copy),
        video_codec: request.video_codec.as_deref(),
        audio_codec: request.audio_codec.as_deref(),
        crf: request.crf,
        preset: request.preset.as_deref(),
        start_seconds: request.start_seconds,
        end_seconds: request.end_seconds,
        timeout: Duration::from_secs(120),
    };
    emit_media_clip_progress(
        context.app,
        MediaClipProgressEvent {
            schema_version: 1,
            job_id: job_id.to_string(),
            status: MediaClipStatus::Active,
            elapsed_seconds: 0,
            output_path: Some(display_path(&output_path)),
            message: "Clip started.".to_string(),
            updated_at: Utc::now().to_rfc3339(),
        },
    );
    let result = run_ffmpeg_video_clip(
        &tool_path,
        &input_path,
        &output_path,
        &ffmpeg_options,
        &context,
    );
    if let Err(error) = result {
        emit_media_clip_progress(
            context.app,
            MediaClipProgressEvent {
                schema_version: 1,
                job_id: job_id.to_string(),
                status: if error == DOWNLOAD_INTERRUPTED_MESSAGE {
                    MediaClipStatus::Canceled
                } else {
                    MediaClipStatus::Failed
                },
                elapsed_seconds: 0,
                output_path: Some(display_path(&output_path)),
                message: error.clone(),
                updated_at: Utc::now().to_rfc3339(),
            },
        );
        return Err(error);
    }
    emit_media_clip_progress(
        context.app,
        MediaClipProgressEvent {
            schema_version: 1,
            job_id: job_id.to_string(),
            status: MediaClipStatus::Completed,
            elapsed_seconds: 0,
            output_path: Some(display_path(&output_path)),
            message: "Clip completed.".to_string(),
            updated_at: Utc::now().to_rfc3339(),
        },
    );
    Ok(MediaClipVideoResponse {
        job_id: job_id.to_string(),
        output_path: display_path(output_path),
    })
}

fn media_transcode_at_root_with_app(
    root: &Path,
    request: MediaTranscodeRequest,
    job_id: &str,
    app: Option<&AppHandle>,
    cancel_flag: &AtomicBool,
) -> Result<MediaClipVideoResponse, String> {
    let input_path = validate_existing_input_file(&request.input_path, "Input media")?;
    let output_path = validate_output_file_path(&request.output_path, "Output media")?;
    let cover_path = match request
        .cover_path
        .as_deref()
        .and_then(|value| sanitize_optional_text(Some(value)))
    {
        Some(value) => Some(validate_existing_input_file(&value, "Cover image")?),
        None => None,
    };
    validate_transcode_options(&request)?;
    let tool_path = resolve_tool_command_path(root, "ffmpeg")?;
    let context = MediaClipExecutionContext {
        job_id,
        app,
        cancel_flag,
        #[cfg(test)]
        progress_sink: None,
    };
    emit_media_clip_progress(
        context.app,
        MediaClipProgressEvent {
            schema_version: 1,
            job_id: job_id.to_string(),
            status: MediaClipStatus::Active,
            elapsed_seconds: 0,
            output_path: Some(display_path(&output_path)),
            message: "Transcode started.".to_string(),
            updated_at: Utc::now().to_rfc3339(),
        },
    );
    let args =
        build_ffmpeg_transcode_args(&input_path, &output_path, cover_path.as_deref(), &request);
    let result = run_ffmpeg_transcode_process(
        &tool_path,
        &output_path,
        args,
        &context,
        Duration::from_secs(600),
    );
    if let Err(error) = result {
        emit_media_clip_progress(
            context.app,
            MediaClipProgressEvent {
                schema_version: 1,
                job_id: job_id.to_string(),
                status: if error == DOWNLOAD_INTERRUPTED_MESSAGE {
                    MediaClipStatus::Canceled
                } else {
                    MediaClipStatus::Failed
                },
                elapsed_seconds: 0,
                output_path: Some(display_path(&output_path)),
                message: error.clone(),
                updated_at: Utc::now().to_rfc3339(),
            },
        );
        return Err(error);
    }
    emit_media_clip_progress(
        context.app,
        MediaClipProgressEvent {
            schema_version: 1,
            job_id: job_id.to_string(),
            status: MediaClipStatus::Completed,
            elapsed_seconds: 0,
            output_path: Some(display_path(&output_path)),
            message: "Transcode completed.".to_string(),
            updated_at: Utc::now().to_rfc3339(),
        },
    );
    Ok(MediaClipVideoResponse {
        job_id: job_id.to_string(),
        output_path: display_path(output_path),
    })
}

fn run_ytdlp_metadata_probe(
    tool_path: &Path,
    source_url: &str,
    extra_args: &[String],
    timeout: Duration,
) -> Result<String, String> {
    let mut args = vec!["--dump-json".to_string(), "--no-playlist".to_string()];
    args.extend(extra_args.iter().cloned());
    args.push(source_url.to_string());
    let mut child = Command::new(tool_path)
        .args(&args)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("yt-dlp metadata probe failed to start: {error}"))?;
    let started = Instant::now();

    loop {
        if child
            .try_wait()
            .map_err(|error| format!("yt-dlp metadata probe wait failed: {error}"))?
            .is_some()
        {
            let output = child
                .wait_with_output()
                .map_err(|error| format!("yt-dlp metadata probe output failed: {error}"))?;
            let stdout = String::from_utf8_lossy(&output.stdout).to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
            if !output.status.success() {
                let detail = if stderr.trim().is_empty() {
                    stdout.trim()
                } else {
                    stderr.trim()
                };
                return Err(format!(
                    "yt-dlp metadata probe exited with status {}: {detail}",
                    output.status
                ));
            }
            return Ok(stdout);
        }

        if started.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err("yt-dlp metadata probe timed out.".to_string());
        }

        thread::sleep(Duration::from_millis(25));
    }
}

fn run_ytdlp_playlist_probe(
    tool_path: &Path,
    source_url: &str,
    extra_args: &[String],
    timeout: Duration,
) -> Result<String, String> {
    let mut args = vec!["--flat-playlist".to_string(), "--dump-json".to_string()];
    args.extend(extra_args.iter().cloned());
    args.push(source_url.to_string());
    let mut child = Command::new(tool_path)
        .args(&args)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("yt-dlp playlist probe failed to start: {error}"))?;
    let started = Instant::now();

    loop {
        if child
            .try_wait()
            .map_err(|error| format!("yt-dlp playlist probe wait failed: {error}"))?
            .is_some()
        {
            let output = child
                .wait_with_output()
                .map_err(|error| format!("yt-dlp playlist probe output failed: {error}"))?;
            let stdout = String::from_utf8_lossy(&output.stdout).to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
            if !output.status.success() {
                let detail = if stderr.trim().is_empty() {
                    stdout.trim()
                } else {
                    stderr.trim()
                };
                return Err(format!(
                    "yt-dlp playlist probe exited with status {}: {detail}",
                    output.status
                ));
            }
            return Ok(stdout);
        }

        if started.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err("yt-dlp playlist probe timed out.".to_string());
        }

        thread::sleep(Duration::from_millis(25));
    }
}

fn run_gallery_dl_url_probe(
    tool_path: &Path,
    source_url: &str,
    context_args: &[String],
    timeout: Duration,
) -> Result<String, String> {
    let mut args = vec!["--get-urls".to_string()];
    args.extend(context_args.iter().cloned());
    args.push(source_url.to_string());
    let mut child = Command::new(tool_path)
        .args(&args)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("gallery-dl URL probe failed to start: {error}"))?;
    let started = Instant::now();

    loop {
        if child
            .try_wait()
            .map_err(|error| format!("gallery-dl URL probe wait failed: {error}"))?
            .is_some()
        {
            let output = child
                .wait_with_output()
                .map_err(|error| format!("gallery-dl URL probe output failed: {error}"))?;
            let stdout = String::from_utf8_lossy(&output.stdout).to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
            if !output.status.success() {
                let detail = if stderr.trim().is_empty() {
                    stdout.trim()
                } else {
                    stderr.trim()
                };
                return Err(format!(
                    "gallery-dl URL probe exited with status {}: {detail}",
                    output.status
                ));
            }
            return Ok(stdout);
        }

        if started.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err("gallery-dl URL probe timed out.".to_string());
        }

        thread::sleep(Duration::from_millis(25));
    }
}

