fn run_ytdlp_subtitle_save(
    tool_path: &Path,
    source_url: &str,
    language: &str,
    format: &str,
    is_auto: bool,
    output_dir: &Path,
    extra_args: &[String],
    timeout: Duration,
) -> Result<PathBuf, String> {
    fs::create_dir_all(output_dir).map_err(|error| error.to_string())?;
    let before = snapshot_files_in_directory(output_dir)?;
    let mut args = vec![
        "--skip-download".to_string(),
        "--write-subs".to_string(),
        "--sub-langs".to_string(),
        language.to_string(),
        "--sub-format".to_string(),
        format.to_string(),
        "--paths".to_string(),
        output_dir.to_string_lossy().to_string(),
        "--no-playlist".to_string(),
    ];
    if is_auto {
        args.push("--write-auto-subs".to_string());
    }
    args.extend(extra_args.iter().cloned());
    args.push(source_url.to_string());

    let mut child = Command::new(tool_path)
        .args(&args)
        .current_dir(output_dir)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("yt-dlp subtitle save failed to start: {error}"))?;
    let started = Instant::now();

    loop {
        if child
            .try_wait()
            .map_err(|error| format!("yt-dlp subtitle save wait failed: {error}"))?
            .is_some()
        {
            let output = child
                .wait_with_output()
                .map_err(|error| format!("yt-dlp subtitle save output failed: {error}"))?;
            let stdout = String::from_utf8_lossy(&output.stdout).to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
            if !output.status.success() {
                let detail = if stderr.trim().is_empty() {
                    stdout.trim()
                } else {
                    stderr.trim()
                };
                return Err(format!(
                    "yt-dlp subtitle save exited with status {}: {detail}",
                    output.status
                ));
            }
            return changed_file_in_directory(output_dir, &before)?
                .ok_or_else(|| "yt-dlp finished but no subtitle file was found.".to_string());
        }

        if started.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err("yt-dlp subtitle save timed out.".to_string());
        }

        thread::sleep(Duration::from_millis(25));
    }
}

