fn run_ffmpeg_video_clip(
    tool_path: &Path,
    input_path: &Path,
    output_path: &Path,
    options: &MediaClipFfmpegOptions<'_>,
    context: &MediaClipExecutionContext<'_>,
) -> Result<(), String> {
    let mut args = vec!["-y".to_string()];
    if let Some(start) = options.start_seconds {
        args.push("-ss".to_string());
        args.push(format_seconds_arg(start));
    }
    if let Some(end) = options.end_seconds {
        args.push("-to".to_string());
        args.push(format_seconds_arg(end));
    }
    args.push("-i".to_string());
    args.push(input_path.to_string_lossy().to_string());
    match options.mode {
        MediaClipMode::Copy => {
            args.push("-c".to_string());
            args.push("copy".to_string());
        }
        MediaClipMode::Reencode => {
            args.push("-c:v".to_string());
            args.push(
                clean_optional_ffmpeg_value(options.video_codec)
                    .unwrap_or("libx264")
                    .to_string(),
            );
            args.push("-c:a".to_string());
            args.push(
                clean_optional_ffmpeg_value(options.audio_codec)
                    .unwrap_or("aac")
                    .to_string(),
            );
            if let Some(crf) = options.crf {
                args.push("-crf".to_string());
                args.push(crf.to_string());
            }
            if let Some(preset) = clean_optional_ffmpeg_value(options.preset) {
                args.push("-preset".to_string());
                args.push(preset.to_string());
            }
        }
    }
    args.push("-progress".to_string());
    args.push("pipe:1".to_string());
    args.push("-nostats".to_string());
    args.push(output_path.to_string_lossy().to_string());

    let mut child = Command::new(tool_path)
        .args(&args)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("FFmpeg clip failed to start: {error}"))?;
    let stdout = child
        .stdout
        .take()
        .ok_or_else(|| "FFmpeg stdout stream was not available.".to_string())?;
    let stderr = child
        .stderr
        .take()
        .ok_or_else(|| "FFmpeg stderr stream was not available.".to_string())?;
    let (stdout_handle, stdout_receiver) = spawn_process_stream_reader(stdout, "stdout", "FFmpeg");
    let (stderr_handle, stderr_receiver) = spawn_process_stream_reader(stderr, "stderr", "FFmpeg");
    let started = Instant::now();
    let mut last_progress_emit = Instant::now()
        .checked_sub(Duration::from_millis(500))
        .unwrap_or_else(Instant::now);
    let mut ffmpeg_elapsed_seconds = None;

    loop {
        for output_line in stdout_receiver.try_iter() {
            if let Some(elapsed_seconds) = parse_ffmpeg_progress_elapsed_seconds(&output_line.line)
            {
                ffmpeg_elapsed_seconds = Some(elapsed_seconds);
                emit_media_clip_context_progress(
                    context,
                    MediaClipProgressEvent {
                        schema_version: 1,
                        job_id: context.job_id.to_string(),
                        status: MediaClipStatus::Active,
                        elapsed_seconds,
                        output_path: Some(display_path(output_path)),
                        message: format!("FFmpeg progress: {elapsed_seconds}s processed."),
                        updated_at: Utc::now().to_rfc3339(),
                    },
                );
            }
        }
        for _output_line in stderr_receiver.try_iter() {}

        if context.cancel_flag.load(Ordering::SeqCst) {
            let _ = child.kill();
            let _ = child.wait();
            let _ = join_process_stream_output(stdout_handle, "stdout", "FFmpeg")?;
            let _ = join_process_stream_output(stderr_handle, "stderr", "FFmpeg")?;
            return Err(DOWNLOAD_INTERRUPTED_MESSAGE.to_string());
        }

        if let Some(status) = child
            .try_wait()
            .map_err(|error| format!("FFmpeg clip wait failed: {error}"))?
        {
            let stdout = join_process_stream_output(stdout_handle, "stdout", "FFmpeg")?;
            let stderr = join_process_stream_output(stderr_handle, "stderr", "FFmpeg")?;
            for output_line in stdout_receiver.try_iter() {
                if let Some(elapsed_seconds) =
                    parse_ffmpeg_progress_elapsed_seconds(&output_line.line)
                {
                    emit_media_clip_context_progress(
                        context,
                        MediaClipProgressEvent {
                            schema_version: 1,
                            job_id: context.job_id.to_string(),
                            status: MediaClipStatus::Active,
                            elapsed_seconds,
                            output_path: Some(display_path(output_path)),
                            message: format!("FFmpeg progress: {elapsed_seconds}s processed."),
                            updated_at: Utc::now().to_rfc3339(),
                        },
                    );
                }
            }
            for _output_line in stderr_receiver.try_iter() {}
            let stdout = String::from_utf8_lossy(&stdout).to_string();
            let stderr = String::from_utf8_lossy(&stderr).to_string();
            if !status.success() {
                let detail = if stderr.trim().is_empty() {
                    stdout.trim()
                } else {
                    stderr.trim()
                };
                return Err(format!("FFmpeg clip exited with status {status}: {detail}"));
            }
            if !output_path.is_file() {
                return Err("FFmpeg finished but no clipped video file was found.".to_string());
            }
            return Ok(());
        }

        if started.elapsed() >= options.timeout {
            let _ = child.kill();
            let _ = child.wait();
            let _ = join_process_stream_output(stdout_handle, "stdout", "FFmpeg")?;
            let _ = join_process_stream_output(stderr_handle, "stderr", "FFmpeg")?;
            return Err("FFmpeg clip timed out.".to_string());
        }

        if last_progress_emit.elapsed() >= Duration::from_millis(250) {
            last_progress_emit = Instant::now();
            emit_media_clip_context_progress(
                context,
                MediaClipProgressEvent {
                    schema_version: 1,
                    job_id: context.job_id.to_string(),
                    status: MediaClipStatus::Active,
                    elapsed_seconds: ffmpeg_elapsed_seconds
                        .unwrap_or_else(|| started.elapsed().as_secs()),
                    output_path: Some(display_path(output_path)),
                    message: "Clipping video.".to_string(),
                    updated_at: Utc::now().to_rfc3339(),
                },
            );
        }

        thread::sleep(Duration::from_millis(25));
    }
}

fn build_ffmpeg_transcode_args(
    input_path: &Path,
    output_path: &Path,
    cover_path: Option<&Path>,
    request: &MediaTranscodeRequest,
) -> Vec<String> {
    let preset = request.preset.unwrap_or(MediaTranscodePreset::H264);
    let mut args = vec![
        "-y".to_string(),
        "-i".to_string(),
        input_path.to_string_lossy().to_string(),
    ];
    if let Some(cover) = cover_path {
        args.push("-i".to_string());
        args.push(cover.to_string_lossy().to_string());
        if matches!(
            preset,
            MediaTranscodePreset::AudioMp3
                | MediaTranscodePreset::AudioAac
                | MediaTranscodePreset::AudioOpus
        ) {
            args.push("-map".to_string());
            args.push("0:a:0".to_string());
            args.push("-map".to_string());
            args.push("1:v:0".to_string());
            args.push("-c:v".to_string());
            args.push("copy".to_string());
            args.push("-disposition:v:0".to_string());
            args.push("attached_pic".to_string());
        } else {
            args.push("-map".to_string());
            args.push("0".to_string());
            args.push("-map".to_string());
            args.push("1".to_string());
            args.push("-disposition:v:1".to_string());
            args.push("attached_pic".to_string());
        }
    }

    match preset {
        MediaTranscodePreset::Copy => {
            args.push("-c".to_string());
            args.push("copy".to_string());
        }
        MediaTranscodePreset::H264 | MediaTranscodePreset::Custom => {
            args.push("-c:v".to_string());
            args.push(
                clean_optional_ffmpeg_value(request.video_codec.as_deref())
                    .unwrap_or("libx264")
                    .to_string(),
            );
            args.push("-c:a".to_string());
            args.push(
                clean_optional_ffmpeg_value(request.audio_codec.as_deref())
                    .unwrap_or("aac")
                    .to_string(),
            );
            args.push("-crf".to_string());
            args.push(request.crf.unwrap_or(23).to_string());
            if let Some(preset) = clean_optional_ffmpeg_value(request.speed_preset.as_deref()) {
                args.push("-preset".to_string());
                args.push(preset.to_string());
            }
        }
        MediaTranscodePreset::H265 => {
            args.extend([
                "-c:v".to_string(),
                "libx265".to_string(),
                "-c:a".to_string(),
                "aac".to_string(),
                "-crf".to_string(),
                request.crf.unwrap_or(28).to_string(),
                "-preset".to_string(),
                clean_optional_ffmpeg_value(request.speed_preset.as_deref())
                    .unwrap_or("medium")
                    .to_string(),
            ]);
        }
        MediaTranscodePreset::Vp9 => {
            args.extend([
                "-c:v".to_string(),
                "libvpx-vp9".to_string(),
                "-c:a".to_string(),
                "libopus".to_string(),
                "-crf".to_string(),
                request.crf.unwrap_or(32).to_string(),
                "-b:v".to_string(),
                "0".to_string(),
            ]);
        }
        MediaTranscodePreset::AudioMp3 => {
            if cover_path.is_none() {
                args.push("-vn".to_string());
            }
            args.extend([
                "-c:a".to_string(),
                "libmp3lame".to_string(),
                "-b:a".to_string(),
                sanitize_audio_bitrate(request.audio_bitrate.as_deref()),
            ]);
        }
        MediaTranscodePreset::AudioAac => {
            if cover_path.is_none() {
                args.push("-vn".to_string());
            }
            args.extend([
                "-c:a".to_string(),
                "aac".to_string(),
                "-b:a".to_string(),
                sanitize_audio_bitrate(request.audio_bitrate.as_deref()),
            ]);
        }
        MediaTranscodePreset::AudioOpus => {
            if cover_path.is_none() {
                args.push("-vn".to_string());
            }
            args.extend([
                "-c:a".to_string(),
                "libopus".to_string(),
                "-b:a".to_string(),
                sanitize_audio_bitrate(request.audio_bitrate.as_deref()),
            ]);
        }
    }

    if let Some(title) = sanitize_optional_text(request.metadata_title.as_deref()) {
        args.push("-metadata".to_string());
        args.push(format!("title={title}"));
    }
    if let Some(artist) = sanitize_optional_text(request.metadata_artist.as_deref()) {
        args.push("-metadata".to_string());
        args.push(format!("artist={artist}"));
    }
    args.push("-progress".to_string());
    args.push("pipe:1".to_string());
    args.push("-nostats".to_string());
    args.push(output_path.to_string_lossy().to_string());
    args
}

fn run_ffmpeg_transcode_process(
    tool_path: &Path,
    output_path: &Path,
    args: Vec<String>,
    context: &MediaClipExecutionContext<'_>,
    timeout: Duration,
) -> Result<(), String> {
    let mut child = Command::new(tool_path)
        .args(&args)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("FFmpeg transcode failed to start: {error}"))?;
    let stdout = child
        .stdout
        .take()
        .ok_or_else(|| "FFmpeg stdout stream was not available.".to_string())?;
    let stderr = child
        .stderr
        .take()
        .ok_or_else(|| "FFmpeg stderr stream was not available.".to_string())?;
    let (stdout_handle, stdout_receiver) = spawn_process_stream_reader(stdout, "stdout", "FFmpeg");
    let (stderr_handle, stderr_receiver) = spawn_process_stream_reader(stderr, "stderr", "FFmpeg");
    let started = Instant::now();
    let mut last_progress_emit = Instant::now()
        .checked_sub(Duration::from_millis(500))
        .unwrap_or_else(Instant::now);
    let mut ffmpeg_elapsed_seconds = None;

    loop {
        for output_line in stdout_receiver.try_iter() {
            if let Some(elapsed_seconds) = parse_ffmpeg_progress_elapsed_seconds(&output_line.line)
            {
                ffmpeg_elapsed_seconds = Some(elapsed_seconds);
                emit_media_clip_context_progress(
                    context,
                    MediaClipProgressEvent {
                        schema_version: 1,
                        job_id: context.job_id.to_string(),
                        status: MediaClipStatus::Active,
                        elapsed_seconds,
                        output_path: Some(display_path(output_path)),
                        message: format!("FFmpeg progress: {elapsed_seconds}s processed."),
                        updated_at: Utc::now().to_rfc3339(),
                    },
                );
            }
        }
        for _output_line in stderr_receiver.try_iter() {}

        if context.cancel_flag.load(Ordering::SeqCst) {
            let _ = child.kill();
            let _ = child.wait();
            let _ = join_process_stream_output(stdout_handle, "stdout", "FFmpeg")?;
            let _ = join_process_stream_output(stderr_handle, "stderr", "FFmpeg")?;
            return Err(DOWNLOAD_INTERRUPTED_MESSAGE.to_string());
        }

        if let Some(status) = child
            .try_wait()
            .map_err(|error| format!("FFmpeg transcode wait failed: {error}"))?
        {
            let stdout = join_process_stream_output(stdout_handle, "stdout", "FFmpeg")?;
            let stderr = join_process_stream_output(stderr_handle, "stderr", "FFmpeg")?;
            for output_line in stdout_receiver.try_iter() {
                if let Some(elapsed_seconds) =
                    parse_ffmpeg_progress_elapsed_seconds(&output_line.line)
                {
                    emit_media_clip_context_progress(
                        context,
                        MediaClipProgressEvent {
                            schema_version: 1,
                            job_id: context.job_id.to_string(),
                            status: MediaClipStatus::Active,
                            elapsed_seconds,
                            output_path: Some(display_path(output_path)),
                            message: format!("FFmpeg progress: {elapsed_seconds}s processed."),
                            updated_at: Utc::now().to_rfc3339(),
                        },
                    );
                }
            }
            for _output_line in stderr_receiver.try_iter() {}
            let stdout = String::from_utf8_lossy(&stdout).to_string();
            let stderr = String::from_utf8_lossy(&stderr).to_string();
            if !status.success() {
                let detail = if stderr.trim().is_empty() {
                    stdout.trim()
                } else {
                    stderr.trim()
                };
                return Err(format!(
                    "FFmpeg transcode exited with status {status}: {detail}"
                ));
            }
            if !output_path.is_file() {
                return Err("FFmpeg finished but no transcoded media file was found.".to_string());
            }
            return Ok(());
        }

        if started.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            let _ = join_process_stream_output(stdout_handle, "stdout", "FFmpeg")?;
            let _ = join_process_stream_output(stderr_handle, "stderr", "FFmpeg")?;
            return Err("FFmpeg transcode timed out.".to_string());
        }

        if last_progress_emit.elapsed() >= Duration::from_millis(250) {
            last_progress_emit = Instant::now();
            emit_media_clip_context_progress(
                context,
                MediaClipProgressEvent {
                    schema_version: 1,
                    job_id: context.job_id.to_string(),
                    status: MediaClipStatus::Active,
                    elapsed_seconds: ffmpeg_elapsed_seconds
                        .unwrap_or_else(|| started.elapsed().as_secs()),
                    output_path: Some(display_path(output_path)),
                    message: "Transcoding media.".to_string(),
                    updated_at: Utc::now().to_rfc3339(),
                },
            );
        }

        thread::sleep(Duration::from_millis(25));
    }
}

fn run_ffmpeg_shot_detection(
    tool_path: &Path,
    input_path: &Path,
    threshold: f64,
    timeout: Duration,
) -> Result<Vec<MediaShotMarker>, String> {
    let filter = format!(
        "select='gt(scene,{})',metadata=mode=print,showinfo",
        format_seconds_arg(threshold)
    );
    let null_output = if cfg!(windows) { "NUL" } else { "/dev/null" };
    let mut child = Command::new(tool_path)
        .args(["-hide_banner", "-nostats", "-i"])
        .arg(input_path)
        .args(["-vf", &filter, "-f", "null", null_output])
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("FFmpeg shot detection failed to start: {error}"))?;
    let started = Instant::now();

    loop {
        if child
            .try_wait()
            .map_err(|error| format!("FFmpeg shot detection wait failed: {error}"))?
            .is_some()
        {
            let output = child
                .wait_with_output()
                .map_err(|error| format!("FFmpeg shot detection output failed: {error}"))?;
            let stdout = String::from_utf8_lossy(&output.stdout).to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
            if !output.status.success() {
                let detail = if stderr.trim().is_empty() {
                    stdout.trim()
                } else {
                    stderr.trim()
                };
                return Err(format!(
                    "FFmpeg shot detection exited with status {}: {detail}",
                    output.status
                ));
            }
            return Ok(parse_ffmpeg_shot_markers(&stderr));
        }

        if started.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err("FFmpeg shot detection timed out.".to_string());
        }

        thread::sleep(Duration::from_millis(25));
    }
}

fn run_ffmpeg_waveform_pcm(
    tool_path: &Path,
    input_path: &Path,
    sample_rate: u32,
    channel_count: u8,
    timeout: Duration,
) -> Result<Vec<i16>, String> {
    let mut child = Command::new(tool_path)
        .args(["-hide_banner", "-nostats", "-i"])
        .arg(input_path)
        .args([
            "-vn",
            "-ac",
            &channel_count.to_string(),
            "-ar",
            &sample_rate.to_string(),
            "-f",
            "s16le",
            "pipe:1",
        ])
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("FFmpeg waveform extraction failed to start: {error}"))?;
    let started = Instant::now();

    loop {
        if child
            .try_wait()
            .map_err(|error| format!("FFmpeg waveform extraction wait failed: {error}"))?
            .is_some()
        {
            let output = child
                .wait_with_output()
                .map_err(|error| format!("FFmpeg waveform extraction output failed: {error}"))?;
            let stdout = output.stdout;
            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
            if !output.status.success() {
                let detail = if stderr.trim().is_empty() {
                    String::from_utf8_lossy(&stdout).trim().to_string()
                } else {
                    stderr.trim().to_string()
                };
                return Err(format!(
                    "FFmpeg waveform extraction exited with status {}: {detail}",
                    output.status
                ));
            }
            if stdout.len() < 2 {
                return Err("FFmpeg waveform extraction produced no audio samples.".to_string());
            }
            return Ok(parse_s16le_samples(&stdout));
        }

        if started.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err("FFmpeg waveform extraction timed out.".to_string());
        }

        thread::sleep(Duration::from_millis(25));
    }
}

fn run_whisper_subtitle_generation(
    tool_path: &Path,
    input_path: &Path,
    output_dir: &Path,
    output_format: &str,
    language: Option<&str>,
    model: Option<&str>,
    task: &str,
    before: &HashMap<PathBuf, OutputFileSnapshot>,
    cancel_flag: &AtomicBool,
    timeout: Duration,
) -> Result<PathBuf, String> {
    let mut args = vec![
        input_path.to_string_lossy().to_string(),
        "--output_dir".to_string(),
        output_dir.to_string_lossy().to_string(),
        "--output_format".to_string(),
        output_format.to_string(),
        "--task".to_string(),
        task.to_string(),
    ];
    if let Some(language) = language {
        args.push("--language".to_string());
        args.push(language.to_string());
    }
    if let Some(model) = model {
        args.push("--model".to_string());
        args.push(model.to_string());
    }

    let mut child = Command::new(tool_path)
        .args(&args)
        .current_dir(output_dir)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("Whisper transcription failed to start: {error}"))?;
    let started = Instant::now();

    loop {
        if cancel_flag.load(Ordering::SeqCst) {
            let _ = child.kill();
            let _ = child.wait();
            return Err(DOWNLOAD_INTERRUPTED_MESSAGE.to_string());
        }

        if child
            .try_wait()
            .map_err(|error| format!("Whisper transcription wait failed: {error}"))?
            .is_some()
        {
            let output = child
                .wait_with_output()
                .map_err(|error| format!("Whisper transcription output failed: {error}"))?;
            let stdout = String::from_utf8_lossy(&output.stdout).to_string();
            let stderr = String::from_utf8_lossy(&output.stderr).to_string();
            if !output.status.success() {
                let detail = if stderr.trim().is_empty() {
                    stdout.trim()
                } else {
                    stderr.trim()
                };
                return Err(format!(
                    "Whisper transcription exited with status {}: {detail}",
                    output.status
                ));
            }

            let expected_extension = format!(".{output_format}");
            let changed = changed_files_recursive(output_dir, before)?
                .into_iter()
                .filter(|path| {
                    path.extension()
                        .and_then(|value| value.to_str())
                        .is_some_and(|extension| {
                            format!(".{}", extension.to_ascii_lowercase()) == expected_extension
                        })
                })
                .collect::<Vec<_>>();
            return changed.into_iter().next().ok_or_else(|| {
                "Whisper finished but no subtitle output file was found.".to_string()
            });
        }

        if started.elapsed() >= timeout {
            let _ = child.kill();
            let _ = child.wait();
            return Err("Whisper transcription timed out.".to_string());
        }

        thread::sleep(Duration::from_millis(100));
    }
}

fn parse_s16le_samples(bytes: &[u8]) -> Vec<i16> {
    bytes
        .chunks_exact(2)
        .map(|chunk| i16::from_le_bytes([chunk[0], chunk[1]]))
        .collect()
}

fn build_waveform_peaks(
    samples: &[i16],
    sample_rate: u32,
    bucket_count: usize,
) -> Result<Vec<WaveformPeak>, String> {
    if samples.is_empty() {
        return Err("Waveform input did not contain audio samples.".to_string());
    }

    let effective_bucket_count = bucket_count.min(samples.len());
    let mut peaks = Vec::with_capacity(effective_bucket_count);
    for index in 0..effective_bucket_count {
        let start = index * samples.len() / effective_bucket_count;
        let end = ((index + 1) * samples.len() / effective_bucket_count).max(start + 1);
        let bucket = &samples[start..end.min(samples.len())];
        let mut min_sample = i16::MAX;
        let mut max_sample = i16::MIN;
        let mut square_sum = 0.0_f64;
        for sample in bucket {
            min_sample = min_sample.min(*sample);
            max_sample = max_sample.max(*sample);
            let normalized = normalize_pcm_sample(*sample);
            square_sum += normalized * normalized;
        }
        let rms = (square_sum / bucket.len() as f64).sqrt();
        peaks.push(WaveformPeak {
            index,
            start_seconds: start as f64 / f64::from(sample_rate),
            end_seconds: end.min(samples.len()) as f64 / f64::from(sample_rate),
            min: normalize_pcm_sample(min_sample),
            max: normalize_pcm_sample(max_sample),
            rms,
        });
    }

    Ok(peaks)
}

fn normalize_pcm_sample(sample: i16) -> f64 {
    if sample == i16::MIN {
        -1.0
    } else {
        f64::from(sample) / f64::from(i16::MAX)
    }
}

fn waveform_cache_path(
    root: &Path,
    input_path: &Path,
    bucket_count: usize,
) -> Result<PathBuf, String> {
    let metadata = fs::metadata(input_path)
        .map_err(|error| format!("Input media metadata is not accessible: {error}"))?;
    let mut hasher = Sha256::new();
    hasher.update(input_path.to_string_lossy().as_bytes());
    hasher.update(metadata.len().to_le_bytes());
    if let Ok(modified) = metadata.modified() {
        if let Ok(duration) = modified.duration_since(std::time::UNIX_EPOCH) {
            hasher.update(duration.as_nanos().to_le_bytes());
        }
    }
    hasher.update(bucket_count.to_le_bytes());
    let digest = hasher.finalize();
    let hash = digest
        .iter()
        .take(12)
        .map(|byte| format!("{byte:02x}"))
        .collect::<String>();
    Ok(root
        .join("cache")
        .join("waveform")
        .join(format!("{hash}.waveform.json")))
}

fn parse_ffmpeg_shot_markers(output: &str) -> Vec<MediaShotMarker> {
    let mut markers = Vec::new();
    let mut pending_timestamp = None;

    for line in output.lines() {
        if let Some(timestamp_seconds) =
            value_after_token(line, "pts_time:").and_then(|value| value.parse::<f64>().ok())
        {
            pending_timestamp = Some(timestamp_seconds);
        }

        if let Some(marker) = parse_ffmpeg_shot_marker_line(line) {
            markers.push(marker);
            pending_timestamp = None;
            continue;
        }

        if let Some(score) = value_after_token(line, "lavfi.scene_score=")
            .or_else(|| value_after_token(line, "scene_score="))
            .and_then(|value| value.parse::<f64>().ok())
        {
            if let Some(timestamp_seconds) = pending_timestamp.take() {
                markers.push(MediaShotMarker {
                    timestamp_seconds,
                    score,
                });
            }
        }
    }

    markers
}

fn parse_ffmpeg_shot_marker_line(line: &str) -> Option<MediaShotMarker> {
    let timestamp_seconds = value_after_token(line, "pts_time:")?.parse::<f64>().ok()?;
    let score = value_after_token(line, "lavfi.scene_score=")
        .or_else(|| value_after_token(line, "scene_score="))?
        .parse::<f64>()
        .ok()?;
    Some(MediaShotMarker {
        timestamp_seconds,
        score,
    })
}

fn value_after_token<'a>(line: &'a str, token: &str) -> Option<&'a str> {
    let after = line.split(token).nth(1)?;
    after.split_whitespace().next()
}

fn parse_ytdlp_metadata_preview(
    fallback_source_url: &str,
    output: &str,
) -> Result<MetadataPreview, String> {
    let value: serde_json::Value = serde_json::from_str(output.trim())
        .map_err(|error| format!("yt-dlp metadata JSON was invalid: {error}"))?;
    let source_url = string_field(&value, "webpage_url")
        .or_else(|| string_field(&value, "original_url"))
        .unwrap_or_else(|| fallback_source_url.to_string());
    let formats = value
        .get("formats")
        .and_then(|formats| formats.as_array())
        .map(|formats| {
            formats
                .iter()
                .filter_map(parse_ytdlp_metadata_format)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();

    Ok(MetadataPreview {
        schema_version: 1,
        platform: classify_platform(&source_url),
        source_url,
        title: string_field(&value, "title"),
        author: string_field(&value, "uploader").or_else(|| string_field(&value, "channel")),
        thumbnail_url: string_field(&value, "thumbnail"),
        duration_seconds: value.get("duration").and_then(json_number_to_u64_rounded),
        formats,
    })
}

fn parse_ytdlp_playlist_preview(
    fallback_source_url: &str,
    output: &str,
    limit: usize,
) -> Result<MetadataPlaylistPreview, String> {
    let trimmed = output.trim();
    if trimmed.is_empty() {
        return Err("yt-dlp playlist metadata was empty.".to_string());
    }

    let mut playlist_value: Option<serde_json::Value> = None;
    let mut entry_values = Vec::new();

    if let Ok(value) = serde_json::from_str::<serde_json::Value>(trimmed) {
        if let Some(entries) = value.get("entries").and_then(|entries| entries.as_array()) {
            entry_values.extend(entries.iter().cloned());
            playlist_value = Some(value);
        } else {
            entry_values.push(value);
        }
    } else {
        for line in trimmed
            .lines()
            .map(str::trim)
            .filter(|line| !line.is_empty())
        {
            let value: serde_json::Value = serde_json::from_str(line)
                .map_err(|error| format!("yt-dlp playlist JSON line was invalid: {error}"))?;
            if let Some(entries) = value.get("entries").and_then(|entries| entries.as_array()) {
                entry_values.extend(entries.iter().cloned());
                playlist_value = Some(value);
            } else {
                entry_values.push(value);
            }
        }
    }

    let parsed_count = entry_values.len();
    let entries = entry_values
        .iter()
        .take(limit)
        .enumerate()
        .filter_map(|(offset, value)| parse_ytdlp_playlist_entry(value, offset))
        .collect::<Vec<_>>();
    let item_count = playlist_value
        .as_ref()
        .and_then(|value| value.get("playlist_count"))
        .and_then(json_number_to_u64_floor)
        .map(|value| value as usize)
        .or_else(|| {
            playlist_value
                .as_ref()
                .and_then(|value| value.get("n_entries"))
                .and_then(json_number_to_u64_floor)
                .map(|value| value as usize)
        })
        .unwrap_or(parsed_count);
    let source_url = playlist_value
        .as_ref()
        .and_then(|value| string_field(value, "webpage_url"))
        .or_else(|| {
            playlist_value
                .as_ref()
                .and_then(|value| string_field(value, "original_url"))
        })
        .unwrap_or_else(|| fallback_source_url.to_string());

    Ok(MetadataPlaylistPreview {
        schema_version: 1,
        platform: classify_platform(&source_url),
        source_url,
        title: playlist_value
            .as_ref()
            .and_then(|value| string_field(value, "title"))
            .or_else(|| {
                entries
                    .first()
                    .and_then(|entry| entry.title.as_ref())
                    .map(ToString::to_string)
            }),
        author: playlist_value
            .as_ref()
            .and_then(|value| string_field(value, "uploader"))
            .or_else(|| {
                playlist_value
                    .as_ref()
                    .and_then(|value| string_field(value, "channel"))
            })
            .or_else(|| {
                entries
                    .first()
                    .and_then(|entry| entry.author.as_ref())
                    .map(ToString::to_string)
            }),
        item_count,
        truncated: parsed_count > entries.len() || item_count > entries.len(),
        entries,
    })
}

fn parse_ytdlp_playlist_entry(
    value: &serde_json::Value,
    fallback_offset: usize,
) -> Option<MetadataPlaylistEntry> {
    let title = string_field(value, "title");
    let url = string_field(value, "url");
    let webpage_url = string_field(value, "webpage_url")
        .or_else(|| string_field(value, "original_url"))
        .or_else(|| absolute_http_url_field(value, "url"));
    let id = string_field(value, "id");
    if title.is_none() && url.is_none() && webpage_url.is_none() && id.is_none() {
        return None;
    }

    Some(MetadataPlaylistEntry {
        index: value
            .get("playlist_index")
            .or_else(|| value.get("playlist_autonumber"))
            .and_then(json_number_to_u64_floor)
            .or_else(|| Some((fallback_offset + 1) as u64)),
        id,
        title,
        url,
        webpage_url,
        duration_seconds: value.get("duration").and_then(json_number_to_u64_rounded),
        author: string_field(value, "uploader").or_else(|| string_field(value, "channel")),
        thumbnail_url: string_field(value, "thumbnail"),
    })
}

fn absolute_http_url_field(value: &serde_json::Value, field: &str) -> Option<String> {
    let candidate = string_field(value, field)?;
    if candidate.starts_with("http://") || candidate.starts_with("https://") {
        Some(candidate)
    } else {
        None
    }
}

fn parse_gallery_dl_url_preview(
    source_url: &str,
    output: &str,
    limit: usize,
) -> Result<GalleryPreview, String> {
    let mut seen = HashSet::new();
    let mut urls = Vec::new();
    for line in output
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
    {
        let Some(url) = extract_first_http_url(line) else {
            continue;
        };
        if seen.insert(url.clone()) {
            urls.push(url);
        }
    }

    if urls.is_empty() {
        return Err("gallery-dl did not report any downloadable URLs.".to_string());
    }

    let item_count = urls.len();
    let entries = urls
        .iter()
        .take(limit)
        .enumerate()
        .map(|(offset, url)| gallery_preview_entry(url, offset + 1))
        .collect::<Vec<_>>();

    Ok(GalleryPreview {
        schema_version: 1,
        source_url: source_url.to_string(),
        platform: classify_platform(source_url),
        item_count,
        truncated: item_count > entries.len(),
        entries,
    })
}

fn extract_first_http_url(line: &str) -> Option<String> {
    extract_http_urls(line).into_iter().next()
}

fn extract_http_urls(text: &str) -> Vec<String> {
    let mut urls = Vec::new();
    let mut seen = HashSet::new();
    let mut index = 0;
    while index < text.len() {
        let rest = &text[index..];
        let Some((offset, marker)) = find_next_url_marker(rest) else {
            break;
        };
        let start = index + offset;
        let candidate = &text[start..];
        let end = candidate
            .find(char::is_whitespace)
            .unwrap_or(candidate.len());
        let raw_url = trim_extracted_url(&candidate[..end]);
        let url = if marker == "fetchdock://" {
            extract_captured_http_url(raw_url)
        } else {
            Some(raw_url.to_string())
        };
        if let Some(url) = url {
            let url = trim_extracted_url(&url).to_string();
            if is_http_url_text(&url) && url.len() > "https://".len() && seen.insert(url.clone()) {
                urls.push(url);
            }
        }
        index = start + end.max(1);
    }
    urls
}

fn find_next_url_marker(text: &str) -> Option<(usize, &'static str)> {
    let lower = text.to_ascii_lowercase();
    ["http://", "https://", "fetchdock://"]
        .into_iter()
        .filter_map(|marker| lower.find(marker).map(|offset| (offset, marker)))
        .min_by_key(|(offset, _)| *offset)
}

fn extract_captured_http_url(raw_url: &str) -> Option<String> {
    let trimmed = raw_url.trim();
    let lower = trimmed.to_ascii_lowercase();
    if !lower.starts_with("fetchdock://") {
        return None;
    }
    let query = trimmed.split_once('?')?.1;
    let mut params = parse_shell_open_query(query);
    params
        .remove("url")
        .or_else(|| params.remove("u"))
        .filter(|url| is_http_url_text(url))
}

fn is_http_url_text(value: &str) -> bool {
    let lower = value.trim().to_ascii_lowercase();
    lower.starts_with("http://") || lower.starts_with("https://")
}

fn trim_extracted_url(value: &str) -> &str {
    value.trim_matches(|character: char| {
        matches!(
            character,
            '"' | '\'' | '`' | ',' | ';' | ':' | '.' | '!' | '?' | ')' | ']' | '}' | '>'
        )
    })
}

fn gallery_preview_entry(url: &str, index: usize) -> GalleryPreviewEntry {
    let file_name = gallery_file_name_from_url(url);
    let extension = file_name.as_deref().and_then(file_extension_from_name);
    let media_kind = extension
        .as_deref()
        .map(media_kind_from_extension)
        .unwrap_or("unknown")
        .to_string();

    GalleryPreviewEntry {
        index: index as u64,
        url: url.to_string(),
        file_name,
        extension,
        media_kind,
    }
}

fn gallery_file_name_from_url(url: &str) -> Option<String> {
    let without_query = url
        .split(['?', '#'])
        .next()
        .unwrap_or(url)
        .trim_end_matches('/');
    let raw_name = without_query.rsplit('/').next()?.trim();
    if raw_name.is_empty() || raw_name.eq_ignore_ascii_case("download") {
        return None;
    }
    Some(sanitize_file_name(raw_name))
}

fn file_extension_from_name(file_name: &str) -> Option<String> {
    let extension = file_name.rsplit_once('.')?.1.trim();
    if extension.is_empty()
        || extension.len() > 12
        || !extension
            .chars()
            .all(|character| character.is_ascii_alphanumeric())
    {
        return None;
    }
    Some(extension.to_ascii_lowercase())
}

fn media_kind_from_extension(extension: &str) -> &'static str {
    match extension.to_ascii_lowercase().as_str() {
        "jpg" | "jpeg" | "png" | "gif" | "webp" | "avif" | "bmp" | "tif" | "tiff" => "image",
        "mp4" | "webm" | "mov" | "m4v" | "mkv" | "avi" => "video",
        "mp3" | "m4a" | "flac" | "ogg" | "opus" | "wav" => "audio",
        _ => "unknown",
    }
}

fn parse_ytdlp_subtitle_options(output: &str) -> Vec<SubtitleOption> {
    let mut subtitles = Vec::new();
    let mut in_table = false;
    let mut is_auto = false;

    for line in output.lines() {
        let trimmed = line.trim();
        if trimmed.is_empty() {
            in_table = false;
            continue;
        }

        if trimmed.contains("Available automatic captions") {
            in_table = false;
            is_auto = true;
            continue;
        }

        if trimmed.contains("Available subtitles") {
            in_table = false;
            is_auto = false;
            continue;
        }

        if trimmed.starts_with("Language") && trimmed.contains("Formats") {
            in_table = true;
            continue;
        }

        if !in_table || trimmed.starts_with('[') {
            continue;
        }

        if let Some(option) = parse_ytdlp_subtitle_option_line(trimmed, is_auto) {
            subtitles.push(option);
        }
    }

    subtitles
}

fn parse_ytdlp_subtitle_option_line(line: &str, is_auto: bool) -> Option<SubtitleOption> {
    let (language, rest) = split_once_whitespace(line)?;
    let (name, formats_text) = split_name_and_formats(rest)?;
    let formats = formats_text
        .split(',')
        .map(str::trim)
        .filter(|format| !format.is_empty())
        .map(ToString::to_string)
        .collect::<Vec<_>>();

    if formats.is_empty() {
        return None;
    }

    Some(SubtitleOption {
        language: language.to_string(),
        name,
        formats,
        is_auto,
    })
}

fn parse_ytdlp_thumbnail_options(output: &str) -> Result<Vec<ThumbnailOption>, String> {
    let value: serde_json::Value = serde_json::from_str(output.trim())
        .map_err(|error| format!("yt-dlp metadata JSON was invalid: {error}"))?;
    let mut thumbnails = value
        .get("thumbnails")
        .and_then(|thumbnails| thumbnails.as_array())
        .map(|thumbnails| {
            thumbnails
                .iter()
                .filter_map(parse_ytdlp_thumbnail_option)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default();

    if thumbnails.is_empty() {
        if let Some(url) = string_field(&value, "thumbnail") {
            thumbnails.push(ThumbnailOption {
                id: None,
                url,
                width: None,
                height: None,
                preference: None,
            });
        }
    }

    Ok(thumbnails)
}

fn parse_ytdlp_thumbnail_option(value: &serde_json::Value) -> Option<ThumbnailOption> {
    Some(ThumbnailOption {
        id: string_field(value, "id"),
        url: string_field(value, "url")?,
        width: value.get("width").and_then(json_number_to_u64_floor),
        height: value.get("height").and_then(json_number_to_u64_floor),
        preference: value.get("preference").and_then(json_number_to_i64_floor),
    })
}

fn parse_ytdlp_chapter_options(output: &str) -> Result<Vec<ChapterOption>, String> {
    let value: serde_json::Value = serde_json::from_str(output.trim())
        .map_err(|error| format!("yt-dlp metadata JSON was invalid: {error}"))?;
    Ok(value
        .get("chapters")
        .and_then(|chapters| chapters.as_array())
        .map(|chapters| {
            chapters
                .iter()
                .filter_map(parse_ytdlp_chapter_option)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default())
}

fn parse_ytdlp_chapter_option(value: &serde_json::Value) -> Option<ChapterOption> {
    let title = string_field(value, "title");
    let start_seconds = value
        .get("start_time")
        .or_else(|| value.get("start"))
        .and_then(json_number_to_f64);
    let end_seconds = value
        .get("end_time")
        .or_else(|| value.get("end"))
        .and_then(json_number_to_f64);

    if title.is_none() && start_seconds.is_none() && end_seconds.is_none() {
        return None;
    }

    Some(ChapterOption {
        title,
        start_seconds,
        end_seconds,
    })
}

fn parse_ytdlp_comment_options(output: &str) -> Result<Vec<CommentOption>, String> {
    let value: serde_json::Value = serde_json::from_str(output.trim())
        .map_err(|error| format!("yt-dlp comments JSON was invalid: {error}"))?;
    Ok(value
        .get("comments")
        .and_then(|comments| comments.as_array())
        .map(|comments| {
            comments
                .iter()
                .filter_map(parse_ytdlp_comment_option)
                .collect::<Vec<_>>()
        })
        .unwrap_or_default())
}

fn parse_ytdlp_comment_option(value: &serde_json::Value) -> Option<CommentOption> {
    let text = string_field(value, "text")
        .or_else(|| string_field(value, "comment"))
        .or_else(|| string_field(value, "html").map(|html| strip_simple_html_tags(&html)))?;
    let normalized_text = text
        .lines()
        .map(str::trim)
        .filter(|line| !line.is_empty())
        .collect::<Vec<_>>()
        .join("\n");
    if normalized_text.is_empty() {
        return None;
    }

    Some(CommentOption {
        id: string_field(value, "id"),
        author: string_field(value, "author")
            .or_else(|| string_field(value, "author_id"))
            .or_else(|| string_field(value, "author_name")),
        text: normalized_text,
        timestamp_seconds: value
            .get("timestamp")
            .or_else(|| value.get("time"))
            .and_then(json_number_to_f64)
            .or_else(|| {
                string_field(value, "time_text").and_then(|text| parse_time_text_seconds(&text))
            }),
        like_count: value
            .get("like_count")
            .or_else(|| value.get("likes"))
            .and_then(json_number_to_i64_floor),
        reply_count: value
            .get("reply_count")
            .or_else(|| value.get("replies"))
            .and_then(json_number_to_i64_floor),
    })
}

fn strip_simple_html_tags(value: &str) -> String {
    let mut output = String::with_capacity(value.len());
    let mut inside_tag = false;
    for character in value.chars() {
        match character {
            '<' => inside_tag = true,
            '>' => inside_tag = false,
            _ if !inside_tag => output.push(character),
            _ => {}
        }
    }
    output
        .replace("&amp;", "&")
        .replace("&lt;", "<")
        .replace("&gt;", ">")
        .replace("&quot;", "\"")
        .replace("&#39;", "'")
        .trim()
        .to_string()
}

fn parse_time_text_seconds(value: &str) -> Option<f64> {
    let parts = value
        .trim()
        .split(':')
        .map(str::trim)
        .filter(|part| !part.is_empty())
        .collect::<Vec<_>>();
    if parts.is_empty() || parts.len() > 3 {
        return None;
    }

    let mut seconds = 0_u64;
    for part in parts {
        let parsed = part.parse::<u64>().ok()?;
        seconds = seconds.saturating_mul(60).saturating_add(parsed);
    }
    Some(seconds as f64)
}

fn validate_subtitle_selector_value(value: &str, label: &str) -> Result<String, String> {
    let trimmed = value.trim();
    if trimmed.is_empty() {
        return Err(format!("{label} is required."));
    }
    if !trimmed
        .chars()
        .all(|character| character.is_ascii_alphanumeric() || matches!(character, '-' | '_' | '.'))
    {
        return Err(format!("{label} contains unsupported characters."));
    }
    Ok(trimmed.to_string())
}

fn split_once_whitespace(value: &str) -> Option<(&str, &str)> {
    let split_at = value.find(char::is_whitespace)?;
    let left = value[..split_at].trim();
    let right = value[split_at..].trim();
    (!left.is_empty() && !right.is_empty()).then_some((left, right))
}

fn split_name_and_formats(value: &str) -> Option<(Option<String>, &str)> {
    let known_format_prefixes = ["vtt", "srt", "ttml", "srv", "json", "ass"];
    let split_at = if known_format_prefixes
        .iter()
        .any(|prefix| value.starts_with(prefix))
    {
        0
    } else {
        [" vtt", " srt", " ttml", " srv", " json", " ass"]
            .iter()
            .filter_map(|marker| value.find(marker))
            .min()?
    };
    let name = value[..split_at]
        .trim()
        .trim_end_matches(',')
        .trim()
        .to_string();
    let formats = value[split_at..].trim();
    Some(((!name.is_empty()).then_some(name), formats))
}

fn parse_ytdlp_metadata_format(value: &serde_json::Value) -> Option<MetadataPreviewFormat> {
    let id = string_field(value, "format_id")?;
    Some(MetadataPreviewFormat {
        id,
        label: string_field(value, "format_note").or_else(|| string_field(value, "format")),
        ext: string_field(value, "ext"),
        width: value.get("width").and_then(json_number_to_u64_floor),
        height: value.get("height").and_then(json_number_to_u64_floor),
        filesize_bytes: value
            .get("filesize")
            .and_then(json_number_to_u64_floor)
            .or_else(|| {
                value
                    .get("filesize_approx")
                    .and_then(json_number_to_u64_floor)
            }),
        vcodec: string_field(value, "vcodec"),
        acodec: string_field(value, "acodec"),
    })
}

fn string_field(value: &serde_json::Value, field: &str) -> Option<String> {
    value
        .get(field)
        .and_then(|value| value.as_str())
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(ToString::to_string)
}

fn json_number_to_u64_floor(value: &serde_json::Value) -> Option<u64> {
    value.as_u64().or_else(|| {
        value
            .as_f64()
            .filter(|number| *number >= 0.0)
            .map(|number| number as u64)
    })
}

fn json_number_to_i64_floor(value: &serde_json::Value) -> Option<i64> {
    value
        .as_i64()
        .or_else(|| value.as_f64().map(|number| number.floor() as i64))
}

fn json_number_to_f64(value: &serde_json::Value) -> Option<f64> {
    value.as_f64().filter(|number| number.is_finite())
}

fn json_number_to_u64_rounded(value: &serde_json::Value) -> Option<u64> {
    value.as_u64().or_else(|| {
        value
            .as_f64()
            .filter(|number| *number >= 0.0)
            .map(|number| number.round() as u64)
    })
}

#[cfg(test)]
fn execute_ytdlp_download(
    root: &Path,
    task: &DownloadTask,
) -> Result<DownloadCopyProgress, String> {
    let cancel_flag = AtomicBool::new(false);
    execute_ytdlp_download_with_app(root, task, None, &cancel_flag)
}

fn execute_ytdlp_download_with_app(
    root: &Path,
    task: &DownloadTask,
    app: Option<&AppHandle>,
    cancel_flag: &AtomicBool,
) -> Result<DownloadCopyProgress, String> {
    let output_dir = task
        .output_dir
        .as_ref()
        .map(PathBuf::from)
        .unwrap_or_else(|| root.join("downloads"));
    let settings = read_downloads_settings(root)?;
    let plan = plan_ytdlp_download_at_root(root, task, &output_dir, &settings)?;
    let tool_path = resolve_tool_command_path(root, &plan.executable)?;
    let effective_output_dir = ytdlp_output_directory(&output_dir, task, &settings);
    fs::create_dir_all(&effective_output_dir).map_err(|error| error.to_string())?;
    let before = snapshot_files_in_directory(&effective_output_dir)?;
    let mut child = Command::new(&tool_path)
        .args(&plan.args)
        .current_dir(&output_dir)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("yt-dlp failed to start: {error}"))?;
    let stdout = child
        .stdout
        .take()
        .ok_or_else(|| "yt-dlp stdout stream was not available.".to_string())?;
    let stderr = child
        .stderr
        .take()
        .ok_or_else(|| "yt-dlp stderr stream was not available.".to_string())?;
    let (stdout_handle, stdout_receiver) = spawn_ytdlp_stream_reader(stdout, "stdout");
    let (stderr_handle, stderr_receiver) = spawn_ytdlp_stream_reader(stderr, "stderr");
    let status = loop {
        for output_line in stdout_receiver.try_iter() {
            handle_ytdlp_process_output_line(
                root,
                task,
                app,
                output_line.stream,
                &output_line.line,
            );
        }
        for output_line in stderr_receiver.try_iter() {
            handle_ytdlp_process_output_line(
                root,
                task,
                app,
                output_line.stream,
                &output_line.line,
            );
        }

        if cancel_flag.load(Ordering::SeqCst) {
            let _ = child.kill();
            let _ = child.wait();
            let _ = join_ytdlp_stream_output(stdout_handle, "stdout")?;
            let _ = join_ytdlp_stream_output(stderr_handle, "stderr")?;
            for output_line in stdout_receiver.try_iter() {
                handle_ytdlp_process_output_line(
                    root,
                    task,
                    app,
                    output_line.stream,
                    &output_line.line,
                );
            }
            for output_line in stderr_receiver.try_iter() {
                handle_ytdlp_process_output_line(
                    root,
                    task,
                    app,
                    output_line.stream,
                    &output_line.line,
                );
            }
            return Err(DOWNLOAD_INTERRUPTED_MESSAGE.to_string());
        }

        if let Some(status) = child
            .try_wait()
            .map_err(|error| format!("yt-dlp wait failed: {error}"))?
        {
            break status;
        }

        thread::sleep(Duration::from_millis(25));
    };
    let stdout = join_ytdlp_stream_output(stdout_handle, "stdout")?;
    let stderr = join_ytdlp_stream_output(stderr_handle, "stderr")?;
    for output_line in stdout_receiver.try_iter() {
        handle_ytdlp_process_output_line(root, task, app, output_line.stream, &output_line.line);
    }
    for output_line in stderr_receiver.try_iter() {
        handle_ytdlp_process_output_line(root, task, app, output_line.stream, &output_line.line);
    }

    if !status.success() {
        let stderr_text = String::from_utf8_lossy(&stderr);
        let stdout_text = String::from_utf8_lossy(&stdout);
        let detail = if !stderr_text.trim().is_empty() {
            stderr_text.trim()
        } else {
            stdout_text.trim()
        };
        return Err(format!("yt-dlp exited with status {status}: {detail}"));
    }

    let output_path = changed_file_in_directory(&effective_output_dir, &before)?
        .ok_or_else(|| "yt-dlp finished but no new output file was found.".to_string())?;
    let downloaded_bytes = fs::metadata(&output_path)
        .map_err(|error| error.to_string())?
        .len();

    Ok(DownloadCopyProgress {
        output_path: display_path(&output_path),
        downloaded_bytes,
        total_bytes: Some(downloaded_bytes),
        file_count: 1,
    })
}

fn plan_external_gallery_download(
    app: &AppHandle,
    task: &DownloadTask,
    cancel_flag: &AtomicBool,
) -> Result<DownloadCopyProgress, String> {
    let (_, root) = resolve_data_root(app).map_err(|error| error.to_string())?;
    prepare_external_gallery_download_at_root(&root, task, Some(app), cancel_flag)
}

fn prepare_external_gallery_download_at_root(
    root: &Path,
    task: &DownloadTask,
    app: Option<&AppHandle>,
    cancel_flag: &AtomicBool,
) -> Result<DownloadCopyProgress, String> {
    let output_dir = task
        .output_dir
        .as_ref()
        .map(PathBuf::from)
        .unwrap_or_else(|| root.join("downloads"));
    let settings = read_downloads_settings(root)?;
    let plan = plan_gallery_download_at_root(root, task, &output_dir, &settings)?;
    append_download_log_line(
        root,
        &task.id,
        &format!(
            "gallery-dl plan prepared: {} {}",
            plan.executable,
            redact_tool_args(&plan.args).join(" ")
        ),
    );
    execute_gallery_download_with_app(root, task, app, cancel_flag)
}

fn plan_gallery_download_at_root(
    root: &Path,
    task: &DownloadTask,
    output_dir: &Path,
    settings: &DownloadsSettings,
) -> Result<ToolCommandPlan, String> {
    if !matches!(task.kind, DownloadKind::Image) {
        return Err("gallery-dl only handles image gallery tasks.".to_string());
    }

    let target_dir = gallery_output_directory(output_dir, task, settings);
    let mut args = vec!["--dest".to_string(), display_path(&target_dir)];
    let context = gallery_dl_context_from_task(task);
    append_gallery_dl_context_args(root, &context, &mut args)?;
    args.push(task.source_url.clone());
    Ok(ToolCommandPlan {
        executable: "gallery-dl".to_string(),
        args,
    })
}

fn gallery_output_directory(
    output_dir: &Path,
    task: &DownloadTask,
    settings: &DownloadsSettings,
) -> PathBuf {
    let base = if settings.organize_by_platform {
        output_dir.join(sanitize_file_name(&task.platform))
    } else {
        output_dir.to_path_buf()
    };
    base.join("gallery-dl").join(sanitize_file_name(&task.id))
}

fn execute_gallery_download_with_app(
    root: &Path,
    task: &DownloadTask,
    app: Option<&AppHandle>,
    cancel_flag: &AtomicBool,
) -> Result<DownloadCopyProgress, String> {
    let output_dir = task
        .output_dir
        .as_ref()
        .map(PathBuf::from)
        .unwrap_or_else(|| root.join("downloads"));
    let settings = read_downloads_settings(root)?;
    let plan = plan_gallery_download_at_root(root, task, &output_dir, &settings)?;
    let tool_path = resolve_tool_command_path(root, &plan.executable)?;
    let effective_output_dir = gallery_output_directory(&output_dir, task, &settings);
    fs::create_dir_all(&effective_output_dir).map_err(|error| error.to_string())?;
    let before = snapshot_files_recursive(&effective_output_dir)?;
    let mut child = Command::new(&tool_path)
        .args(&plan.args)
        .current_dir(&output_dir)
        .stdin(Stdio::null())
        .stdout(Stdio::piped())
        .stderr(Stdio::piped())
        .spawn()
        .map_err(|error| format!("gallery-dl failed to start: {error}"))?;
    let stdout = child
        .stdout
        .take()
        .ok_or_else(|| "gallery-dl stdout stream was not available.".to_string())?;
    let stderr = child
        .stderr
        .take()
        .ok_or_else(|| "gallery-dl stderr stream was not available.".to_string())?;
    let (stdout_handle, stdout_receiver) =
        spawn_process_stream_reader(stdout, "stdout", "gallery-dl");
    let (stderr_handle, stderr_receiver) =
        spawn_process_stream_reader(stderr, "stderr", "gallery-dl");
    let status = loop {
        for output_line in stdout_receiver.try_iter() {
            handle_gallery_process_output_line(
                root,
                task,
                app,
                output_line.stream,
                &output_line.line,
            );
        }
        for output_line in stderr_receiver.try_iter() {
            handle_gallery_process_output_line(
                root,
                task,
                app,
                output_line.stream,
                &output_line.line,
            );
        }

        if cancel_flag.load(Ordering::SeqCst) {
            let _ = child.kill();
            let _ = child.wait();
            let _ = join_process_stream_output(stdout_handle, "stdout", "gallery-dl")?;
            let _ = join_process_stream_output(stderr_handle, "stderr", "gallery-dl")?;
            for output_line in stdout_receiver.try_iter() {
                handle_gallery_process_output_line(
                    root,
                    task,
                    app,
                    output_line.stream,
                    &output_line.line,
                );
            }
            for output_line in stderr_receiver.try_iter() {
                handle_gallery_process_output_line(
                    root,
                    task,
                    app,
                    output_line.stream,
                    &output_line.line,
                );
            }
            return Err(DOWNLOAD_INTERRUPTED_MESSAGE.to_string());
        }

        if let Some(status) = child
            .try_wait()
            .map_err(|error| format!("gallery-dl wait failed: {error}"))?
        {
            break status;
        }

        thread::sleep(Duration::from_millis(25));
    };
    let stdout = join_process_stream_output(stdout_handle, "stdout", "gallery-dl")?;
    let stderr = join_process_stream_output(stderr_handle, "stderr", "gallery-dl")?;
    for output_line in stdout_receiver.try_iter() {
        handle_gallery_process_output_line(root, task, app, output_line.stream, &output_line.line);
    }
    for output_line in stderr_receiver.try_iter() {
        handle_gallery_process_output_line(root, task, app, output_line.stream, &output_line.line);
    }

    if !status.success() {
        let stderr_text = String::from_utf8_lossy(&stderr);
        let stdout_text = String::from_utf8_lossy(&stdout);
        let detail = if !stderr_text.trim().is_empty() {
            stderr_text.trim()
        } else {
            stdout_text.trim()
        };
        return Err(format!("gallery-dl exited with status {status}: {detail}"));
    }

    let changed = changed_files_recursive(&effective_output_dir, &before)?;
    if changed.is_empty() {
        return Err("gallery-dl finished but no new output files were found.".to_string());
    }
    let downloaded_bytes = changed
        .iter()
        .filter_map(|path| fs::metadata(path).ok())
        .map(|metadata| metadata.len())
        .sum::<u64>();

    Ok(DownloadCopyProgress {
        output_path: display_path(&effective_output_dir),
        downloaded_bytes,
        total_bytes: Some(downloaded_bytes),
        file_count: changed.len().try_into().unwrap_or(u32::MAX),
    })
}

fn handle_gallery_process_output_line(
    root: &Path,
    task: &DownloadTask,
    app: Option<&AppHandle>,
    stream: &str,
    line: &str,
) {
    let trimmed = line.trim();
    if !trimmed.is_empty() {
        append_download_log_line(root, &task.id, &format!("gallery-dl {stream}: {trimmed}"));
    }
    if let Some(app) = app {
        emit_download_progress(
            app,
            DownloadProgressEvent {
                schema_version: 1,
                task_id: task.id.clone(),
                status: DownloadStatus::Active,
                downloaded_bytes: task.downloaded_bytes.unwrap_or(0),
                total_bytes: task.total_bytes,
                speed_bytes_per_sec: None,
                eta_seconds: None,
                file_count: None,
                output_path: task.output_path.clone(),
                message: trimmed
                    .is_empty()
                    .then(|| "gallery-dl is running.".to_string())
                    .unwrap_or_else(|| trimmed.to_string()),
                updated_at: Utc::now().to_rfc3339(),
            },
        );
    }
}

fn resolve_tool_command_path(root: &Path, tool_id: &str) -> Result<PathBuf, String> {
    validate_tool_id(tool_id)?;
    let settings = read_tool_settings(root)?;
    if let Some(raw_path) = settings.path_overrides.get(tool_id) {
        return validate_tool_override_path(tool_id, raw_path);
    }
    if let Some(managed_path) = managed_tool_path(root, tool_id).filter(|path| path.is_file()) {
        return Ok(managed_path);
    }
    find_tool_on_path(tool_id, None).ok_or_else(|| {
        format!("{tool_id} was not found. Install it from Settings or set a valid executable path.")
    })
}

#[derive(Clone, Copy, PartialEq, Eq)]
struct OutputFileSnapshot {
    modified: std::time::SystemTime,
    len: u64,
}

fn snapshot_files_in_directory(
    directory: &Path,
) -> Result<HashMap<PathBuf, OutputFileSnapshot>, String> {
    let mut snapshot = HashMap::new();
    if !directory.exists() {
        return Ok(snapshot);
    }

    for entry in fs::read_dir(directory).map_err(|error| error.to_string())? {
        let entry = entry.map_err(|error| error.to_string())?;
        let metadata = entry.metadata().map_err(|error| error.to_string())?;
        if !metadata.is_file() {
            continue;
        }
        snapshot.insert(
            entry.path(),
            OutputFileSnapshot {
                modified: metadata
                    .modified()
                    .unwrap_or(std::time::SystemTime::UNIX_EPOCH),
                len: metadata.len(),
            },
        );
    }

    Ok(snapshot)
}

fn snapshot_files_recursive(
    directory: &Path,
) -> Result<HashMap<PathBuf, OutputFileSnapshot>, String> {
    let mut snapshot = HashMap::new();
    if !directory.exists() {
        return Ok(snapshot);
    }

    let mut pending = vec![directory.to_path_buf()];
    while let Some(current) = pending.pop() {
        for entry in fs::read_dir(&current).map_err(|error| error.to_string())? {
            let entry = entry.map_err(|error| error.to_string())?;
            let metadata = entry.metadata().map_err(|error| error.to_string())?;
            if metadata.is_dir() {
                pending.push(entry.path());
                continue;
            }
            if !metadata.is_file() {
                continue;
            }
            snapshot.insert(
                entry.path(),
                OutputFileSnapshot {
                    modified: metadata
                        .modified()
                        .unwrap_or(std::time::SystemTime::UNIX_EPOCH),
                    len: metadata.len(),
                },
            );
        }
    }

    Ok(snapshot)
}

fn changed_file_in_directory(
    directory: &Path,
    before: &HashMap<PathBuf, OutputFileSnapshot>,
) -> Result<Option<PathBuf>, String> {
    if !directory.exists() {
        return Ok(None);
    }

    let mut newest: Option<(std::time::SystemTime, PathBuf)> = None;
    for entry in fs::read_dir(directory).map_err(|error| error.to_string())? {
        let entry = entry.map_err(|error| error.to_string())?;
        let metadata = entry.metadata().map_err(|error| error.to_string())?;
        if !metadata.is_file() {
            continue;
        }
        let modified = metadata
            .modified()
            .unwrap_or(std::time::SystemTime::UNIX_EPOCH);
        let snapshot = OutputFileSnapshot {
            modified,
            len: metadata.len(),
        };
        if before.get(&entry.path()) == Some(&snapshot) {
            continue;
        }
        let replace = newest
            .as_ref()
            .map_or(true, |(current_modified, _)| modified > *current_modified);
        if replace {
            newest = Some((modified, entry.path()));
        }
    }

    Ok(newest.map(|(_, path)| path))
}

fn changed_files_recursive(
    directory: &Path,
    before: &HashMap<PathBuf, OutputFileSnapshot>,
) -> Result<Vec<PathBuf>, String> {
    let after = snapshot_files_recursive(directory)?;
    let mut changed = after
        .into_iter()
        .filter_map(|(path, snapshot)| (before.get(&path) != Some(&snapshot)).then_some(path))
        .collect::<Vec<_>>();
    changed.sort();
    Ok(changed)
}

fn move_generated_output_to_requested_path(
    generated_path: PathBuf,
    requested_path: Option<PathBuf>,
    label: &str,
) -> Result<PathBuf, String> {
    let Some(requested_path) = requested_path else {
        return Ok(generated_path);
    };
    if generated_path == requested_path {
        return Ok(requested_path);
    }
    fs::copy(&generated_path, &requested_path)
        .map_err(|error| format!("Failed to write requested {label} output: {error}"))?;
    let _ = fs::remove_file(&generated_path);
    Ok(requested_path)
}

fn parse_content_range_total(value: &str) -> Option<u64> {
    value
        .rsplit_once('/')
        .and_then(|(_, total)| total.parse::<u64>().ok())
}

fn sanitize_header_value(value: Option<&str>) -> Option<String> {
    value
        .map(str::trim)
        .filter(|value| !value.is_empty())
        .map(|value| value.replace(['\r', '\n'], " "))
        .map(|value| value.split_whitespace().collect::<Vec<_>>().join(" "))
}

struct ParsedHttpUrl {
    scheme: HttpScheme,
    host: String,
    port: u16,
    path: String,
}

struct ParsedProxyUrl {
    kind: ProxyKind,
    host: String,
    port: u16,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum HttpScheme {
    Http,
    Https,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum ProxyKind {
    Http,
    Socks5,
}

fn parse_http_url(source_url: &str) -> Result<ParsedHttpUrl, String> {
    let (scheme, remainder, default_port) = if let Some(remainder) =
        source_url.strip_prefix("http://")
    {
        (HttpScheme::Http, remainder, 80)
    } else if let Some(remainder) = source_url.strip_prefix("https://") {
        (HttpScheme::Https, remainder, 443)
    } else {
        return Err("Direct file download supports http:// and https:// URLs only.".to_string());
    };
    let (authority, path) = match remainder.split_once('/') {
        Some((authority, path)) => (authority, format!("/{path}")),
        None => (remainder, "/".to_string()),
    };
    if authority.is_empty() {
        return Err("URL host is missing.".to_string());
    }

    let (host, port) = match authority.rsplit_once(':') {
        Some((host, port)) => (
            host.to_string(),
            port.parse::<u16>()
                .map_err(|_| "URL port is invalid.".to_string())?,
        ),
        None => (authority.to_string(), default_port),
    };

    if host.is_empty() {
        return Err("URL host is missing.".to_string());
    }

    Ok(ParsedHttpUrl {
        scheme,
        host,
        port,
        path,
    })
}

fn parse_direct_file_proxy(value: Option<&str>) -> Result<Option<ParsedProxyUrl>, String> {
    let Some(value) = sanitize_optional_text(value) else {
        return Ok(None);
    };
    let (kind, remainder, default_port) = if let Some(remainder) = value.strip_prefix("http://") {
        (ProxyKind::Http, remainder, 8080)
    } else if let Some(remainder) = value.strip_prefix("https://") {
        (ProxyKind::Http, remainder, 8080)
    } else if let Some(remainder) = value.strip_prefix("socks5://") {
        (ProxyKind::Socks5, remainder, 1080)
    } else if let Some(remainder) = value.strip_prefix("socks5h://") {
        (ProxyKind::Socks5, remainder, 1080)
    } else {
        return Err(
            "Direct file proxy supports http://, https://, socks5://, and socks5h:// URLs."
                .to_string(),
        );
    };

    let authority = remainder.split('/').next().unwrap_or_default();
    if authority.is_empty() || authority.contains('@') {
        return Err("Direct file proxy must be host:port without credentials.".to_string());
    }

    let (host, port) = match authority.rsplit_once(':') {
        Some((host, port)) => (
            host.to_string(),
            port.parse::<u16>()
                .map_err(|_| "Direct file proxy port is invalid.".to_string())?,
        ),
        None => (authority.to_string(), default_port),
    };
    if host.is_empty() {
        return Err("Direct file proxy host is missing.".to_string());
    }

    Ok(Some(ParsedProxyUrl { kind, host, port }))
}

fn http_authority(host: &str, port: u16, scheme: HttpScheme) -> String {
    match (scheme, port) {
        (HttpScheme::Http, 80) | (HttpScheme::Https, 443) => host.to_string(),
        _ => format!("{host}:{port}"),
    }
}

fn http_absolute_url(parsed: &ParsedHttpUrl) -> String {
    let scheme = match parsed.scheme {
        HttpScheme::Http => "http",
        HttpScheme::Https => "https",
    };
    format!(
        "{scheme}://{}{}",
        http_authority(&parsed.host, parsed.port, parsed.scheme),
        parsed.path
    )
}

fn plan_direct_file_output(
    output_dir: &Path,
    task: &DownloadTask,
    settings: &DownloadsSettings,
) -> Result<DownloadOutputPlan, String> {
    if let Some(output_path) = task
        .output_path
        .as_deref()
        .map(str::trim)
        .filter(|path| !path.is_empty())
    {
        let requested_path = PathBuf::from(output_path);
        if settings.skip_existing && requested_path.exists() {
            let existing_bytes = fs::metadata(&requested_path)
                .map_err(|error| error.to_string())?
                .len();
            return Ok(DownloadOutputPlan::SkipExisting {
                output_path: requested_path,
                existing_bytes,
            });
        }
        return Ok(DownloadOutputPlan::Download {
            output_path: requested_path,
        });
    }

    let file_name = download_file_name_for_task(task, &settings.filename_template);
    let target_dir = if settings.organize_by_platform {
        output_dir.join(sanitize_file_name(&task.platform))
    } else {
        output_dir.to_path_buf()
    };
    let requested_path = target_dir.join(&file_name);
    if settings.skip_existing && requested_path.exists() {
        let existing_bytes = fs::metadata(&requested_path)
            .map_err(|error| error.to_string())?
            .len();
        return Ok(DownloadOutputPlan::SkipExisting {
            output_path: requested_path,
            existing_bytes,
        });
    }

    Ok(DownloadOutputPlan::Download {
        output_path: unique_download_path_for_file_name(&target_dir, &file_name),
    })
}

fn plan_webpage_archive_output(
    output_dir: &Path,
    task: &DownloadTask,
    settings: &DownloadsSettings,
) -> Result<DownloadOutputPlan, String> {
    if let Some(output_path) = task
        .output_path
        .as_deref()
        .map(str::trim)
        .filter(|path| !path.is_empty())
    {
        let requested_path = PathBuf::from(output_path);
        if settings.skip_existing && requested_path.exists() {
            let existing_bytes = fs::metadata(&requested_path)
                .map_err(|error| error.to_string())?
                .len();
            return Ok(DownloadOutputPlan::SkipExisting {
                output_path: requested_path,
                existing_bytes,
            });
        }
        return Ok(DownloadOutputPlan::Download {
            output_path: requested_path,
        });
    }

    let file_name = webpage_archive_file_name_for_task(task, &settings.filename_template);
    let target_dir = if settings.organize_by_platform {
        output_dir.join(sanitize_file_name(&task.platform))
    } else {
        output_dir.to_path_buf()
    };
    let requested_path = target_dir.join(&file_name);
    if settings.skip_existing && requested_path.exists() {
        let existing_bytes = fs::metadata(&requested_path)
            .map_err(|error| error.to_string())?
            .len();
        return Ok(DownloadOutputPlan::SkipExisting {
            output_path: requested_path,
            existing_bytes,
        });
    }

    Ok(DownloadOutputPlan::Download {
        output_path: unique_download_path_for_file_name(&target_dir, &file_name),
    })
}

fn unique_download_path_for_file_name(output_dir: &Path, file_name: &str) -> PathBuf {
    let mut candidate = output_dir.join(file_name);
    if !candidate.exists() {
        return candidate;
    }

    let stem = candidate
        .file_stem()
        .and_then(|value| value.to_str())
        .unwrap_or("download")
        .to_string();
    let extension = candidate
        .extension()
        .and_then(|value| value.to_str())
        .map(|value| format!(".{value}"))
        .unwrap_or_default();

    for index in 1..1000 {
        candidate = output_dir.join(format!("{stem}-{index}{extension}"));
        if !candidate.exists() {
            return candidate;
        }
    }

    output_dir.join(format!(
        "{stem}-{}{}",
        Utc::now().timestamp_millis(),
        extension
    ))
}

fn download_file_name_for_task(task: &DownloadTask, template: &str) -> String {
    let fallback_name = file_name_from_url(&task.source_url);
    let (fallback_title, fallback_ext) = split_file_name_parts(&fallback_name);
    let title = if task.title.trim().is_empty() || task.title == task.source_url {
        fallback_title
    } else {
        task.title.trim().to_string()
    };
    let rendered = sanitize_filename_template(template)
        .replace("{title}", &title)
        .replace("{platform}", &task.platform)
        .replace("{ext}", &fallback_ext);
    sanitize_file_name(&rendered)
}

fn webpage_archive_file_name_for_task(task: &DownloadTask, template: &str) -> String {
    let fallback_name = file_name_from_url(&task.source_url);
    let (fallback_title, _) = split_file_name_parts(&fallback_name);
    let title = if task.title.trim().is_empty() || task.title == task.source_url {
        fallback_title
    } else {
        task.title.trim().to_string()
    };
    let rendered = sanitize_filename_template(template)
        .replace("{title}", &title)
        .replace("{platform}", &task.platform)
        .replace("{ext}", "html");
    let sanitized = sanitize_file_name(&rendered);
    if sanitized.ends_with(".html") || sanitized.ends_with(".htm") {
        sanitized
    } else {
        format!("{sanitized}.html")
    }
}

fn split_file_name_parts(file_name: &str) -> (String, String) {
    let path = Path::new(file_name);
    let title = path
        .file_stem()
        .and_then(|value| value.to_str())
        .filter(|value| !value.is_empty())
        .unwrap_or("download")
        .to_string();
    let ext = path
        .extension()
        .and_then(|value| value.to_str())
        .filter(|value| !value.is_empty())
        .unwrap_or("bin")
        .to_string();

    (title, ext)
}

fn partial_download_path(final_path: &Path) -> PathBuf {
    let file_name = final_path
        .file_name()
        .and_then(|value| value.to_str())
        .unwrap_or("download.bin");
    final_path.with_file_name(format!("{file_name}.part"))
}

fn file_name_from_url(source_url: &str) -> String {
    let without_query = source_url.split(['?', '#']).next().unwrap_or(source_url);
    let raw_name = without_query
        .rsplit('/')
        .find(|part| !part.is_empty())
        .unwrap_or("download.bin");
    sanitize_file_name(raw_name)
}

fn content_disposition_safe_file_name(header: &str) -> Option<String> {
    let mut fallback = None;
    for part in header.split(';').skip(1) {
        let Some((name, value)) = part.split_once('=') else {
            continue;
        };
        let name = name.trim();
        let value = value.trim();
        if name.eq_ignore_ascii_case("filename*") {
            if let Some(file_name) = content_disposition_extended_file_name(value) {
                return Some(file_name);
            }
        } else if name.eq_ignore_ascii_case("filename") {
            fallback = fallback.or_else(|| content_disposition_quoted_file_name(value));
        }
    }
    fallback
}

fn content_disposition_extended_file_name(value: &str) -> Option<String> {
    let value = content_disposition_unquote(value);
    let mut parts = value.splitn(3, '\'');
    let charset = parts.next()?.trim();
    let _language = parts.next()?;
    let encoded = parts.next()?.trim();
    if !charset.eq_ignore_ascii_case("utf-8") {
        return None;
    }
    content_disposition_sanitize_candidate(&percent_decode_component(encoded))
}

fn content_disposition_quoted_file_name(value: &str) -> Option<String> {
    let value = content_disposition_unquote(value);
    content_disposition_sanitize_candidate(&value)
}

fn content_disposition_unquote(value: &str) -> String {
    let trimmed = value.trim();
    let quoted = trimmed
        .strip_prefix('"')
        .and_then(|value| value.strip_suffix('"'));
    let Some(quoted) = quoted else {
        return trimmed.to_string();
    };

    let mut output = String::new();
    let mut escaped = false;
    for character in quoted.chars() {
        if escaped {
            output.push(character);
            escaped = false;
        } else if character == '\\' {
            escaped = true;
        } else {
            output.push(character);
        }
    }
    if escaped {
        output.push('\\');
    }
    output
}

fn content_disposition_sanitize_candidate(value: &str) -> Option<String> {
    let raw_name = value
        .trim()
        .rsplit(['/', '\\'])
        .find(|part| !part.trim().is_empty())?;
    (!matches!(raw_name.trim(), "." | "..")).then(|| sanitize_file_name(raw_name))
}

fn sanitize_file_name(raw_name: &str) -> String {
    let sanitized: String = raw_name
        .chars()
        .map(|character| {
            if character.is_ascii_alphanumeric() || matches!(character, '.' | '-' | '_') {
                character
            } else {
                '_'
            }
        })
        .collect();
    if sanitized.is_empty() || sanitized == "." || sanitized == ".." {
        "download.bin".to_string()
    } else {
        sanitized
    }
}

fn normalize_positions(tasks: &mut [DownloadTask]) {
    tasks.sort_by_key(|task| task.position);
    for (index, task) in tasks.iter_mut().enumerate() {
        task.position = (index + 1) as u32;
    }
}

