fn normalize_http_url(raw_url: &str) -> Result<String, String> {
    let url = raw_url.trim();
    if url.starts_with("http://") || url.starts_with("https://") {
        Ok(url.to_string())
    } else {
        Err("Enter a valid http or https URL.".to_string())
    }
}

fn validate_output_dir(raw_path: Option<&str>) -> Result<Option<String>, String> {
    let Some(path) = raw_path.map(str::trim).filter(|path| !path.is_empty()) else {
        return Ok(None);
    };
    let candidate = PathBuf::from(path);
    if !candidate.exists() {
        return Err(format!("Output directory does not exist: {path}"));
    }
    if !candidate.is_dir() {
        return Err(format!("Output path is not a directory: {path}"));
    }

    fs::metadata(&candidate)
        .map_err(|error| format!("Output directory is not accessible: {error}"))?;
    ensure_output_dir_writable(&candidate)?;
    Ok(Some(display_path(candidate)))
}

fn validate_existing_input_file(raw_path: &str, label: &str) -> Result<PathBuf, String> {
    let path = raw_path.trim();
    if path.is_empty() {
        return Err(format!("{label} path is required."));
    }
    let candidate = PathBuf::from(path);
    if !candidate.exists() {
        return Err(format!("{label} does not exist: {path}"));
    }
    if !candidate.is_file() {
        return Err(format!("{label} is not a file: {path}"));
    }
    fs::metadata(&candidate).map_err(|error| format!("{label} is not accessible: {error}"))?;
    Ok(candidate)
}

fn validate_existing_folder(path: &Path, label: &str) -> Result<(), String> {
    if path.as_os_str().is_empty() {
        return Err(format!("{label} path is required."));
    }
    if !path.exists() {
        return Err(format!("{label} does not exist: {}", display_path(path)));
    }
    if !path.is_dir() {
        return Err(format!("{label} is not a folder: {}", display_path(path)));
    }
    fs::metadata(path).map_err(|error| format!("{label} is not accessible: {error}"))?;
    Ok(())
}

fn validate_output_file_path(raw_path: &str, label: &str) -> Result<PathBuf, String> {
    let path = raw_path.trim();
    if path.is_empty() {
        return Err(format!("{label} path is required."));
    }
    let candidate = PathBuf::from(path);
    let parent = candidate
        .parent()
        .ok_or_else(|| format!("{label} parent directory is required."))?;
    if !parent.exists() {
        return Err(format!(
            "{label} parent directory does not exist: {}",
            parent.to_string_lossy()
        ));
    }
    if !parent.is_dir() {
        return Err(format!(
            "{label} parent is not a directory: {}",
            parent.to_string_lossy()
        ));
    }
    ensure_output_dir_writable(parent)?;
    Ok(candidate)
}

fn supported_library_format(path: &Path) -> Option<String> {
    let extension = path.extension()?.to_str()?.to_ascii_lowercase();
    match extension.as_str() {
        "pdf" | "epub" | "cbz" | "txt" | "html" | "htm" => Some(extension),
        _ => None,
    }
}

fn supported_music_format(path: &Path) -> Option<String> {
    let extension = path.extension()?.to_str()?.to_ascii_lowercase();
    match extension.as_str() {
        "mp3" | "flac" | "m4a" | "ogg" | "opus" => Some(extension),
        _ => None,
    }
}

fn supported_cover_format(path: &Path) -> bool {
    let Some(extension) = path.extension().and_then(|value| value.to_str()) else {
        return false;
    };
    matches!(
        extension.to_ascii_lowercase().as_str(),
        "jpg" | "jpeg" | "png" | "webp"
    )
}

fn find_music_cover_path(track_path: &Path) -> Option<PathBuf> {
    let folder = track_path.parent()?;
    let stem = track_path.file_stem().and_then(|value| value.to_str())?;
    let candidate_names = [
        format!("{stem}.jpg"),
        format!("{stem}.jpeg"),
        format!("{stem}.png"),
        format!("{stem}.webp"),
        "cover.jpg".to_string(),
        "cover.jpeg".to_string(),
        "cover.png".to_string(),
        "cover.webp".to_string(),
        "folder.jpg".to_string(),
        "folder.jpeg".to_string(),
        "folder.png".to_string(),
        "front.jpg".to_string(),
        "front.jpeg".to_string(),
        "front.png".to_string(),
        "album.jpg".to_string(),
        "album.png".to_string(),
    ];
    for name in candidate_names {
        let candidate = folder.join(name);
        if candidate.is_file() && supported_cover_format(&candidate) {
            return Some(candidate);
        }
    }
    None
}

fn read_music_metadata_sidecar(track_path: &Path) -> Result<Option<MusicMetadataSidecar>, String> {
    let Some(folder) = track_path.parent() else {
        return Ok(None);
    };
    let Some(stem) = track_path.file_stem().and_then(|value| value.to_str()) else {
        return Ok(None);
    };
    let candidates = [
        folder.join(format!("{stem}.fetchdock.json")),
        folder.join(format!("{stem}.metadata.json")),
        folder.join("metadata.json"),
    ];
    for candidate in candidates {
        if !candidate.is_file() {
            continue;
        }
        let metadata = fs::metadata(&candidate).map_err(|error| error.to_string())?;
        if metadata.len() > 64 * 1024 {
            return Err(format!(
                "Music metadata sidecar is too large: {}",
                display_path(candidate)
            ));
        }
        let bytes = fs::read(&candidate).map_err(|error| error.to_string())?;
        let mut sidecar: MusicMetadataSidecar = serde_json::from_slice(&bytes)
            .map_err(|error| format!("Music metadata sidecar must be JSON: {error}"))?;
        sidecar.title = sidecar
            .title
            .as_deref()
            .and_then(|value| sanitize_optional_text(Some(value)));
        sidecar.artist = sidecar
            .artist
            .as_deref()
            .and_then(|value| sanitize_optional_text(Some(value)));
        sidecar.album = sidecar
            .album
            .as_deref()
            .and_then(|value| sanitize_optional_text(Some(value)));
        if sidecar.title.is_some() || sidecar.artist.is_some() || sidecar.album.is_some() {
            return Ok(Some(sidecar));
        }
    }
    Ok(None)
}

fn read_embedded_music_metadata(
    track_path: &Path,
    format: &str,
) -> Result<Option<EmbeddedMusicMetadata>, String> {
    let metadata = fs::metadata(track_path).map_err(|error| error.to_string())?;
    if metadata.len() > 80_000_000 {
        return Ok(None);
    }
    let bytes = fs::read(track_path).map_err(|error| error.to_string())?;
    let tags = match format {
        "mp3" => read_mp3_metadata_tags(&bytes),
        "flac" | "ogg" | "opus" => read_vorbis_comment_metadata(&bytes),
        "m4a" => read_m4a_metadata_tags(&bytes),
        _ => EmbeddedMusicMetadata::default(),
    };
    if tags.title.is_some() || tags.artist.is_some() || tags.album.is_some() {
        Ok(Some(tags))
    } else {
        Ok(None)
    }
}

fn extract_embedded_music_cover_to_cache(
    root: &Path,
    track_path: &Path,
    format: &str,
) -> Result<Option<String>, String> {
    let metadata = fs::metadata(track_path).map_err(|error| error.to_string())?;
    if metadata.len() > 120_000_000 {
        return Ok(None);
    }
    let bytes = fs::read(track_path).map_err(|error| error.to_string())?;
    let Some((cover_bytes, extension)) = embedded_music_cover_bytes(&bytes, format) else {
        return Ok(None);
    };
    if cover_bytes.len() > 8_000_000 {
        return Ok(None);
    }
    let output_path = music_cover_cache_path(root, track_path, extension);
    if output_path.is_file() {
        return Ok(Some(display_path(output_path)));
    }
    if let Some(parent) = output_path.parent() {
        fs::create_dir_all(parent).map_err(|error| error.to_string())?;
    }
    fs::write(&output_path, cover_bytes).map_err(|error| error.to_string())?;
    Ok(Some(display_path(output_path)))
}

fn embedded_music_cover_bytes(bytes: &[u8], format: &str) -> Option<(Vec<u8>, &'static str)> {
    match format {
        "mp3" => id3v2_apic_cover(bytes),
        "flac" => flac_picture_cover(bytes),
        "ogg" | "opus" => vorbis_picture_comment_cover(bytes),
        "m4a" => m4a_covr_cover(bytes),
        _ => None,
    }
}

fn id3v2_apic_cover(bytes: &[u8]) -> Option<(Vec<u8>, &'static str)> {
    if bytes.len() < 10 || &bytes[..3] != b"ID3" {
        return None;
    }
    let tag_size = synchsafe_u32(&bytes[6..10])? as usize;
    let tag_end = 10_usize.saturating_add(tag_size).min(bytes.len());
    let mut offset = 10_usize;
    while offset + 10 <= tag_end {
        let id = &bytes[offset..offset + 4];
        let frame_size = u32::from_be_bytes([
            bytes[offset + 4],
            bytes[offset + 5],
            bytes[offset + 6],
            bytes[offset + 7],
        ]) as usize;
        offset += 10;
        if frame_size == 0 || offset + frame_size > tag_end {
            break;
        }
        if id == b"APIC" {
            let payload = &bytes[offset..offset + frame_size];
            if let Some(result) = parse_apic_payload(payload) {
                return Some(result);
            }
        }
        offset += frame_size;
    }
    None
}

fn parse_apic_payload(payload: &[u8]) -> Option<(Vec<u8>, &'static str)> {
    let (&encoding, rest) = payload.split_first()?;
    let mime_end = rest.iter().position(|byte| *byte == 0)?;
    let mime = String::from_utf8_lossy(&rest[..mime_end]).to_ascii_lowercase();
    let extension = image_extension_from_mime(&mime)?;
    let mut offset = 1 + mime_end + 1;
    offset += 1;
    if encoding == 1 || encoding == 2 {
        while offset + 1 < payload.len() {
            if payload[offset] == 0 && payload[offset + 1] == 0 {
                offset += 2;
                break;
            }
            offset += 2;
        }
    } else {
        while offset < payload.len() {
            if payload[offset] == 0 {
                offset += 1;
                break;
            }
            offset += 1;
        }
    }
    let image = payload.get(offset..)?.to_vec();
    (!image.is_empty()).then_some((image, extension))
}

fn flac_picture_cover(bytes: &[u8]) -> Option<(Vec<u8>, &'static str)> {
    if let Some(result) = native_flac_picture_cover(bytes) {
        return Some(result);
    }
    let marker = b"METADATA_BLOCK_PICTURE";
    let index = bytes
        .windows(marker.len())
        .position(|window| window == marker)?;
    let start = index.saturating_sub(256);
    let end = (index + marker.len() + 8_000_000).min(bytes.len());
    let region = &bytes[start..end];
    if let Some(jpeg_index) = region
        .windows(3)
        .position(|window| window == [0xff, 0xd8, 0xff])
    {
        let absolute = start + jpeg_index;
        let image_end = find_jpeg_end(bytes, absolute).unwrap_or(end);
        return Some((bytes[absolute..image_end].to_vec(), "jpg"));
    }
    if let Some(png_index) = region
        .windows(8)
        .position(|window| window == b"\x89PNG\r\n\x1a\n")
    {
        let absolute = start + png_index;
        let image_end = find_png_end(bytes, absolute).unwrap_or(end);
        return Some((bytes[absolute..image_end].to_vec(), "png"));
    }
    None
}

fn native_flac_picture_cover(bytes: &[u8]) -> Option<(Vec<u8>, &'static str)> {
    if !bytes.starts_with(b"fLaC") {
        return None;
    }
    let mut offset = 4_usize;
    while offset + 4 <= bytes.len() {
        let header = bytes[offset];
        let is_last = header & 0x80 != 0;
        let block_type = header & 0x7f;
        let length = ((bytes[offset + 1] as usize) << 16)
            | ((bytes[offset + 2] as usize) << 8)
            | bytes[offset + 3] as usize;
        offset += 4;
        let end = offset.checked_add(length)?;
        let block = bytes.get(offset..end)?;
        if block_type == 6 {
            if let Some(result) = parse_flac_picture_block(block) {
                return Some(result);
            }
        }
        offset = end;
        if is_last {
            break;
        }
    }
    None
}

fn vorbis_picture_comment_cover(bytes: &[u8]) -> Option<(Vec<u8>, &'static str)> {
    let encoded = find_ascii_base64_comment_value(bytes, "METADATA_BLOCK_PICTURE", 12_000_000)?;
    let picture_block = decode_base64_bytes(&encoded)?;
    parse_flac_picture_block(&picture_block)
}

fn parse_flac_picture_block(bytes: &[u8]) -> Option<(Vec<u8>, &'static str)> {
    let mut offset = 4_usize;
    let mime_len = read_be_u32_at(bytes, offset)? as usize;
    offset = offset.checked_add(4)?;
    let mime_end = offset.checked_add(mime_len)?;
    let mime = String::from_utf8_lossy(bytes.get(offset..mime_end)?).to_ascii_lowercase();
    let extension = image_extension_from_mime(&mime)?;
    offset = mime_end;
    let description_len = read_be_u32_at(bytes, offset)? as usize;
    offset = offset.checked_add(4)?.checked_add(description_len)?;
    offset = offset.checked_add(16)?;
    let data_len = read_be_u32_at(bytes, offset)? as usize;
    offset = offset.checked_add(4)?;
    let data_end = offset.checked_add(data_len)?;
    let data = bytes.get(offset..data_end)?.to_vec();
    (!data.is_empty()).then_some((data, extension))
}

fn m4a_covr_cover(bytes: &[u8]) -> Option<(Vec<u8>, &'static str)> {
    let index = bytes.windows(4).position(|window| window == b"covr")?;
    let search_end = (index + 8_000_000).min(bytes.len());
    let region = &bytes[index..search_end];
    if let Some(jpeg_index) = region
        .windows(3)
        .position(|window| window == [0xff, 0xd8, 0xff])
    {
        let absolute = index + jpeg_index;
        let image_end = find_jpeg_end(bytes, absolute).unwrap_or(search_end);
        return Some((bytes[absolute..image_end].to_vec(), "jpg"));
    }
    if let Some(png_index) = region
        .windows(8)
        .position(|window| window == b"\x89PNG\r\n\x1a\n")
    {
        let absolute = index + png_index;
        let image_end = find_png_end(bytes, absolute).unwrap_or(search_end);
        return Some((bytes[absolute..image_end].to_vec(), "png"));
    }
    None
}

fn image_extension_from_mime(mime: &str) -> Option<&'static str> {
    match mime {
        "image/jpeg" | "image/jpg" => Some("jpg"),
        "image/png" => Some("png"),
        "image/webp" => Some("webp"),
        _ => None,
    }
}

fn find_jpeg_end(bytes: &[u8], start: usize) -> Option<usize> {
    bytes[start..]
        .windows(2)
        .position(|window| window == [0xff, 0xd9])
        .map(|position| start + position + 2)
}

fn find_png_end(bytes: &[u8], start: usize) -> Option<usize> {
    let marker = b"IEND";
    bytes[start..]
        .windows(marker.len())
        .position(|window| window == marker)
        .map(|position| start + position + marker.len() + 4)
}

fn read_mp3_metadata_tags(bytes: &[u8]) -> EmbeddedMusicMetadata {
    read_id3v2_metadata_tags(bytes)
        .or_else(|| read_id3v1_metadata_tags(bytes))
        .unwrap_or_default()
}

fn read_id3v1_metadata_tags(bytes: &[u8]) -> Option<EmbeddedMusicMetadata> {
    if bytes.len() < 128 {
        return None;
    }
    let tag = &bytes[bytes.len() - 128..];
    if &tag[..3] != b"TAG" {
        return None;
    }
    Some(EmbeddedMusicMetadata {
        title: latin1_tag_text(&tag[3..33]),
        artist: latin1_tag_text(&tag[33..63]),
        album: latin1_tag_text(&tag[63..93]),
    })
}

fn read_id3v2_metadata_tags(bytes: &[u8]) -> Option<EmbeddedMusicMetadata> {
    if bytes.len() < 10 || &bytes[..3] != b"ID3" {
        return None;
    }
    let tag_size = synchsafe_u32(&bytes[6..10])? as usize;
    let tag_end = 10_usize.saturating_add(tag_size).min(bytes.len());
    let mut offset = 10_usize;
    let mut metadata = EmbeddedMusicMetadata::default();
    while offset + 10 <= tag_end {
        let id = &bytes[offset..offset + 4];
        if id.iter().all(|byte| *byte == 0) {
            break;
        }
        let frame_size = u32::from_be_bytes([
            bytes[offset + 4],
            bytes[offset + 5],
            bytes[offset + 6],
            bytes[offset + 7],
        ]) as usize;
        offset += 10;
        if frame_size == 0 || offset + frame_size > tag_end {
            break;
        }
        let value = decode_id3_text_frame(&bytes[offset..offset + frame_size]);
        match id {
            b"TIT2" => metadata.title = value,
            b"TPE1" => metadata.artist = value,
            b"TALB" => metadata.album = value,
            _ => {}
        }
        offset += frame_size;
    }
    (metadata.title.is_some() || metadata.artist.is_some() || metadata.album.is_some())
        .then_some(metadata)
}

fn synchsafe_u32(bytes: &[u8]) -> Option<u32> {
    (bytes.len() == 4).then(|| {
        ((bytes[0] as u32) << 21)
            | ((bytes[1] as u32) << 14)
            | ((bytes[2] as u32) << 7)
            | bytes[3] as u32
    })
}

fn decode_id3_text_frame(bytes: &[u8]) -> Option<String> {
    let (&encoding, payload) = bytes.split_first()?;
    match encoding {
        0 => latin1_tag_text(payload),
        1 => decode_utf16_bom_tag_text(payload),
        2 => decode_utf16be_tag_text(payload),
        3 => {
            let text = String::from_utf8_lossy(payload).to_string();
            sanitize_optional_text(Some(&text))
        }
        _ => None,
    }
}

fn read_vorbis_comment_metadata(bytes: &[u8]) -> EmbeddedMusicMetadata {
    let mut metadata = EmbeddedMusicMetadata::default();
    for key in ["TITLE", "ARTIST", "ALBUM"] {
        if let Some(value) = find_ascii_comment_value(bytes, key) {
            match key {
                "TITLE" => metadata.title = Some(value),
                "ARTIST" => metadata.artist = Some(value),
                "ALBUM" => metadata.album = Some(value),
                _ => {}
            }
        }
    }
    metadata
}

fn read_m4a_metadata_tags(bytes: &[u8]) -> EmbeddedMusicMetadata {
    let mut metadata = EmbeddedMusicMetadata::default();
    metadata.title = find_m4a_atom_text(bytes, b"\xA9nam");
    metadata.artist =
        find_m4a_atom_text(bytes, b"\xA9ART").or_else(|| find_m4a_atom_text(bytes, b"aART"));
    metadata.album = find_m4a_atom_text(bytes, b"\xA9alb");
    metadata
}

fn find_m4a_atom_text(bytes: &[u8], atom: &[u8; 4]) -> Option<String> {
    let index = bytes.windows(4).position(|window| window == atom)?;
    let search_end = (index + 512).min(bytes.len());
    let region = &bytes[index + 4..search_end];
    let data_index = region.windows(4).position(|window| window == b"data")?;
    let start = index + 4 + data_index + 12;
    let end = (start + 256).min(bytes.len());
    utf8_tag_text(&bytes[start..end])
}

fn find_ascii_comment_value(bytes: &[u8], key: &str) -> Option<String> {
    find_ascii_comment_value_with_limit(bytes, key, 256)
}

fn find_ascii_comment_value_with_limit(bytes: &[u8], key: &str, limit: usize) -> Option<String> {
    let needle = format!("{key}=");
    let index = bytes
        .windows(needle.len())
        .position(|window| window.eq_ignore_ascii_case(needle.as_bytes()))?;
    let start = index + needle.len();
    let end = bytes[start..]
        .iter()
        .position(|byte| *byte == 0 || *byte == b'\n' || *byte == b'\r')
        .map(|position| start + position)
        .unwrap_or_else(|| (start + limit).min(bytes.len()));
    utf8_tag_text(&bytes[start..end])
}

fn find_ascii_base64_comment_value(bytes: &[u8], key: &str, limit: usize) -> Option<String> {
    let needle = format!("{key}=");
    let index = bytes
        .windows(needle.len())
        .position(|window| window.eq_ignore_ascii_case(needle.as_bytes()))?;
    let start = index + needle.len();
    let end_limit = (start + limit).min(bytes.len());
    let end = bytes[start..end_limit]
        .iter()
        .position(|byte| {
            !byte.is_ascii_alphanumeric()
                && !matches!(*byte, b'+' | b'/' | b'=' | b'\r' | b'\n' | b'\t' | b' ')
        })
        .map(|position| start + position)
        .unwrap_or(end_limit);
    let value = String::from_utf8_lossy(&bytes[start..end]).to_string();
    sanitize_optional_text(Some(&value))
}

fn decode_base64_bytes(value: &str) -> Option<Vec<u8>> {
    let mut output = Vec::with_capacity(value.len() * 3 / 4);
    let mut buffer = [0_u8; 4];
    let mut count = 0_usize;
    for byte in value.bytes() {
        if byte.is_ascii_whitespace() {
            continue;
        }
        let decoded = match byte {
            b'A'..=b'Z' => byte - b'A',
            b'a'..=b'z' => byte - b'a' + 26,
            b'0'..=b'9' => byte - b'0' + 52,
            b'+' => 62,
            b'/' => 63,
            b'=' => 64,
            _ => return None,
        };
        buffer[count] = decoded;
        count += 1;
        if count == 4 {
            push_base64_chunk(&buffer, &mut output)?;
            count = 0;
        }
    }
    if count > 0 {
        for item in buffer.iter_mut().skip(count) {
            *item = 64;
        }
        push_base64_chunk(&buffer, &mut output)?;
    }
    Some(output)
}

fn push_base64_chunk(buffer: &[u8; 4], output: &mut Vec<u8>) -> Option<()> {
    if buffer[0] == 64 || buffer[1] == 64 {
        return None;
    }
    let first = (buffer[0] << 2) | (buffer[1] >> 4);
    output.push(first);
    if buffer[2] != 64 {
        let second = ((buffer[1] & 0x0f) << 4) | (buffer[2] >> 2);
        output.push(second);
    }
    if buffer[3] != 64 {
        let third = ((buffer[2] & 0x03) << 6) | buffer[3];
        output.push(third);
    }
    Some(())
}

fn read_be_u32_at(bytes: &[u8], offset: usize) -> Option<u32> {
    let slice = bytes.get(offset..offset + 4)?;
    Some(u32::from_be_bytes([slice[0], slice[1], slice[2], slice[3]]))
}

fn latin1_tag_text(bytes: &[u8]) -> Option<String> {
    let text = bytes
        .iter()
        .copied()
        .take_while(|byte| *byte != 0)
        .map(char::from)
        .collect::<String>();
    sanitize_optional_text(Some(text.trim()))
}

fn utf8_tag_text(bytes: &[u8]) -> Option<String> {
    let end = bytes
        .iter()
        .position(|byte| *byte == 0)
        .unwrap_or(bytes.len());
    let text = String::from_utf8_lossy(&bytes[..end]).to_string();
    sanitize_optional_text(Some(&text))
}

fn decode_utf16_bom_tag_text(bytes: &[u8]) -> Option<String> {
    if bytes.starts_with(&[0xff, 0xfe]) {
        return decode_utf16le_tag_text(&bytes[2..]);
    }
    if bytes.starts_with(&[0xfe, 0xff]) {
        return decode_utf16be_tag_text(&bytes[2..]);
    }
    decode_utf16be_tag_text(bytes)
}

fn decode_utf16le_tag_text(bytes: &[u8]) -> Option<String> {
    let units = bytes
        .chunks(2)
        .take_while(|chunk| chunk.len() == 2 && (chunk[0] != 0 || chunk[1] != 0))
        .map(|chunk| u16::from_le_bytes([chunk[0], chunk[1]]))
        .collect::<Vec<_>>();
    let text = String::from_utf16_lossy(&units);
    sanitize_optional_text(Some(&text))
}

fn decode_utf16be_tag_text(bytes: &[u8]) -> Option<String> {
    let units = bytes
        .chunks(2)
        .take_while(|chunk| chunk.len() == 2 && (chunk[0] != 0 || chunk[1] != 0))
        .map(|chunk| u16::from_be_bytes([chunk[0], chunk[1]]))
        .collect::<Vec<_>>();
    let text = String::from_utf16_lossy(&units);
    sanitize_optional_text(Some(&text))
}

fn infer_title_author_from_path(path: &Path) -> (String, Option<String>) {
    let stem = path
        .file_stem()
        .and_then(|value| value.to_str())
        .unwrap_or("Untitled")
        .trim();
    let normalized = normalize_file_label(stem);
    if let Some((author, title)) = normalized.split_once(" - ") {
        let author = author.trim();
        let title = title.trim();
        if !author.is_empty() && !title.is_empty() {
            return (title.to_string(), Some(author.to_string()));
        }
    }
    (normalized, None)
}

fn infer_music_fields_from_path(path: &Path) -> (Option<String>, Option<String>, String) {
    let stem = path
        .file_stem()
        .and_then(|value| value.to_str())
        .unwrap_or("Untitled");
    let mut title = normalize_file_label(stem);
    if let Some((_, rest)) = title.split_once(" - ") {
        title = rest.trim().to_string();
    }
    let album = path
        .parent()
        .and_then(|value| value.file_name())
        .and_then(|value| value.to_str())
        .map(normalize_file_label)
        .filter(|value| !value.is_empty());
    let artist = path
        .parent()
        .and_then(|value| value.parent())
        .and_then(|value| value.file_name())
        .and_then(|value| value.to_str())
        .map(normalize_file_label)
        .filter(|value| !value.is_empty());
    (artist, album, title)
}

fn normalize_file_label(value: &str) -> String {
    let label = value.replace(['_', '.'], " ");
    let label = label.split_whitespace().collect::<Vec<_>>().join(" ");
    label.trim().trim_matches('-').trim().to_string()
}

fn modified_at_rfc3339(metadata: &fs::Metadata) -> Option<String> {
    metadata
        .modified()
        .ok()
        .map(chrono::DateTime::<Utc>::from)
        .map(|value| value.to_rfc3339())
}

fn push_unique_non_empty(values: &mut Vec<String>, value: String) {
    let trimmed = value.trim();
    if !trimmed.is_empty() && !values.iter().any(|existing| existing == trimmed) {
        values.push(trimmed.to_string());
    }
}

fn normalize_btih_hash(value: &str) -> Result<String, String> {
    let hash = value.trim();
    if hash.len() == 40 && hash.chars().all(|character| character.is_ascii_hexdigit()) {
        return Ok(hash.to_ascii_lowercase());
    }
    if hash.len() == 32
        && hash
            .chars()
            .all(|character| matches!(character.to_ascii_uppercase(), 'A'..='Z' | '2'..='7'))
    {
        return Ok(base32_btih_to_hex(hash));
    }
    Err("Magnet info hash must be 40 hex characters or a 32-character base32 hash.".to_string())
}

fn base32_btih_to_hex(value: &str) -> String {
    let mut buffer: u32 = 0;
    let mut bits = 0_u8;
    let mut output = Vec::with_capacity(20);
    for character in value.chars() {
        let Some(digit) = base32_digit(character) else {
            continue;
        };
        buffer = (buffer << 5) | u32::from(digit);
        bits += 5;
        while bits >= 8 {
            bits -= 8;
            output.push(((buffer >> bits) & 0xff) as u8);
        }
        if bits == 0 {
            buffer = 0;
        } else {
            buffer &= (1_u32 << bits) - 1;
        }
    }
    output
        .into_iter()
        .take(20)
        .map(|byte| format!("{byte:02x}"))
        .collect()
}

fn base32_digit(character: char) -> Option<u8> {
    match character.to_ascii_uppercase() {
        'A'..='Z' => Some(character.to_ascii_uppercase() as u8 - b'A'),
        '2'..='7' => Some(character as u8 - b'2' + 26),
        _ => None,
    }
}

fn percent_decode_component(value: &str) -> String {
    let mut output = Vec::with_capacity(value.len());
    let bytes = value.as_bytes();
    let mut index = 0;
    while index < bytes.len() {
        match bytes[index] {
            b'+' => {
                output.push(b' ');
                index += 1;
            }
            b'%' if index + 2 < bytes.len() => {
                let high = hex_value(bytes[index + 1]);
                let low = hex_value(bytes[index + 2]);
                if let (Some(high), Some(low)) = (high, low) {
                    output.push(high * 16 + low);
                    index += 3;
                } else {
                    output.push(bytes[index]);
                    index += 1;
                }
            }
            byte => {
                output.push(byte);
                index += 1;
            }
        }
    }
    String::from_utf8_lossy(&output).to_string()
}

fn subtitle_workshop_format_for_path(path: &Path) -> Result<String, String> {
    let extension = path
        .extension()
        .and_then(|value| value.to_str())
        .unwrap_or("")
        .to_ascii_lowercase();
    match extension.as_str() {
        "srt" | "vtt" | "ass" => Ok(extension),
        _ => Err("Subtitle Workshop supports .srt, .vtt, and .ass files.".to_string()),
    }
}

fn count_text_lines(content: &str) -> usize {
    if content.is_empty() {
        0
    } else {
        content.lines().count()
    }
}

fn read_subtitle_text_file(path: &Path) -> Result<String, String> {
    let bytes = fs::read(path).map_err(|error| format!("Failed to read subtitle file: {error}"))?;
    decode_subtitle_text_bytes(&bytes)
}

fn decode_subtitle_text_bytes(bytes: &[u8]) -> Result<String, String> {
    if bytes.starts_with(&[0xef, 0xbb, 0xbf]) {
        return String::from_utf8(bytes[3..].to_vec())
            .map_err(|error| format!("Failed to decode UTF-8 subtitle file: {error}"));
    }
    if bytes.starts_with(&[0xff, 0xfe]) {
        return decode_utf16_subtitle_bytes(&bytes[2..], true);
    }
    if bytes.starts_with(&[0xfe, 0xff]) {
        return decode_utf16_subtitle_bytes(&bytes[2..], false);
    }
    match String::from_utf8(bytes.to_vec()) {
        Ok(text) => Ok(text),
        Err(_) => Ok(decode_windows_1252_subtitle_bytes(bytes)),
    }
}

fn decode_utf16_subtitle_bytes(bytes: &[u8], little_endian: bool) -> Result<String, String> {
    let chunks = bytes.chunks_exact(2);
    if !chunks.remainder().is_empty() {
        return Err("Failed to decode UTF-16 subtitle file: incomplete code unit.".to_string());
    }
    let units = chunks
        .map(|chunk| {
            let pair = [chunk[0], chunk[1]];
            if little_endian {
                u16::from_le_bytes(pair)
            } else {
                u16::from_be_bytes(pair)
            }
        })
        .collect::<Vec<_>>();
    String::from_utf16(&units)
        .map_err(|error| format!("Failed to decode UTF-16 subtitle file: {error}"))
}

fn decode_windows_1252_subtitle_bytes(bytes: &[u8]) -> String {
    bytes
        .iter()
        .map(|byte| match *byte {
            0x80..=0x9f => char::from_u32(WINDOWS_1252_C1_CODEPOINTS[usize::from(*byte - 0x80)])
                .unwrap_or(char::REPLACEMENT_CHARACTER),
            value => char::from(value),
        })
        .collect()
}

const WINDOWS_1252_C1_CODEPOINTS: [u32; 32] = [
    0x20ac, 0xfffd, 0x201a, 0x0192, 0x201e, 0x2026, 0x2020, 0x2021, 0x02c6, 0x2030, 0x0160, 0x2039,
    0x0152, 0xfffd, 0x017d, 0xfffd, 0xfffd, 0x2018, 0x2019, 0x201c, 0x201d, 0x2022, 0x2013, 0x2014,
    0x02dc, 0x2122, 0x0161, 0x203a, 0x0153, 0xfffd, 0x017e, 0x0178,
];

fn validate_clip_times(start_seconds: Option<f64>, end_seconds: Option<f64>) -> Result<(), String> {
    for (label, value) in [
        ("start_seconds", start_seconds),
        ("end_seconds", end_seconds),
    ] {
        if let Some(seconds) = value {
            if !seconds.is_finite() || seconds < 0.0 {
                return Err(format!("{label} must be a finite non-negative number."));
            }
        }
    }
    if let (Some(start), Some(end)) = (start_seconds, end_seconds) {
        if end <= start {
            return Err("end_seconds must be greater than start_seconds.".to_string());
        }
    }
    Ok(())
}

fn sanitize_clip_seconds(value: Option<f64>) -> Option<f64> {
    value.filter(|seconds| seconds.is_finite() && *seconds >= 0.0)
}

fn validate_scene_threshold(value: Option<f64>) -> Result<f64, String> {
    let threshold = value.unwrap_or(0.35);
    if !threshold.is_finite() || !(0.0..=1.0).contains(&threshold) {
        return Err("Scene threshold must be between 0 and 1.".to_string());
    }
    Ok(threshold)
}

fn validate_waveform_bucket_count(value: Option<usize>) -> Result<usize, String> {
    let bucket_count = value.unwrap_or(256);
    if !(1..=4096).contains(&bucket_count) {
        return Err("Waveform bucket count must be between 1 and 4096.".to_string());
    }
    Ok(bucket_count)
}

fn validate_clip_reencode_options(request: &MediaClipVideoRequest) -> Result<(), String> {
    if request.mode.unwrap_or(MediaClipMode::Copy) == MediaClipMode::Copy {
        return Ok(());
    }

    if let Some(crf) = request.crf {
        if crf > 51 {
            return Err("CRF must be between 0 and 51.".to_string());
        }
    }
    for (label, value) in [
        ("Video codec", request.video_codec.as_deref()),
        ("Audio codec", request.audio_codec.as_deref()),
        ("Preset", request.preset.as_deref()),
    ] {
        if let Some(value) = value {
            let trimmed = value.trim();
            if trimmed.is_empty() {
                continue;
            }
            if !trimmed.chars().all(|character| {
                character.is_ascii_alphanumeric() || matches!(character, '_' | '-' | '.')
            }) {
                return Err(format!("{label} contains unsupported characters."));
            }
        }
    }

    Ok(())
}

fn validate_transcode_options(request: &MediaTranscodeRequest) -> Result<(), String> {
    if let Some(crf) = request.crf {
        if crf > 51 {
            return Err("Transcode CRF must be between 0 and 51.".to_string());
        }
    }
    for (label, value) in [
        ("Video codec", request.video_codec.as_deref()),
        ("Audio codec", request.audio_codec.as_deref()),
        ("Speed preset", request.speed_preset.as_deref()),
    ] {
        if let Some(value) = clean_optional_ffmpeg_value(value) {
            validate_simple_ffmpeg_token(value, label)?;
        }
    }
    if let Some(value) = sanitize_optional_text(request.audio_bitrate.as_deref()) {
        if !is_valid_audio_bitrate(&value) {
            return Err("Audio bitrate must look like 128k, 192k, or 2m.".to_string());
        }
    }
    Ok(())
}

fn sanitize_whisper_output_format(value: Option<&str>) -> Result<String, String> {
    let format = value
        .and_then(|value| sanitize_optional_text(Some(value)))
        .unwrap_or_else(|| "srt".to_string())
        .to_ascii_lowercase();
    match format.as_str() {
        "srt" | "vtt" | "txt" => Ok(format),
        _ => Err("Whisper output format must be srt, vtt, or txt.".to_string()),
    }
}

fn sanitize_whisper_task(value: Option<&str>) -> Result<String, String> {
    let task = value
        .and_then(|value| sanitize_optional_text(Some(value)))
        .unwrap_or_else(|| "transcribe".to_string())
        .to_ascii_lowercase();
    match task.as_str() {
        "transcribe" | "translate" => Ok(task),
        _ => Err("Whisper task must be transcribe or translate.".to_string()),
    }
}

fn sanitize_optional_whisper_token(
    value: Option<&str>,
    label: &str,
) -> Result<Option<String>, String> {
    let Some(value) = value.and_then(|value| sanitize_optional_text(Some(value))) else {
        return Ok(None);
    };
    if value
        .chars()
        .all(|character| character.is_ascii_alphanumeric() || matches!(character, '_' | '-' | '.'))
    {
        Ok(Some(value))
    } else {
        Err(format!("{label} contains unsupported characters."))
    }
}

fn clean_optional_ffmpeg_value(value: Option<&str>) -> Option<&str> {
    value.map(str::trim).filter(|value| !value.is_empty())
}

fn validate_simple_ffmpeg_token(value: &str, label: &str) -> Result<(), String> {
    if value
        .chars()
        .all(|character| character.is_ascii_alphanumeric() || matches!(character, '_' | '-' | '.'))
    {
        Ok(())
    } else {
        Err(format!("{label} contains unsupported characters."))
    }
}

fn sanitize_audio_bitrate(value: Option<&str>) -> String {
    value
        .and_then(|value| sanitize_optional_text(Some(value)))
        .filter(|value| is_valid_audio_bitrate(value))
        .unwrap_or_else(|| "192k".to_string())
}

fn is_valid_audio_bitrate(value: &str) -> bool {
    let value = value.trim().to_ascii_lowercase();
    let Some(unit) = value.chars().last() else {
        return false;
    };
    if unit != 'k' && unit != 'm' {
        return false;
    }
    let number = &value[..value.len().saturating_sub(1)];
    !number.is_empty() && number.chars().all(|character| character.is_ascii_digit())
}

fn format_seconds_arg(seconds: f64) -> String {
    let formatted = format!("{seconds:.3}");
    formatted
        .trim_end_matches('0')
        .trim_end_matches('.')
        .to_string()
}

fn ensure_output_dir_writable(path: &Path) -> Result<(), String> {
    let probe_name = format!(
        ".fetchdock-write-test-{}-{}",
        Utc::now().timestamp_nanos_opt().unwrap_or_default(),
        OUTPUT_DIR_PROBE_COUNTER.fetch_add(1, Ordering::SeqCst)
    );
    let probe_path = path.join(probe_name);
    match fs::OpenOptions::new()
        .write(true)
        .create_new(true)
        .open(&probe_path)
    {
        Ok(file) => {
            drop(file);
            fs::remove_file(&probe_path)
                .map_err(|error| format!("Output directory write probe cleanup failed: {error}"))
        }
        Err(error) => Err(format!("Output directory is not writable: {error}")),
    }
}

