fn classify_platform(url: &str) -> String {
    let lower = url.to_ascii_lowercase();
    for (needle, platform) in [
        ("youtube.com", "youtube"),
        ("youtu.be", "youtube"),
        ("instagram.com", "instagram"),
        ("tiktok.com", "tiktok"),
        ("twitter.com", "twitter_x"),
        ("x.com", "twitter_x"),
        ("reddit.com", "reddit"),
        ("redd.it", "reddit"),
        ("twitch.tv", "twitch"),
        ("pinterest.", "pinterest"),
        ("vimeo.com", "vimeo"),
        ("bsky.app", "bluesky"),
        ("bilibili.com", "bilibili"),
        ("b23.tv", "bilibili"),
        ("douyin.com", "douyin"),
        ("iesdouyin.com", "douyin"),
        ("pixiv.net", "pixiv"),
        ("deviantart.com", "deviantart"),
        ("artstation.com", "artstation"),
        ("flickr.com", "flickr"),
        ("tumblr.com", "tumblr"),
        ("imgur.com", "imgur"),
        ("imgur.io", "imgur"),
        ("kemono.su", "kemono"),
        ("kemono.party", "kemono"),
        ("newgrounds.com", "newgrounds"),
        ("xiaohongshu.com", "xiaohongshu"),
        ("xhslink.com", "xiaohongshu"),
        ("kuaishou.com", "kuaishou"),
        ("kuaishouapp.com", "kuaishou"),
        ("gifshow.com", "kuaishou"),
        ("youku.com", "youku"),
        ("iqiyi.com", "iqiyi"),
        ("iq.com", "iqiyi"),
        ("v.qq.com", "tencent_video"),
        ("video.qq.com", "tencent_video"),
        ("mgtv.com", "mango_tv"),
        ("hunantv.com", "mango_tv"),
    ] {
        if lower.contains(needle) {
            return platform.to_string();
        }
    }

    if is_direct_file_url(url) {
        return "direct_file".to_string();
    }

    "generic".to_string()
}

fn is_direct_file_url(url: &str) -> bool {
    let path = url.split(['?', '#']).next().unwrap_or(url);
    let extension = path.rsplit('.').next().unwrap_or("").to_ascii_lowercase();
    matches!(
        extension.as_str(),
        "7z" | "aac"
            | "ass"
            | "avi"
            | "cbz"
            | "epub"
            | "flac"
            | "gif"
            | "jpeg"
            | "jpg"
            | "m4a"
            | "mkv"
            | "mov"
            | "mp3"
            | "mp4"
            | "ogg"
            | "opus"
            | "pdf"
            | "png"
            | "rar"
            | "srt"
            | "tar"
            | "txt"
            | "vtt"
            | "wav"
            | "webm"
            | "webp"
            | "zip"
    )
}

fn resolve_data_root(app: &AppHandle) -> Result<(AppMode, PathBuf), anyhow::Error> {
    let exe_dir = std::env::current_exe()?
        .parent()
        .map(Path::to_path_buf)
        .ok_or_else(|| anyhow::anyhow!("Unable to resolve executable directory"))?;

    if exe_dir.join("portable").exists()
        || exe_dir.join(".portable").exists()
        || exe_dir.join("portable.txt").exists()
    {
        return Ok((AppMode::Portable, exe_dir.join("data")));
    }

    let data_dir = app
        .path()
        .app_data_dir()
        .map_err(|error| anyhow::anyhow!(error.to_string()))?;

    Ok((AppMode::Regular, data_dir))
}

fn app_paths(root: &Path) -> AppPaths {
    AppPaths {
        config_dir: display_path(root.join("config")),
        data_dir: display_path(root),
        cache_dir: display_path(root.join("cache")),
        downloads_dir: display_path(root.join("downloads")),
        plugins_dir: display_path(root.join("plugins")),
        dependencies_dir: display_path(root.join("dependencies")),
        logs_dir: display_path(root.join("logs")),
    }
}

fn display_path(path: impl AsRef<Path>) -> String {
    path.as_ref().to_string_lossy().to_string()
}

