    #[test]
    fn saves_http_thumbnail_file() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-thumbnail-save-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        let output_dir = root.join("thumbs");
        std::fs::create_dir_all(&output_dir).unwrap();
        let listener = TcpListener::bind("127.0.0.1:0").unwrap();
        let port = listener.local_addr().unwrap().port();
        let server = thread::spawn(move || {
            let (mut stream, _) = listener.accept().unwrap();
            let mut buffer = [0_u8; 1024];
            let _ = stream.read(&mut buffer).unwrap();
            stream
                .write_all(b"HTTP/1.1 200 OK\r\nContent-Length: 4\r\n\r\njpeg")
                .unwrap();
        });

        let result = super::metadata_save_thumbnail_at_root(
            &root,
            super::MetadataSaveThumbnailRequest {
                url: format!("http://127.0.0.1:{port}/thumb.jpg"),
                output_dir: Some(output_dir.to_string_lossy().to_string()),
                file_name: Some("cover.jpg".to_string()),
                user_agent: None,
                referer: None,
                proxy: None,
                cookie_bucket_id: None,
                auth_payload_ref: None,
                rate_limit: None,
            },
        )
        .unwrap();

        assert!(result.output_path.ends_with("cover.jpg"));
        assert_eq!(std::fs::read(&result.output_path).unwrap(), b"jpeg");
        server.join().unwrap();
        std::fs::remove_dir_all(root).unwrap();
    }

