        assert!(result.peaks[0].max < 0.0);
        assert!(result.peaks[2].max > 0.99);
        assert!(std::path::Path::new(&result.cache_path).is_file());
        let saved = std::fs::read_to_string(&result.cache_path).unwrap();
        assert!(saved.contains("\"bucket_count\":4"));
