    #[test]
    fn merges_local_subtitle_files() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-subtitle-merge-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        std::fs::create_dir_all(&root).unwrap();
        let first_path = root.join("en.vtt");
        let second_path = root.join("ja.vtt");
        let output_path = root.join("merged.vtt");
        std::fs::write(&first_path, "WEBVTT\n\n00:00.000 --> 00:01.000\nHello\n").unwrap();
        std::fs::write(
            &second_path,
            "WEBVTT\n\n00:01.000 --> 00:02.000\nこんにちは\n",
        )
        .unwrap();

        let result =
            super::metadata_merge_subtitles_at_root(super::MetadataMergeSubtitlesRequest {
                input_paths: vec![
                    first_path.to_string_lossy().to_string(),
                    second_path.to_string_lossy().to_string(),
                ],
                output_path: output_path.to_string_lossy().to_string(),
            })
            .unwrap();

        assert_eq!(result.merged_count, 2);
        assert_eq!(result.output_path, output_path.to_string_lossy());
        let merged = std::fs::read_to_string(&output_path).unwrap();
        assert!(merged.contains("Hello"));
        assert!(merged.contains("こんにちは"));
        assert!(merged.contains("\n\n"));

        std::fs::remove_dir_all(root).unwrap();
    }

    #[test]
    fn merges_utf16le_bom_local_subtitle_files() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-subtitle-merge-utf16-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        std::fs::create_dir_all(&root).unwrap();
        let first_path = root.join("en.vtt");
        let second_path = root.join("ja.srt");
        let output_path = root.join("merged.vtt");
        std::fs::write(&first_path, "WEBVTT\n\n00:00.000 --> 00:01.000\nHello\n").unwrap();
        let second_text = "1\n00:00:01,000 --> 00:00:02,000\nUTF16 subtitle\n";
        let mut second_bytes = vec![0xff, 0xfe];
        for unit in second_text.encode_utf16() {
            second_bytes.extend_from_slice(&unit.to_le_bytes());
        }
        std::fs::write(&second_path, second_bytes).unwrap();

        let result =
            super::metadata_merge_subtitles_at_root(super::MetadataMergeSubtitlesRequest {
                input_paths: vec![
                    first_path.to_string_lossy().to_string(),
                    second_path.to_string_lossy().to_string(),
                ],
                output_path: output_path.to_string_lossy().to_string(),
            })
            .unwrap();

        assert_eq!(result.merged_count, 2);
        let merged = std::fs::read_to_string(&output_path).unwrap();
        assert!(merged.contains("Hello"));
        assert!(merged.contains("UTF16 subtitle"));

        std::fs::remove_dir_all(root).unwrap();
    }

