    #[test]
    fn download_tasks_inherit_network_defaults_from_settings() {
        let mut settings = test_downloads_settings();
        settings.default_user_agent = Some("GlobalAgent/1.0".to_string());
        settings.default_referer = Some("https://example.com/default".to_string());
        settings.default_proxy = Some("socks5://127.0.0.1:1080".to_string());
        settings.default_rate_limit = Some("2M".to_string());
        settings.default_live_from_start = true;
        settings.default_concurrent_fragments = Some(4);
        let now = "2026-07-11T00:00:00Z";

        let inherited = super::build_download_task_from_request_with_settings(
            super::CreateDownloadRequest {
                source_url: "https://www.youtube.com/watch?v=abc123".to_string(),
                kind: Some(super::DownloadKind::Video),
                output_dir: None,
                output_path: None,
                title_override: None,
                user_agent: None,
                referer: None,
                proxy: None,
                cookie_bucket_id: None,
                auth_payload_ref: None,
                rate_limit: None,
                live_from_start: None,
                concurrent_fragments: None,
                custom_ytdlp_args: None,
                start_seconds: None,
                end_seconds: None,
                quality: None,
                audio_format: None,
                thumbnail_url: None,
                expected_sha256: None,
                subtitles: None,
                sponsorblock: None,
                metadata: None,

                run_after_active_slot: None,
            },
            1,
            now,
            &settings,
        )
        .unwrap();

        assert_eq!(inherited.user_agent.as_deref(), Some("GlobalAgent/1.0"));
        assert_eq!(
            inherited.referer.as_deref(),
            Some("https://example.com/default")
        );
        assert_eq!(inherited.proxy.as_deref(), Some("socks5://127.0.0.1:1080"));
        assert_eq!(inherited.rate_limit.as_deref(), Some("2M"));
        assert!(inherited.live_from_start);
        assert_eq!(inherited.concurrent_fragments, Some(4));

        let override_task = super::build_download_task_from_request_with_settings(
            super::CreateDownloadRequest {
                source_url: "https://www.youtube.com/watch?v=override".to_string(),
                kind: Some(super::DownloadKind::Video),
                output_dir: None,
                output_path: None,
                title_override: None,
                user_agent: Some("TaskAgent/2.0".to_string()),
                referer: Some("https://example.com/task".to_string()),
                proxy: Some("http://127.0.0.1:8080".to_string()),
                cookie_bucket_id: None,
                auth_payload_ref: None,
                rate_limit: Some("500K".to_string()),
                live_from_start: Some(false),
                concurrent_fragments: Some(2),
                custom_ytdlp_args: None,
                start_seconds: None,
                end_seconds: None,
                quality: None,
                audio_format: None,
                thumbnail_url: None,
                expected_sha256: None,
                subtitles: None,
                sponsorblock: None,
                metadata: None,

                run_after_active_slot: None,
            },
            2,
            now,
            &settings,
        )
        .unwrap();

        assert_eq!(override_task.user_agent.as_deref(), Some("TaskAgent/2.0"));
        assert_eq!(
            override_task.referer.as_deref(),
            Some("https://example.com/task")
        );
        assert_eq!(
            override_task.proxy.as_deref(),
            Some("http://127.0.0.1:8080")
        );
        assert_eq!(override_task.rate_limit.as_deref(), Some("500K"));
        assert!(!override_task.live_from_start);
        assert_eq!(override_task.concurrent_fragments, Some(2));
    }

