    #[test]
    fn executes_ytdlp_plan_with_configured_tool_path() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-ytdlp-exec-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        std::fs::create_dir_all(root.join("downloads")).unwrap();
        let (tool_path, observed_args_path) = fake_ytdlp_tool(&root);
        super::set_tool_path_override(&root, "yt-dlp", tool_path.to_string_lossy().as_ref())
            .unwrap();

        let mut task = test_task("https://www.youtube.com/watch?v=abc123");
        task.platform = "youtube".to_string();
        task.output_dir = Some(root.join("downloads").to_string_lossy().to_string());
        task.quality = Some("720p".to_string());

        let progress = super::execute_ytdlp_download(&root, &task).unwrap();

        let observed_args = std::fs::read_to_string(&observed_args_path).unwrap();
        assert!(observed_args.contains("--format"));
        assert!(observed_args.contains("bestvideo[height<=720]+bestaudio/best[height<=720]/best"));
        assert!(observed_args.contains("https://www.youtube.com/watch?v=abc123"));
        assert!(progress.output_path.ends_with("video-output.mp4"));
        assert_eq!(progress.downloaded_bytes, 13);
        assert_eq!(progress.total_bytes, Some(13));

        std::fs::remove_dir_all(root).unwrap();
    }

