    #[test]
    fn streams_ytdlp_progress_while_process_is_running() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-ytdlp-stream-progress-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        let downloads_dir = root.join("downloads");
        std::fs::create_dir_all(&downloads_dir).unwrap();
        let (tool_path, _observed_args_path, progress_marker_path) =
            fake_ytdlp_tool_with_delayed_progress(&root);
        super::set_tool_path_override(&root, "yt-dlp", tool_path.to_string_lossy().as_ref())
            .unwrap();
        let now = "2026-07-11T00:00:00Z";

        let created = super::create_download_task_at_root(
            &root,
            super::CreateDownloadRequest {
                source_url: "https://www.youtube.com/watch?v=stream-progress".to_string(),
                kind: Some(super::DownloadKind::Video),
                output_dir: Some(downloads_dir.to_string_lossy().to_string()),
                output_path: None,
                title_override: Some("Stream progress".to_string()),
                user_agent: None,
                referer: None,
                proxy: None,
                cookie_bucket_id: None,
                auth_payload_ref: None,
                rate_limit: None,
                live_from_start: None,
                concurrent_fragments: None,
                custom_ytdlp_args: None,
                start_seconds: None,
                end_seconds: None,
                quality: Some("720p".to_string()),
                audio_format: None,
                thumbnail_url: None,
                expected_sha256: None,
                subtitles: None,
                sponsorblock: None,
                metadata: None,

                run_after_active_slot: None,
            },
            now,
        )
        .unwrap();

        super::queue_download_start_at_root(&root, &created.id, now).unwrap();
        let active = super::activate_runnable_downloads_at_root(&root, now).unwrap();
        assert_eq!(active.len(), 1);

        let worker_root = root.clone();
        let worker_task = active[0].clone();
        let handle = thread::spawn(move || {
            let cancel_flag = std::sync::atomic::AtomicBool::new(false);
            super::prepare_external_ytdlp_download_at_root(
                &worker_root,
                &worker_task,
                None,
                &cancel_flag,
            )
        });

        let started_waiting = std::time::Instant::now();
        while !progress_marker_path.exists()
            && started_waiting.elapsed() < std::time::Duration::from_secs(2)
        {
            thread::sleep(std::time::Duration::from_millis(25));
        }
        assert!(
            progress_marker_path.exists(),
            "fake yt-dlp did not emit progress"
        );

        let progress_wait_started = std::time::Instant::now();
        let mut observed_downloaded_while_running = None;
        let mut observed_total_while_running = None;
        while progress_wait_started.elapsed() < std::time::Duration::from_millis(1500)
            && !handle.is_finished()
        {
            let persisted = super::read_download_tasks(&root).unwrap();
            observed_downloaded_while_running = persisted[0].downloaded_bytes;
            observed_total_while_running = persisted[0].total_bytes;
            if observed_downloaded_while_running == Some(4_456_448) {
                break;
            }
            thread::sleep(std::time::Duration::from_millis(25));
        }

        let progress = handle.join().unwrap().unwrap();
        assert_eq!(progress.downloaded_bytes, 13);
        assert_eq!(observed_downloaded_while_running, Some(4_456_448));
        assert_eq!(observed_total_while_running, Some(10 * 1024 * 1024));

        std::fs::remove_dir_all(root).unwrap();
    }

    #[test]
    fn cancels_running_ytdlp_child_process() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-ytdlp-cancel-child-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        let downloads_dir = root.join("downloads");
        std::fs::create_dir_all(&downloads_dir).unwrap();
        let (tool_path, started_marker_path) = fake_ytdlp_tool_that_waits_without_output(&root);
        super::set_tool_path_override(&root, "yt-dlp", tool_path.to_string_lossy().as_ref())
            .unwrap();

        let mut task = test_task("https://www.youtube.com/watch?v=cancel-child");
        task.kind = super::DownloadKind::Video;
        task.platform = "youtube".to_string();
        task.output_dir = Some(downloads_dir.to_string_lossy().to_string());
        let cancel_flag = std::sync::Arc::new(std::sync::atomic::AtomicBool::new(false));

        let worker_root = root.clone();
        let worker_task = task.clone();
        let worker_cancel_flag = cancel_flag.clone();
        let handle = thread::spawn(move || {
            super::execute_ytdlp_download_with_app(
                &worker_root,
                &worker_task,
                None,
                &worker_cancel_flag,
            )
        });

        let started_waiting = std::time::Instant::now();
        while !started_marker_path.exists()
            && started_waiting.elapsed() < std::time::Duration::from_secs(2)
        {
            thread::sleep(std::time::Duration::from_millis(25));
        }
        assert!(
            started_marker_path.exists(),
            "fake yt-dlp child did not start"
        );

        cancel_flag.store(true, std::sync::atomic::Ordering::SeqCst);
        let error = match handle.join().unwrap() {
            Ok(progress) => panic!("expected canceled yt-dlp, got {}", progress.output_path),
            Err(error) => error,
        };
        assert_eq!(error, super::DOWNLOAD_INTERRUPTED_MESSAGE);
        assert!(std::fs::read_dir(&downloads_dir).unwrap().next().is_none());

        std::fs::remove_dir_all(root).unwrap();
    }

