    #[test]
    fn stores_download_settings_and_limits_scheduler_slots() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-download-settings-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));

        let too_low = super::DownloadsSettings {
            schema_version: 99,
            max_concurrency: 0,
            default_output_dir: None,
            organize_by_platform: false,
            filename_template: "".to_string(),
            skip_existing: false,
            default_quality: "".to_string(),
            default_audio_format: "bad-format".to_string(),
            default_user_agent: Some(" FetchDock/Global\r\nAgent ".to_string()),
            default_referer: Some(" https://example.com/source ".to_string()),
            default_proxy: Some(" socks5://127.0.0.1:1080 ".to_string()),
            default_rate_limit: Some(" 2M ".to_string()),
            default_live_from_start: true,
            default_concurrent_fragments: Some(32),
            custom_ytdlp_args: None,
            subtitles: super::SubtitleSettings {
                languages: vec![" en ".to_string(), "".to_string(), "en".to_string()],
                auto: true,
                embed: false,
                keep_vtt: true,
            },
            sponsorblock: super::SponsorBlockSettings {
                enabled: true,
                categories: vec![" sponsor ".to_string(), "".to_string(), "intro".to_string()],
            },
            metadata: super::MetadataSettings {
                embed_metadata: true,
                embed_thumbnail: true,
                split_chapters: false,
            },
        };

        let saved = super::write_downloads_settings(&root, &too_low).unwrap();
        let restored = super::read_downloads_settings(&root).unwrap();

        assert_eq!(saved.schema_version, 1);
        assert_eq!(saved.max_concurrency, 1);
        assert_eq!(saved.default_quality, "best");
        assert_eq!(saved.default_audio_format, "m4a");
        assert_eq!(
            saved.default_user_agent.as_deref(),
            Some("FetchDock/Global Agent")
        );
        assert_eq!(
            saved.default_referer.as_deref(),
            Some("https://example.com/source")
        );
        assert_eq!(
            saved.default_proxy.as_deref(),
            Some("socks5://127.0.0.1:1080")
        );
        assert_eq!(saved.default_rate_limit.as_deref(), Some("2M"));
        assert!(saved.default_live_from_start);
        assert_eq!(saved.default_concurrent_fragments, None);
        assert_eq!(saved.subtitles.languages, vec!["en".to_string()]);
        assert!(saved.subtitles.auto);
        assert!(saved.subtitles.keep_vtt);
        assert!(saved.sponsorblock.enabled);
        assert_eq!(
            saved.sponsorblock.categories,
            vec!["sponsor".to_string(), "intro".to_string()]
        );
        assert!(saved.metadata.embed_metadata);
        assert!(saved.metadata.embed_thumbnail);
        assert!(!saved.metadata.split_chapters);
        assert_eq!(restored, saved);
        assert_eq!(
            super::available_download_slots(restored.max_concurrency, 0),
            1
        );
        assert_eq!(super::available_download_slots(3, 1), 2);
        assert_eq!(super::available_download_slots(3, 4), 0);
        assert_eq!(
            super::sanitize_max_concurrency(usize::MAX),
            super::MAX_ACTIVE_DOWNLOADS_LIMIT
        );

        std::fs::remove_dir_all(root).unwrap();
    }

    #[test]
    fn detects_managed_path_and_missing_dependency_tools() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-tools-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        let managed_ytdlp = root
            .join("dependencies")
            .join("yt-dlp")
            .join(super::tool_executable_file_name("yt-dlp"));
        std::fs::create_dir_all(managed_ytdlp.parent().unwrap()).unwrap();
        std::fs::write(&managed_ytdlp, b"").unwrap();

        let tools = super::detect_tool_statuses(&root, Some("")).unwrap();
        let ytdlp = tools.iter().find(|tool| tool.id == "yt-dlp").unwrap();
        let ffmpeg = tools.iter().find(|tool| tool.id == "ffmpeg").unwrap();

        assert_eq!(tools.len(), 5);
        assert_eq!(ytdlp.state, super::ToolState::Error);
        assert!(ytdlp.managed);
        assert_eq!(
            ytdlp.path.as_deref(),
            Some(managed_ytdlp.to_string_lossy().as_ref())
        );
        assert_eq!(ffmpeg.state, super::ToolState::Missing);
        assert!(!ffmpeg.managed);

        std::fs::remove_dir_all(root).unwrap();
    }

    #[test]
    fn saves_tool_path_overrides_and_rejects_invalid_paths() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-tool-overrides-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        let override_dir = root.join("manual-tools");
        let override_path = override_dir.join(super::tool_executable_file_name("ffmpeg"));
        std::fs::create_dir_all(&override_dir).unwrap();
        std::fs::write(&override_path, b"").unwrap();

        let saved = super::set_tool_path_override(
            &root,
            "ffmpeg",
            override_path.to_string_lossy().as_ref(),
        )
        .unwrap();
        let tools = super::detect_tool_statuses(&root, Some("")).unwrap();
        let ffmpeg = tools.iter().find(|tool| tool.id == "ffmpeg").unwrap();

        assert_eq!(
            saved.path.as_deref(),
            Some(override_path.to_string_lossy().as_ref())
        );
        assert_eq!(ffmpeg.state, super::ToolState::Error);
        assert!(!ffmpeg.managed);
        assert_eq!(
            ffmpeg.path.as_deref(),
            Some(override_path.to_string_lossy().as_ref())
        );
        assert!(super::set_tool_path_override(
            &root,
            "ffmpeg",
            override_dir.to_string_lossy().as_ref()
        )
        .is_err());
        assert!(super::set_tool_path_override(
            &root,
            "ffmpeg",
            root.join("missing.exe").to_string_lossy().as_ref()
        )
        .is_err());
        assert!(super::set_tool_path_override(
            &root,
            "not-a-tool",
            override_path.to_string_lossy().as_ref()
        )
        .is_err());

        super::clear_tool_path_override(&root, "ffmpeg").unwrap();
        let restored = super::detect_tool_statuses(&root, Some("")).unwrap();
        let restored_ffmpeg = restored.iter().find(|tool| tool.id == "ffmpeg").unwrap();

        assert_eq!(restored_ffmpeg.state, super::ToolState::Missing);

        std::fs::remove_dir_all(root).unwrap();
    }

