    #[test]
    fn keeps_existing_managed_dependency_when_update_verification_fails() {
        let listener = TcpListener::bind("127.0.0.1:0").unwrap();
        let port = listener.local_addr().unwrap().port();
        let server = thread::spawn(move || {
            let (mut stream, _) = listener.accept().unwrap();
            let mut request_buffer = [0; 512];
            let _ = stream.read(&mut request_buffer).unwrap();
            stream
                .write_all(b"HTTP/1.1 200 OK\r\nContent-Length: 3\r\n\r\nbad")
                .unwrap();
        });
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-tool-update-preserve-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        let final_path = super::managed_tool_path(&root, "yt-dlp").unwrap();
        std::fs::create_dir_all(final_path.parent().unwrap()).unwrap();
        std::fs::write(&final_path, b"old").unwrap();
        let mut settings = super::ToolSettings {
            schema_version: 1,
            ..Default::default()
        };
        settings.download_sources.insert(
            "yt-dlp".to_string(),
            super::ToolDownloadSource {
                url: format!("http://127.0.0.1:{port}/yt-dlp.exe"),
                sha256: "ba7816bf8f01cfea414140de5dae2223b00361a396177a9cb410ff61f20015ad"
                    .to_string(),
                archive_member: None,
            },
        );
        super::write_tool_settings(&root, &settings).unwrap();
        let mut stages = Vec::new();

        let status = super::request_tool_update_with_progress(&root, "yt-dlp", &mut |update| {
            stages.push(update.stage)
        })
        .unwrap();
        server.join().unwrap();

        assert_eq!(status.state, super::ToolState::Error);
        assert_eq!(std::fs::read(&final_path).unwrap(), b"old");
        assert!(!final_path.with_file_name("yt-dlp.exe.download").exists());
        assert_eq!(
            stages,
            vec![
                super::ToolInstallStage::Downloading,
                super::ToolInstallStage::Verifying
            ]
        );

        std::fs::remove_dir_all(root).unwrap();
    }

