    #[test]
    fn stores_download_tasks_in_sqlite_database() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-sqlite-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        std::fs::create_dir_all(root.join("db")).unwrap();
        let mut task = test_task("http://127.0.0.1/file.bin");
        task.id = "sqlite-task".to_string();

        super::write_download_tasks(&root, &[task.clone()]).unwrap();
        let restored = super::read_download_tasks(&root).unwrap();

        assert!(root.join("db").join("fetchdock.sqlite3").exists());
        assert_eq!(restored.len(), 1);
        assert_eq!(restored[0].id, task.id);

        std::fs::remove_dir_all(root).unwrap();
    }

    #[test]
    fn does_not_reimport_legacy_json_when_sqlite_store_exists() {
        let root = std::env::temp_dir().join(format!(
            "fetchdock-test-sqlite-existing-{}",
            std::time::SystemTime::now()
                .duration_since(std::time::UNIX_EPOCH)
                .unwrap()
                .as_nanos()
        ));
        std::fs::create_dir_all(root.join("db")).unwrap();
        let mut legacy_task = test_task("http://127.0.0.1/file.bin");
        legacy_task.id = "legacy-task".to_string();
        std::fs::write(
            root.join("db").join("download-tasks.json"),
            serde_json::to_vec(&vec![legacy_task]).unwrap(),
        )
        .unwrap();

        super::write_download_tasks(&root, &[]).unwrap();
        let restored = super::read_download_tasks(&root).unwrap();

        assert!(restored.is_empty());

        std::fs::remove_dir_all(root).unwrap();
    }

    #[test]
    fn classifies_transient_http_errors_as_retryable() {
        let classified =
            super::classify_download_error("HTTP request failed: HTTP/1.1 503 Service Unavailable");

        assert_eq!(classified.category, super::DownloadErrorCategory::Network);
        assert!(classified.retryable);
    }

    #[test]
    fn classifies_missing_ytdlp_as_dependency_missing() {
        let classified = super::classify_download_error(
            "yt-dlp was not found. Install it from Settings or set a valid executable path.",
        );

        assert_eq!(
            classified.category,
            super::DownloadErrorCategory::DependencyMissing
        );
        assert!(!classified.retryable);
    }

