    #[test]
    fn parses_ytdlp_download_progress_line() {
        let progress = super::parse_ytdlp_progress_line(
            "[download]  42.5% of   10.00MiB at    1.25MiB/s ETA 00:04",
        )
        .unwrap();

        assert_eq!(progress.total_bytes, Some(10 * 1024 * 1024));
        assert_eq!(progress.downloaded_bytes, 4_456_448);
        assert_eq!(progress.speed_bytes_per_sec, Some(1_310_720));
        assert_eq!(progress.eta_seconds, Some(4));
    }

    #[test]
    fn builds_ytdlp_download_progress_event() {
        let mut task = test_task("https://www.youtube.com/watch?v=event");
        task.id = "event-task".to_string();
        task.output_path = Some("E:/Downloads/video.mp4".to_string());
        let progress = super::YtdlpProgress {
            downloaded_bytes: 4_456_448,
            total_bytes: Some(10 * 1024 * 1024),
            speed_bytes_per_sec: Some(1_310_720),
            eta_seconds: Some(4),
        };

        let event = super::ytdlp_progress_event(&task, &progress);

        assert_eq!(event.schema_version, 1);
        assert_eq!(event.task_id, "event-task");
        assert_eq!(event.status, super::DownloadStatus::Active);
        assert_eq!(event.downloaded_bytes, 4_456_448);
        assert_eq!(event.total_bytes, Some(10 * 1024 * 1024));
        assert_eq!(event.speed_bytes_per_sec, Some(1_310_720));
        assert_eq!(event.eta_seconds, Some(4));
        assert_eq!(event.file_count, Some(1));
        assert_eq!(event.output_path.as_deref(), Some("E:/Downloads/video.mp4"));
        assert_eq!(event.message, "Downloading.");
    }

    #[test]
    fn recovers_interrupted_active_tasks_to_queue() {
        let mut task = test_task("http://127.0.0.1/file.bin");
        task.id = "active".to_string();
        task.title = "file".to_string();
        task.status = super::DownloadStatus::Active;
        task.downloaded_bytes = Some(128);
        task.total_bytes = Some(1024);
        task.started_at = Some("2026-07-11T00:00:01Z".to_string());
        let mut tasks = vec![task];

        let recovered = super::recover_interrupted_tasks(&mut tasks);

        assert_eq!(recovered, 1);
        assert_eq!(tasks[0].status, super::DownloadStatus::Queued);
        assert!(tasks[0].last_error.is_some());
    }
